"use strict";(globalThis.webpackChunkbytesofpurpose_blog=globalThis.webpackChunkbytesofpurpose_blog||[]).push([[71830],{74308:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"a-guide-to-these-posts","metadata":{"permalink":"/thoughts/a-guide-to-these-posts","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-06-24-a-guide-to-these-posts.mdx","source":"@site/blog/2026-06-24-a-guide-to-these-posts.mdx","title":"A Guide to These Posts","description":"How this blog is organized: what the sidebar emoji mean, the kinds of posts I write, and where to start reading.","date":"2026-06-24T00:00:00.000Z","tags":[{"inline":true,"label":"meta","permalink":"/thoughts/tags/meta"}],"readingTime":2.07,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"a-guide-to-these-posts","title":"A Guide to These Posts","kind":"legend","sidebar_label":"Start Here","description":"How this blog is organized: what the sidebar emoji mean, the kinds of posts I write, and where to start reading.","authors":["oeid"],"tags":["meta"],"date":"2026-06-24T00:00:00.000Z","draft":false},"unlisted":false,"nextItem":{"title":"Shipping a Component Package, and Proving It Works","permalink":"/thoughts/shipping-a-component-package"}},"content":"If you are new here, this is the front door. It explains how the Posts list is\\norganized, what the little emoji next to each title mean, and where to start.\\n\\n\x3c!-- truncate --\x3e\\n\\n## The emoji tell you the TYPE of post\\n\\nEvery post in the sidebar leads with an emoji. The emoji is not decoration and it is\\nnot about the topic. It tells you what KIND of thing the post is, so you can scan the\\nlist and find the format you are in the mood for. Here is the legend:\\n\\n| Emoji | Kind | What it is |\\n|---|---|---|\\n| \u2753 | Question set | A set of questions to ask yourself, grouped by theme. The \\"What I Ask Myself\\" series. |\\n| \ud83e\udde9 | Framework | A reusable model for thinking about something. \\"A Framework for\\", \\"The Anatomy of\\". |\\n| \ud83d\udcad | Reflection | A personal essay or set of takeaways. \\"Notes From\\", \\"What X Taught Me\\", affirmations. |\\n| \ud83c\udfd7\ufe0f | System design | An architecture or build write-up: how something was designed and shipped. |\\n| \ud83d\udcd0 | Design story | The story behind a design: why it exists, with a link to the full design doc. |\\n| \ud83e\uddea | Tutorial | A hands-on, learn-by-doing walkthrough. \\"A Hands-On Way to\\", \\"Running X Locally\\". |\\n| \ud83d\udcd6 | Reference | A concept explainer or taxonomy. \\"A Taxonomy of\\", \\"What Does X Mean\\". |\\n| \ud83c\udf99\ufe0f | Event recap | Notes from a conference or event. |\\n| \ud83e\udded | Legend | A guide like this one: it indexes a set of posts and the conventions they share. |\\n\\nThe title in the sidebar is kept short on purpose. The full title still lives at the\\ntop of each post and in the browser tab.\\n\\n## Where to start\\n\\nA few entry points depending on what you came for:\\n\\n- **To sit with a question about yourself**, start with the question sets (\u2753). The\\n  keystone is [What I Ask Myself](/thoughts/what-i-ask-myself), which explains the\\n  practice and the power icons on each question.\\n- **To borrow a way of thinking**, browse the frameworks (\ud83e\udde9).\\n- **To see how something was built**, read the system designs (\ud83c\udfd7\ufe0f) and tutorials (\ud83e\uddea).\\n- **For a shorter, more personal read**, the reflections (\ud83d\udcad) are the place.\\n\\n## How the question sets work\\n\\nThe largest group here is the question sets. Each one is a themed collection of\\nquestions I actually return to, with a power icon on every question showing what kind\\nof charge it carries (a jolt, a burn, something that reshapes you over time). The full\\nlegend for those power icons lives in the keystone post,\\n[What I Ask Myself](/thoughts/what-i-ask-myself). If you only read one thing, read that."},{"id":"shipping-a-component-package","metadata":{"permalink":"/thoughts/shipping-a-component-package","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-06-23-shipping-a-component-package.md","source":"@site/blog/2026-06-23-shipping-a-component-package.md","title":"Shipping a Component Package, and Proving It Works","description":"How I extracted my blog\'s React components into a published package, proved it consumable from a second repo, and gave that repo a CI-built Pages deploy that installs it.","date":"2026-06-23T10:00:00.000Z","tags":[{"inline":true,"label":"system-design","permalink":"/thoughts/tags/system-design"},{"inline":true,"label":"devops","permalink":"/thoughts/tags/devops"},{"inline":true,"label":"github-actions","permalink":"/thoughts/tags/github-actions"},{"inline":true,"label":"generative-ai","permalink":"/thoughts/tags/generative-ai"},{"inline":true,"label":"claude","permalink":"/thoughts/tags/claude"}],"readingTime":3.24,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"shipping-a-component-package","title":"Shipping a Component Package, and Proving It Works","kind":"design-story","sidebar_label":"Shipping a Package","description":"How I extracted my blog\'s React components into a published package, proved it consumable from a second repo, and gave that repo a CI-built Pages deploy that installs it.","authors":["oeid"],"tags":["system-design","devops","github-actions","generative-ai","claude"],"date":"2026-06-23T10:00","draft":false},"unlisted":false,"prevItem":{"title":"A Guide to These Posts","permalink":"/thoughts/a-guide-to-these-posts"},"nextItem":{"title":"Autonomous Build Agents: Designing the Build Half of Low-Code Delivery","permalink":"/thoughts/autonomous-build-agents"}},"content":"My blog had grown a small library of custom React components for design posts: an animated UX `Walkthrough`, a `Mockup` frame, a footnoted diagram, an assumption highlight. They were good enough that I wanted to use them in other projects too. The honest test of \\"reusable\\" is not whether the code looks clean. It is whether a *different* repo can actually install it and render it. So I set out to make that true, end to end.\\n\\n\x3c!-- truncate --\x3e\\n\\n## From components to a package\\n\\nThe first step was extracting the four components into a real package, `@omars-lab/blog-ui`, published to GitHub Packages. That meant a proper build (an ES module plus type declarations plus a bundled stylesheet), a release pipeline (tag, build, publish on a GitHub Actions workflow), and a dress rehearsal step so I could see exactly what would ship before it shipped. The blog itself consumes the package locally, so any breaking change shows up in the blog\'s build immediately.\\n\\nPublishing was the easy half. The interesting half was proving the package was genuinely usable somewhere else.\\n\\n## Proving it from a second repo\\n\\nI have a separate teaching project, a \\"getting started with Claude agents\\" guide, that ships a simple web page. I rebuilt that page as a Vite app whose only job, for the purposes of this exercise, was to `yarn add @omars-lab/blog-ui` from GitHub Packages, import a component, and render it. If a real bundler in a real second repo could resolve the package, pull in its styles, and put a working `Walkthrough` on screen, then \\"reusable\\" was no longer an aspiration.\\n\\nIt worked: the bundler resolved the package, the component\'s scoped styles landed in the output, and the page rendered the animated walkthrough. That was the proof I wanted.\\n\\n## The quieter problem: how does it deploy?\\n\\nProving the build works locally is one thing. Getting that site *deployed* is another, because the build now depended on a package behind authentication. The site published to GitHub Pages, and the existing setup served a committed copy of the built files. That has a sharp edge: if the source changes and nobody rebuilds and commits, the live site silently drifts from the source.\\n\\nSo I moved the deploy into CI, where every publish is a fresh build of the current source. The wrinkle is that the CI build has to install the private package, which needs a token. The neat part: because the package and the deploying repo are owned by the same account, the repository\'s built-in Actions token can read it directly, no personal access token, no stored secret. The build authenticates with a credential that already exists.\\n\\nI wrote that migration up as a design doc, including the same-owner auth trick, the two-job build-and-deploy pattern, and how I validate the workflow before it runs:\\n\\n\ud83d\udc49 **[Building a Pages Deploy That Consumes a Private Package](/designs/design-actions-pages-deploy)**\\n\\n## What I leaned on\\n\\nA few first-party sources did the heavy lifting, and they are worth bookmarking if you are wiring up the same thing:\\n\\n- [Using custom workflows with GitHub Pages](https://docs.github.com/en/pages/getting-started-with-github-pages/using-custom-workflows-with-github-pages) for the build-and-deploy model.\\n- [actions/upload-pages-artifact](https://github.com/actions/upload-pages-artifact) and [actions/deploy-pages](https://github.com/actions/deploy-pages) for the two-job handoff.\\n- [actionlint](https://github.com/rhysd/actionlint) for catching workflow mistakes before they ever run in CI.\\n\\n## The takeaway\\n\\n\\"Reusable\\" is a claim you can actually test. Extract the code into a package, publish it, then make a *different* repo install and render it, and deploy that repo from source so the proof keeps holding. The components I started with are now a thing other projects can depend on, and there is a second site standing on them to show it."},{"id":"autonomous-build-agents","metadata":{"permalink":"/thoughts/autonomous-build-agents","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-06-22-autonomous-build-agents.md","source":"@site/blog/2026-06-22-autonomous-build-agents.md","title":"Autonomous Build Agents: Designing the Build Half of Low-Code Delivery","description":"The story behind a design for autonomous build agents: how a delivery org could carry a work item through configuration and validation on a client\'s system, safely.","date":"2026-06-22T10:00:00.000Z","tags":[{"inline":true,"label":"system-design","permalink":"/thoughts/tags/system-design"},{"inline":true,"label":"architecture","permalink":"/thoughts/tags/architecture"},{"inline":true,"label":"generative-ai","permalink":"/thoughts/tags/generative-ai"},{"inline":true,"label":"claude","permalink":"/thoughts/tags/claude"},{"inline":true,"label":"agents","permalink":"/thoughts/tags/agents"},{"inline":true,"label":"designs","permalink":"/thoughts/tags/designs"}],"readingTime":1.32,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"autonomous-build-agents","title":"Autonomous Build Agents: Designing the Build Half of Low-Code Delivery","kind":"design-story","sidebar_label":"Build Agents","description":"The story behind a design for autonomous build agents: how a delivery org could carry a work item through configuration and validation on a client\'s system, safely.","authors":["oeid"],"tags":["system-design","architecture","generative-ai","claude","agents","designs"],"date":"2026-06-22T10:00","draft":false},"unlisted":false,"prevItem":{"title":"Shipping a Component Package, and Proving It Works","permalink":"/thoughts/shipping-a-component-package"},"nextItem":{"title":"Ecommerce Site Scanner: A Lead Engine That Finds What\'s Wrong","permalink":"/thoughts/ecommerce-site-scanner"}},"content":"I co-designed this one with Claude the way I wish I always wrote high-level designs: I drove the structure (purpose, scope, options, decisions, risks) and used Claude as a co-designer, proposing architectures, naming the trade-offs, and pushing back when a decision was hand-wavy. This is the story behind it. The full design doc is on the Designs blog.\\n\\n\ud83d\udc49 **[Read the design: Autonomous Build Agents](/designs/design-autonomous-build-agents)**\\n\\n\x3c!-- truncate --\x3e\\n\\n## The problem\\n\\nA delivery org has already automated the *planning* phase of low-code SaaS delivery: documents in, sprint-ready work items out. But the *build* is still entirely manual. Someone picks up each work item and configures it by hand.\\n\\n## The design\\n\\nThis design proposes four agents (Instance Readiness, Auto Developer, Auto Tester, Knowledge Transfer Writer) that pick up a work item and carry it through configuration and validation. The hard part is cross-instance execution: the agents run on the org\'s own build instance but must safely change a *client\'s* system. Three architectures are compared, from a reviewable \\"instance commit\\" artifact to a live supervised bridge.\\n\\n## Why it\'s worth reading\\n\\nThe design is marked **In Review**: it has genuine open questions, not the tidy certainty of a post-mortem. The cross-instance safety question in particular is the kind of decision where the options matter more than the answer. Read it like a colleague\'s notes, and if a better idea occurs to you, that is exactly the kind of review the document was built to invite.\\n\\n\ud83d\udc49 **[Open the full design doc](/designs/design-autonomous-build-agents)**"},{"id":"ecommerce-site-scanner","metadata":{"permalink":"/thoughts/ecommerce-site-scanner","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-06-22-ecommerce-site-scanner.md","source":"@site/blog/2026-06-22-ecommerce-site-scanner.md","title":"Ecommerce Site Scanner: A Lead Engine That Finds What\'s Wrong","description":"The story behind a design for an autonomous lead-generation engine that scans ecommerce sites for growth problems, verifies a contact, and drafts outreach for a human to send.","date":"2026-06-22T10:00:00.000Z","tags":[{"inline":true,"label":"system-design","permalink":"/thoughts/tags/system-design"},{"inline":true,"label":"architecture","permalink":"/thoughts/tags/architecture"},{"inline":true,"label":"generative-ai","permalink":"/thoughts/tags/generative-ai"},{"inline":true,"label":"claude","permalink":"/thoughts/tags/claude"},{"inline":true,"label":"ecommerce","permalink":"/thoughts/tags/ecommerce"},{"inline":true,"label":"designs","permalink":"/thoughts/tags/designs"}],"readingTime":1.19,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"ecommerce-site-scanner","title":"Ecommerce Site Scanner: A Lead Engine That Finds What\'s Wrong","kind":"design-story","sidebar_label":"Site Scanner","description":"The story behind a design for an autonomous lead-generation engine that scans ecommerce sites for growth problems, verifies a contact, and drafts outreach for a human to send.","authors":["oeid"],"tags":["system-design","architecture","generative-ai","claude","ecommerce","designs"],"date":"2026-06-22T10:00","draft":false},"unlisted":false,"prevItem":{"title":"Autonomous Build Agents: Designing the Build Half of Low-Code Delivery","permalink":"/thoughts/autonomous-build-agents"},"nextItem":{"title":"Markdown Review Studio: Closing the Loop Between Feedback and Edit","permalink":"/thoughts/markdown-review-studio"}},"content":"This is one of four high-level designs I worked through with Claude as a co-designer: I drove the structure and the decisions, Claude proposed architectures and named the trade-offs. This post is the story; the full design doc is on the Designs blog.\\n\\n\ud83d\udc49 **[Read the design: Ecommerce Site Scanner and Lead Generation Engine](/designs/design-ecommerce-site-scanner-and-lead-generation-engine)**\\n\\n\x3c!-- truncate --\x3e\\n\\n## The problem\\n\\nA two-person founding team cannot hand-prospect enough qualified ecommerce leads. The work is real but it does not scale with two pairs of hands.\\n\\n## The design\\n\\nThis design is an autonomous engine that discovers sites, scans their public pages for growth-marketing problems, estimates size, finds and verifies a contact, scores the lead with explainable reasons, and drafts a personalized outreach message for a human to send. Outreach stays draft-only, with a human on every send.\\n\\nIt is also the front door to a bigger idea: the scanning intelligence that *finds* what is wrong is the same engine that will later *fix* it (see the [Self-Healing Storefront](/thoughts/self-healing-storefront)).\\n\\n## Why it\'s worth reading\\n\\nThe design is **In Review**, so you are seeing the open questions too: how to verify a contact responsibly, how to keep scoring explainable, where the human stays in the loop. Read it like a colleague\'s notes.\\n\\n\ud83d\udc49 **[Open the full design doc](/designs/design-ecommerce-site-scanner-and-lead-generation-engine)**"},{"id":"markdown-review-studio","metadata":{"permalink":"/thoughts/markdown-review-studio","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-06-22-markdown-review-studio.md","source":"@site/blog/2026-06-22-markdown-review-studio.md","title":"Markdown Review Studio: Closing the Loop Between Feedback and Edit","description":"The story behind a design for a local-first app to review markdown with visually anchored comments and trigger Claude Code to act on them, with every round committed to git.","date":"2026-06-22T10:00:00.000Z","tags":[{"inline":true,"label":"system-design","permalink":"/thoughts/tags/system-design"},{"inline":true,"label":"architecture","permalink":"/thoughts/tags/architecture"},{"inline":true,"label":"generative-ai","permalink":"/thoughts/tags/generative-ai"},{"inline":true,"label":"claude","permalink":"/thoughts/tags/claude"},{"inline":true,"label":"tooling","permalink":"/thoughts/tags/tooling"},{"inline":true,"label":"designs","permalink":"/thoughts/tags/designs"}],"readingTime":1.23,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"markdown-review-studio","title":"Markdown Review Studio: Closing the Loop Between Feedback and Edit","kind":"design-story","sidebar_label":"Review Studio","description":"The story behind a design for a local-first app to review markdown with visually anchored comments and trigger Claude Code to act on them, with every round committed to git.","authors":["oeid"],"tags":["system-design","architecture","generative-ai","claude","tooling","designs"],"date":"2026-06-22T10:00","draft":false},"unlisted":false,"prevItem":{"title":"Ecommerce Site Scanner: A Lead Engine That Finds What\'s Wrong","permalink":"/thoughts/ecommerce-site-scanner"},"nextItem":{"title":"Self-Healing Storefront: An Agent That Runs Its Own A/B Tests","permalink":"/thoughts/self-healing-storefront"}},"content":"The most meta of four designs I co-designed with Claude, and the one I most want to build. I drove the structure and decisions; Claude proposed architectures and named the trade-offs. This is the story; the full design doc is on the Designs blog.\\n\\n\ud83d\udc49 **[Read the design: Markdown Review Studio](/designs/design-markdown-review-studio)**\\n\\n\x3c!-- truncate --\x3e\\n\\n## The problem\\n\\nReviewing long markdown documents (like these very design docs) with an AI assistant is lossy: feedback is unanchored prose in a chat window, and the link between a comment and the edit it produced is never recorded. You lose the trail from \\"here is my feedback\\" to \\"the doc changed because of it.\\"\\n\\n## The design\\n\\nMarkdown Review Studio is a local-first web app to view a markdown file, leave visually anchored comments, and trigger Claude Code to act on them, with every round committed to git. It closes the loop between \\"here is my feedback\\" and \\"the doc is updated.\\"\\n\\nFittingly, it is the tool I would use to review the other three designs in this set.\\n\\n## Why it\'s worth reading\\n\\nThe design is **In Review**. The open questions are about the anchoring (how a comment stays attached to the right span as the doc changes) and the git-per-round model. Read it like a colleague\'s notes, and if you would build it differently, that is the kind of review the doc invites.\\n\\n\ud83d\udc49 **[Open the full design doc](/designs/design-markdown-review-studio)**"},{"id":"self-healing-storefront","metadata":{"permalink":"/thoughts/self-healing-storefront","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-06-22-self-healing-storefront.md","source":"@site/blog/2026-06-22-self-healing-storefront.md","title":"Self-Healing Storefront: An Agent That Runs Its Own A/B Tests","description":"The story behind a design for an autonomous experimentation agent: it turns detected conversion problems into a ranked backlog of A/B tests, ships the winners, and reports the dollar lift.","date":"2026-06-22T10:00:00.000Z","tags":[{"inline":true,"label":"system-design","permalink":"/thoughts/tags/system-design"},{"inline":true,"label":"architecture","permalink":"/thoughts/tags/architecture"},{"inline":true,"label":"generative-ai","permalink":"/thoughts/tags/generative-ai"},{"inline":true,"label":"claude","permalink":"/thoughts/tags/claude"},{"inline":true,"label":"ecommerce","permalink":"/thoughts/tags/ecommerce"},{"inline":true,"label":"experimentation","permalink":"/thoughts/tags/experimentation"},{"inline":true,"label":"designs","permalink":"/thoughts/tags/designs"}],"readingTime":1.13,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"self-healing-storefront","title":"Self-Healing Storefront: An Agent That Runs Its Own A/B Tests","kind":"design-story","sidebar_label":"Self-Healing Store","description":"The story behind a design for an autonomous experimentation agent: it turns detected conversion problems into a ranked backlog of A/B tests, ships the winners, and reports the dollar lift.","authors":["oeid"],"tags":["system-design","architecture","generative-ai","claude","ecommerce","experimentation","designs"],"date":"2026-06-22T10:00","draft":false},"unlisted":false,"prevItem":{"title":"Markdown Review Studio: Closing the Loop Between Feedback and Edit","permalink":"/thoughts/markdown-review-studio"},"nextItem":{"title":"A Hands-On Way to Learn What a Claude Agent Actually Is","permalink":"/thoughts/getting-started-with-claude-agents"}},"content":"One of four designs I co-designed with Claude (I drove the structure and decisions; Claude proposed architectures and named the trade-offs). This is the story behind it; the full design doc lives on the Designs blog.\\n\\n\ud83d\udc49 **[Read the design: Self-Healing Storefront](/designs/design-self-healing-storefront)**\\n\\n\x3c!-- truncate --\x3e\\n\\n## The problem\\n\\nThe [Ecommerce Site Scanner](/thoughts/ecommerce-site-scanner) *finds* what is wrong with a store. This is the *fix* half: once you know the conversion problems, who actually runs the experiments to fix them, safely, on live traffic?\\n\\n## The design\\n\\nThis is an autonomous experimentation agent for ecommerce. It turns detected conversion problems plus a store\'s own analytics into a ranked backlog of A/B tests, generates on-brand variants, runs them safely on live traffic with statistics suited to the store\'s traffic level, ships the winners, and reports the dollar lift in plain language.\\n\\nAutonomy is gated by risk: low-risk copy and layout changes can ship automatically; pricing and checkout changes always need human approval.\\n\\n## Why it\'s worth reading\\n\\nThe design is **In Review**. The interesting open questions are about trust: how much autonomy is safe at each risk tier, and how to do honest statistics on a store that does not have Amazon-scale traffic. Read it like a colleague\'s notes.\\n\\n\ud83d\udc49 **[Open the full design doc](/designs/design-self-healing-storefront)**"},{"id":"getting-started-with-claude-agents","metadata":{"permalink":"/thoughts/getting-started-with-claude-agents","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-06-19-getting-started-with-claude-agents.md","source":"@site/blog/2026-06-19-getting-started-with-claude-agents.md","title":"A Hands-On Way to Learn What a Claude Agent Actually Is","description":"I built a small, readable example you can open and poke at to answer one question: what is an agent, and what is a skill? It\'s a working stock-research agent that doubles as a teaching tool.","date":"2026-06-19T10:00:00.000Z","tags":[{"inline":true,"label":"ai","permalink":"/thoughts/tags/ai"},{"inline":true,"label":"generative-ai","permalink":"/thoughts/tags/generative-ai"},{"inline":true,"label":"agents","permalink":"/thoughts/tags/agents"},{"inline":true,"label":"claude","permalink":"/thoughts/tags/claude"},{"inline":true,"label":"getting-started","permalink":"/thoughts/tags/getting-started"}],"readingTime":2.55,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"getting-started-with-claude-agents","title":"A Hands-On Way to Learn What a Claude Agent Actually Is","kind":"reflection","sidebar_label":"Claude Agents","description":"I built a small, readable example you can open and poke at to answer one question: what is an agent, and what is a skill? It\'s a working stock-research agent that doubles as a teaching tool.","authors":["oeid"],"tags":["ai","generative-ai","agents","claude","getting-started"],"date":"2026-06-19T10:00"},"unlisted":false,"prevItem":{"title":"Self-Healing Storefront: An Agent That Runs Its Own A/B Tests","permalink":"/thoughts/self-healing-storefront"},"nextItem":{"title":"Teaching AI to Read a Pattern and Write Its Code","permalink":"/thoughts/recreating-an-image-as-dsl"}},"content":"The fastest way to understand Claude agents isn\'t to read a framework\'s docs. It\'s to open a small, working agent and read it the way you\'d read a colleague\'s playbook. So I built one to play with, and put it online for anyone curious.\\n\\n\ud83d\udc49 **[Getting Started with Claude Agents](https://blog.bytesofpurpose.com/getting-started-with-claude-agents/)**: open it, poke around, and the question *\\"what is an agent? what is a skill?\\"* should answer itself.\\n\\n\x3c!-- truncate --\x3e\\n\\n## What you\'re looking at\\n\\nIt\'s two things at once:\\n\\n- A **working agent**, a stock research associate that surveys the market each morning, shortlists a few names worth a closer look, pulls the filings and numbers, builds a spreadsheet with sourced math, and stress-tests its own thesis before signing off.\\n- A **teaching example**, where the folders are named so that opening them explains the ideas. You don\'t need to know Python, JSON, or any SDK to read it. You read it like a research analyst\'s notes.\\n\\n## The one idea worth keeping\\n\\nIf you take away nothing else, take this:\\n\\n> **An agent is a *who*.** It\'s a role, like \\"senior research associate,\\" that decides what to do next.\\n> **A skill is a *how*.** It\'s a specific recipe, like \\"spread the financials,\\" that the agent follows.\\n\\nThe agent file describes the role and the workflow. Each skill file describes one recipe and nothing else, and the skills don\'t know about each other. They just do their one job well. The agent reads its own definition and picks which skill to invoke. That separation is the whole trick: each skill can be read alone, copied into another project, or rewritten, and the agent picks it up automatically. No DSL, no central registry, just markdown a domain expert can read and edit.\\n\\n## Why I think it clicks\\n\\nEvery skill maps to a discipline you\'d recognize from a real desk: a morning idea sweep, a source-of-truth data fetch, the qualitative read, the model, the validation pass before sign-off. If you\'ve ever trained a junior person, you\'ve effectively taught them each of these as a separate skill. Seeing it laid out that way is what made agents stop feeling abstract for me.\\n\\nThere\'s even a built-in `explain-agent` step that walks the project and draws you an interactive diagram of how the whole thing fits together, which is handy for onboarding someone else.\\n\\n## Go play\\n\\nYou\'ll need [Claude Code](https://claude.com/download). After that it\'s double-click-to-run: one command sets things up, another opens it in Claude, and you ask it *\\"what\'s worth looking at today?\\"* It stops to confirm with you at the expensive steps, so nothing runs away from you.\\n\\nIt\'s a teaching example, not a production trading system. It triages and explains, and it doesn\'t give investment advice. But as a way to *get* what agents and skills are, opening it beats any explanation I could write here.\\n\\n**[Try the intro agent \u2192](https://blog.bytesofpurpose.com/getting-started-with-claude-agents/)**\\n\\nIf it helps something click, [buy me a coffee \u2615](https://buymeacoffee.com/omareid)."},{"id":"recreating-an-image-as-dsl","metadata":{"permalink":"/thoughts/recreating-an-image-as-dsl","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-06-07-recreating-an-image-as-dsl.md","source":"@site/blog/2026-06-07-recreating-an-image-as-dsl.md","title":"Teaching AI to Read a Pattern and Write Its Code","description":"I spent weeks trying to get AI to look at an Islamic geometric pattern and hand me back the code that draws it. Here is the rabbit hole: what worked, what failed, and the mistakes I kept making.","date":"2026-06-07T10:00:00.000Z","tags":[{"inline":true,"label":"ai","permalink":"/thoughts/tags/ai"},{"inline":true,"label":"generative-ai","permalink":"/thoughts/tags/generative-ai"},{"inline":true,"label":"geometry","permalink":"/thoughts/tags/geometry"},{"inline":true,"label":"dsl","permalink":"/thoughts/tags/dsl"},{"inline":true,"label":"computer-vision","permalink":"/thoughts/tags/computer-vision"},{"inline":true,"label":"islamic-geometric-patterns","permalink":"/thoughts/tags/islamic-geometric-patterns"},{"inline":true,"label":"agents","permalink":"/thoughts/tags/agents"}],"readingTime":18.54,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"recreating-an-image-as-dsl","title":"Teaching AI to Read a Pattern and Write Its Code","kind":"tutorial","sidebar_label":"Image to DSL","description":"I spent weeks trying to get AI to look at an Islamic geometric pattern and hand me back the code that draws it. Here is the rabbit hole: what worked, what failed, and the mistakes I kept making.","authors":["oeid"],"tags":["ai","generative-ai","geometry","dsl","computer-vision","islamic-geometric-patterns","agents"],"date":"2026-06-07T10:00","draft":false},"unlisted":false,"prevItem":{"title":"A Hands-On Way to Learn What a Claude Agent Actually Is","permalink":"/thoughts/getting-started-with-claude-agents"},"nextItem":{"title":"Everyone Is a Salesperson: What an Engineer Took From \'To Sell Is Human\'","permalink":"/thoughts/everyone-is-a-salesperson"}},"content":"import Evidence from \'@site/src/components/Evidence\';\\n\\nI have an image of a sacred geometric pattern: interlocking stars and tiles, the kind carved into mosque walls and ceilings for a thousand years. I wanted AI to look at that image and hand me back the *recipe*, the exact set of instructions that would redraw it from scratch. Not a blurry copy. The construction. The code.\\n\\nThat problem turned out to be a beautiful, deceptive rabbit hole, and I went all the way down it with a small fleet of AI agents. This is the honest field journal of that descent: what I tried, what worked, what failed in interesting ways, the mistakes I kept making even after I knew better, and what the research community already knows about why this is so hard.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Why this is seductive, and why it\'s deceptively hard\\n\\nIf you can turn a *picture* of a pattern into the *program* that generates it, you get something magical: a drawing you can edit by changing numbers instead of pushing pixels. Want the same pattern with twelve-fold symmetry instead of ten? Change a parameter. Want it bigger, recolored, re-tiled? It\'s just code now.\\n\\nThe catch is that you\'re running a machine backwards. Drawing a pattern *from* a recipe is easy and deterministic: same recipe, same picture, every time. Going the other way, from a finished picture back to a recipe that would produce it, is what mathematicians call an *inverse problem*, and inverse problems are notoriously underdetermined. Lots of different recipes can produce the very same picture. (Hold onto that sentence; it comes back at the end and reframes the whole thing.)\\n\\n## The cast: three small tools that argue with each other\\n\\nI didn\'t build one big AI that reads images. I built three small, opinionated tools and made them work in a loop. Naming them up front, because the rest of the story is them passing notes to each other:\\n\\n- **bikar**, the *drawer*. It takes a recipe written in a tiny custom language (a **DSL**, a domain-specific language; think \\"a programming language that only knows how to talk about one thing,\\" here Islamic geometric construction) and renders the pattern as an SVG. Compass-and-straightedge moves, girih tiles, star constructions. If you can say it in bikar\'s language, bikar draws it.\\n- **qiyas**, the *looker*. Arabic \u0642\u064a\u0627\u0633, \\"measurement.\\" You give it a drawing and it writes down what it sees: every shape, how many sides, where it sits, what symmetry the whole thing has. Then it can compare two drawings and score how alike they are. Classical computer vision, no neural network, no training data.\\n- **sacred-patterns**, the *loop*. It holds a guess at the recipe, asks bikar to draw it, asks qiyas how close the drawing is to the target, nudges the recipe, and tries again. The orchestrator that keeps trying.\\n\\nPut together, they form a render-score-revise loop:\\n\\n```\\n   bikar  \u2500\u2500draws\u2500\u2500\u25b6  a drawing  \u2500\u2500\u25b6   qiyas looks at it\\n (the recipe)                              \u2502\\n     \u25b2                                     \u25bc\\n     \u2502                          \\"how close to the target?\\"\\n  nudge the recipe  \u25c0\u2500\u2500\u2500\u2500 a similarity score \u25c0\u2500\u2500\u2500\u2500\u2518\\n (sacred-patterns)\\n```\\n\\nIt keeps going until the score stops improving. That\'s the whole machine.\\n\\n## The trick I actually used (and its embarrassing catch)\\n\\nHere\'s where I got clever, and where the honesty has to start.\\n\\nReading a recipe out of raw pixels is brutally hard. So I cheated, productively. When bikar draws a pattern, I had it *leave breadcrumbs in the drawing*: invisible notes attached to each shape saying \\"I am a six-sided polygon,\\" \\"I have ten-fold symmetry,\\" \\"I was built from this circle.\\" qiyas doesn\'t have to *guess* those facts from jittery pixel geometry; it just *reads the notes*. I called this principle **DSL-as-source-of-truth**: when the tool that drew the thing already knows a fact for certain, propagate that fact as authoritative instead of re-deriving it downstream.[^breadcrumb]\\n\\nIt worked spectacularly. On a corpus of twelve patterns, the loop recovered the structure essentially perfectly, an **ARI of 1.0**.[^ari] (ARI, the Adjusted Rand Index, is a standard 0-to-1 score for \\"did you group these things the same way the truth groups them\\"; 1.0 is a perfect match.) The breadcrumb path recovered about five times more shapes than the old approach of rasterizing and re-tracing the image.\\n\\nAnd now the catch, which I have to say plainly: **the breadcrumbs only exist because I\'m the one who drew it.** A photograph of a thousand-year-old mosque ceiling has no breadcrumbs. The whole loop quietly assumes bikar is the author of record. So what I actually built, when I\'m being honest, is a superb *round-trip validator*, a thing that proves \\"yes, this recipe really does reproduce this drawing,\\" and **not yet** a from-a-photo *inference engine* that reads a recipe out of an image it has never seen.[^round-trip] The gap between those two is the real distance to the goal, and naming it is the most useful thing in this whole post.\\n\\n## What actually worked\\n\\nA few things earned their place and I\'d do them all again:\\n\\n- **The breadcrumb fast-path.** Reading the producer\'s own knowledge instead of re-deriving it dissolved a whole cluster of detector bugs at once. When you control the producer, trust the producer.\\n- **Two weak signals fused into one strong one.** For deciding \\"are these two shapes the same kind,\\" neither pure geometry (a *turning function*, a rotation-invariant fingerprint of a shape\'s outline) nor pure provenance (which construction step made it) was enough alone; geometry saturated, provenance over-fragmented. Fused, they closed the gap to that ARI of 1.0.\\n- **Render-and-look as a discipline.** My single most repeated lesson: *don\'t trust a number until you\'ve looked at the picture the number is describing.* I built a review portal and an automated browser screenshot into the loop specifically because I kept catching bugs with my eyes that every metric had cheerfully reported green.\\n- **Empirical root-cause over backlog hypotheses.** When something scored wrong, the move that consistently paid off was to *measure the actual cause* (render the per-case error and look) rather than guessing from a list of plausible explanations. A real measurement disproved three plausible guesses in a single afternoon more than once.\\n\\n## What didn\'t work, and the one I want to tell as a story\\n\\nThere were plenty of dead ends. The hand-authored *girih* fields (the interlocking-tile quasicrystal patterns) hit a wall I\'ll come back to. Trying to recover a pattern\'s rotation by counting shapes was too coarse, because too many different angles share a shape count. And there was the self-inflicted false-green where I set a tolerance on the wrong copy of a function and \\"measured\\" the default behavior while believing I\'d changed it. Painful, instructive, mine.\\n\\nBut the one worth telling slowly is the **F2 identity saga**, because it\'s the cleanest example of committing to a belief and having the data execute it.\\n\\nThe setup: I wanted the loop to answer \\"have I seen this *kind* of shape before, in some other drawing?\\" To grade that, I needed an answer key, a label that says which shapes count as \\"the same kind.\\" The obvious choice was the names I\'d already given shapes in my own patterns: `.hexagon`, `.royal`, `.turquoise`. I wrote the decision doc, picked that option, and ran it on the real corpus.\\n\\nIt scored badly. It put the right answer at the top of the list only about 46% of the time, where I\'d hoped for 95%.[^f2-key] My first instinct (the wrong one, and I\'ll own it) was to assume the *measuring tool* was broken. It wasn\'t. The answer key was. Those names weren\'t shape descriptions at all; they were *colors and aspirational role-names*. The label `.hexagon` was stuck on shapes with 3, 5, 6, 7, 8, and 10 sides. `.royal` was a color worn by 4-, 8-, 12-, and 20-sided shapes. I had built a geometry tool and was grading it against an answer key that grouped shapes *by paint*.\\n\\nSo I reversed, and here\'s the part that still makes me wince. I picked what looked like the principled fix: have bikar stamp each shape with an authoritative `data-shape-id`, since the producer *knows* the true shape, so trust it, exactly per my own DSL-as-source-of-truth principle. I built the whole cross-repo cascade. Then I measured it. And `shape_id` scored *worse than the thing it replaced*, a near coin-flip. Why? Because the \\"authoritative\\" id was the *author\'s name for the shape*, and I\'d reused a name like `scalene_tri_poly` across geometrically different triangles in different patterns: the same variable name in two files pointing at two different things.[^f2-shapeid] Authorship isn\'t correctness. The DSL author had named a *role*, not a geometry.\\n\\nThe fix that finally held was the boring one I\'d had in hand the whole time: grade against the *detector\'s own* geometric classification (triangle, square, pentagon, decagon, lens, circle). Against that honest label, the same fingerprint scored an EER of 0.035 and a perfect top-1, proof the descriptor was never broken and the answer key always was.[^f2-geom] (EER, equal-error-rate, is a lower-is-better score for a matcher; 0.035 is very good.) Two reversals, one real lesson: a measurement is only as honest as the label you grade it against, and \\"I authored it, so it\'s true\\" is a trap.\\n\\n## The mistakes I kept making\\n\\nWhen I sat down and read back through weeks of my own agent transcripts (**37 distinct mistakes across six work windows**), the painful discovery wasn\'t any single error.[^mistakes] It was that the *same families* of error kept recurring even though I\'d written down the lesson each time. Four of them, in plain terms:\\n\\n1. **I committed to a premise before checking it was true.** The F2 saga above is the poster child, but it happened over and over: write the decision, pick the option, sometimes regenerate a 258-file corpus, *then* discover the premise was false.\\n2. **I trusted a stale claim and built on it.** A fact that was true three steps ago, inherited into a new context and used as load-bearing without re-checking, and it had quietly gone false.\\n3. **I tuned the metric instead of fixing the cause.** Under plateau pressure, the reflex to nudge a threshold until the gate goes green, when the gate going red was telling me something real.\\n4. **I shipped a verdict without looking at the picture.** An overlay in the wrong quadrant, a render that came out blank, a 27%-of-content-dropped trace, all of which a five-second look would have caught and a green test did not.\\n\\nHere\'s the meta-lesson, and it\'s the one I actually believe. **A good principle written down does not save you at the moment of temptation.** I *had* the tenets: \\"verify before claiming done,\\" \\"don\'t tune to fit,\\" \\"render and look.\\" The strongest, most-repeated ones still saw repeat offenses, because the moment you\'re most likely to skip the check (a plateau, a resumed session, a budget scare) is exactly the moment a written-down principle is easiest to rationalize past. What you need isn\'t a better-worded reminder; it\'s an *enforced check at that moment*. (That realization is literally why I just finished building a decision-coherence gate into the loop. Consider it the epilogue.)\\n\\n## What the research actually says\\n\\nBefore I let myself feel either too clever or too foolish, I went and read what the field knows. I ran a structured literature sweep, and it was both humbling and reassuring.\\n\\nThe good news: **this is a real, named inverse problem**, and my overall shape is the established one. Recovering a generative program from an image is formally *program synthesis over a grammar*. [InverseCSG](https://dl.acm.org/doi/10.1145/3272127.3275006) puts it exactly: \\"Observing that CSG is a formal grammar, we formulate this inverse CSG problem as a program synthesis problem.\\" And the render-score-revise loop I leaned on is *the* mechanism in the literature, not a workaround: [CSGNet](https://people.cs.umass.edu/~smaji/papers/csgnet_pami20.pdf) runs a renderer in the loop with a similarity reward and converges in about ten iterations; [VIGA](https://arxiv.org/html/2601.11109v1) (a 2026 preprint) runs \\"analysis-by-synthesis as an execution-grounded closed loop\\" that writes a program, renders it, compares, and revises.[^research-loop] I\'d reinvented a wheel, but the right wheel.\\n\\nThe one genuinely novel wrinkle is my breadcrumb shortcut. *No* surveyed system reads producer-embedded metadata as ground truth; every published loop compares the *rendered output* perceptually or structurally. My DSL-as-source-of-truth is a shortcut the literature neither blesses nor forbids, and it\'s sound *precisely because* I control the producer, which is the same reason it sidesteps rather than solves the real photo case.\\n\\nThe dead ends got graded too. The hand-authored girih wall is **confirmed dead** by the field: [Lu and Steinhardt](https://paulsteinhardt.org/wp-content/uploads/2023/01/LuSteinhardt2007.pdf) (*Science*, 2007) showed that girih fields are generated by a *finite, deterministic substitution rule*, and that medieval artisans were effectively running a recursive subdivision algorithm.[^girih] Hand-placing tiles is genuinely the wrong move; the right move is to teach bikar the substitution rule as a single primitive. My rotation-by-shape-count dead end was **refuted**: the turning function I was already citing ([Arkin et al.](https://www.researchgate.net/publication/220181545_An_Efficiently_Computable_Metric_for_Comparing_Polygonal_Shapes), 1991) recovers orientation directly, so I\'d abandoned a bad method for the right reason but missed that the replacement was already in my own bibliography. And [Bokeloh, Wand and Seidel](https://dl.acm.org/doi/10.1145/1778765.1778841) (SIGGRAPH 2010) confirmed that symmetry is the load-bearing cue for this whole class of problem, which is exactly what my loop leans on.\\n\\nThen the deepest twist, the one that reframes the goal. [Kaplan](https://cs.uwaterloo.ca/~csk/publications/Papers/kaplan_2005.pdf) (2005) proved that the forward map is *many-to-one*: different underlying constructions can render the *identical* star pattern.[^kaplan] So there is no single \\"correct\\" recipe for an image, only an equivalence class of recipes that all produce it. \\"Recover *the* construction\\" was always the wrong goal; the honest target is \\"recover *a* construction, ideally the simplest member of the class.\\" The problem isn\'t just hard. It\'s provably non-unique.\\n\\n## What it cost\\n\\nLet me be candid about the bill, because the bill is part of the point.\\n\\nThis was **roughly five to nine weeks of active iteration**: the intensive window runs late April through the start of June 2026, depending on where you mark the start. Across the three repos it produced **on the order of 1,200 git commits** (qiyas ~721, bikar ~331, sacred-patterns ~168, though sacred-patterns predates this project, so its project-relevant share is smaller). The retrospective that anchors this post was itself distilled from **37 transcript-witnessed mistakes across six work windows, 61 decision documents, and 239 commits scanned**.\\n\\nOn compute, I have to be careful and honest: **I did not meter tokens directly, because there was no meter running.** The closest proxy I have is the size of the saved agent-session transcripts on disk: about **one gigabyte** of conversation-and-tool-output (sacred-patterns ~911 MB, including a single 900 MB session that ran from April 30 to June 1; qiyas ~125 MB).[^cost] That\'s the back-and-forth the agents and I generated, not a token count. The true token spend is larger than the text alone, and I\'m not going to invent a precise figure I didn\'t measure. Treat the gigabyte as a *texture-of-effort* proxy, not an invoice.\\n\\nThe point I want to make with those numbers isn\'t \\"look how much.\\" It\'s *where* the cost went. The expensive part was not writing the code. It was the **re-deciding**: committing to a premise, having the data falsify it, reversing, sometimes regenerating a whole corpus, and doing that again. Tie it back to the mistakes section: the costliest line item in weeks of work was relitigating things I\'d already decided, because the principle that should have stopped me wasn\'t enforced at the moment I needed it. If you want one laymanized line: *weeks of iteration, about 1,200 commits, and roughly a gigabyte of AI conversation, and the priciest part was re-deciding things I\'d already decided.*\\n\\n## Where it goes next\\n\\nThe honest open problems, in rough order of how much they\'d move the needle:\\n\\n- **The actual photo case.** The from-a-photo cascade (rasterize, trace, re-derive every fact with no breadcrumbs) is scoped but *has never been run*. That\'s the line between \\"round-trip validator\\" and \\"inference engine,\\" and it\'s still in front of me.\\n- **The girih primitive.** Teach bikar the Lu-Steinhardt substitution rule as a first-class move so the quasicrystal fields render gap-free instead of being hand-faked. The field already told me this is the right answer.\\n- **A self-generating training pipeline.** Have bikar emit many patterns *with* their known recipes, and verify detection at scale, a technique the literature ([Gaidon et al.](https://link.springer.com/article/10.1007/s11263-018-1108-0), 2018) confirms is well-established.\\n- **The unanswered question:** what does the loop loop *until*? Given Kaplan\'s non-uniqueness, \\"until it matches the original exactly\\" may be the wrong stopping condition. \\"Until it matches a *member of the equivalence class*, preferring the simplest\\" is closer, but I haven\'t operationalized it yet.\\n\\n## What I\'d tell someone starting this\\n\\nTwo things.\\n\\nFirst, the technical one: when you control the producer, lean on it shamelessly, but *write down, in big letters, exactly where that crutch stops working*, because it\'s the most comfortable place to fool yourself. My breadcrumbs got me to a perfect score on the easy regime and zero distance closer to the hard one, and it took me an embarrassingly long time to say that plainly.\\n\\nSecond, the one about working with AI agents: they are brilliant and overconfident in the same breath. An agent will commit to a premise with total fluency and build three days of work on it before the data gets a word in, which is *exactly* what I do, just faster. The fix was never a smarter agent. It was an enforced check at the moment of temptation, for the agent and for me alike. AI as a collaborator is a force multiplier on both your insight and your mistakes; the discipline that decides which one wins is the part you actually have to build.\\n\\n---\\n\\n> **A note on the footnotes.** Each one below points at the exact file and line range in the project\'s own source repos that justifies the claim. Links into the public `sacred-patterns` repo are clickable for everyone; links into the private `qiyas` and `bikar` repos render as a clickable permalink only when I\'m viewing this locally (they would 404 for you), so in the public build they appear as a plain citation. The permalinks are pinned to a fixed commit, so the line ranges never drift.\\n\\n[^ari]: <Evidence repo=\\"sacred-patterns\\" sha=\\"746bed6\\" path=\\"docs/retrospectives/2026-06-06-image-to-dsl-retrospective.md\\" lines=\\"64-66\\" note=\\"the I1 SVG-direct regime reached ARI=1.0 on the 12-pattern corpus and recovered ~5x more shapes than the raster path\\" />\\n\\n[^round-trip]: <Evidence repo=\\"sacred-patterns\\" sha=\\"746bed6\\" path=\\"docs/retrospectives/2026-06-06-image-to-dsl-retrospective.md\\" lines=\\"30-33\\" note=\\"the executive summary\'s own admission: a superb round-trip validator, never yet run on a real photograph (the I2 cascade is deferred)\\" />\\n\\n[^breadcrumb]: <Evidence repo=\\"bikar\\" sha=\\"595eb84\\" path=\\"CLAUDE.md\\" lines=\\"46\\" note=\\"bikar Tenet 23, DSL-as-source-of-truth: when the authoring layer knows a fact, propagate it as authoritative instead of re-deriving it downstream\\" />\\n\\n[^f2-key]: <Evidence repo=\\"qiyas\\" sha=\\"3e41793\\" path=\\"docs/decisions/2026-05-29-f2-face-class-is-wrong-retrieval-label.md\\" lines=\\"17-34\\" note=\\"the 46% top-1 result, and the finding that the fill-class names group shapes by paint, not geometry (.hexagon spans 3,5,6,7,8,10 sides)\\" />\\n\\n[^f2-shapeid]: <Evidence repo=\\"qiyas\\" sha=\\"3e41793\\" path=\\"docs/decisions/2026-05-29-f2-face-class-is-wrong-retrieval-label.md\\" lines=\\"390-401\\" note=\\"the falsification table where shape_id is the worst label (mAP 0.296, near coin-flip), and the scalene_tri_poly witness with distances 0.0, 8.04, and 33.05 proving the name spans distinct triangles\\" />\\n\\n[^f2-geom]: <Evidence repo=\\"qiyas\\" sha=\\"3e41793\\" path=\\"docs/decisions/2026-05-29-f2-face-class-is-wrong-retrieval-label.md\\" lines=\\"453-464\\" note=\\"Option E accepted 2026-06-01: gating on the detector\'s geom_label gives EER=0.0346 and a perfect top-1, proving the descriptor was sound and the answer key was the problem\\" />\\n\\n[^mistakes]: <Evidence repo=\\"sacred-patterns\\" sha=\\"746bed6\\" path=\\"docs/retrospectives/2026-06-06-image-to-dsl-retrospective.md\\" lines=\\"118-139\\" note=\\"the repeated-mistakes section: 37 transcript-witnessed mistakes across 6 windows, and the meta-lesson that a tenet alone does not prevent the mistake at the moment of temptation\\" />\\n\\n[^girih]: <Evidence repo=\\"sacred-patterns\\" sha=\\"746bed6\\" path=\\"docs/retrospectives/2026-06-06-image-to-dsl-retrospective.md\\" lines=\\"110-111\\" note=\\"the three hand-authored medallion-10 girih attempts that all hit an A6=0 floor for different geometric reasons; the fix is a producer-side substitution-rule primitive\\" />\\n\\n[^research-loop]: <Evidence repo=\\"sacred-patterns\\" sha=\\"746bed6\\" path=\\"docs/retrospectives/2026-06-06-image-to-dsl-priorart.md\\" lines=\\"24-38\\" note=\\"prior-art verdict: the renderer-in-the-loop, iterate-until-plateau shape is Confirmed established (CSGNet ~10-iteration convergence; VIGA write-render-compare-revise)\\" />\\n\\n[^kaplan]: <Evidence repo=\\"sacred-patterns\\" sha=\\"746bed6\\" path=\\"docs/retrospectives/2026-06-06-image-to-dsl-priorart.md\\" lines=\\"87-93\\" note=\\"Kaplan (2005): the forward map is many-to-one, distinct constructions render the identical pattern, so \'recover the construction\' is the wrong goal and the target is an equivalence class\\" />\\n\\n[^cost]: <Evidence repo=\\"sacred-patterns\\" sha=\\"746bed6\\" path=\\"docs/retrospectives/2026-06-06-image-to-dsl-retrospective.md\\" lines=\\"5-13\\" note=\\"the retrospective frontmatter: the 2026-04-28..2026-06-01 window, the 64 MB qiyas and 900 MB sacred-patterns transcripts (the labeled proxy for effort), 61 decision docs, 239 commits scanned\\" />"},{"id":"everyone-is-a-salesperson","metadata":{"permalink":"/thoughts/everyone-is-a-salesperson","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-09-27-everyone-is-a-salesperson.md","source":"@site/blog/2017-09-27-everyone-is-a-salesperson.md","title":"Everyone Is a Salesperson: What an Engineer Took From \'To Sell Is Human\'","description":"Daniel Pink\'s \'To Sell Is Human\' reframed selling as moving people, not closing deals. Here\'s what stuck with me, and how it changed the way I work as an engineer who used to think sales was someone else\'s job.","date":"2026-06-06T10:00:00.000Z","tags":[{"inline":true,"label":"product-management","permalink":"/thoughts/tags/product-management"},{"inline":true,"label":"software-engineering","permalink":"/thoughts/tags/software-engineering"},{"inline":true,"label":"mindset","permalink":"/thoughts/tags/mindset"}],"readingTime":4.97,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"everyone-is-a-salesperson","title":"Everyone Is a Salesperson: What an Engineer Took From \'To Sell Is Human\'","kind":"reflection","sidebar_label":"Everyone Sells","description":"Daniel Pink\'s \'To Sell Is Human\' reframed selling as moving people, not closing deals. Here\'s what stuck with me, and how it changed the way I work as an engineer who used to think sales was someone else\'s job.","authors":["oeid"],"tags":["product-management","software-engineering","mindset"],"date":"2026-06-06T10:00","draft":false},"unlisted":false,"prevItem":{"title":"Teaching AI to Read a Pattern and Write Its Code","permalink":"/thoughts/recreating-an-image-as-dsl"},"nextItem":{"title":"A Framework for Quantifying Yourself","permalink":"/thoughts/a-framework-for-quantifying-yourself"}},"content":"I used to think of \\"sales\\" as a department down the hall. It was something other people did so that I could stay in my editor and write code. Then I read Daniel Pink\'s *To Sell Is Human: The Surprising Truth About Moving Others*, and the wall I\'d put between \\"building\\" and \\"selling\\" stopped making sense.\\n\\n\x3c!-- truncate --\x3e\\n\\nThis isn\'t a summary of the book. It\'s the handful of ideas that stuck with me, in my own words, and how I\'ve tried to use them. If they resonate, read Pink\'s book; the research and stories behind these points are his, and they\'re worth your time.\\n\\n## The reframe: selling is moving people\\n\\nPink\'s central move is to redefine what selling even is. Underneath the cold-call caricature, \\"sales\\" is just the act of getting someone to part with something they value (time, attention, effort, money) in exchange for something they\'ll be better off having. By that definition, almost everything I do at work is selling. Convincing a team to adopt an approach, getting a reviewer to prioritize my PR, persuading a stakeholder that a refactor is worth the quarter: none of it exchanges money, but all of it is moving people.\\n\\nPink calls this **non-sales selling**, and his argument that we\'re all doing it now landed hard for me. Two of his reasons especially:\\n\\n- **Small and flat organizations make everyone a seller.** In a big company, selling is a specialized function so that everyone else can specialize too. The smaller or flatter the org, the more those boundaries dissolve. Designers analyze, analysts design, and engineers end up influencing customers directly. I\'ve watched this happen on my own teams: the further you get from a rigid org chart, the more \\"not my job\\" stops being a defense.\\n- **Information parity flipped the seller\'s role.** Pink borrows the economist\'s phrase *caveat venditor* (seller beware) to describe a world where the buyer can often know as much as the seller. When you can no longer win by hoarding information, your job changes from gatekeeper to guide. You stop being the person who has the facts and become the person who helps make sense of them.\\n\\nThe line that reframed my own work the most: the most effective way to sell a product is often to build something so genuinely useful, and to help people understand it so well, that they move themselves. \\"Products people buy\\" beat \\"products people are sold.\\"\\n\\n## The engineer\'s version: serve, don\'t pitch\\n\\nThe part of the book I keep coming back to as an engineer is the idea of putting builders in front of the people they build for. Pink describes \\"forward-deployed engineers\\": instead of routing every customer interaction through an account executive, you put real engineers in the field. They fix problems on the spot, and more importantly, they discover problems the customer didn\'t even know they had.\\n\\nThat matched something I\'d felt but never named. The best \\"selling\\" I\'ve done wasn\'t pitching at all. It was sitting with someone using the thing I built, watching where they got stuck, and fixing it. Interacting with people around their problems isn\'t selling in the brochure sense. But it sells. It\'s also just good engineering and good product work, which is why the distinction between the two has mostly collapsed for me.\\n\\n## The three qualities I try to practice: attunement, buoyancy, clarity\\n\\nPink organizes the \\"how\\" of moving people into three qualities. I won\'t reproduce his framework in full, but here\'s what each one means to me in practice.\\n\\n### Attunement: take the other person\'s perspective\\n\\nAttunement is bringing yourself into harmony with the other person and the situation. The counterintuitive finding that stuck with me is that *power gets in the way* of this. The more authority you feel, the worse you get at seeing things from someone else\'s seat. So the move is to deliberately turn your power down: assume the smaller chair so the other person can take the bigger one, and lead with your ears instead of your mouth. As an engineer, my version of this is resisting the urge to explain my solution before I\'ve actually understood their problem.\\n\\n### Buoyancy: stay afloat in a sea of rejection\\n\\nBuoyancy is how you handle the steady drip of \\"no.\\" Three pieces of it changed my habits:\\n\\n- **Ask, don\'t assert.** Before a hard conversation, interrogative self-talk (\\"Can I move these people?\\") beats declarative pep talk (\\"I\'m going to crush this\\"), because a question makes you actually marshal your reasons.\\n- **Mind your ratio.** Positive emotion needs to outweigh negative by a healthy margin, but not infinitely; a little negativity keeps you honest and tells you when you\'re on the wrong path.\\n- **Explain setbacks as temporary, specific, and external.** How you narrate a rejection determines whether you persist. A bad outcome that\'s \\"this one thing, this once\\" is survivable in a way that \\"everything, always, because of me\\" is not.\\n\\n### Clarity: help people find the right problem\\n\\nClarity is the ability to make sense of a murky situation and help others see what\'s worth doing. In a world where information is everywhere, the scarce skill isn\'t access, it\'s framing: surfacing the problem someone should be solving, not just answering the question they walked in with. That\'s curation, not gatekeeping, and it\'s most of what I think senior engineering and product judgment actually is.\\n\\n## Why this stuck\\n\\nWhat I took from *To Sell Is Human* wasn\'t a set of closing techniques. It was permission to drop a false distinction. I\'m not a builder who occasionally has to suffer through selling. The building and the moving-people are the same job, done well. Pink\'s framing (attunement, buoyancy, clarity, and a posture of service over pitch) gave me a vocabulary for something the best engineers and PMs I know already do instinctively.\\n\\nIf any of this resonates, the book is worth reading in full. The ideas are Daniel Pink\'s; the stubborn wall I had to take down was mine."},{"id":"a-framework-for-quantifying-yourself","metadata":{"permalink":"/thoughts/a-framework-for-quantifying-yourself","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2025-09-17-a-framework-for-quantifying-yourself.md","source":"@site/blog/2025-09-17-a-framework-for-quantifying-yourself.md","title":"A Framework for Quantifying Yourself","description":"Treat your own life like a system worth measuring. A self-quantification framework built on one loop: measure, track, report, evaluate, with the planning questions that make each step actionable.","date":"2026-06-06T10:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"},{"inline":true,"label":"self-quantification","permalink":"/thoughts/tags/self-quantification"}],"readingTime":6.53,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"a-framework-for-quantifying-yourself","title":"A Framework for Quantifying Yourself","kind":"framework","sidebar_label":"Quantifying Yourself","description":"Treat your own life like a system worth measuring. A self-quantification framework built on one loop: measure, track, report, evaluate, with the planning questions that make each step actionable.","authors":["oeid"],"tags":["productivity","self-quantification"],"date":"2026-06-06T10:00","draft":false},"unlisted":false,"prevItem":{"title":"Everyone Is a Salesperson: What an Engineer Took From \'To Sell Is Human\'","permalink":"/thoughts/everyone-is-a-salesperson"},"nextItem":{"title":"What Does GTM Mean? (And Is It the Same as an Experiment Dial-Up Plan?)","permalink":"/thoughts/what-does-gtm-mean"}},"content":"What if you ran your own life the way a business runs itself, with metrics, dashboards, weekly reports, and a clear sense of what\'s trending up or down? That\'s the premise of what I call the **Analyzer**: a role I play that treats my own behavior, time, and growth as a system worth measuring.\\n\\n\x3c!-- truncate --\x3e\\n\\nI used to keep this as a flat list of two dozen \\"activities.\\" But once you look closely, they\'re not two dozen separate things. They\'re a handful of **verbs** applied across many **domains**. You *measure* what matters, *track* it over time, *report* on how it trends, and *evaluate* what it means, and the evaluation changes what you measure next. One loop.\\n\\n```mermaid\\nflowchart LR\\n    A([Determine value:<br/>what\'s worth knowing?]) --\x3e B[Measure<br/>set up the metric]\\n    B --\x3e C[Track<br/>record over time]\\n    C --\x3e D[Report<br/>dashboards & trends]\\n    D --\x3e E[Evaluate<br/>what does it mean?]\\n    E --\x3e|adjust what matters| A\\n    E --\x3e|act differently| C\\n    F[(Tooling &<br/>catalog)] -.supports.- B\\n    F -.supports.- C\\n    F -.supports.- D\\n```\\n\\nThe rest of this post walks the loop. Under each step I\'ve kept the actual **planning questions** I work through, not a summary of them, deduplicated so each unique question appears once.\\n\\n## [Step 0] Determine value: what\'s even worth measuring?\\n\\nBefore you measure anything, decide what deserves the attention. Measurement has a cost; spend it where it creates leverage.\\n\\n- How do you measure the value of something?\\n- What criteria should I use to evaluate value?\\n- How do I compare different options?\\n- What factors contribute to long-term value?\\n- How do I assess return on investment?\\n- What metrics indicate value creation?\\n- How do I evaluate both quantitative and qualitative value?\\n- What value frameworks should I apply to different decisions?\\n- What value do I get out of analyzing these metrics, and how does that analysis change my behavior?\\n\\n## [Step 1] Measure: define the metrics\\n\\nIdentify and implement the measurement systems, and the specific personal metrics that matter most for growth and success. (This merges what used to be two near-identical lists, \\"measuring things\\" and \\"identifying personal metrics.\\")\\n\\n- What are all the different things I am measuring?\\n- How do you measure effectively, and what should you measure?\\n- What tools and tech can you measure with?\\n- What metrics about me am I capturing?\\n- What are all the different metrics I want to identify about myself?\\n- What are all the different things I want to measure about myself?\\n- How will I quantify improvements in different aspects of my life?\\n- Can I apply business-level metrics to myself? What kinds of metrics do businesses capture?\\n- What personal metrics are most important for my goals?\\n- How do I balance different types of metrics?\\n- What leading vs lagging indicators should I track?\\n\\n## [Step 2] Track: record over time\\n\\nSystematically monitor and record data over time. Tracking is the same activity whatever the subject, so I keep one set of meta-questions, then a list of the **domains** I actually track.\\n\\n**The questions:**\\n\\n- What should I track about myself, and what do I constantly need to keep track of?\\n- What am I currently keeping track of?\\n- What are my personal commitments, and what are the things I have to do every day?\\n- How will I master my trade?\\n- When should I organize myself, and how frequently do I clean up my notes?\\n- Should I start tracking when I clean up my notes? Can that be auto-derived from when tasks get simultaneously closed?\\n- Which personal metrics can be automatically derived, and which need special work to derive?\\n- How do I measure progress within each thing I track?\\n- How do I ensure data quality and consistency?\\n\\n**The domains I track** (each is the *same* activity pointed at a different part of life):\\n\\n- **Time**: methods, categories, allocation, patterns, and avoiding time-wasters without making tracking a burden.\\n- **Computer usage**: digital productivity, time-wasting apps, behavioral patterns, and privacy considerations.\\n- **Initiatives**: milestones, success measures, when to adjust, required resources, risks, and progress communication.\\n- **Learnings**: learning activities, progress, knowledge gaps, retention, effective methods, and skill development.\\n- **Roles**: success per role, relevant metrics, balancing competing demands, satisfaction, and engagement.\\n- **Sales**: activities, performance, opportunities, trends, and forecasting.\\n- **Spirituality**: practices, growth, engagement, consistency, goals, and community.\\n- **Thoughts**: capturing ideas, spotting patterns, organizing/categorizing, and mining them for personal growth.\\n- **Activities & artifacts**: how often I do/use things, how many processes a document touches, how often I open or edit it, and which provide the most value.\\n\\n## [Step 3] Report: surface the trends\\n\\nTurn recorded data into reports, dashboards, and visualizations so you can actually *see* what\'s happening and decide. (This consolidates the old \\"reporting things,\\" \\"generating reports,\\" \\"structuring weekly reports,\\" and \\"crafting dashboards\\" into one step.)\\n\\n**Reports & dashboards:**\\n\\n- How do I track my progress and view my accomplishments?\\n- Of the things I\'m tracking, how are they trending, and in the right direction?\\n- How often should I generate reports, and in what format?\\n- What key insights should reports highlight, and how do I make them actionable?\\n- What automation can I implement for reporting, and how do I ensure accuracy and consistency?\\n- What audience am I creating reports for, and how do I evolve them as needs change?\\n- What data belongs on a dashboard, and how do I design effective visualizations?\\n- What layout, update cadence, and alerts make a dashboard actionable?\\n- How do I keep dashboards relevant over time?\\n\\n**The weekly cadence** (the one report I run on a fixed rhythm):\\n\\n- What should be included in weekly reports, and how do I structure them for clarity?\\n- Which metrics matter most for a weekly review, and how do I compare week-over-week?\\n- What actions should result from weekly reports, and how do I keep the format consistent?\\n- What templates make this efficient, and how do I ensure it actually drives improvement?\\n\\n## [Step 4] Evaluate: what does it mean, and what changes?\\n\\nClose the loop. Assess your own performance against the data, then let the verdict reshape what you measure and how you act.\\n\\n- How do I evaluate my own performance, and what criteria keep it objective?\\n- What feedback mechanisms should I use?\\n- How do I track personal growth over time, and how do I maintain objectivity in self-assessment?\\n- What areas need improvement?\\n- How do I celebrate achievements?\\n- What goals should I set based on these evaluations?\\n- How productive was my day/week/month, and what factors drove it?\\n- What patterns emerge, and how can I improve the underlying metrics?\\n\\n## The tooling layer (cuts across every step)\\n\\nTwo supporting activities don\'t sit *in* the loop; they hold it up: keeping an inventory of what you track, and using the right tools to do it.\\n\\n**Cataloging what you track:**\\n\\n- What am I currently tracking, and how do I organize it into sensible categories?\\n- How do I ensure I don\'t lose track of important items, and how do I prioritize what to track?\\n- What should I *stop* tracking, and how do I maintain the system over time?\\n\\n**Leveraging tools:**\\n\\n- What tools are available, and how do I choose and integrate the right ones?\\n- What automation can I implement, and how do I ensure data quality and consistency?\\n- What backup and security measures do I need?\\n- How do I train myself to use tools well, and which give the best ROI?\\n\\n## Why bother?\\n\\nThe point of all this isn\'t surveillance of the self. It\'s leverage. Vague intentions (\\"be more productive,\\" \\"grow spiritually,\\" \\"use my time better\\") don\'t move until they\'re attached to something you can observe and steer. Pick even one lap around the loop (decide what\'s worth measuring, measure it, track it, report on it, evaluate it) and a fuzzy ambition becomes a system with a feedback loop. That\'s the whole game: measure what matters, watch how it trends, and let what you see change what you do next."},{"id":"what-does-gtm-mean","metadata":{"permalink":"/thoughts/what-does-gtm-mean","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-06-05-what-does-gtm-mean.md","source":"@site/blog/2026-06-05-what-does-gtm-mean.md","title":"What Does GTM Mean? (And Is It the Same as an Experiment Dial-Up Plan?)","description":"GTM (go-to-market) strategy is the plan for how a product reaches and wins customers. Here\'s what it actually covers, and why a dial-up plan isn\'t the same thing.","date":"2026-06-05T10:00:00.000Z","tags":[{"inline":true,"label":"product-management","permalink":"/thoughts/tags/product-management"},{"inline":true,"label":"go-to-market","permalink":"/thoughts/tags/go-to-market"},{"inline":true,"label":"strategy","permalink":"/thoughts/tags/strategy"},{"inline":true,"label":"experimentation","permalink":"/thoughts/tags/experimentation"},{"inline":true,"label":"launch","permalink":"/thoughts/tags/launch"}],"readingTime":1.92,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"what-does-gtm-mean","title":"What Does GTM Mean? (And Is It the Same as an Experiment Dial-Up Plan?)","kind":"reference","sidebar_label":"What Is GTM?","description":"GTM (go-to-market) strategy is the plan for how a product reaches and wins customers. Here\'s what it actually covers, and why a dial-up plan isn\'t the same thing.","authors":["oeid"],"tags":["product-management","go-to-market","strategy","experimentation","launch"],"date":"2026-06-05T10:00","draft":false},"unlisted":false,"prevItem":{"title":"A Framework for Quantifying Yourself","permalink":"/thoughts/a-framework-for-quantifying-yourself"},"nextItem":{"title":"What I Ask Myself","permalink":"/thoughts/what-i-ask-myself"}},"content":"\\"GTM\\" gets thrown around as if everyone agrees on what it covers. When someone says they \\"owned the GTM strategy,\\" do they mean they planned how a product wins customers, or do they mean they ran the rollout? Those are different things, and conflating them quietly inflates one while underselling the other.\\n\\n\x3c!-- truncate --\x3e\\n\\n## What GTM (go-to-market) strategy actually means\\n\\nA GTM strategy is the plan for how a product reaches and wins customers. It typically covers:\\n\\n- **Target segment / ICP** &mdash; who the customer is\\n- **Positioning & messaging** &mdash; what value prop, against what alternatives\\n- **Pricing & packaging**\\n- **Channels** &mdash; sales-led, self-serve, partners, marketing motions\\n- **Launch sequencing** &mdash; pilot, GA, expansion, and how you ramp\\n- **Cross-functional alignment** &mdash; sales, marketing, product, support all rowing together\\n- **Success metrics** &mdash; adoption, revenue, retention\\n\\nIt\'s fundamentally a commercial, customer-facing plan. The audience is the market.\\n\\n## Is an experiment dial-up plan GTM strategy?\\n\\nNot by itself, no. An experiment dial-up plan (ramp from 1% to 5% to 50% to 100%, with guardrail metrics, holdouts, and kill criteria) is a rollout / launch-execution / experimentation strategy. It\'s about safely shipping and validating a feature, measured by statistical impact, not about how you win customers in a market.\\n\\nThey\'re related but distinct:\\n\\n| | Experiment dial-up plan | GTM strategy |\\n|---|---|---|\\n| **Question it answers** | \\"How do we safely ramp and prove this works?\\" | \\"How do we bring this to market and win customers?\\" |\\n| **Audience** | Internal (eng, science, leadership) | The market / customers |\\n| **Owned by** | Eng / PM / science | Product marketing, PM, sales, biz |\\n| **Success metric** | Lift, guardrails, no regressions | Adoption, revenue, market share |\\n\\n## The overlap\\n\\nThe dial-up can be one component of a launch within a broader GTM plan. If the work included positioning a new line of business, sequencing the launch, aligning sales / marketing / biz, and defining how the capability reached customers, then \\"GTM strategy\\" is fair.\\n\\nIf it was mainly the technical rollout, the experiment ramp, and deciding which teams build what, that\'s more accurately launch strategy, rollout strategy, or technical execution.\\n\\nThe distinction matters because the two require different skills and signal different things. Calling a rollout plan a \\"GTM strategy\\" claims market ownership you may not have done; calling a real GTM effort \\"just a rollout\\" undersells it. Name the work for what it actually was."},{"id":"what-i-ask-myself","metadata":{"permalink":"/thoughts/what-i-ask-myself","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-01-24-what-i-ask-myself.mdx","source":"@site/blog/2026-01-24-what-i-ask-myself.mdx","title":"What I Ask Myself","description":"Why I treat self-questioning as a practice, how I run it, and the legend behind the little icons on every question I publish.","date":"2026-01-24T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":2.64,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"what-i-ask-myself","title":"What I Ask Myself","kind":"legend","sidebar_label":"Ask Myself","description":"Why I treat self-questioning as a practice, how I run it, and the legend behind the little icons on every question I publish.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2026-01-24T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What Does GTM Mean? (And Is It the Same as an Experiment Dial-Up Plan?)","permalink":"/thoughts/what-does-gtm-mean"},"nextItem":{"title":"How I Ask Others Questions","permalink":"/thoughts/how-i-ask-others-questions"}},"content":"I keep a running collection of questions I ask myself. Not affirmations, not goals,\\nnot a journal prompt I found online once and never reused. Questions I come back to,\\non purpose, because the answer keeps changing and the changing is the point.\\n\\nThis post is the front door to that collection. It explains why I do this at all,\\nhow I actually run the practice, and what the little icons on every question mean.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Why ask yourself questions at all\\n\\nMost of my bad decisions came from never asking the question underneath the decision.\\nI\'d optimize how I was doing something for months before noticing I\'d never asked\\nwhether it was worth doing. A good question is a flashlight: it doesn\'t answer\\nanything for you, it just points at the part of the room you\'ve been avoiding.\\n\\nThe practice is simple. I keep the questions grouped by what they\'re really about,\\nI revisit a group when its season comes around, and I write the answer down so I can\\nwatch it move over the years. A question I answered one way at 25 I answer differently\\nat 35, and the gap between those two answers tells me more than either answer alone.\\n\\n## How I run it\\n\\nA few rules I\'ve settled on:\\n\\n- **Group by what the question is really asking**, not by where I found it. The\\n  grouping is part of the thinking.\\n- **Revisit on a cadence, not on a whim.** Some questions are yearly. Some are for\\n  hard weeks only. The cadence is part of the question.\\n- **Write the answer down.** An unrecorded answer can\'t be compared to next year\'s.\\n  The record is the whole point.\\n- **Keep the ones that sting.** If a question is comfortable to answer, it\'s probably\\n  not doing any work.\\n\\n## The power of a question\\n\\nNot every question hits the same way. Some wake you up, some make you uncomfortable,\\nsome slowly reshape who you are. I mark each question with one or more **power** icons\\nso you can see, at a glance, what kind of charge it carries. A calm everyday question\\ngets no icon at all.\\n\\nThis is the legend. It\'s the same set of icons you\'ll see on every question across\\nthe series:\\n\\n<PowerLegend />\\n\\nA question can carry more than one. \\"What is the purpose of your life?\\" both burns\\n(Fire) and forges (Anvil): it\'s uncomfortable to sit with, and answering it honestly,\\nyear after year, changes who you are.\\n\\nAlongside the power, each question card carries three quieter labels:\\n\\n- **Priority** (Core / High / Medium / Low). How foundational the question is.\\n- **Frequency** (Yearly, Monthly, \\"In hard stretches\\"). When its season comes around.\\n- **Depth** (Quick / Moderate / Deep). How much sitting-with it really demands.\\n\\nClick any question to open the full card: why it matters, how often to ask it, when\\nto ask it, and how often to write the answer down.\\n\\n## The collection\\n\\nThe questions live in themed sets. Start wherever the title stings a little:\\n\\n- [What I Ask Myself: To Find Purpose](/thoughts/questions-for-finding-your-purpose)\\n\\nMore sets are published across the series, each tagged `question-set`. This page is\\nthe legend they all share."},{"id":"how-i-ask-others-questions","metadata":{"permalink":"/thoughts/how-i-ask-others-questions","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2026-01-23-how-i-ask-others-questions.mdx","source":"@site/blog/2026-01-23-how-i-ask-others-questions.mdx","title":"How I Ask Others Questions","description":"The other half of my questioning practice: how I ask other people questions in a way that opens them up instead of putting them on the defensive.","date":"2026-01-23T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"communication","permalink":"/thoughts/tags/communication"}],"readingTime":2.84,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"how-i-ask-others-questions","title":"How I Ask Others Questions","kind":"reflection","sidebar_label":"Asking Others","description":"The other half of my questioning practice: how I ask other people questions in a way that opens them up instead of putting them on the defensive.","authors":["oeid"],"tags":["self-reflection","communication"],"date":"2026-01-23T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself","permalink":"/thoughts/what-i-ask-myself"},"nextItem":{"title":"The Evolution of a Repository: A Maturity Model","permalink":"/thoughts/evolution-of-a-repo"}},"content":"I write a lot about the questions I ask myself. This is about the other half of the\\npractice: how I ask questions of other people. The two are related, but the skills\\nare different. A question I ask myself only has to be honest. A question I ask you\\nhas to be honest *and* safe enough that you\'ll actually answer it.\\n\\n\x3c!-- truncate --\x3e\\n\\n## A question is an invitation, not a test\\n\\nThe fastest way to shut someone down is to ask a question they hear as a trap. \\"Why\\ndid you do it that way?\\" is a real question, but most people hear an accusation. The\\nsame curiosity, asked as \\"what were you optimizing for there?\\", opens the door instead\\nof guarding it.\\n\\nSo the first thing I watch is what the question *feels like* to receive. Before I ask,\\nI check: does this sound like I\'m genuinely curious, or like I already have a verdict\\nand I\'m collecting evidence? People can tell the difference instantly, and they answer\\nthe version they think they heard.\\n\\n## The questions that open people up\\n\\nA few patterns I reach for:\\n\\n- **Ask about the reasoning, not the result.** \\"What made that the right call at the\\n  time?\\" gets you the actual thinking. \\"Was that a good idea?\\" gets you a defense.\\n- **Ask for the story, not the summary.** \\"How did that start?\\" gives people room to\\n  walk you through it. They\'ll tell you things they\'d never list if you asked directly.\\n- **Ask what they\'d change.** \\"If you ran it again, what would you do differently?\\"\\n  invites reflection without forcing a confession. It assumes growth, not failure.\\n- **Leave silence after the question.** The most useful thing people say is usually the\\n  second thing, after the pause. If I fill the silence, I never hear it.\\n\\n## The questions that close people down\\n\\nThe mirror image, the ones I try to catch myself before asking:\\n\\n- **Leading questions** that are really statements wearing a question mark. \\"Don\'t you\\n  think we should just start over?\\" isn\'t a question. It\'s a position I\'m asking you to\\n  ratify.\\n- **Stacked questions** where I ask three things at once and the person only answers the\\n  easiest one. One question at a time gets a real answer to each.\\n- **\\"Why\\" aimed at a person** instead of a decision. \\"Why are you like that?\\" is an\\n  attack. \\"Why does that approach work better?\\" is curiosity. Same word, opposite effect.\\n\\n## Listening is part of the question\\n\\nA question isn\'t finished when I stop talking. The other half is what I do with the\\nanswer. If I ask something and then argue with the response, I\'ve taught the person\\nthat my questions aren\'t safe, and the next answer will be smaller and more careful.\\n\\nSo I try to earn the next honest answer with how I receive this one: take it seriously,\\nfollow it where it goes, and let the person see that telling me the real thing didn\'t\\ncost them anything. That\'s what makes someone willing to be asked again.\\n\\n## Where this connects\\n\\nThe inward practice and the outward one feed each other. The questions I\'ve learned to\\nsit with myself are usually the ones I can ask other people without flinching, and the\\nanswers other people trust me with often become questions I take back to\\n[ask myself](/thoughts/what-i-ask-myself). Curiosity, pointed in either direction, is\\nthe same muscle."},{"id":"evolution-of-a-repo","metadata":{"permalink":"/thoughts/evolution-of-a-repo","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2025-11-23-the-evolution-of-a-repo.md","source":"@site/blog/2025-11-23-the-evolution-of-a-repo.md","title":"The Evolution of a Repository: A Maturity Model","description":"Understand the different phases of repository maturity and learn practical steps to evolve your codebase from prototype to enterprise-grade.","date":"2025-11-23T10:00:00.000Z","tags":[{"inline":true,"label":"software-engineering","permalink":"/thoughts/tags/software-engineering"},{"inline":true,"label":"codebase-management","permalink":"/thoughts/tags/codebase-management"},{"inline":true,"label":"technical-debt","permalink":"/thoughts/tags/technical-debt"},{"inline":true,"label":"architecture","permalink":"/thoughts/tags/architecture"},{"inline":true,"label":"best-practices","permalink":"/thoughts/tags/best-practices"}],"readingTime":8.62,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"evolution-of-a-repo","title":"The Evolution of a Repository: A Maturity Model","kind":"framework","sidebar_label":"Repo Evolution","description":"Understand the different phases of repository maturity and learn practical steps to evolve your codebase from prototype to enterprise-grade.","authors":["oeid"],"tags":["software-engineering","codebase-management","technical-debt","architecture","best-practices"],"date":"2025-11-23T10:00","draft":false},"unlisted":false,"prevItem":{"title":"How I Ask Others Questions","permalink":"/thoughts/how-i-ask-others-questions"},"nextItem":{"title":"The Anatomy of Doing: A Framework for Acting on What Matters","permalink":"/thoughts/the-anatomy-of-doing"}},"content":"Every codebase starts somewhere, often as a quick prototype or exploratory project. But as it grows, evolves, and accumulates contributors, it needs to mature. Understanding where your repository sits in its maturity lifecycle and knowing how to evolve it to the next phase is crucial for maintaining a healthy, productive codebase.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Why Repository Maturity Matters\\n\\nA mature repository isn\'t just about having tests or documentation. It\'s about creating an environment where developers can work efficiently, confidently, and sustainably. An immature codebase slows down development, increases bugs, and makes onboarding new contributors difficult. Conversely, a mature codebase enables faster iteration, reduces risk, and scales with your team.\\n\\n## The Repository Maturity Model\\n\\nThe journey from prototype to enterprise-grade can be broken down into five distinct phases. Each phase has its own characteristics, challenges, and requirements for advancement.\\n\\n| Phase | Typical Characteristics | Common Issues / Technical Debt | What It Takes to Advance to Next Phase |\\n|-------|------------------------|--------------------------------|----------------------------------------|\\n| **1. Prototype / Exploration** | \u2022 One or two contributors<br/>\u2022 Loose, exploratory code<br/>\u2022 \\"utils/\\" dumping ground<br/>\u2022 Minimal docs<br/>\u2022 Weak or no structure | \u2022 No tests<br/>\u2022 Code duplication<br/>\u2022 Hard-coded configs<br/>\u2022 Inconsistent styles<br/>\u2022 High uncertainty about design choices | \u2022 Identify core functionality<br/>\u2022 Basic repo reorganization<br/>\u2022 Add README, setup instructions<br/>\u2022 Introduce linting/formatting (Prettier, ESLint, Black, etc.)<br/>\u2022 Establish minimal CI (linting, build) |\\n| **2. Early Development** | \u2022 Folder structure stabilizing<br/>\u2022 Growing set of modules<br/>\u2022 Some configs externalized<br/>\u2022 First signs of contributors adding structure | \u2022 Partial tests, often flaky<br/>\u2022 Utils folder still overgrown<br/>\u2022 Architecture not clearly defined<br/>\u2022 Manual processes (manual deploys, manual schema changes) | \u2022 Define architecture boundaries<br/>\u2022 Strengthen modularization<br/>\u2022 Introduce meaningful test suites<br/>\u2022 Clean up utils into well-defined packages<br/>\u2022 Add basic automation (build, type-checking) |\\n| **3. Growth / Scaling** | \u2022 More contributors<br/>\u2022 Enforced coding standards<br/>\u2022 CI reliably running tests<br/>\u2022 Defined branching strategy (PR reviews, trunk-based, etc.) | \u2022 Slow build/test times<br/>\u2022 Some tech debt slowing iteration<br/>\u2022 Outdated docs<br/>\u2022 Legacy code paths that resist refactors | \u2022 Improve CI/CD performance<br/>\u2022 Decompose monolithic areas<br/>\u2022 Add layered testing: unit, integration, e2e<br/>\u2022 Invest in internal documentation<br/>\u2022 Introduce observability basics (logging structure, error reporting) |\\n| **4. Mature Product Codebase** | \u2022 Clear architecture (domain-driven, layered, microservices, etc.)<br/>\u2022 High test coverage<br/>\u2022 Automated CI/CD with quality gates<br/>\u2022 Code owners & review guidelines<br/>\u2022 Consistent patterns through the repo | \u2022 Complexity creep<br/>\u2022 Strong conventions, but risk of bureaucracy<br/>\u2022 Harder to evolve core abstractions<br/>\u2022 Minor legacy pockets | \u2022 Periodic architecture reviews<br/>\u2022 Intentional refactoring roadmap<br/>\u2022 Improve developer experience (local env speed-ups, scaffolding tools)<br/>\u2022 Strengthen monitoring and security practices |\\n| **5. Enterprise-Grade / Operational Excellence** | \u2022 Fully automated releases & rollbacks<br/>\u2022 Strong observability<br/>\u2022 Security scanning, SAST/DAST, dependency auditing<br/>\u2022 Well-defined service boundaries<br/>\u2022 Everything documented (design docs, runbooks)<br/>\u2022 Predictable development velocity | \u2022 Potential over-engineering<br/>\u2022 Heavy change management processes<br/>\u2022 Strict requirements may slow innovation | \u2022 Continuous improvement loops<br/>\u2022 Governance balancing innovation & safety<br/>\u2022 Sunset strategies for deprecated modules<br/>\u2022 Regular dependency modernization efforts |\\n\\n## Evolving Your Repository: A Practical Guide\\n\\nMoving from one phase to another requires intentional effort and strategic changes. Here\'s what it takes to evolve your repository, with concrete examples and checklists for each transition.\\n\\n### Phase 1 \u2192 Phase 2: From Prototype to Early Development\\n\\n**Goal**: Establish basic structure and automation to support multiple contributors.\\n\\n#### Checklist:\\n\\n- [ ] **Identify Core Functionality**\\n  - Document what the repository actually does\\n  - Separate core features from experimental code\\n  - Create a clear project purpose statement\\n\\n- [ ] **Basic Repository Organization**\\n  - Establish a consistent folder structure (e.g., `src/`, `tests/`, `docs/`)\\n  - Move utilities into logical modules instead of a single `utils/` folder\\n  - Create a `README.md` with setup instructions\\n\\n- [ ] **Code Quality Foundations**\\n  - Add a formatter (Prettier for JS/TS, Black for Python, gofmt for Go)\\n  - Set up a linter (ESLint, Pylint, golangci-lint)\\n  - Configure your editor/IDE to use these tools\\n\\n- [ ] **Minimal CI Pipeline**\\n  - Set up GitHub Actions, GitLab CI, or similar\\n  - Run linting on every PR\\n  - Ensure the project builds successfully\\n  - Add a basic test runner (even if tests are minimal)\\n\\n#### Example Changes:\\n\\n**Before (Phase 1):**\\n```\\nproject/\\n\u251c\u2500\u2500 utils.py          # Everything goes here\\n\u251c\u2500\u2500 main.py\\n\u2514\u2500\u2500 config.py         # Hard-coded values\\n```\\n\\n**After (Phase 2):**\\n```\\nproject/\\n\u251c\u2500\u2500 src/\\n\u2502   \u251c\u2500\u2500 core/\\n\u2502   \u2502   \u251c\u2500\u2500 models.py\\n\u2502   \u2502   \u2514\u2500\u2500 services.py\\n\u2502   \u2514\u2500\u2500 utils/\\n\u2502       \u251c\u2500\u2500 validation.py\\n\u2502       \u2514\u2500\u2500 formatting.py\\n\u251c\u2500\u2500 tests/\\n\u2502   \u2514\u2500\u2500 test_core.py\\n\u251c\u2500\u2500 .github/\\n\u2502   \u2514\u2500\u2500 workflows/\\n\u2502       \u2514\u2500\u2500 ci.yml\\n\u251c\u2500\u2500 .prettierrc\\n\u251c\u2500\u2500 README.md\\n\u2514\u2500\u2500 requirements.txt\\n```\\n\\n### Phase 2 \u2192 Phase 3: From Early Development to Growth\\n\\n**Goal**: Enable multiple contributors to work efficiently with confidence.\\n\\n#### Checklist:\\n\\n- [ ] **Define Architecture Boundaries**\\n  - Document the high-level architecture\\n  - Establish clear module boundaries and interfaces\\n  - Create an architecture decision record (ADR) template\\n\\n- [ ] **Strengthen Testing**\\n  - Aim for 60-70% test coverage on critical paths\\n  - Add integration tests for key workflows\\n  - Fix flaky tests (identify root causes, add retries/timeouts where appropriate)\\n  - Set up test coverage reporting\\n\\n- [ ] **Modularize Utilities**\\n  - Break down the `utils/` folder into domain-specific modules\\n  - Create clear, single-responsibility utility functions\\n  - Document utility functions with docstrings\\n\\n- [ ] **Automate Common Tasks**\\n  - Automate builds and deployments\\n  - Add type checking to CI (TypeScript, mypy, etc.)\\n  - Create scripts for common development tasks (setup, testing, building)\\n\\n- [ ] **Establish Collaboration Patterns**\\n  - Define a branching strategy (Git Flow, GitHub Flow, or trunk-based)\\n  - Set up PR templates\\n  - Establish code review guidelines\\n\\n#### Example Changes:\\n\\n**Before (Phase 2):**\\n```python\\n# utils.py - everything mixed together\\ndef validate_email(email):\\n    # validation logic\\n    pass\\n\\ndef format_currency(amount):\\n    # formatting logic\\n    pass\\n\\ndef send_notification(user, message):\\n    # notification logic\\n    pass\\n```\\n\\n**After (Phase 3):**\\n```python\\n# src/utils/validation.py\\n\\"\\"\\"Email and input validation utilities.\\"\\"\\"\\ndef validate_email(email: str) -> bool:\\n    \\"\\"\\"Validate email format.\\"\\"\\"\\n    # validation logic\\n    pass\\n\\n# src/utils/formatting.py\\n\\"\\"\\"Data formatting utilities.\\"\\"\\"\\ndef format_currency(amount: float, currency: str = \\"USD\\") -> str:\\n    \\"\\"\\"Format amount as currency string.\\"\\"\\"\\n    # formatting logic\\n    pass\\n\\n# src/services/notification.py\\n\\"\\"\\"Notification service.\\"\\"\\"\\ndef send_notification(user: User, message: str) -> None:\\n    \\"\\"\\"Send notification to user.\\"\\"\\"\\n    # notification logic\\n    pass\\n```\\n\\n### Phase 3 \u2192 Phase 4: From Growth to Mature Product\\n\\n**Goal**: Create a maintainable, scalable codebase that supports long-term development.\\n\\n#### Checklist:\\n\\n- [ ] **Optimize CI/CD Performance**\\n  - Parallelize test execution\\n  - Use build caching (Docker layers, npm/yarn cache, etc.)\\n  - Split tests into fast/slow suites\\n  - Consider test sharding for large test suites\\n\\n- [ ] **Decompose Monolithic Areas**\\n  - Identify tightly coupled modules\\n  - Extract services or packages where appropriate\\n  - Use dependency injection to reduce coupling\\n\\n- [ ] **Layered Testing Strategy**\\n  - Unit tests: Fast, isolated, high coverage\\n  - Integration tests: Test component interactions\\n  - E2E tests: Critical user journeys only\\n  - Set up test pyramid metrics\\n\\n- [ ] **Internal Documentation**\\n  - Document complex algorithms and business logic\\n  - Create architecture diagrams\\n  - Maintain a \\"how to contribute\\" guide\\n  - Document common patterns and anti-patterns\\n\\n- [ ] **Observability Foundations**\\n  - Structured logging (JSON logs, log levels)\\n  - Error tracking (Sentry, Rollbar, etc.)\\n  - Basic metrics (request counts, error rates)\\n  - Health check endpoints\\n\\n#### Example Changes:\\n\\n**Before (Phase 3):**\\n```javascript\\n// Everything in one file, no separation of concerns\\nfunction processOrder(order) {\\n  // validate order\\n  // calculate total\\n  // charge customer\\n  // update inventory\\n  // send confirmation email\\n  // log everything\\n  console.log(\\"Processing order:\\", order);\\n}\\n```\\n\\n**After (Phase 4):**\\n```javascript\\n// src/domain/order.js - Domain logic\\nclass OrderService {\\n  constructor(orderRepository, paymentService, inventoryService, notificationService, logger) {\\n    this.orderRepository = orderRepository;\\n    this.paymentService = paymentService;\\n    this.inventoryService = inventoryService;\\n    this.notificationService = notificationService;\\n    this.logger = logger;\\n  }\\n\\n  async processOrder(order) {\\n    this.logger.info(\'Processing order\', { orderId: order.id });\\n    \\n    const validatedOrder = await this.validateOrder(order);\\n    const total = this.calculateTotal(validatedOrder);\\n    \\n    await this.paymentService.charge(total);\\n    await this.inventoryService.update(validatedOrder.items);\\n    await this.notificationService.sendConfirmation(validatedOrder);\\n    \\n    return await this.orderRepository.save(validatedOrder);\\n  }\\n}\\n```\\n\\n### Phase 4 \u2192 Phase 5: From Mature to Enterprise-Grade\\n\\n**Goal**: Achieve operational excellence with automated, secure, and reliable systems.\\n\\n#### Checklist:\\n\\n- [ ] **Fully Automated Release Process**\\n  - Automated versioning (semantic versioning)\\n  - Automated changelog generation\\n  - Automated rollback capabilities\\n  - Blue-green or canary deployments\\n\\n- [ ] **Comprehensive Observability**\\n  - Distributed tracing\\n  - Application performance monitoring (APM)\\n  - Business metrics dashboards\\n  - Alerting for critical issues\\n\\n- [ ] **Security Hardening**\\n  - Static application security testing (SAST)\\n  - Dynamic application security testing (DAST)\\n  - Dependency vulnerability scanning\\n  - Secrets management\\n  - Regular security audits\\n\\n- [ ] **Documentation Excellence**\\n  - Design documents for major features\\n  - Runbooks for operational procedures\\n  - API documentation (OpenAPI/Swagger)\\n  - Architecture decision records (ADRs)\\n\\n- [ ] **Developer Experience**\\n  - One-command local environment setup\\n  - Fast feedback loops (hot reload, fast tests)\\n  - Code generation/scaffolding tools\\n  - Clear contribution guidelines\\n\\n#### Example Changes:\\n\\n**Before (Phase 4):**\\n```yaml\\n# Manual deployment process\\n# 1. Build locally\\n# 2. Test manually\\n# 3. Tag release\\n# 4. Deploy to staging\\n# 5. Manual smoke tests\\n# 6. Deploy to production\\n# 7. Monitor logs manually\\n```\\n\\n**After (Phase 5):**\\n```yaml\\n# .github/workflows/release.yml\\nname: Release\\non:\\n  push:\\n    tags:\\n      - \'v*\'\\n\\njobs:\\n  release:\\n    runs-on: ubuntu-latest\\n    steps:\\n      - uses: actions/checkout@v3\\n      - name: Run tests\\n        run: npm test\\n      - name: Security scan\\n        run: npm audit --audit-level=high\\n      - name: Build\\n        run: npm run build\\n      - name: Deploy to staging\\n        run: ./scripts/deploy.sh staging\\n      - name: Run E2E tests\\n        run: npm run test:e2e\\n      - name: Deploy to production (canary)\\n        run: ./scripts/deploy-canary.sh\\n      - name: Monitor canary\\n        run: ./scripts/monitor-canary.sh\\n      - name: Full rollout\\n        if: success()\\n        run: ./scripts/deploy-full.sh\\n```\\n\\n## Key Principles for Evolution\\n\\nRegardless of which phase transition you\'re making, keep these principles in mind:\\n\\n1. **Incremental Progress**: Don\'t try to jump multiple phases at once. Focus on one transition at a time.\\n\\n2. **Measure Before and After**: Track metrics like build times, test coverage, deployment frequency, and bug rates to validate improvements.\\n\\n3. **Team Buy-In**: Evolution requires team consensus. Make sure everyone understands the \\"why\\" behind changes.\\n\\n4. **Automate First**: Before adding manual processes, see if you can automate them.\\n\\n5. **Document Decisions**: Use ADRs to capture why architectural decisions were made.\\n\\n6. **Balance Speed and Quality**: Don\'t let perfect be the enemy of good. Make progress, then iterate.\\n\\n## Recognizing When You\'re Ready to Evolve\\n\\nYou might be ready to evolve to the next phase if:\\n\\n- **Phase 1 \u2192 2**: You have more than one contributor or plan to add contributors soon\\n- **Phase 2 \u2192 3**: You\'re spending significant time fixing bugs that tests would have caught\\n- **Phase 3 \u2192 4**: Build/test times are slowing down development velocity\\n- **Phase 4 \u2192 5**: You need to support multiple environments, compliance requirements, or high availability\\n\\n## Conclusion\\n\\nRepository evolution is an ongoing journey, not a destination. The goal isn\'t to reach Phase 5 immediately. It\'s to ensure your repository\'s maturity matches your team\'s needs and the project\'s requirements.\\n\\nStart by honestly assessing where your repository currently sits, then pick one transition to focus on. Use the checklists and examples above as a guide, but adapt them to your specific context and constraints.\\n\\nRemember: a mature repository is one that enables your team to ship features confidently and efficiently. If your current phase is working well for your team size and project scope, that\'s perfectly fine. Evolve when the pain of staying in your current phase outweighs the effort of moving forward.\\n\\n---\\n\\n*What phase is your repository currently in? Have you successfully evolved a repository from one phase to another? Share your experiences and lessons learned!*"},{"id":"the-anatomy-of-doing","metadata":{"permalink":"/thoughts/the-anatomy-of-doing","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2025-09-17-the-anatomy-of-doing.md","source":"@site/blog/2025-09-17-the-anatomy-of-doing.md","title":"The Anatomy of Doing: A Framework for Acting on What Matters","description":"A personal operating system for execution: the handful of triggers that should pull you into action, and the loop that keeps the action honest.","date":"2025-09-17T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"}],"readingTime":4.44,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"the-anatomy-of-doing","title":"The Anatomy of Doing: A Framework for Acting on What Matters","kind":"framework","sidebar_label":"Anatomy of Doing","description":"A personal operating system for execution: the handful of triggers that should pull you into action, and the loop that keeps the action honest.","authors":["oeid"],"tags":["productivity"],"date":"2025-09-17T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"The Evolution of a Repository: A Maturity Model","permalink":"/thoughts/evolution-of-a-repo"},"nextItem":{"title":"AI Engineer World Fair 2025","permalink":"/thoughts/ai-engineer-world-fair-2025"}},"content":"I spent a long time confusing *being busy* with *doing the right things*. The fix\\nwasn\'t a better to-do app. It was getting clear about the small number of things\\nthat should actually trigger action, and the loop that keeps that action pointed at\\nwhat matters. This is that framework: the anatomy of doing.\\n\\n\x3c!-- truncate --\x3e\\n\\n```mermaid\\nflowchart LR\\n    T[\\"Notice a trigger<br/>(need \xb7 priority \xb7 reference<br/>\xb7 reflection \xb7 intent)\\"] --\x3e A[\\"Act<br/>(once, or on a rhythm)\\"]\\n    A --\x3e C[\\"Curate<br/>(keep what\'s necessary,<br/>cut the rest, classify)\\"]\\n    C --\x3e R[\\"Reflect weekly<br/>(review, find the refinement)\\"]\\n    R --\x3e T\\n```\\n\\n## What pulls you into action\\n\\nMost of the noise in a productivity system comes from treating every input the same.\\nIn practice, almost everything I act on traces back to one of a few triggers:\\n\\n- **A need.** Something has to grow, get organized, or get built, including the\\n  tools I need and the tools I *want* to make. The discipline here is ranking:\\n  when needs compete, which one actually matters most, and how do I weigh an urgent\\n  need against a long-term one?\\n- **A priority.** Some things need doing now; some can wait. The work is deciding\\n  which is which, separating urgent from important, and protecting deadlines\\n  instead of reacting to whatever is loudest.\\n- **A reference.** Notes, links, and captured information are worthless if they only\\n  accumulate. The question that keeps them alive: what does this reference actually\\n  ask me to *do*, and how do I make sure captured information turns into action\\n  rather than clutter?\\n- **A reflection.** Insight is the input that\'s easiest to waste. When I notice a\\n  pattern in how I\'m working, the only thing that makes the reflection real is\\n  translating it into a concrete next step.\\n- **An intent.** Underneath all of it is the question of *why* I\'m doing this at\\n  all. Capturing the intent behind an action, and checking that the action still\\n  aligns with it, is what keeps the whole system from drifting into motion for its\\n  own sake.\\n\\nIf a task can\'t be traced back to one of these, that\'s usually a sign it doesn\'t\\nbelong on the list.\\n\\n## Keeping action consistent\\n\\nTriggers get you moving. Consistency is what compounds. Two things matter here.\\n\\nThe first is **rhythm**: recurring action on the right cadence. Not everything\\ndeserves the same frequency, so the useful move is to sort recurring work by time\\nscale (daily, weekly, monthly, quarterly, yearly). Once it\'s sorted, the system\'s\\njob is just to make sure nothing recurring quietly falls off, and to keep improving\\nthe recurring work instead of running it on autopilot forever.\\n\\nThe second is a **weekly iteration**. Once a week I review what I did, find the one\\nor two things worth refining, and feed that back in. Weekly is short enough to\\ncorrect course and long enough to see a pattern. The trap to avoid is letting the\\nreview *replace* the doing. Iteration is in service of execution, not a substitute\\nfor it.\\n\\n## Curating, not just accumulating\\n\\nThe failure mode of a productive person isn\'t idleness. It\'s doing a lot of\\nunnecessary things efficiently. So a real part of doing is *curation*: deciding\\nwhat\'s genuinely necessary and cutting the rest. That means having criteria for\\n\\"necessary,\\" staying alert to work that only *feels* productive, and (just as\\nimportant) making sure nothing genuinely necessary is slipping through while I\'m\\nbusy trimming.\\n\\nThe same instinct applies to understanding your own action. It helps to **classify**\\nwhat you do, to know the categories of work you actually engage in, because you\\ncan\'t balance or optimize a set of activities you\'ve never named.\\n\\n## When you don\'t know what to do\\n\\nSome of the time the honest answer is *I\'m not sure what to do next.* That\'s its own\\nskill. The move is to widen the field before narrowing it, to list what you *can*\\ndo before deciding what you *will*:\\n\\n- ideas you can refine\\n- projects you can work on\\n- things you can tinker with\\n- experiments you can run\\n- books you can read and topics you can learn\\n- scripts you can write and processes you can establish\\n\\nSeeing the options laid out usually makes the next action obvious. And when it\\ndoesn\'t, that\'s a decision-making process to improve, not a personal failing.\\n\\n## The environment around the work\\n\\nNone of this survives contact with a bad environment. Part of doing is deliberately\\ncrafting the surroundings (the workspace, the tools, the background conditions)\\nthat keep me focused and motivated by default, and adapting that environment to the\\nkind of work in front of me rather than fighting it.\\n\\n## The loop\\n\\nPut together, doing isn\'t a list of tasks. It\'s a loop:\\n\\n[Step 1] **Notice the trigger:** a need, a priority, a reference, a reflection, or\\nan intent worth acting on.\\n\\n[Step 2] **Act**, on the right cadence. Once for one-offs, on a rhythm for\\nrecurring work.\\n\\n[Step 3] **Curate:** keep what\'s necessary, cut what isn\'t, classify what\'s left so\\nyou can see it clearly.\\n\\n[Step 4] **Reflect weekly:** review, find the refinement, and feed it back into the\\ntriggers so the next pass is sharper.\\n\\nThe goal was never to do *more*. It was to make sure the doing stays pointed at what\\nactually matters, and to have a loop that catches it when it drifts."},{"id":"ai-engineer-world-fair-2025","metadata":{"permalink":"/thoughts/ai-engineer-world-fair-2025","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2025-06-15-ai-engineer-world-fair-2025.md","source":"@site/blog/2025-06-15-ai-engineer-world-fair-2025.md","title":"AI Engineer World Fair 2025","description":"My experience attending the AI Engineer World Fair in June 2025 - key insights, tools, and trends shaping the future of AI engineering.","date":"2025-06-15T10:00:00.000Z","tags":[{"inline":true,"label":"ai-engineering","permalink":"/thoughts/tags/ai-engineering"},{"inline":true,"label":"conference","permalink":"/thoughts/tags/conference"},{"inline":true,"label":"genai","permalink":"/thoughts/tags/genai"},{"inline":true,"label":"tools","permalink":"/thoughts/tags/tools"},{"inline":true,"label":"trends","permalink":"/thoughts/tags/trends"},{"inline":true,"label":"networking","permalink":"/thoughts/tags/networking"}],"readingTime":1.08,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"ai-engineer-world-fair-2025","title":"AI Engineer World Fair 2025","kind":"event-recap","sidebar_label":"AI Engineer Fair","description":"My experience attending the AI Engineer World Fair in June 2025 - key insights, tools, and trends shaping the future of AI engineering.","authors":["oeid"],"tags":["ai-engineering","conference","genai","tools","trends","networking"],"date":"2025-06-15T10:00","draft":false},"unlisted":false,"prevItem":{"title":"The Anatomy of Doing: A Framework for Acting on What Matters","permalink":"/thoughts/the-anatomy-of-doing"},"nextItem":{"title":"The Design Thinking Mindset: Notes on Human-Centered Design","permalink":"/thoughts/the-design-thinking-mindset"}},"content":"I attended the AI Engineer World Fair in June 2025. Here are the key insights and trends I discovered.\\n\\n\x3c!-- truncate --\x3e\\n\\n# AI Engineer World Fair 2025\\n\\n> **Read the full notes \u2192 [AI Engineer World Fair 2025](/craft/generative-ai/mental-models/2025-06-15-ai-engineer-world-fair)**\\n\\nA few themes stood out across the talks and hallway conversations:\\n\\n## Takeaways\\n\\n- **MCP is becoming the connective tissue.** The Model Context Protocol gives agents a\\n  consistent interface to external tools, and the interesting parts are the less-obvious\\n  capabilities (elicitation, dynamic tool discovery, stateful interactions), not just the\\n  tool calls.\\n- **Browser-acting agents got real.** Tools like Nova Act break web tasks into smaller,\\n  reliable steps and can run sessions in parallel, closing the gap between \\"chat\\" and\\n  \\"actually does the thing.\\"\\n- **Workflows vs. agents is the architecture decision.** Composable, explicitly-ordered\\n  pipelines (workflows) and memory-bearing, turn-based agents (with supervisors that call\\n  other agents as tools) are different tools for different jobs, and picking wrong is where\\n  projects stall.\\n- **Graph-shaped memory is the hallucination story.** GraphRAG approaches keep causal\\n  links between concepts in memory, which the talks framed as a path to fewer\\n  hallucinations and better hypothesis generation.\\n\\nThe full set of notes (frameworks, agent-memory patterns, and the mind map) lives in the\\nlinked doc above."},{"id":"the-design-thinking-mindset","metadata":{"permalink":"/thoughts/the-design-thinking-mindset","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2024-02-25-the-design-thinking-mindset.md","source":"@site/blog/2024-02-25-the-design-thinking-mindset.md","title":"The Design Thinking Mindset: Notes on Human-Centered Design","description":"Reflections on human-centered design: the inspiration-ideation-implementation loop, and the mindset shifts (empathy, ambiguity, iteration) that make it work.","date":"2024-02-25T00:00:00.000Z","tags":[{"inline":true,"label":"product-management","permalink":"/thoughts/tags/product-management"},{"inline":true,"label":"mindset","permalink":"/thoughts/tags/mindset"}],"readingTime":4.12,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"the-design-thinking-mindset","title":"The Design Thinking Mindset: Notes on Human-Centered Design","kind":"reflection","sidebar_label":"Design Thinking","description":"Reflections on human-centered design: the inspiration-ideation-implementation loop, and the mindset shifts (empathy, ambiguity, iteration) that make it work.","authors":["oeid"],"tags":["product-management","mindset"],"date":"2024-02-25T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"AI Engineer World Fair 2025","permalink":"/thoughts/ai-engineer-world-fair-2025"},"nextItem":{"title":"A Framework for Prioritizing","permalink":"/thoughts/a-framework-for-prioritizing"}},"content":"These are my reflections on human-centered design, drawn from time spent with the\\ndesign-thinking literature that came out of IDEO and the Stanford d.school. It\'s not\\na summary of any one source. It\'s the framework and the mindset shifts that I found\\ngenuinely changed how I approach building things for people.\\n\\n\x3c!-- truncate --\x3e\\n\\n## A system of spaces, not a sequence of steps\\n\\nThe first reframing: design thinking isn\'t a checklist you run top to bottom. It\'s a\\nset of **overlapping spaces** you move between. The literature names three:\\ninspiration, ideation, and implementation. You don\'t graduate cleanly from one to\\nthe next; you loop back as you learn.\\n\\n```mermaid\\nflowchart LR\\n    Inspiration[\\"Inspiration<br/>(immerse \xb7 observe \xb7 understand needs)\\"] --\x3e Ideation[\\"Ideation<br/>(synthesize \xb7 generate \xb7 prototype)\\"]\\n    Ideation --\x3e Implementation[\\"Implementation<br/>(build \xb7 test \xb7 bring to market)\\"]\\n    Ideation -. \\"learn & loop back\\" .-> Inspiration\\n    Implementation -. \\"learn & loop back\\" .-> Ideation\\n```\\n\\nWhat I like about holding it as spaces rather than steps is that it gives you\\npermission to go backwards. Discovering in implementation that you misread a need\\nisn\'t failure, it\'s the loop working.\\n\\n## Inspiration: people can\'t tell you what they want\\n\\nThe phase that changed my instincts the most is the first one. The temptation is to\\nstart by asking people what they need, through surveys and focus groups. The\\nuncomfortable truth the field keeps surfacing is that **people often can\'t tell you\\nwhat they want.** Stated preferences are weak signal.\\n\\nWhat\'s strong signal is **behavior**. You learn more by going out and observing how\\npeople actually live and work than by asking them to introspect. The job in this\\nphase is to embed yourself in their world deeply enough that their unmet needs become\\nvisible, the ones they\'d never have named.\\n\\nThere\'s a craft point here too about the **brief** you start from. Too abstract and\\nthe team wanders; too specific and you get something incremental and safe. A good\\nbrief constrains just enough to leave room for the unexpected.\\n\\n## Ideation: have a lot of ideas\\n\\nThe middle space is about synthesis and volume. You distill what you observed into\\ninsights, then deliberately generate *many* competing ideas rather than committing\\nearly to the obvious one. The point worth internalizing: more choices mean more\\ncomplexity, and the natural human reflex is to cut that complexity by retreating to\\nthe safe, incremental option. Resisting that reflex is most of the work.\\n\\nI keep coming back to Linus Pauling\'s line, that to have a good idea you should have\\na lot of ideas. Testing ideas against each other is what makes the eventual one\\nbolder than what you\'d have reached by defending your first guess.\\n\\n## Implementation: make it real, then make it last\\n\\nThe last space is the path from a project into people\'s actual lives. The questions\\nshift from \\"what should this be\\" to \\"how do I make it real, how do I tell if it\'s\\nworking, and how do I make it sustainable.\\" It\'s also where the earlier loops pay\\noff or expose themselves: a solution that was never prototyped against real needs\\ntends to fail here, not because the idea was bad but because it was never tested\\nagainst the people it was for.\\n\\n## The mindset matters more than the method\\n\\nThe part I underestimated is that design thinking is as much a **mindset** as a\\nprocess. A few of the shifts that stuck with me:\\n\\n[Step 1] **Empathy.** You can\'t generate anything new if you only ever live inside\\nyour own experience. The core skill is stepping into someone else\'s perspective and\\nsolving the problem from there.\\n\\n[Step 2] **Embrace ambiguity.** Start from genuinely not knowing the answer.\\nPermission to not know is what makes room to be creative.\\n\\n[Step 3] **Creative confidence.** The belief that everyone is creative, that\\ncreativity is a way of approaching the world rather than a talent for drawing or\\nsculpting. Anyone can approach a problem like a designer.\\n\\n[Step 4] **Optimism.** Treat the answer as out there and findable, even when you\\ncan\'t see it yet.\\n\\n[Step 5] **Iterate relentlessly.** Continual refining is what gets you more ideas,\\nmore approaches, and a faster path to something that works.\\n\\n## Why this is a \\"third way\\"\\n\\nThe framing that ties it together for me: leaning entirely on analysis carries real\\nrisk, and leaning entirely on gut feeling carries just as much. What design thinking\\ndoes is braid the two together. It\'s a deeply human process that values ideas with emotional\\nmeaning *and* functional rigor, and that\'s what makes it a real third way rather than\\na softer synonym for \\"brainstorming.\\"\\n\\n## What I took from it\\n\\nWatch behavior, not stated preferences. Generate many ideas before committing.\\nPrototype against real people early. And treat empathy, ambiguity, and iteration as a\\nmindset you bring, not steps you check off. The method is useful, but the mindset is\\nwhat travels to every problem.\\n\\n*Reflections on human-centered design, drawn from the IDEO / Stanford d.school\\ndesign-thinking literature.*"},{"id":"a-framework-for-prioritizing","metadata":{"permalink":"/thoughts/a-framework-for-prioritizing","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2020-05-26-a-framework-for-prioritizing.md","source":"@site/blog/2020-05-26-a-framework-for-prioritizing.md","title":"A Framework for Prioritizing","description":"Prioritizing isn\'t a one-time ranking. It\'s a set of recurring questions: what factors matter, how to evaluate candidates, when to de-prioritize, and how to get better at it over time.","date":"2020-05-26T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"}],"readingTime":2.59,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"a-framework-for-prioritizing","title":"A Framework for Prioritizing","kind":"framework","sidebar_label":"Prioritizing","description":"Prioritizing isn\'t a one-time ranking. It\'s a set of recurring questions: what factors matter, how to evaluate candidates, when to de-prioritize, and how to get better at it over time.","authors":["oeid"],"tags":["productivity"],"date":"2020-05-26T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"The Design Thinking Mindset: Notes on Human-Centered Design","permalink":"/thoughts/the-design-thinking-mindset"},"nextItem":{"title":"The Song of Life","permalink":"/thoughts/the-song-of-life"}},"content":"Most advice on prioritization stops at \\"rank your list.\\" But ranking is the easy\\npart. The hard part is everything around it: deciding which factors should even\\ncount, evaluating candidates against them, knowing when to *reverse* a priority you\\nonce held, and retrospecting so you get better at the whole loop. This is the\\nframework of questions I use, organized by the stage of prioritizing you\'re in.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Establishing your current focus\\n\\nStart by naming what you\'re actually focused on right now, across each area you care\\nabout:\\n\\n- What questions are you focused on answering *now*?\\n- What initiatives have you decided to work on *now*, for your career, your\\n  marketing, your projects, your learning, your growth?\\n\\nThe point of listing focus by area is to notice where you\'ve quietly let everything\\nbecome a priority, which is the same as having none.\\n\\n## Choosing your prioritization factors\\n\\nBefore you rank anything, decide what you\'re ranking *by*:\\n\\n- What factors should you consider when prioritizing? What *must* you consider?\\n- How do the factors compare? Which factor outranks the others, and how do you\\n  determine that?\\n- Which candidate is easier to do? Which needs to be done now? Which are you most\\n  interested in doing?\\n- How often should you revisit each of these concerns? (And what\'s the difference\\n  between a *factor* and a *concern*?)\\n\\n## Surfacing the candidates\\n\\nYou can\'t prioritize what you haven\'t gathered:\\n\\n- What are the things you\'re prioritizing, and where do they live? Are they in your\\n  tracker? Scattered across roles?\\n- What initiatives are in the running?\\n\\nA recurring failure mode: getting repeatedly sucked into low-value polish (tuning a\\npublic profile, picking which work to showcase) when the higher priority is\\nshipping the thing at all.\\n\\n## Evaluating projects\\n\\nWhen the candidates are projects, score each against a consistent checklist:\\n\\n- Will this project help you learn something you want to learn?\\n- Does it overlap with the things you enjoy doing? Do you *want* to work on it?\\n- How marketable is it? How distributable is it?\\n- What else should you weigh before committing?\\n\\n## Classifying what you\'ve prioritized\\n\\nOnce something clears the bar, decide where it belongs:\\n\\n- What goes on the roadmap, and what goes straight into your day-to-day task system?\\n- What *doesn\'t* need prioritizing at all? (Small experiments, for instance, are\\n  often cheap enough to just do.)\\n\\n## De-prioritizing\\n\\nReversing priorities is as important as setting them:\\n\\n- What did you once want to do that you no longer want to do?\\n- What obstacles are hindering the goals you\'ve kept?\\n- What goals depend on other goals or activities being done first?\\n\\nLetting go of a stale priority frees more capacity than squeezing one more task into\\nthe day.\\n\\n## Retrospecting the process itself\\n\\nFinally, treat prioritization as a skill you improve, not a chore you endure:\\n\\n- How can you get better at prioritizing?\\n- What shortcomings have you observed in how you do it?\\n- What can you do now versus what you\'d need to learn to do something new?\\n\\nPrioritization isn\'t a list you sort once. It\'s a loop you run: focus, weigh,\\ngather, evaluate, classify, prune, and reflect. Then run it again."},{"id":"the-song-of-life","metadata":{"permalink":"/thoughts/the-song-of-life","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2020-03-23-the-song-of-life.md","source":"@site/blog/2020-03-23-the-song-of-life.md","title":"The Song of Life","description":"A set of philosophical reflections on life, death, purpose, words, and the strange symmetry between programs and existence.","date":"2020-03-23T00:00:00.000Z","tags":[{"inline":true,"label":"philosophy","permalink":"/thoughts/tags/philosophy"},{"inline":true,"label":"mindset","permalink":"/thoughts/tags/mindset"}],"readingTime":4.37,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"the-song-of-life","title":"The Song of Life","kind":"reflection","sidebar_label":"Song of Life","description":"A set of philosophical reflections on life, death, purpose, words, and the strange symmetry between programs and existence.","authors":["oeid"],"tags":["philosophy","mindset"],"date":"2020-03-23T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"A Framework for Prioritizing","permalink":"/thoughts/a-framework-for-prioritizing"},"nextItem":{"title":"Affirmations for the Inner Game","permalink":"/thoughts/affirmations-for-the-inner-game"}},"content":"These are reflections I\'ve collected over years of philosophical wandering: about\\nwhat life is for, why death isn\'t to be feared, the mystical weight of words, and\\nthe odd symmetry between writing a program and living a life. They aren\'t arguments\\nso much as meditations. Read them slowly.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Life\'s purpose and meaning\\n\\nThe Prophet (SAAW) loved God. How beautiful life is when you return to the one you\\nlove. And while you are away from your love, you learn to do what makes them happy.\\nYou do what you want, not knowing that your lover is aware. But fret not: love is\\ntrue, and all is forgiven in Love.\\n\\nWhat kind of life are you living if, at the end, you don\'t know where you are\\ngoing? You don\'t know what will happen to you?\\n\\n## The song of life\\n\\nMusic is inherently playful. The point is not to reach the end of the song; it\'s\\nthe song itself. You *play* the piano. You don\'t *work* the piano.\\n\\nYour life is your art. What is your art as an artist?\\n\\nLife is a musical thing. We were supposed to sing and dance, not rush to reach the\\nend. It\'s like Hajj: a pilgrimage to reach God, but once you\'re there, you dance\\nwith God.\\n\\n## Living and loving\\n\\nI live to live. I live to love. To love what I do. To do what I love.\\n\\nI love. I live. One day I will leave you, with my love, and go to the One that\\ncreated you and me to love.\\n\\n## Death, the return\\n\\nWhy do you fear death? You are simply returning to whom you love. He did not create\\nyou in vain. He will take care of you when you part.\\n\\n## The recursion of life\\n\\nIn nature: cells and planets. In life: death is the base case. Success in life\\nstarts at realizing death. Start working towards your death. I don\'t want to die\\nregretfully; I want to live towards my death.\\n\\nGod recursively created us: the ability to perpetuate yourself through your\\ngenerations, in our cells, the planets, the universe. What is the folded value of\\nhumanity?\\n\\n## Understanding purpose\\n\\nTo understand our purpose, we must understand why we were created. What use does God\\nhave from us? None. God doesn\'t need us to do anything; God is not benefiting from\\nus. So it\'s in our best interest to emulate God, to learn about God, to reflect the\\ndivine purpose.\\n\\nHow can you love God if you don\'t know God?\\n\\n## The power of words\\n\\n*Motivation on demand. And God said \\"Be\\" and it was.*\\n\\nWe underestimate the power of words. Words are powerful. We think in words. We sell\\nin words. We speak in words. We pursue with words. We are surrounded by words since\\nbirth. We fall in love through words. We transfer emotions through words. And when\\nwe pass, we are remembered through words.\\n\\nWords can make the hairs on our backs stand. We start wars over words. We form\\nalliances through words. Words drive the world. They drive the way we think about\\nourselves. They affect how we feel. They can make our day or break our day. Whether\\nwe like it or not, words have mystical powers over us.\\n\\nThat\'s why it\'s so important to surround ourselves with positive words: words that\\nmotivate us, that influence us to become better people, that remind us to believe in\\nourselves, that help keep us determined, that remind us that we are blessed.\\n\\nMind came before matter. Words came before the matter. Everything is language.\\nEverything can be described with words. God taught Adam all the words.\\n\\nWords can teach you how to cook. Words can inspire you. Words govern technology.\\nWe think in words. Some words were never meant to be. Some things were never meant\\nto be said. Some words are captured deep inside. Words have the power to change;\\nwords have the power to hold. Words can capture your essence for everyone else to\\nsee. Words can capture your mind for everyone to enjoy.\\n\\n## Understanding programming\\n\\nOur lives begin with an event (birth) and end with an event (death). What lies\\nin-between these two milestones is a collection of choices. Similarly, programs\\nstart with an event (double-clicking an icon) and end with an event (closing the\\nprogram), and what lies in-between is a collection of choices.\\n\\nChoices are black and white. Do I play soccer, or not play soccer?\\n\\nWe looked at a fish; we built ships. We looked at birds; we built planes. We looked\\nat humans; we built computers. Computers are a masterful manifestation of choices.\\n\\n## Understanding problem solving\\n\\nIs problem solving breaking things down to the simplest pieces, then piecing them\\nback together in a structured fashion, by sequencing the elements and relating them?\\n\\nWe conquered chemistry through elements. We conquered computers through bits, through\\ndata. Language is letters and symbols. Language is assigning meaning to words.\\nLanguage is assigning meaning to the meaning of different sequences of words.\\n\\nIs problem solving breaking things down to the smallest *meaningful* elements, or\\nsimply breaking things down to the smallest *possible* element?\\n\\nDo letters have meaning by themselves? Do bits have meaning by themselves?"},{"id":"affirmations-for-the-inner-game","metadata":{"permalink":"/thoughts/affirmations-for-the-inner-game","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2019-01-01-affirmations-for-the-inner-game.md","source":"@site/blog/2019-01-01-affirmations-for-the-inner-game.md","title":"Affirmations for the Inner Game","description":"A collection of faith-based and motivational affirmations I\'ve returned to over the years, organized by theme: faith, strength, discipline, failure, focus, confidence, and living fully.","date":"2019-01-01T00:00:00.000Z","tags":[{"inline":true,"label":"mindset","permalink":"/thoughts/tags/mindset"}],"readingTime":9.78,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"affirmations-for-the-inner-game","title":"Affirmations for the Inner Game","kind":"reflection","sidebar_label":"Inner Game","description":"A collection of faith-based and motivational affirmations I\'ve returned to over the years, organized by theme: faith, strength, discipline, failure, focus, confidence, and living fully.","authors":["oeid"],"tags":["mindset"],"date":"2019-01-01T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"The Song of Life","permalink":"/thoughts/the-song-of-life"},"nextItem":{"title":"A Taxonomy of Learning Resources","permalink":"/thoughts/a-taxonomy-of-learning-resources"}},"content":"For years I\'ve kept a running list of affirmations: faith-based reminders, lines from motivational talks, and one-liners that snapped me out of a rut. Some are scripture-adjacent, some are pure hype, some are questions I ask myself. They were scattered across notebooks and notes apps until I gathered and grouped them by theme.\\n\\n\x3c!-- truncate --\x3e\\n\\nI\'m sharing them here the way I use them: not as a system to follow, but as a deck to flip through when you need the right words. Read the section that matches where your head is. Take what resonates, leave the rest.\\n\\n## Faith & Trusting God\\n\\n### Order my steps\\n- He is orchestrating your strength\\n- He is giving you steps you are capable of handling\\n- Hold his hand and start to climb to your potential\\n- Order my steps Lord\\n- I trust you\\n- You have equipped me with everything I need right now\\n- Your life will move in the direction of your words\\n- What better words than his\\n- The Names of God should drive your actions\\n- I put in him all it takes to withstand the pressure\\n- Walk by faith and not by sight\\n- God just needs to will to do, you need to act. Will is not enough!\\n\\n### God has a plan\\n- GOD HAS SOMETHING IN PLAN FOR YOU\\n- HE WON\'T GIVE YOU SOMETHING YOU CAN\'T TAKE\\n- HE WON\'T GIVE YOU A CHALLENGE YOU CAN\'T HANDLE\\n- HE IS BUILDING EVERYONE OF US\\n- God is not preparing the blessing for you, God is preparing you for the blessings!\\n- Any time you get anything too soon, you will trip on the steps!\\n- What is God preparing you for?\\n\\n### God is with you\\n- GOD HAS ALWAYS BEEN THERE AND HE ALWAYS WILL\\n- YOU DON\'T HAVE TO SEE HIM TO KNOW THAT SOMEONE IS LOOKING OUT FOR YOU\\n- God knows that you will be able to bear the burden he gave you, and that you will come out of it stronger, better!\\n- God will not present you with something you can\'t handle!\\n- Have you been trusted with some trouble?!\\n- YOU NEVER PROMISE THE OBVIOUS, YOU ONLY PROMISE WHEN THERE IS A CAUSE FOR DOUBT. GOD PROMISES THAT HE WONT GIVE YOU SOMETHING YOU CAN HANDLE!\\n\\n### Pray to Him\\n- DO NOT ABUSE GOD\'S MERCY!\\n- THE PRESENCE OF A STORM DOES NOT INDICATE THE ABSENCE OF GOD\\n- Why do you only beg Him when it starts to storm?!\\n\\n### Faith as a force\\n- Faith is the oil that takes the friction out of living\\n- It all starts with belief\\n- BELIEVE!\\n- Faith finds a way!\\n- I am going to show you how great I am! ~ Muhammad Ali\\n- I work on making the people around me believe that we are going to be great.\\n- Don\'t believe its a lack of funds that makes you unsuccessful, its a lack of belief!\\n- HE IS ABLE WHO THINKS HE IS ABLE\\n- I WILL\\n- Change your garments!\\n- Prepare for something that hasn\'t happened yet!\\n\\n## Strength, Pain & Endurance\\n\\n### Let hardships build you\\n- Things don\'t happen by accident! I didn\'t stumble upon you by accident!\\n- The steps of a good man are ordered by God!\\n- Experiences build you. They give you faith.\\n- Be thankful for experiences\\n- Be thankful for goodbyes\\n- When pain comes it\'s time to show your character\\n- I never fail, I only have learning experiences!\\n- NOTHING JUST HAPPENS!\\n- Praise God in the middle of the pain, trust where He is taking you!\\n- Your strength is perfected in the weak places of life!\\n- I want you to praise me in the middle of the pain then I know you trust me that I am taking you somewhere!\\n- Im sickening to talking to people who think that things just happen.\\n\\n### Deal with pain\\n- It\'s how you handle the pain!\\n- I CHOOSE TO FIGHT BACK!\\n- PAIN IS NOT PERMANENT!\\n- PAIN IS TEMPORARY!\\n- I can guarantee you, if you work through your pain, on the other side, there is a reward!\\n- I\'M HAVING A CHARACTER BUILDING DAY!\\n\\n### Learn from pain\\n- Our Pains Are Similar, Our Solutions Are Different!\\n- Somebody can take the hand you\'ve been dealt and be successful!\\n- What Can I Do With The Stuff You Gave Me!\\n\\n### Be strong\\n- Be strong! And have the audacity to keep being strong!\\n- When you are strong, nobody can shake you\\n- She was strong enough to push through\\n- If you bend you won\'t break\\n- I was weak, I was vulnerable, I was hurting, I was in pain, I was at my worst, but I was still a giant!\\n- I\'M A GIANT! I\'M A FREAK! WHEN I WANTED TO FOLD I DIDN\'T FOLD!\\n- YOU CAN\'T MESS WITH A HURT GIANT!\\n- YOUR PAIN WON\'T STOP ME! IF YOU WANT ME TO STOP, YOU HAVE TO KILL ME!\\n\\n### Never quit\\n- THE UNSTOPPABLE MARCH\\n- DON\'T STOP TILL YOU REACH THE TOP!\\n- IF YOU ARE WEAK YOU WILL QUIT!\\n- YOU CANT AFFORD TO BE TIRED!\\n- TOUGH TIMES DONT LAST FOREVER!\\n- TOUGH TIMES DON\'T LAST, TOUGH PEOPLE DO!\\n- You cannot be a WAIVER!\\n- Be relentless\\n- IF YOU GET TIRED, LEARN TO REST, NOT QUIT!\\n- When You Cannot, You Must!\\n- IF YOU QUIT THIS TIME, YOU WILL QUIT AGAIN!\\n- Quitters never win! Winners never quit!\\n- They were ready to quit, but they didn\'t. Don\'t be a quitter!\\n- Go where people believe you are unstoppable!\\n\\n## Discipline, Action & Drive\\n\\n### Act now\\n- This Moment. This Moment. Now. Now. Now. Do You Get What I Am Saying!\\n- You need to work out the muscle of doing!\\n- Push forward and take action anyway!\\n- Take consistent action everyday!\\n- If I don\'t do this work, ... who will!\\n- One Good Deed Leads To Another!\\n- You Cant Live At All Unless You Live Fully Now. START!\\n- ACTIONS EXPRESS PRIORITIES!\\n- You have just got to make one more decision!\\n- Ideation without execution is delusion!\\n- Thinking is the first step towards a revolution!\\n\\n### Discipline yourself\\n- Discipline Yourself!\\n- Your life will never change if you do not do the things you do not feel like doing!\\n- What are your MUSTs?!\\n- We don\'t get what we want, we get what we have to have!\\n- What changes people is when their should\'s become musts!\\n- What must you do?!\\n\\n### Drive and passion\\n- What drives you?!\\n- Let Love Drive You!\\n- Empires Fall... Love Survives!\\n- The Real Revolution, The Revolution Of The Mind, The Loveolution\\n- Purpose is your belief in motion!\\n- DON\'T PURSUE PROCESS. PURSUE PURPOSE!\\n- PASSIONS AND PURPOSE ALWAYS PRODUCE PROFIT!\\n- Its about history ... that never repeats itself!\\n- Let your passion take you places!\\n\\n### Be thankful\\n- Trade what upsets you - the expectations that are not being met - with appreciation for what you have!\\n\\n## Risk, Failure & Imperfection\\n\\n### Be ready to fail\\n- ADOPT A FAIL FIRST MENTALITY!\\n- DO YOU HAVE THE GUTS TO FAIL?\\n- IF YOU DON\'T FAIL ... YOU ARE NOT TRYING!\\n\\n### Avoid perfection\\n- If you have everything under control, you are moving too slow!\\n- ENGINEERS ARE TOO OBSESSED WITH PERFECTION TO DO ANYTHING!\\n- THERE ARE STAGES TO A PRODUCT ...\\n- YOU DON\'T INVEST IN PERFECTING YOUR TECH UNTIL YOU ARE CONFIDENT IN YOUR TECH!\\n\\n## Focus & Self-Mastery\\n\\n### Be focused\\n- You can\'t afford to be a wandering generality!\\n- You must be a meaningful specific!\\n- You have to really be committed to something to get everything you can out of it!\\n- You can\'t do everything at once...\\n\\n### Focus on your strengths\\n- Are you doing things right or are you doing the right things?\\n- Turn your strengths into superpowers ...\\n\\n### Be resourceful\\n- How resourceful are you?\\n- What resources do you have?\\n\\n### Be mindful of your thoughts\\n- What thoughts do you allow into your mind?!\\n- Pay attention to your inner dialog\\n\\n### Be mindful of your tongue\\n- Words are powerful!\\n\\n### Listen closely\\n- Listen to your intuition, the voice that tells you this is what you could do!\\n\\n## Confidence & Fearlessness\\n\\n### Confidence through experience\\n- You have been through plenty!\\n- You have seen enough!\\n- EGO is the anesthesia that deadens the pain of stupidity\\n- Pride is the burden of a foolish person\\n\\n### Self-belief\\n- Trust your ideas\\n- You are lead!\\n- Promote yourself\\n\\n### Accepting praise\\n- Humiliating yourself is not humble\\n\\n### Be fearless\\n- Fear finds you in different ways.\\n- The Illusion of Security Robs Ambition!\\n- You don\'t want to be secure, you want to be strong\\n\\n### Stand your ground\\n- WALK ALONE IF YOU HAVE TO!\\n- Don\'t be mad at people who stop clapping\\n- At some point in your life you will find yourself alone\\n- Stand Your Ground\\n\\n## Identity, Purpose & Living Fully\\n\\n### Mindset reminders\\n- It\'s important to sort through the things I want... as they partially capture WHY I DO what I do!\\n- We don\'t complain on the things we can\'t change!\\n- When will you stop eating dirt\\n- Stop complaining about where you are!\\n\\n### Be unique\\n- THEIR CAN ONLY BE 1, AND YOU ARE IT!!\\n- DONT LET THE WORLD TELL YOU WHO YOU ARE\\n- You are different because of God! Because you need to do something for his name!\\n- The fact that you are different is not an accident!\\n- Everything that you are is for a reason!\\n- You are the sum of all of your experiences, thoughts and skills\\n- OWN YOUR STORY\\n- DONT LET THE WORLD TELL YOU WHAT TO REGRET\\n- If you don\'t like where you are from, you can never love where you are going\\n- YOU DESERVE TO BE AROUND PEOPLE THAT PUSH YOU!\\n\\n### Life is temporary\\n- What dreams will die with you?\\n- What talents will die with you?\\n- How you living?\\n- We either live our dreams or live our fears, which one are you living?\\n- ALL HUMANS DIE BUT FEW HAVE LIVED!\\n- LIFE IS EITHER A DARING ADVENTURE ... OR NOTHING!\\n\\n### Unleash yourself\\n- I CAN, I WILL, I MUST!\\n- Free Yourself From The Shackles Of Your Mind!\\n- A lot of people like to complain but they wont do anything about their situation.\\n- YOU could have been free years ago!\\n- The Real Battle Ground Is In Your Mind!\\n- A New Outfit Doesn\'t Make New You A New Person!\\n- A New Life Comes From A New Mind And A New Way Of Looking At Your Life\\n- Its What You Say About You THAT Threatens Your Destiny!\\n- YOU HAVE TO FIX THE MIND BEFORE YOU CAN ACCEPT A BLESSING!\\n- If you don\'t change your attitude, you wont reach your altitude!\\n- Exercise your mind!\\n- Rethink your mountaintop!\\n- I am going to do everything in my power to become a victor not a victim!\\n\\n### You matter\\n- You must realize who you are!\\n- Decide you love your self enough!\\n- Repeat after me: I am good enough!\\n- We\'re So Busy Studying Other People We Fail To Study Ourselves\\n- Do not Allow The Opinion Of Others To Control Your Future\\n- You can\'t relive my experience!\\n- You can\'t imitate my passion!\\n- You can\'t replicate my will!\\n- You can\'t live my vision!\\n- You get in life what you deserve not what you want!\\n- Treat Your Voice Like A Kite And The Wind Is The Song. - Pharrell Williams\\n- Use your genius on your own behalf\\n- Act on your own behalf!\\n- Act on your dreams!\\n- Turn your life into a work of art because anything less is a tragedy!\\n- I haven\'t had my most creative moment yet!\\n- DEEP DOWN IN YOUR HEART YOU KNOW YOU ARE NOT LIVING TO YOUR TRUE POTENTIAL!\\n- What will you do before your body perishes?\\n\\n### Wisdom and notes\\n- Judge a tree by the fruit that it bears!\\n- When you\'re poor, you have to dig inside for value!\\n- The toughest battles come to the toughest warriors!\\n- I am more than my mind! I have a heart and soul!\\n- As I mature my thinking ... different quotes take on different meanings ...\\n\\n## A note on these\\n\\nThese aren\'t original to me. They\'re collected over years from sermons, speeches, books, and the occasional 2 a.m. realization, then filed under the themes above. The point of keeping them isn\'t to memorize a creed. It\'s to have the right sentence within reach when the moment calls for it."},{"id":"a-taxonomy-of-learning-resources","metadata":{"permalink":"/thoughts/a-taxonomy-of-learning-resources","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2018-01-01-a-taxonomy-of-learning-resources.mdx","source":"@site/blog/2018-01-01-a-taxonomy-of-learning-resources.mdx","title":"A Taxonomy of Learning Resources","description":"The full menu of places you can learn from, and the questions worth asking before you commit time to any of them.","date":"2018-01-01T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"}],"readingTime":4.54,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"a-taxonomy-of-learning-resources","title":"A Taxonomy of Learning Resources","kind":"reference","sidebar_label":"Learning Resources","description":"The full menu of places you can learn from, and the questions worth asking before you commit time to any of them.","authors":["oeid"],"tags":["productivity"],"date":"2018-01-01T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"Affirmations for the Inner Game","permalink":"/thoughts/affirmations-for-the-inner-game"},"nextItem":{"title":"Starting With Why: Notes From Trying to Find My Own","permalink":"/thoughts/finding-your-why"}},"content":"import CategoryCarousel from \'@site/src/components/CategoryCarousel\';\\n\\nWhen people talk about \\"learning,\\" they usually mean one or two channels: a book,\\nmaybe a course. But the actual menu is much wider, and most of the leverage comes\\nfrom knowing the whole menu so you can pick the right channel for the thing you\'re\\ntrying to learn. This is the taxonomy I keep, with the questions I ask before\\ncommitting time to any of it.\\n\\n\x3c!-- truncate --\x3e\\n\\nThe cards under each category are a living list of the specific resources I\'ve\\ncollected. They grow over time. If a category has no cards yet, I simply haven\'t\\nfilled it in.\\n\\n## Getting started\\n\\nIf you just want a place to begin, you don\'t need the whole menu. Start here:\\n\\n[Step 1] Pick **one book** on the thing you\'re learning, and write down why you\'re\\nreading it and what you expect to get out of it.\\n\\n[Step 2] Find **one person** who\'s further along (a mentor, or someone whose work\\nyou admire) and study how they learned it.\\n\\n[Step 3] Keep a **running list of videos and blogs** for the in-between time, so idle\\nmoments turn into progress instead of hunting.\\n\\n[Step 4] Once you\'re moving, **reach for the rest of the menu** below as the work\\ndemands it: papers when you hit the edge, repositories to read real code,\\ncompetitions when you need pressure and a goal.\\n\\nThe rest of this post is that full menu.\\n\\n## Why a taxonomy at all\\n\\nA resource type is worthless until you can answer two questions about it: *why am I\\nreaching for this one*, and *what do I expect to get out of it*. A taxonomy makes\\nthose questions concrete. Instead of \\"I should learn more,\\" you get \\"this is a\\n*mentors* problem, not a *books* problem,\\" which is a far more actionable place to\\nstart.\\n\\n## The channels\\n\\n### Books\\n\\nThe default, and still one of the best. The useful discipline is to be deliberate:\\nwhy am I reading *this* book, what do I expect to learn from it, and how will I find\\nthe next one? Reading lists from people you respect are a strong source. Libraries,\\nebook memberships, and bundle sites keep the cost down, and audiobooks open up time\\nyou\'d otherwise lose.\\n\\n<CategoryCarousel topic=\\"learning-resources\\" category=\\"books\\" />\\n\\n### Courses\\n\\nStructured, paced, and good when you need a guided path rather than a reference.\\nThe questions: which courses am I actually taking versus collecting, which do I\\n*need* versus merely want, and when will I take them? The trap with courses is\\naccumulation. A subscription you never open is not learning.\\n\\n<CategoryCarousel topic=\\"learning-resources\\" category=\\"courses\\" />\\n\\n### Videos\\n\\nBest for the times when reading isn\'t an option (on a treadmill, commuting, winding\\ndown). The practice that makes videos work is curation: keep a running, organized\\nlist of what to watch and where you get it from, so the moment you have idle time\\nyou\'re not hunting for something.\\n\\n<CategoryCarousel topic=\\"learning-resources\\" category=\\"videos\\" />\\n\\n### Blogs\\n\\nWhere you find the current, opinionated, in-the-weeds thinking that hasn\'t made it\\ninto books yet. Worth maintaining a small set you follow, and treating an\\ninteresting author as a node in a network: who do *they* read and link to?\\n\\n<CategoryCarousel topic=\\"learning-resources\\" category=\\"blogs\\" />\\n\\n### Mentors\\n\\nThe highest-bandwidth channel, and the one people underuse. The questions are about\\n*what* a mentor is for: refining your learning plan, pointing you at what matters\\nmore than what\'s merely interesting, and naming the gaps you can\'t see in yourself.\\nChoosing one is its own filter: who do I respect, who has the bandwidth, and would\\nthey be willing to review the actual work I produce?\\n\\n<CategoryCarousel topic=\\"learning-resources\\" category=\\"mentors\\" />\\n\\n### Pioneers, masters, and experts\\n\\nEven without direct access, you can learn from the field\'s big names by studying\\nwhat they wrote, recorded, and built. Pick a few people whose work you admire and\\ngo deep on their output.\\n\\n<CategoryCarousel topic=\\"learning-resources\\" category=\\"experts\\" />\\n\\n### Research papers\\n\\nWhere the field\'s edge actually lives. The hard part is access and navigation:\\nwhere do practitioners look for papers, who can point you at the good ones, and how\\ndo you use a paper\'s references to find the rest of the conversation.\\n\\n### Everything else\\n\\nBeyond those, the menu keeps going, and each entry is the right tool for a specific\\njob:\\n\\n- **Conferences** for talks, presentations, and the pulse of an industry.\\n- **Forums** (Stack Overflow, Reddit, specialized communities) for problem-shaped,\\n  just-in-time answers.\\n- **Repositories** for learning by reading real open-source code.\\n- **Cheatsheets** for fast reference once you already understand the thing.\\n- **Curriculums** for a structured path, including published university curricula.\\n- **Competitions** (Kaggle, hackathons, coding challenges) for learning under\\n  pressure with a clear goal.\\n- **Standards and specifications** for the authoritative definition of how\\n  something is supposed to work.\\n- **Reports** for a synthesized industry-level view.\\n- **Presentations** for a compressed, opinionated take on a topic.\\n- **Platforms** that bundle many of the above into one place.\\n- **Datasets** for the kind of learning that only happens by doing.\\n\\n<CategoryCarousel topic=\\"learning-resources\\" category=\\"forums\\" />\\n\\n## Maintaining the list\\n\\nThe taxonomy is only useful if it\'s alive. The maintenance questions are simple but\\nworth asking on a rhythm: what can I actually learn from right now, and which\\nresources am I leaning on most? The ones you reach for repeatedly are signal. Prune\\nthe rest, and keep refilling the channels you\'ve found pay off."},{"id":"finding-your-why","metadata":{"permalink":"/thoughts/finding-your-why","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-09-27-finding-your-why.md","source":"@site/blog/2017-09-27-finding-your-why.md","title":"Starting With Why: Notes From Trying to Find My Own","description":"Reflections sparked by Simon Sinek\'s Start With Why: why purpose comes before product, the pull of manipulation, and what it means to be a \'why\' person.","date":"2017-09-27T00:00:00.000Z","tags":[{"inline":true,"label":"mindset","permalink":"/thoughts/tags/mindset"},{"inline":true,"label":"go-to-market","permalink":"/thoughts/tags/go-to-market"}],"readingTime":3.1,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"finding-your-why","title":"Starting With Why: Notes From Trying to Find My Own","kind":"reflection","sidebar_label":"Finding Your Why","description":"Reflections sparked by Simon Sinek\'s Start With Why: why purpose comes before product, the pull of manipulation, and what it means to be a \'why\' person.","authors":["oeid"],"tags":["mindset","go-to-market"],"date":"2017-09-27T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"A Taxonomy of Learning Resources","permalink":"/thoughts/a-taxonomy-of-learning-resources"},"nextItem":{"title":"What The Power of Habit Taught Me About Changing Behavior","permalink":"/thoughts/the-habit-loop"}},"content":"I read Simon Sinek\'s *Start With Why* at a point when I was trying to figure out my\\nown. What follows isn\'t a summary of the book. It\'s the thinking it set off in me:\\nthe questions I kept circling, and the few ideas that reorganized how I look at\\ncompanies, products, and myself. If the questions land, read the book.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Why before what\\n\\nThe core inversion is simple and hard to live by: most people and companies know\\n*what* they do and *how* they do it, but very few can say *why*. And the why is what\\nactually moves people. A product is just proof of the why. People don\'t buy what you\\nmake so much as the reason you make it.\\n\\nOnce that clicks, you start reading companies differently. You can almost predict a\\ncompany\'s future actions from its purpose, and you can ask a sharper diagnostic\\nquestion about any of them: have its actions actually been in tune with its stated\\nwhy, or has it drifted? I caught myself wanting to go down the list of the Fortune\\n500 and write the real why next to each one.\\n\\n## The pull of manipulation\\n\\nThe other half of the book that stuck with me is the catalogue of **manipulations**,\\nthe levers companies pull when they don\'t have a why: promotions, fear, novelty,\\npeer pressure. They work, but only for the transaction in front of you. They buy a\\nsale, not loyalty.\\n\\nIt made me want to turn the lens on my own wanting. Why do I actually want a given\\nthing? Because it\'s genuinely valuable to me, or to stop other people from judging\\nme? How much of desire is just peer pressure wearing a nicer outfit? You can\'t build\\nsomething honest until you can tell the difference in yourself.\\n\\n## What it means to be a \\"why\\" person\\n\\nSinek splits the world into **why types** and **how types**, and the interesting\\nclaim is that they need each other: the why type supplies the cause and the\\ndirection, the how type builds the thing that makes it real. Neither is complete\\nalone.\\n\\nI spent a lot of these notes asking, bluntly, which one I am, and how you\'d even\\n*become* a why type if you weren\'t one. The honest answer I arrived at is that it\\nstarts with a discipline, not an epiphany: reminding yourself each morning why you\\ngot up and why you\'re doing the work, and documenting the moments you catch yourself\\nthinking \\"wouldn\'t it be great if...\\", because those are the breadcrumbs that lead\\nback to your purpose.\\n\\n## Purpose as the thing underneath the work\\n\\nThe thread under all of it, for me, is that purpose isn\'t a marketing layer you add\\nat the end. It\'s the thing the rest is built on. A leader\'s real job, the CEO\'s job,\\nis to keep the why alive in what the company does, what it focuses on, and how it\\ntreats the world. When the why gets lost, the decline tends to follow.\\n\\nThe same is true one level down, for a person. I came out of this less interested in\\n\\"what should I build\\" and more interested in \\"what do I actually believe, and what\\nwould I build *because* of it.\\" That\'s a slower question. It\'s also the only one that\\nseems to compound.\\n\\n## What I took from it\\n\\n*Start With Why* gave me a vocabulary for something I\'d felt but couldn\'t name: that\\nthe most durable companies, and the most grounded people, run on a reason that comes\\nbefore the product. Find the why. Be honest about manipulation, including your own.\\nAnd treat purpose as infrastructure, not decoration.\\n\\n*Reflections on *Start With Why* by Simon Sinek.*"},{"id":"the-habit-loop","metadata":{"permalink":"/thoughts/the-habit-loop","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-09-27-the-habit-loop.md","source":"@site/blog/2017-09-27-the-habit-loop.md","title":"What The Power of Habit Taught Me About Changing Behavior","description":"Reflections on Charles Duhigg\'s The Power of Habit: the loop behind every habit, why willpower behaves like a muscle, and the one rule that actually changes behavior.","date":"2017-09-27T00:00:00.000Z","tags":[{"inline":true,"label":"mindset","permalink":"/thoughts/tags/mindset"},{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"}],"readingTime":4.18,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"the-habit-loop","title":"What The Power of Habit Taught Me About Changing Behavior","kind":"reflection","sidebar_label":"The Habit Loop","description":"Reflections on Charles Duhigg\'s The Power of Habit: the loop behind every habit, why willpower behaves like a muscle, and the one rule that actually changes behavior.","authors":["oeid"],"tags":["mindset","productivity"],"date":"2017-09-27T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"Starting With Why: Notes From Trying to Find My Own","permalink":"/thoughts/finding-your-why"},"nextItem":{"title":"Questions for Starting a Business","permalink":"/thoughts/questions-for-starting-a-business"}},"content":"A while back I read *The Power of Habit* by Charles Duhigg, and it changed how I\\nthink about why I do the things I do without deciding to. These are my reflections\\non the ideas that stuck, not a summary of the book. If they resonate, read the book\\nitself: the case studies are worth it.\\n\\n\x3c!-- truncate --\x3e\\n\\n```mermaid\\nflowchart LR\\n    Cue[\\"Cue<br/>(the trigger)\\"] --\x3e Routine[\\"Routine<br/>(the behavior)\\"]\\n    Routine --\x3e Reward[\\"Reward<br/>(the payoff)\\"]\\n    Reward -. \\"craving<br/>(anticipation)\\" .-> Cue\\n```\\n\\n## The loop underneath everything\\n\\nThe idea that reframed it all for me is that a habit isn\'t a single thing, it\'s a\\nloop with three parts: a **cue** that triggers it, a **routine** you run, and a\\n**reward** that makes it worth repeating. Once that loop is established, your brain\\nstops actively participating. It runs the routine on autopilot so it can save effort\\nfor something else.\\n\\nThat reframing matters because \\"I have a bad habit\\" stops being a character flaw and\\nbecomes a *mechanism*. And mechanisms can be taken apart. If I can name the cue and\\nthe reward around a routine I don\'t like, I\'m no longer fighting a vague failing of\\nwillpower. I\'m debugging a loop.\\n\\n## Craving is the engine\\n\\nWhat I\'d missed before reading this is that a cue and a reward aren\'t enough on their\\nown. The thing that actually powers the loop is the **craving** in between, the\\nanticipation of the reward once the cue shows up. The habit gets strong when your\\nbrain starts *expecting* the reward the moment it sees the cue.\\n\\nThat\'s a useful lever. To build a habit I want, I shouldn\'t just set up a reward, I\\nshould give the anticipation something to latch onto. And to break one I don\'t want,\\nit helps to see that the pull I feel at the cue is the craving, not me.\\n\\n## The one rule that actually changes a habit\\n\\nThe most practical idea in the book is also the simplest. You can\'t really erase an\\nold habit. What works is to **keep the same cue and the same reward, and change only\\nthe routine in the middle.** The loop stays intact; you swap out the behavior it\\nruns.\\n\\nThis is why \\"just stop\\" almost never works and why substitution does. The cue is\\nstill going to fire and the craving is still going to demand its reward. The question\\nisn\'t how to make those go away, it\'s what better routine you can route them into.\\n\\n## Willpower is a muscle, not a trait\\n\\nTwo things about willpower reshaped how I plan my days. First, it behaves like a\\n**muscle**: it\'s strengthenable with practice, but it also **fatigues**. Spend it\\nall on self-control at work and there\'s little left for the evening. Second, of all\\nthe habits you could build, the research kept pointing at willpower itself as the\\nsingle most important one for individual success, more predictive than raw talent.\\n\\nThe practical move that follows is to make the important behaviors **automatic** so\\nthey don\'t draw down the willpower budget, and to decide *ahead of time* how you\'ll\\nrespond when a known hard moment arrives, rather than spending willpower improvising\\nin the moment.\\n\\n## Keystone habits and small wins\\n\\nNot all habits are equal. Some are **keystone habits**: change one and it quietly\\ndislodges and remakes a whole set of others. Exercise was the recurring example,\\nsomething that has nothing directly to do with, say, eating better or working more\\nfocused, yet tends to drag those along with it.\\n\\nWhat makes keystone habits work is **small wins**. A small, early success is\\nevidence that bigger change is possible, and that belief is what convinces you to\\nkeep going. So the strategy isn\'t to overhaul everything at once. It\'s to find the\\none habit whose change ripples outward, and to stack small wins until the belief\\ntakes hold.\\n\\n## Belief, and why it needs other people\\n\\nThe part I underestimated is the social one. The book makes the case that for a\\nchanged habit to *stick* permanently, you have to believe change is possible, and\\nthat belief is far easier to hold inside a **community**, even one as small as two\\npeople. Habits change more durably when they\'re held up by other people who believe\\nthe same thing.\\n\\nThat reframes a lot of behavior change as a social problem, not just a personal one.\\nThe group isn\'t a nice-to-have. It\'s often the thing that makes the new loop\\npermanent instead of temporary.\\n\\n## What I took from it\\n\\nThe throughline, for me: behavior I thought was just *who I am* is usually a loop I\\ncan examine. Find the cue and the reward, change only the routine, protect willpower\\nby automating what matters, pick the keystone habit that pulls the rest along, and\\nlean on a community to make the change believable. None of it is willpower-as-grit.\\nIt\'s understanding the machine and working with it.\\n\\n*Reflections on *The Power of Habit* by Charles Duhigg.*"},{"id":"questions-for-starting-a-business","metadata":{"permalink":"/thoughts/questions-for-starting-a-business","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-04-16-questions-for-starting-a-business.mdx","source":"@site/blog/2017-04-16-questions-for-starting-a-business.mdx","title":"Questions for Starting a Business","description":"The questions to work through when starting a business, from business model and audience to legal structure, plus the mindset to keep going.","date":"2017-04-16T00:00:00.000Z","tags":[{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"},{"inline":true,"label":"entrepreneurship","permalink":"/thoughts/tags/entrepreneurship"}],"readingTime":10.98,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-starting-a-business","title":"Questions for Starting a Business","kind":"question-set","sidebar_label":"Starting a Business","description":"The questions to work through when starting a business, from business model and audience to legal structure, plus the mindset to keep going.","authors":["oeid"],"tags":["question-set","entrepreneurship"],"date":"2017-04-16T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What The Power of Habit Taught Me About Changing Behavior","permalink":"/thoughts/the-habit-loop"},"nextItem":{"title":"Questions for Starting a Blog","permalink":"/thoughts/questions-for-starting-a-blog"}},"content":"Starting a business is partly a checklist of questions and partly a mindset. The questions force you to get specific about what you are offering, who it is for, and how it reaches them. The mindset is what keeps you moving when the questions get hard. Here is both.\\n\\n\x3c!-- truncate --\x3e\\n\\n## The dimensions to think through\\n\\n<SectionBanner why=\\"A business has many moving parts, and the ones you ignore early are the ones that bite you later. Naming every dimension up front (model, mission, branding, fulfillment, marketing, audience, legal, tax, experience) keeps you from building something with a hole in it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'spark\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"At its core, a business has to answer how it sells and makes money and what it offers customers. Get this wrong and the rest does not matter. This is the dimension everything else hangs from.\\"\\n  howOften=\\"Quarterly, and whenever the offering or pricing changes\\"\\n  when=\\"At the very start, and at every major pivot\\"\\n  record=\\"Write a one-paragraph description of your business model and what you offer\\">\\n  Business model and offerings: how are you going to sell and make money? At its core, what are you offering your customers?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The story, mission, and purpose are why anyone (including you) should care. They power the pitch and carry you through the hard parts when the spreadsheet is not enough.\\"\\n  howOften=\\"Quarterly, and whenever you tell the story publicly\\"\\n  when=\\"When crafting your pitch, your landing page, or your reason to keep going\\"\\n  record=\\"Write the why in a sentence or two you could say out loud\\">\\n  Story, mission, pitch, purpose, passion: why are you doing this?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"You do not have to invent everything. Reference catalogs of who you can learn from shorten the path and keep you from repeating known mistakes.\\"\\n  howOften=\\"Monthly, as you discover people worth learning from\\"\\n  when=\\"When you hit a problem someone has clearly solved before\\"\\n  record=\\"Keep a running list of references and what each one teaches you\\">\\n  Reference catalogs: who can you learn from?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Quotes, branding, logos, and landing pages are the impressions you make before anyone tries your product. They set expectations, so they are worth designing deliberately.\\"\\n  howOften=\\"Monthly, as the brand takes shape\\"\\n  when=\\"When building anything customer-facing\\"\\n  record=\\"Collect the impressions you want to make and audit whether your assets create them\\">\\n  Quotes, branding, logos, landing pages: what impressions will you make on others?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Fulfillment is the unglamorous pipeline that turns a sale into a delivered product. If order processing breaks, customers leave no matter how good the offering is.\\"\\n  howOften=\\"Monthly, and as order volume grows\\"\\n  when=\\"Before your first real order, and when fulfillment starts to strain\\"\\n  record=\\"Map your order-processing pipeline end to end\\">\\n  Fulfillment: what is your order processing pipeline?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Marketing, content, blog posts, SEO, and search trends are how customers actually find you. Knowing what they search for tells you what to publish and how to be discoverable.\\"\\n  howOften=\\"Weekly, as part of an ongoing content habit\\"\\n  when=\\"When deciding what content to create and which terms to target\\"\\n  record=\\"Track the search terms your customers use and the content that ranks for them\\">\\n  Marketing, content, blog posts, SEO, search trends: how will you get customers to your site? What do they search for?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Knowing your ideal customers (how they think, where they spend their time) is the foundation under marketing, product, and pricing. Build for everyone and you build for no one.\\"\\n  howOften=\\"Quarterly, and whenever you learn something new about your buyers\\"\\n  when=\\"When deciding who to serve and where to reach them\\"\\n  record=\\"Write a profile of your ideal customer, including how they think and where they spend time\\">\\n  Audience: who are your ideal customers? How do they think? Where do they spend their time?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Legal structure is how you keep yourself safe. Choosing the right setup (even something as simple as a DBA) protects you before there is anything to protect.\\"\\n  howOften=\\"Once at setup, and again as the business grows or changes form\\"\\n  when=\\"Before you take money or sign anything serious\\"\\n  record=\\"Note the legal structure you chose and why it fits your risk\\">\\n  Legal structure: how will you keep yourself safe? A DBA?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"yearly\\"\\n  depth=\\"quick\\"\\n  why=\\"Tax structure decides how much you keep and how much paperwork you carry. Handling it deliberately avoids a painful surprise later.\\"\\n  howOften=\\"Yearly, around tax planning, and at setup\\"\\n  when=\\"When setting up the business and before each tax year\\"\\n  record=\\"Document how you will handle taxes and who advises you on it\\">\\n  Tax structure: how will you handle taxes?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Customer experience is the sum of every impression you leave. Deciding the experience you want people to have gives every other dimension a target to aim at.\\"\\n  howOften=\\"Monthly, as you observe real customer interactions\\"\\n  when=\\"When designing any touchpoint a customer will feel\\"\\n  record=\\"Describe the experience you want, then audit whether reality matches it\\">\\n  Customer experience: what experience do you want people to have?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Why start a business?\\n\\n<SectionBanner why=\\"I want to start a business mostly to know what it takes. These questions surface the scope of what you are signing up for (the kinds of businesses that exist, and everything you will have to worry about) before you are in too deep to back out.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Starting a business to know what it takes is a legitimate reason on its own. But naming the kinds of businesses and the full list of things you will have to worry about turns a vague ambition into a map of the work ahead.\\"\\n  howOften=\\"Yearly, and whenever the motivation needs a refresh\\"\\n  when=\\"At the very start, and when you wonder why you are doing this\\"\\n  record=\\"Write your honest reason, then list the kinds of businesses and the worries each one carries\\">\\n  Why start a business? What are the different kinds of businesses? What are all the different things I will have to worry about?\\n</Question>\\n\\n</QuestionSection>\\n\\n## What kind of business?\\n\\n<SectionBanner why=\\"The shape of the business should fit what you like doing and where you can add value. These questions narrow a huge space (small business or not, what it solves, what you enjoy) down to something you would actually want to run, like the painting-coffee-cups idea I keep coming back to.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The best business to start sits at the intersection of what a small business can solve, what you like doing, and where you can add value. Working through these together keeps you from chasing an idea you will resent.\\"\\n  howOften=\\"Quarterly, as your interests and ideas evolve\\"\\n  when=\\"When choosing what kind of business to pursue\\"\\n  record=\\"List your current ideas (for example, painting coffee cups) and score each on enjoyment and value added\\">\\n  Should I start a small business? What does the small business solve? What are the things I like doing? How can I add value? What are some of the ideas I currently have?\\n</Question>\\n\\n</QuestionSection>\\n\\nA few framing thoughts on how businesses actually work:\\n\\n- Businesses consider requests for proof of the value you add.\\n- Great magic makes you careful about what you believe in.\\n- Business and sales are like a magic trick. It is all about perception.\\n- Should product management and engineers have a tense relationship? Why?\\n\\nSome concrete next steps if you go this route:\\n\\n- Figure out your personal products.\\n- Figure out what people are most likely to spend their resources on.\\n- Figure out how to be more resourceful.\\n- Read on: convincing, making a product, starting a business, pleasing others, and behavior.\\n\\nOne pattern worth noticing: people make money off making something easy to use. Tools like Sheetsu and Microsoft Flow are simple examples of turning friction into a product.\\n\\n## What I want to contribute\\n\\n<SectionBanner why=\\"Before the mechanics, it helps to name what I actually want to give. For me it is pushing people to rise, learning what it means to create a business, and growing myself in the process. The lists below are my own answers, kept as a record of why I am doing this and what I will need.\\" />\\n\\n**What do I want to do?**\\n\\n- Push people to rise, and gauge where they are motivationally and passionately.\\n- Find out what it means to create a business: how a product is built, what relationships need to be made, and the processes involved.\\n- Give back to people and push them to be great.\\n\\n**Why do I want to do it?**\\n\\n- To help others and to grow myself.\\n- To understand the stages of motivation and the stages of success.\\n- To put together a process for building a product and for starting a business.\\n- To face my fears and develop myself.\\n- To build a site.\\n- To put myself in a position where I must.\\n\\n**What do I need?**\\n\\n- Motivation\\n- Story\\n- Research\\n- Product\\n- Marketing\\n\\n## The mindset to keep going\\n\\n<SectionBanner why=\\"The questions above are the easy part; following through is harder. This is the material I come back to when I need to keep going, kept as prose because it is meant to be read and felt, not answered.\\" />\\n\\nThe questions above are the easy part. Following through is harder. Here is the material I come back to when I need to keep going.\\n\\n### It\'s possible\\n\\n> Your dream is possible. Others have done it, so why can\'t you?\\n\\nYou can live your dream. Choose your future, and live it.\\n\\n### It\'s necessary\\n\\nImprovement is not optional. Work on yourself, develop yourself, and keep asking: how can I improve this? How can I improve the lives of those around me?\\n\\nRemove the energy drainers. People who stopped working on themselves, who stopped dreaming, will pull you down. Get the losers out of your life. Then align yourself with people who attract you upward: people who are unstoppable, unreasonable, unwilling to live life just as it is, and who want more.\\n\\nKnow this:\\n\\n- People like to complain, but they won\'t do anything about their situation.\\n- You are an uncommon breed. Not everybody will see it, join you, or share the vision, and that is fine.\\n- I can do this. Even though people don\'t see it for me, I can see it for myself.\\n\\nUnderstand the importance of adjusting your strategy. Become creative. Be flexible. Be a good model of truth, integrity, and commitment. Surround yourself with winners.\\n\\n> If not you, then who? If not now, then when?\\n\\nYou are the author of your own story. Setbacks are part of the path. Review your dream every day, and remember: it\'s not over until I win.\\n\\n### It\'s me\\n\\nNo one can do it but you.\\n\\n- Have goals, make a plan, and think constantly about how you can improve.\\n- Take personal responsibility. Make it your personal business to succeed, and to come through when everyone is doubting you.\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"This is the question the whole mindset section builds toward. The talents you let go to the grave unused are the real cost of not following through. Asking it forces an honest reckoning with what you are doing with what you have.\\"\\n  howOften=\\"Yearly, as a confronting check on whether you are using what you were given\\"\\n  when=\\"When you are tempted to play it safe, or to put the dream off again\\"\\n  record=\\"Name the talents you risk wasting, which you have used, and which you have lost\\">\\n  What talents and abilities will go to the grave with you? Which ones did you use? Which ones did you lose? What is your music?\\n</Question>\\n\\n</QuestionSection>\\n\\n### Face your fears\\n\\nRun toward your dream. Work toward it. Act on your ideas. Life is about stretching, challenging yourself, and working on ways to improve.\\n\\nIn the process you will incur disappointment, failure, pain, setbacks, and defeats. But you will also discover that you have greatness within you, that you are more powerful than you can begin to imagine, that you are greater than your circumstances, and that you don\'t have to go through life as the victim.\\n\\nMost people don\'t work on their dreams. The reason is usually fear: fear of failure, fear of success. Face your fears. Put yourself in a position where you must.\\n\\nAnd when you don\'t feel worthy, take risks on yourself anyway. Most people are not risk takers. They earn a living, raise a family, and die. Believe in yourself.\\n\\n> Someone\'s opinion of you does not have to become your reality."},{"id":"questions-for-starting-a-blog","metadata":{"permalink":"/thoughts/questions-for-starting-a-blog","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-25-questions-for-starting-a-blog.mdx","source":"@site/blog/2017-02-25-questions-for-starting-a-blog.mdx","title":"Questions for Starting a Blog","description":"Five steps of questions to work through before starting a blog: why, name, content, technology, and how you\'ll market it.","date":"2017-02-25T00:00:00.000Z","tags":[{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"},{"inline":true,"label":"writing","permalink":"/thoughts/tags/writing"}],"readingTime":4.56,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-starting-a-blog","title":"Questions for Starting a Blog","kind":"question-set","sidebar_label":"Starting a Blog","description":"Five steps of questions to work through before starting a blog: why, name, content, technology, and how you\'ll market it.","authors":["oeid"],"tags":["question-set","writing"],"date":"2017-02-25T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"Questions for Starting a Business","permalink":"/thoughts/questions-for-starting-a-business"},"nextItem":{"title":"The Questions I Want to Answer","permalink":"/thoughts/the-questions-i-want-to-answer"}},"content":"Before you spin up a blog, it helps to settle a handful of questions first. Here is a five-step set to work through, from why you\'re doing it to how you\'ll get it in front of people. Answer these and the rest gets a lot easier.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Step 1: Why?\\n\\n<SectionBanner why=\\"Every later decision (the name, the cadence, the tech, the marketing) inherits its answer from this one. A blog without a clear why drifts and dies, so it is worth getting honest about purpose before writing a single post.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"core\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The reason you start the blog sets its direction, its tone, and how long you will stick with it. If you cannot say what you will gain or what vision you are chasing, motivation evaporates the first time it gets hard.\\"\\n  howOften=\\"Before you start, and revisit quarterly to check the blog still serves the why\\"\\n  when=\\"At the very beginning, and whenever you feel like quitting\\"\\n  record=\\"Write a short statement of purpose and vision; revisit it when momentum dips\\">\\n  Why do I want to start a blog? What purpose will it serve? What will I gain out of it? What is my vision for it? How long do I plan on maintaining it?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Step 2: The name\\n\\n<SectionBanner why=\\"The name is the first impression and the hardest thing to change later. A good one captures the vision from Step 1 in a few words, so it is worth pausing on rather than grabbing the first available domain.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"A name that captures your vision does a lot of marketing work for free. Picking it deliberately, anchored to the purpose you just defined, beats settling for whatever was available.\\"\\n  howOften=\\"Once, up front, with a deliberate brainstorm\\"\\n  when=\\"After you have a clear vision and are ready to commit to an identity\\"\\n  record=\\"List candidate names and check each against your vision; pick the one that fits best\\">\\n  Now that you have a vision, what name captures it?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Step 3: What content, and how often?\\n\\n<SectionBanner why=\\"Consistency is what separates a living blog from an abandoned one. Deciding the cadence up front (and what triggers a new post) turns writing from a someday intention into a commitment you can actually keep.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"A blog only compounds if you keep feeding it. Committing to a trigger (a filled notebook, an idea worth sharing, or a set time frame elapsing) removes the daily debate about whether to write and replaces it with a rule.\\"\\n  howOften=\\"Decide once, then enforce it on your chosen cadence\\"\\n  when=\\"When setting up your writing routine, and whenever the cadence slips\\"\\n  record=\\"Write down your posting trigger and cadence, and track whether you are hitting it\\">\\n  Will you be consistently writing posts for the blog? If so, how often? Commit yourself to creating a new post every so often: every time your notebook fills up, every time you have an idea worth sharing, or every time some chosen time frame goes by without a post.\\n</Question>\\n\\n</QuestionSection>\\n\\n## Step 4: What technology?\\n\\n<SectionBanner why=\\"The tech stack decides how much you will fight your tools instead of writing. These choices (hosted versus self-run, your own UI and backend, what you embed) trade convenience against control, and the right answer depends entirely on your why.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Hosting and platform choices set your ceiling and your maintenance burden. A public host is fast to start; your own server, cloud setup, UI, or backend buys control at the cost of effort. Knowing what you want to embed shapes which path is even viable.\\"\\n  howOften=\\"Once, during setup, and again only if you outgrow your choice\\"\\n  when=\\"When standing up the blog, and when you hit a limitation of your current platform\\"\\n  record=\\"List your requirements (including anything you want to embed) and match a platform to them\\">\\n  Will you be using a public blog hosting site? Will you run your own server? Will you run your blog on the cloud? Will you create your own UI for the blog? Will you create your own backend for the blog? What do you plan on embedding into your blog?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Step 5: How will you market it?\\n\\n<SectionBanner why=\\"Writing into the void is discouraging; even a little distribution changes everything. Deciding how people will find your blog (your resume, your friends, catchy titles, answering questions people are already asking) turns a private journal into something that reaches readers.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Great posts that nobody sees do not build anything. Planning your channels up front (putting it on your resume, telling friends, writing catchy titles, finding questions people ask and referencing your posts in answers) gives the writing a chance to land.\\"\\n  howOften=\\"Monthly, as you build distribution habits\\"\\n  when=\\"After you have a few posts worth sharing, and when growth stalls\\"\\n  record=\\"Pick the channels you will actually use and track which ones bring readers\\">\\n  How will you make others aware of your blog? Will you put it on your resume? Will you tell your friends about it? Will you use catchy titles? Will you find questions people are asking and reference it in answers?\\n</Question>\\n\\n</QuestionSection>"},{"id":"the-questions-i-want-to-answer","metadata":{"permalink":"/thoughts/the-questions-i-want-to-answer","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-24-the-questions-i-want-to-answer.mdx","source":"@site/blog/2017-02-24-the-questions-i-want-to-answer.mdx","title":"The Questions I Want to Answer","description":"A running catalog of the big questions I find worth answering, about value, opportunity, society, and the act of questioning itself.","date":"2017-02-24T00:00:00.000Z","tags":[{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"},{"inline":true,"label":"philosophy","permalink":"/thoughts/tags/philosophy"}],"readingTime":13.35,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"the-questions-i-want-to-answer","title":"The Questions I Want to Answer","kind":"question-set","sidebar_label":"Questions to Answer","description":"A running catalog of the big questions I find worth answering, about value, opportunity, society, and the act of questioning itself.","authors":["oeid"],"tags":["question-set","philosophy"],"date":"2017-02-24T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"Questions for Starting a Blog","permalink":"/thoughts/questions-for-starting-a-blog"},"nextItem":{"title":"What I Ask Myself: To Capture What I Could Do","permalink":"/thoughts/questions-for-capturing-what-you-could-do"}},"content":"This is an early, evolving catalog of the questions I find worth answering. It is more raw and aphoristic than my later question sets, and that is the point: it is a place to gather what I am curious about, figure out where I need to understand more, and consolidate the questions worth pursuing as part of a larger quest. Treat it as a living list, not a finished argument.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Value\\n\\n<SectionBanner why=\\"Value is where attention and money actually flow, and following that flow is the surest way to find what people genuinely care about. If I can read where value pools, I can read what to build.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The places people willingly spend time and money are a map of real demand. Most of my product instincts are downstream of reading that map correctly.\\"\\n  howOften=\\"Quarterly, and whenever I am evaluating a new direction\\"\\n  when=\\"When deciding what to build, what to study, or where to focus effort\\"\\n  record=\\"Keep a running note of where you observe time and money concentrating, with a concrete example each time\\">\\n  Where are people more likely to spend their time and money?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Avoiding Failure\\n\\n<SectionBanner why=\\"Knowing why people fail is cheaper than learning it firsthand. If failure usually traces back to a missing resource, then resourcefulness becomes the thing worth cultivating.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"If I can name the common causes of failure ahead of time, I can design around them instead of walking into them. A frequent root cause is the lack of some critical resource.\\"\\n  howOften=\\"Quarterly, and after any setback worth a post-mortem\\"\\n  when=\\"Before committing to something risky, and when reviewing why a past effort stalled\\"\\n  record=\\"List the failure modes you observe, and tag each with the resource that was missing\\">\\n  What makes people fail? (Often it is the lack of a certain resource.)\\n</Question>\\n\\n</QuestionSection>\\n\\n## Measurement\\n\\n<SectionBanner why=\\"What I measure is what I steer by, so the act of choosing the right questions to track is itself a high-leverage decision. These are the questions about which questions to keep close.\\" />\\n\\n### Resourcefulness\\n\\n<SectionBanner why=\\"Resourcefulness is the antidote to the failure mode above. Knowing what I have and what makes each resource special is how I do more with less.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Resourcefulness compounds. The more deliberately I notice what I can draw on, the more options I have when things get hard.\\"\\n  howOften=\\"Monthly, as part of a regular inventory\\"\\n  when=\\"When you feel stuck or short on options\\"\\n  record=\\"Keep a living inventory of your resources and revisit it when stuck\\">\\n  How can I be more resourceful? What resources do I have available? What is special about each of my resources?\\n</Question>\\n\\n</QuestionSection>\\n\\n### Opportunity\\n\\n<SectionBanner why=\\"Opportunity often hides in arbitrage: a gap in knowledge or time that I can exploit before others do. Learning to spot those gaps is most of the game.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Opportunity is rarely evenly distributed. The biggest openings tend to sit where there is a knowledge arbitrage or a time arbitrage that few people have noticed yet.\\"\\n  howOften=\\"Monthly, and whenever you spot an asymmetry\\"\\n  when=\\"When scanning a market, a field, or your own skill set for unfair advantages\\"\\n  record=\\"Write down each arbitrage you spot and why it exists\\">\\n  Where is the opportunity? Where is there a knowledge arbitrage? Where is there time arbitrage?\\n</Question>\\n\\n</QuestionSection>\\n\\n### Purpose\\n\\n<SectionBanner why=\\"Beneath all the measurement questions sits the simplest one: what do I actually want to do? The idea that will not let go of me is usually pointing at the answer.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"The idea that keeps infatuating me is a signal, not a distraction. Naming what I want to do is the anchor the rest of this catalog hangs from.\\"\\n  howOften=\\"Once or twice a year, and any time a new idea takes hold of you\\"\\n  when=\\"During reflection, or when an idea will not leave you alone\\"\\n  record=\\"Name the infatuating idea plainly; revisit to see whether it persists\\">\\n  What do I want to do? What \\"idea\\" is infatuating you?\\n</Question>\\n\\n</QuestionSection>\\n\\n### Motivation\\n\\n<SectionBanner why=\\"Motivation is the why behind the organizing. If I cannot explain why I have chosen to do what I am doing, the effort will not survive the hard stretches.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing why I organized myself a particular way keeps the structure honest. When the reason fades, the structure should change.\\"\\n  howOften=\\"Quarterly, or when your routine starts to feel hollow\\"\\n  when=\\"When you notice yourself going through the motions\\"\\n  record=\\"Write the honest reason, not the impressive one\\">\\n  Why have you decided to organize yourself? Why have you decided to do what you are doing?\\n</Question>\\n\\n</QuestionSection>\\n\\n### Metrics\\n\\n<SectionBanner why=\\"If answering questions is the work, then counting answers is how I know the work is happening. A simple tally keeps the practice accountable.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"A running count of answered questions turns an abstract quest into something I can actually track. Per-book throughput tells me where I am learning fastest.\\"\\n  howOften=\\"Weekly, or as you finish each source\\"\\n  when=\\"After reading a book or working through a problem\\"\\n  record=\\"Tally answered questions, and note how many came from each book\\">\\n  Track how many questions I have answered? How many questions am I answering per book?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Learnings\\n\\n<SectionBanner why=\\"The questions I enjoy answering point toward the questions worth building a life around. Pleasure in the work is a reliable compass.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"What I enjoy answering is what I will keep answering without external pressure. That self-sustaining energy is a clue about where my calling lives.\\"\\n  howOften=\\"Monthly, as you notice which questions energize you\\"\\n  when=\\"When reviewing what you have been working on lately\\"\\n  record=\\"Note which questions felt effortless to chase versus which felt like a chore\\">\\n  What questions do I enjoy answering?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Spending\\n\\n<SectionBanner why=\\"How people spend money and time is the most honest record of what they value. If I can read that record, even from something as ordinary as the house someone wants, I can understand people better.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Spending is revealed preference. What people pour money and time into tells me what they actually want, regardless of what they say. Even a home someone is drawn to leaks personal attributes through its features.\\"\\n  howOften=\\"Quarterly, and whenever you study a market or an audience\\"\\n  when=\\"When trying to understand what an audience truly cares about\\"\\n  record=\\"Collect specific examples of spending patterns and what they imply about the person\\">\\n  What do people spend most of their money on? Their time? Why do people spend their money? Their time? Can you infer personal attributes about someone from a home they are interested in, based on the different features of the house? Where are people spending their time?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Data\\n\\n<SectionBanner why=\\"Every question above eventually needs evidence, and evidence needs a source. Knowing where the data lives is the difference between a hunch and an answer.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"Many of these questions are answerable if I can find the right dataset. Public sources like the SEC are an obvious starting point worth cataloging.\\"\\n  howOften=\\"As needed, when a question demands evidence\\"\\n  when=\\"When a question can only be answered with real data\\"\\n  record=\\"Keep a list of data sources and what each one can answer\\">\\n  Where is the data at? The SEC?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Resources\\n\\n<SectionBanner why=\\"Understanding what companies possess is how I learn to think about leverage at scale. Their resources are the raw material of everything they produce.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Companies are concentrations of resources. Cataloging what they hold teaches me how value is assembled, and where the leverage points are.\\"\\n  howOften=\\"Quarterly, or when studying a particular company\\"\\n  when=\\"When analyzing how a business creates and captures value\\"\\n  record=\\"List the resources a company possesses and how each one contributes to its advantage\\">\\n  What resources do companies possess?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Planning\\n\\n<SectionBanner why=\\"Planning is one of the deepest questions in this catalog: who mastered it, whether it even matters more than direction, and how granular it should be. I want to understand the craft of planning at every scale, from a person to a country.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'anvil\', \'chisel\']}\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Planning scales strangely. The same instinct that organizes a person can, in principle, organize a country, and history is full of people who mastered it. I want to know when planning helps, when mere direction is enough, and when granularity tips into paralysis.\\"\\n  howOften=\\"Quarterly, and whenever you set out to build a plan\\"\\n  when=\\"When putting together any plan, for yourself or something larger\\"\\n  record=\\"Study planners you admire; extract the principles, and note where you are being too granular\\">\\n  How do you put together a plan for yourself? How do you put a plan together for an entire country? How can you extract someone\'s plan from history? Who mastered planning? Is planning needed, or direction? What level of planning is needed to be successful? Are you being too granular?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Thinking\\n\\n<SectionBanner why=\\"Automating thought is the frontier I keep circling: thinking, creativity, ideation. The deepest version of the question is not whether we can, but whether we should, and why we want to.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'spark\', \'fire\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"The race to automate thinking, creativity, and ideation is one of the most consequential of our time. The question that matters most is the one underneath: is automating all of our ideas even a good idea, and why do we want to?\\"\\n  howOften=\\"Yearly, as a standing philosophical question to revisit\\"\\n  when=\\"When the topic of automation, AI, or machine creativity comes up\\"\\n  record=\\"Write your evolving stance on whether and why thought should be automated\\">\\n  Who is after automating thought? Automating thinking? Automating creativity? Automating ideation? Automating all of the ideas? Is it a good idea to do so? Why do we want to do so?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Growing\\n\\n<SectionBanner why=\\"Growth is so assumed that we rarely ask what happens when it stops, for a person or a company. Sitting with the absence of growth clarifies why it matters.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Both people and companies treat growth as a default. Asking what happens when either one stops growing reveals what growth was actually doing, and what depends on it.\\"\\n  howOften=\\"Yearly, or when you notice stagnation\\"\\n  when=\\"When growth slows in your own life or in something you are watching\\"\\n  record=\\"Write what changes, for a person and for a company, when growth halts\\">\\n  What happens if people stop growing? What happens if companies stop growing?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Purpose\\n\\n<SectionBanner why=\\"I keep returning to products because they sit at the meeting point of what I want to make and what people want. Understanding how good products get created is part of understanding what I want to do. I like products because they interface with people\'s carnal desires.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Products are how I want to act on everything else in this catalog. Knowing whether I want to create them, how one is created, and what good ones look like turns a vague pull into a craft I can learn.\\"\\n  howOften=\\"Quarterly, and whenever you study a product you admire\\"\\n  when=\\"When deciding whether building products is the path, and when studying examples\\"\\n  record=\\"Collect examples of good products and write what makes each one work\\">\\n  Do I want to be creating products? How does one create products? What are some examples of good products?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Society\\n\\n<SectionBanner why=\\"I want to better understand people: detecting the problems they have, and knowing how they respond. The goal is to lay a foundation for helping people understand people, with technology as the lever. Who has spent the time to model people\'s interests?\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'spark\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"If I can use technology to surface where people complain most and to see the most prominent problems across the world, I can point my work at real, widely-felt needs instead of guesses. This is the foundation for helping people understand people.\\"\\n  howOften=\\"Yearly, as a long-horizon direction to refine\\"\\n  when=\\"When considering how technology could serve society at scale\\"\\n  record=\\"Sketch concrete ways technology could surface and model society\'s real problems\\">\\n  How can technology help society? How can technology help understand society? Can we sift through social media to see where the average person complains the most? Can we see the most prominent problems in different parts of the world?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Questions on Questions\\n\\n<SectionBanner why=\\"This catalog is itself a system, and a system needs maintenance. These are the meta-questions about how to organize questions, whether they inherit from each other, and whether the set paints a complete picture without repeating itself.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'chisel\', \'anvil\']}\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"If questions are my unit of work, then organizing them well is leverage. I want to know whether they can inherit from each other, how to map them to their essential contexts, whether the set is complete, and whether I am asking the same thing twice.\\"\\n  howOften=\\"Monthly, as part of maintaining this catalog\\"\\n  when=\\"When the question list grows unwieldy or starts to feel redundant\\"\\n  record=\\"Define your taxonomy: how questions relate, what contexts they map to, and which are ready to answer\\">\\n  How do I organize my questions? Can questions inherit from each other? On what basis? How do I map questions to their essential contexts? What contexts am I tracking? Are the dependencies of the contexts the same as the dependencies of the questions? Do your questions paint a complete picture? Are you asking the same thing twice? What questions are you ready to answer? What do you need to do to be able to come up with an answer? What questions should you always ask yourself? What are the questions you need to ask yourself?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Inference\\n\\n<SectionBanner why=\\"Inference is where credibility lives. I want to know how collective inference works, how accurate ours is, and where I want my word to be trusted, because the questions I dedicate my life to answering will only matter if people believe the answers.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"These are the deepest questions in the catalog: how inference is amplified or reduced, what counts as evidence, whether I am even qualified to answer, and which questions I want to spend the rest of my life on. They decide where my credibility is staked.\\"\\n  howOften=\\"Yearly, as long-horizon questions that should refine slowly\\"\\n  when=\\"During deep reflection on what to commit your life to answering\\"\\n  record=\\"Write the questions you want to be trusted on, and what you must know to earn that trust\\">\\n  How do you do collective inference? On what basis is a possible inference amplified or reduced? How accurate is our inference? Where do you want your word to be trusted? Where do you want to be credible? Into what will you put your time? What kinds of questions do you want to answer for the rest of your life? What will we do for evidence? Am I qualified to answer this question? What must I know to answer this question?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-capturing-what-you-could-do","metadata":{"permalink":"/thoughts/questions-for-capturing-what-you-could-do","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-13-questions-for-capturing-what-you-could-do.mdx","source":"@site/blog/2017-02-13-questions-for-capturing-what-you-could-do.mdx","title":"What I Ask Myself: To Capture What I Could Do","description":"How I brainstorm and organize everything I could do: goals, commitments, challenges, and the things I want to create.","date":"2017-02-13T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":14.42,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-capturing-what-you-could-do","title":"What I Ask Myself: To Capture What I Could Do","kind":"question-set","sidebar_label":"Capturing Ideas","description":"How I brainstorm and organize everything I could do: goals, commitments, challenges, and the things I want to create.","authors":["oeid"],"tags":["productivity","question-set"],"date":"2017-02-13T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"The Questions I Want to Answer","permalink":"/thoughts/the-questions-i-want-to-answer"},"nextItem":{"title":"What I Ask Myself: To Decide What to Learn","permalink":"/thoughts/questions-for-deciding-what-to-learn"}},"content":"Before I can decide what to work on now, I have to see the whole field of what I *could* do. Prioritizing too early quietly throws away options I never even named. These questions are for the capture step: brainstorming and organizing my goals, commitments, challenges, and the things I want to build across every domain of my life, before any of it gets ranked.\\n\\n\x3c!-- truncate --\x3e\\n\\n## What do you want to do?\\n\\n<SectionBanner why=\\"The first job of capture is to empty my head onto the page. Anything that stays unnamed can\'t be chosen later, so this section casts the widest possible net before any sorting begins. I record goals in the context of my roles.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"The things I\'ve idly thought about doing are the raw material for everything else. If I don\'t capture them when they surface, they evaporate.\\"\\n  howOften=\\"Weekly, or whenever an idea pops up\\"\\n  when=\\"During a brainstorm or capture session\\"\\n  record=\\"Keep a running list; nothing is too small to note\\">\\n  What have I thought about doing?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming my distinct streams of work shows me how my effort is actually divided. It\'s easy to think I have one focus when I really have five competing ones.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When my attention feels split across too many fronts\\"\\n  record=\\"List each stream of work as its own line\\">\\n  What are my different streams of work?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The whole point of capture is to feed this question well. Once everything is on the table, asking what to do with my time has real options to choose from.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When planning where the week\'s hours go\\"\\n  record=\\"Pick from your captured list, don\'t invent on the spot\\">\\n  What should I do with my time?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Most options are not equally valuable. Forcing the most-valuable-now question keeps capture from becoming an excuse to do everything at once.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When choosing the next thing to actually start\\"\\n  record=\\"Name the single highest-value option and why\\">\\n  What\'s the most valuable thing I can do now?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Capturing what I could do is only half of it; the other half is doing it efficiently. This question pushes me to use the time I have, not just plan around it.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When reviewing how the week\'s time was spent\\"\\n  record=\\"Note where time leaks and where it could compound\\">\\n  How can I make the most out of my time?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Initiatives are the bundles my scattered ideas group into. Naming them, and the reason each one matters, turns a pile of wants into a small set of things I can stand behind.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When organizing captured ideas into bigger themes\\"\\n  record=\\"List each initiative, then write why it\'s important\\">\\n  What initiatives do I have? Why do I think each of these initiatives is important?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A goal without the tasks under it is just a slogan. Counting the tasks per objective shows me which goals are actually fleshed out and which are still hollow.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When breaking goals down into actionable work\\"\\n  record=\\"For each objective, list its tasks and count them\\">\\n  What must be done in order to realize my goals? How many tasks do I have in each objective?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Goals by category\\n\\n<SectionBanner why=\\"Capturing goals one domain at a time keeps any area of life from being silently skipped. Walking the categories deliberately, from career to spiritual, makes the blind spots obvious.\\" />\\n\\n<QuestionSection>\\n\\n### Career\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Career goals drift if I never name them. Writing them down, including the skills and the position I\'m aiming for, gives my work somewhere to point.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"During a review of where my career is heading\\"\\n  record=\\"Write the goal, the skills it needs, and the role you\'re aiming for\\">\\n  What are my career goals? What skills do I want to attain? What position do I want to reach?\\n</Question>\\n\\n### Family\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Family goals rarely show up on a task list, so they get crowded out by work that does. Naming them protects the part of life that matters most but shouts least.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When checking that family isn\'t being squeezed out\\"\\n  record=\\"Write what you want to accomplish for and with your family\\">\\n  What are my family goals? What do I want to accomplish for my family?\\n</Question>\\n\\n### Financial\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Money goals are easy to leave vague, which makes them easy to ignore. Naming concrete milestones turns a fuzzy hope into something I can track.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When reviewing financial direction\\"\\n  record=\\"Write the goal plus specific, dated milestones\\">\\n  What are my financial goals? What financial milestones do I want to reach?\\n</Question>\\n\\n### Growth\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Personal growth is the category most likely to stay abstract. Asking which aspects to improve, whether daily work is needed, and what recurring action each demands turns a wish to be better into an actual practice.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When designing or reviewing habits\\"\\n  record=\\"For each aspect, note whether it needs daily work and the recurring action it implies\\">\\n  How do I want to grow as a person? What aspects of myself do I want to improve? Do I need to improve these aspects of me on a daily basis? If so, what recurring action do I need to take for each aspect?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Even within growth, I can\'t work on everything. This question forces me to narrow to the few areas that truly deserve focus right now.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When too many growth fronts are competing\\"\\n  record=\\"Name the small set you\'ll truly focus on this month\\">\\n  What sets of things should I truly currently be focusing on?\\n</Question>\\n\\n### Health\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Health is the base everything else runs on, and the first thing sacrificed under pressure. Naming the goals keeps it from being an afterthought.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When reviewing physical well-being\\"\\n  record=\\"Write the health goals and how you\'ll improve physical well-being\\">\\n  What are my health goals? How do I want to improve my physical well-being?\\n</Question>\\n\\n### Learning\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"There\'s far more I could learn than I have time for. Capturing the wants, then choosing what to focus on, keeps learning intentional instead of random.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When deciding what to study next\\"\\n  record=\\"List what you want to learn, then mark what you\'ve chosen to focus on\\">\\n  What do I want to learn? What skills do I need to develop? Of the things I could possibly learn about, what have I chosen to focus on?\\n</Question>\\n\\n### Spiritual\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Spiritual goals shape who I\'m becoming at the deepest level, but they\'re the easiest to leave unspoken. Naming them gives that growth a direction.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"During reflection on spiritual direction\\"\\n  record=\\"Write the spiritual goals and how you want to grow\\">\\n  What are my spiritual goals? How do I want to grow spiritually?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Commitments\\n\\n<SectionBanner why=\\"Commitments are the goals I\'ve already bound my time to, which makes them the truest signal of my real priorities. This section audits whether what I\'ve committed to still matches what I care about.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"A commitment is a goal I\'ve physically committed my time to, which is different from one I merely hold. Listing them and checking whether they reflect my priorities is where the honesty lives, because commitments don\'t lie about where my hours go.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When auditing where my time actually goes\\"\\n  record=\\"List each commitment; mark whether it reflects a real priority\\">\\n  What are my commitments? What have I physically committed my time to doing? Do my commitments reflect my priorities? How does this differ from my goals?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"A commitment that will stick with me until I die is a different weight than a passing one. Naming the lifelong ones clarifies what I\'ve actually built my identity around.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"During deep reflection on lasting commitments\\"\\n  record=\\"Name the commitments meant to last a lifetime\\">\\n  What commitments have I made that will stick with me until I die?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Initiatives and commitments are easy to confuse, but they aren\'t the same: an initiative is something I want to do, a commitment is something I\'ve bound myself to. Keeping the distinction clear keeps my capture honest.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When organizing the difference between wants and obligations\\"\\n  record=\\"Note which captured items are initiatives versus commitments\\">\\n  Are initiatives the same as commitments?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A commitment has a shape: when it started, how long it lasts, and how much daily time it eats. Knowing those details tells me what I can realistically add or must drop.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When checking whether I\'m honoring my commitments\\"\\n  record=\\"For each commitment, note its start date, duration, daily cost, and whether you\'re keeping up\\">\\n  When did I make each of my commitments? Am I keeping up with each of my commitments? How long does each of my commitments last for? How much of my daily time does each commitment consume?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A commitment usually exists to advance some personal goal. Tracing each one back to the goal it partially realizes keeps me from honoring obligations that no longer serve anything I want.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When tying commitments back to underlying goals\\"\\n  record=\\"For each commitment, note which personal goal it partially realizes\\">\\n  Which of my personal goals do I attempt to partially realize through my commitments?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Sorting commitments by who they\'re to, annual, family, self, spiritual, reveals whether any whole category is being neglected. The gaps are usually the relationships I claim matter most.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When checking that no category of commitment is empty\\"\\n  record=\\"Group commitments by who they\'re to; look for empty categories\\">\\n  What are my annual commitments? What commitments have I made to my family? What commitments have I made to myself? What commitments have I made spiritually?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Challenges\\n\\n<SectionBanner why=\\"I need to consistently create new challenges to keep myself engaged. This section captures the hard things I\'m choosing on purpose, because comfortable goals rarely grow me.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Challenge is what keeps work from going stale. Asking how I\'ll challenge myself, and how I already am, keeps me reaching just past my current edge instead of coasting.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When the work has started to feel too comfortable\\"\\n  record=\\"Name the challenge you\'ll set and the one you\'re already in\\">\\n  How will I challenge myself? How am I challenging myself? What will I push myself to do?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Motivation and difficulty point at the same target from two sides. Capturing what I\'m motivated to do alongside what feels hard reveals the difficult things worth attempting.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When deciding which hard things are worth the effort\\"\\n  record=\\"List what motivates you and the hard goals you want to reach\\">\\n  What am I motivated to do? What difficult things do I want to accomplish?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming the challenges I\'m facing and the milestones that feel out of reach makes them concrete. A vague sense of difficulty is paralyzing; a named obstacle can be planned around.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When something feels too hard to start\\"\\n  record=\\"List current challenges and the milestones that seem hard to reach\\">\\n  What challenges am I facing? What milestones seem hard to reach?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Things to build (artifactual outcomes)\\n\\n<SectionBanner why=\\"Some goals produce a thing I can point at: an app, a site, a document. Capturing those artifacts separately keeps the tangible outputs from getting lost among abstract aims.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Building something produces a concrete artifact, which is satisfying and shareable in a way abstract goals aren\'t. Capturing what I want to make keeps the tangible outputs on my radar.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When brainstorming things to create\\"\\n  record=\\"List the apps, sites, diagrams, or documents you want to produce\\">\\n  What do I want to build/create? What artifacts do I want to produce? What apps, sites, diagrams, or documents do I want to make?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Themes\\n\\n<SectionBanner why=\\"Across all my initiatives, a few recurring themes tend to repeat. Spotting them tells me where my real interests cluster and where my ideas keep coming from.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Themes that scale across many initiatives reveal my deeper patterns, and noticing where my ideas come from shows me how to generate more of them deliberately.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When looking for the patterns beneath my scattered ideas\\"\\n  record=\\"Name the themes that recur, and where the ideas originate\\">\\n  What themes scale across my initiatives? On what basis do I have ideas? Where do my ideas come from?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Why nots\\n\\n<SectionBanner why=\\"The fastest way to find missed options is to ask why I\'m not already doing something. This section deliberately hunts for the things I\'ve overlooked rather than the ones already on the list.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The \'why don\'t I\' question is a deliberate provocation. It surfaces the things I\'ve dismissed without examining, which is where overlooked opportunities tend to hide.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When the option list feels too safe or too short\\"\\n  record=\\"List the things you\'re NOT doing that deserve a second look\\">\\n  Why don\'t I...? What am I NOT doing that I should consider?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Reflecting on your initiatives\\n\\n<SectionBanner why=\\"Once initiatives are captured, they deserve a second look: what goals hide inside them, why I want them, and how they\'re shifting over time. Capture without reflection just produces a longer list.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Initiatives often contain goals I never stated explicitly, and the reasons I want each thing change as I do. Digging into the hidden goals and tracking how my wants shift keeps the capture honest over time.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When reviewing how my interests are evolving\\"\\n  record=\\"For each initiative, name the hidden goal, the reason, and how it\'s changed\\">\\n  What goals are hidden in my initiatives? Why do I want to do each of these things? As time has progressed, how are the things I want to work on changing?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Identifying projects\\n\\n<SectionBanner why=\\"A project is a bundle of work with a definite outcome, and it\'s the unit I actually execute on. This section turns loose ideas and learning objectives into projects worth committing to. Innovating, for me, is taking an idea and merging it with what I\'m passionate about until it becomes a project bundle I can work on.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A project needs a defined end: an artifact, a change in state. Naming the potential projects and their outcomes is what separates real bundles of work from vague intentions.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When turning ideas into concrete projects\\"\\n  record=\\"For each project, write the end result and the reason to do it\\">\\n  What projects can I potentially work on? What bundle of work can I do? What is the end result / artifact / change in state of each project? Why should I work on each project?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"There\'s a real method to going from a raw idea to a workable project. Naming how I refine ideas and learning objectives into project bundles makes that process repeatable instead of accidental.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When an idea is ready to become real work\\"\\n  record=\\"Write the steps you take from idea to defined work bundle\\">\\n  How do I go from a project idea to a work bundle? How can I refine my ideas / learning objectives into projects?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Completed projects are evidence of which objectives I\'ve actually advanced. Reflecting backward closes the loop, showing me whether my finished work served the goals I claimed to care about.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When reviewing what finished projects actually moved forward\\"\\n  record=\\"For each completed project, note which objectives it advanced\\">\\n  What objectives were advanced by the projects I have already completed? What objectives have I advanced through my projects?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-deciding-what-to-learn","metadata":{"permalink":"/thoughts/questions-for-deciding-what-to-learn","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-13-questions-for-deciding-what-to-learn.mdx","source":"@site/blog/2017-02-13-questions-for-deciding-what-to-learn.mdx","title":"What I Ask Myself: To Decide What to Learn","description":"How I choose what to learn next, build a curriculum, and keep up with the learning commitments I make to myself.","date":"2017-02-13T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":8.98,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-deciding-what-to-learn","title":"What I Ask Myself: To Decide What to Learn","kind":"question-set","sidebar_label":"What to Learn","description":"How I choose what to learn next, build a curriculum, and keep up with the learning commitments I make to myself.","authors":["oeid"],"tags":["productivity","question-set"],"date":"2017-02-13T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Capture What I Could Do","permalink":"/thoughts/questions-for-capturing-what-you-could-do"},"nextItem":{"title":"What I Ask Myself: To Find Where to Improve","permalink":"/thoughts/questions-for-finding-where-to-improve"}},"content":"There is always more to learn than time to learn it. The hard part is not finding material, it is deciding what deserves my attention next and then actually committing to it. These questions walk from picking topics, to prioritizing them, to building a curriculum, to protecting the time and keeping the commitments.\\n\\n\x3c!-- truncate --\x3e\\n\\n## What to learn\\n\\n<SectionBanner why=\\"The first step is surfacing everything I might want to learn before judging any of it. Casting a wide net here keeps me from defaulting to whatever\'s trendy or in front of me.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Before I can prioritize, I have to name the field. Listing what I want to learn and what I should be learning are two different lists, and the gap between them is worth seeing.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When deciding where learning time should go\\"\\n  record=\\"Two lists: what you want to learn, and what you should\\">\\n  What do I want to learn? What should I be learning?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Mastery is different from dabbling, and it has to be chosen on purpose. Asking what\'s valuable to master, and where my strengths and weaknesses lie, points learning at what actually compounds.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When deciding what to go deep on versus sample\\"\\n  record=\\"Name what\'s worth mastering; note your real strengths and weaknesses\\">\\n  What should I master in, and what is valuable for me to learn? What are my strengths and weaknesses?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"What I want to accomplish in life implies what I need to learn to get there. Working backward from the life goal to the learning, and naming where I want to grow, keeps study tied to something that matters.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When connecting learning to longer-term goals\\"\\n  record=\\"Write the life goal, then the learning it implies, then where you want to grow\\">\\n  What do I want to accomplish in my life, and what learning does that imply? Where do I want to grow?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Learning often comes in bundles, not single topics, and some of it is side interest rather than core. A learning catalogue captures all of it in one place so nothing gets lost.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When organizing the full range of things I want to learn\\"\\n  record=\\"Build a catalogue of bundles, including the side interests\\">\\n  What bundles of knowledge do I want to learn more about? What do I want to study on the side? Should I make a learning catalogue of everything I want to learn?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Learning priorities\\n\\n<SectionBanner why=\\"With the field surfaced, the next job is ordering it. Difficulty estimates and value tell me what to learn first, so I\'m not spending my best energy on the least useful thing.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Priority and difficulty together tell me where to start. Knowing which topics I\'ve done before lets me estimate effort, and naming what\'s most valuable to learn first keeps me from sequencing badly.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When ordering the learning backlog\\"\\n  record=\\"Rank topics by value; flag the ones you\'ve done before as easier to estimate\\">\\n  What are my learning priorities? Which topics have I done before, so I can estimate their level of difficulty? What is most valuable for me to learn first?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Your learning plan and curriculum\\n\\n<SectionBanner why=\\"A plan turns intentions into a path: what I\'ll learn, by when, and in what order. This section builds the curriculum and the backlog so learning has structure instead of being a pile of bookmarks.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"A learning plan with dates and phases is what turns a wish list into a curriculum. Naming what I\'ll learn, by when, and in what sequence makes the journey real instead of perpetual someday-learning.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When designing or revising the curriculum\\"\\n  record=\\"Write the plan: topics, target dates, and the phases in order\\">\\n  What is my learning plan? What will I learn, and by when? What is my learning journey and curriculum? What will the phases of my learning be?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Goals make learning measurable, and choosing what to focus on now keeps the plan from being everything at once. This is where the broad field gets narrowed to a workable focus.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When setting concrete learning goals for the season\\"\\n  record=\\"Write the learning goals and the one focus for now\\">\\n  What learning goals will I set for myself? What do I think is worth learning, and what should I focus on now?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A backlog holds everything I could learn; a commitment marks the slice I\'ve actually signed up for. Keeping both, and tracking which backlog items I\'ve committed to, keeps the plan honest about capacity.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When promoting items from backlog to committed\\"\\n  record=\\"Maintain a backlog; mark which items you\'ve actually committed to learn\\">\\n  What is my learning backlog of things I could possibly learn? Which items from my backlog have I actually committed myself to learning?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Making time for learning\\n\\n<SectionBanner why=\\"A plan is worthless without protected time, and learning time is the first thing the day eats. This section is about carving out and reclaiming hours, including the idle ones.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Learning loses to everything urgent unless its time is explicitly protected. Asking how to maximize and explicitly allocate learning time is what keeps it from being perpetually squeezed out.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When planning the week and protecting learning blocks\\"\\n  record=\\"Write the hours you\'ve explicitly blocked for learning\\">\\n  How do I maximize how much time I allocate to learning? What time have I explicitly allocated for learning?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"Idle time, exercising, vacuuming, doing dishes, grilling, is hidden learning capacity if the material fits the moment. Figuring out what kind of material sticks during those windows unlocks hours I\'m already spending.\\"\\n  howOften=\\"As situations come up\\"\\n  when=\\"When looking for hidden pockets of time to learn\\"\\n  record=\\"Note which material actually sticks during hands-busy time\\">\\n  Could I learn during idle time, the way some people listen to audiobooks while exercising, vacuuming, doing the dishes, or grilling? Can I learn from any material while exercising, or is there a specific kind that sticks better?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Learning commitments\\n\\n<SectionBanner why=\\"A commitment is what turns a plan into something I\'m accountable to. This section pins down exactly what I\'ve signed up to learn, how much time per week, and whether I\'m keeping up.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Vague intent to \'learn more\' never survives a busy week. Naming exactly what I\'ve committed to, the resources I\'ll work through, and a concrete weekly number like four hours of studying, reading, and programming, is what makes it stick. Checking whether I\'m keeping up keeps the commitment honest.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When making or reviewing a learning commitment\\"\\n  record=\\"Write the specific commitment, the resources, the weekly hours, and whether you\'re on track\\">\\n  How will I commit myself to learning, and what exactly have I committed to learn? What resources have I committed to working through? How much time am I going to spend learning every week? Could I aim for something like 4 hours per week of studying, reading, and programming? Am I keeping up with my commitments?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Certifications are one milestone, but not the only one. Asking why they matter and whether they\'re the only proof of learning keeps me from chasing credentials when real understanding is the actual goal.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When deciding whether a certification is worth pursuing\\"\\n  record=\\"Note which certifications matter and what other milestones prove your learning\\">\\n  Should I be working on any certifications? Why are certifications important? Are certifications the only milestone that can reflect my level of learning?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Overlapping learning with work\\n\\n<SectionBanner why=\\"The cheapest learning is the kind that overlaps with what I\'m already building. This section looks for where work and study can reinforce each other instead of competing for hours.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Work hands me chances to learn things on someone else\'s clock. Adjusting my plan around the technologies I\'ll touch at work, and deliberately overlapping learning with building, doubles the return on both.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When work introduces a technology I want to learn anyway\\"\\n  record=\\"Note where what you\'re learning can overlap with what you\'re building\\">\\n  How might my learning plan shift based on the opportunities I have to work on different technologies at work? Where can I deliberately overlap what I am learning with what I am building?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Consolidating your learning material\\n\\n<SectionBanner why=\\"Learning material scattered across bookmarks, links, photos, and screenshots is material I\'ll never actually use. This section is about gathering it all into one place I can return to.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Material spread across browser bookmarks, LinkedIn saves, phone photos of books, and screenshots might as well not exist. Consolidating and indexing it in one place is what makes it usable instead of just collected.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When learning material has scattered across too many places\\"\\n  record=\\"Pick one index; pull bookmarks, saved links, book photos, and screenshots into it\\">\\n  Where do I capture notes on all the different things I want to learn from? How do I index all of my learning material in one place? Could I categorize my browser bookmarks, consolidate saved links from LinkedIn, gather the photos of books on my phone, and collect screenshots of useful websites?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Feeding your curiosity\\n\\n<SectionBanner why=\\"Underneath all the planning is curiosity, the engine that makes learning sustainable. This section tunes into what I\'m actually drawn to right now, because forced learning rarely lasts.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Curiosity is the most renewable source of learning energy. Noticing what I\'m curious about right now, and what it pushes me toward, keeps the plan alive instead of purely dutiful.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When current curiosity should steer what\'s next\\"\\n  record=\\"Note what you\'re curious about now and where it pulls you\\">\\n  What am I curious about right now, and what does that push me to learn more about? What are the different kinds of things I want to learn?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-finding-where-to-improve","metadata":{"permalink":"/thoughts/questions-for-finding-where-to-improve","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-13-questions-for-finding-where-to-improve.mdx","source":"@site/blog/2017-02-13-questions-for-finding-where-to-improve.mdx","title":"What I Ask Myself: To Find Where to Improve","description":"How I spot my gaps and weaknesses, find growth openings, and decide what to work on improving next.","date":"2017-02-13T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":8.26,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-finding-where-to-improve","title":"What I Ask Myself: To Find Where to Improve","kind":"question-set","sidebar_label":"Where to Improve","description":"How I spot my gaps and weaknesses, find growth openings, and decide what to work on improving next.","authors":["oeid"],"tags":["productivity","question-set"],"date":"2017-02-13T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Decide What to Learn","permalink":"/thoughts/questions-for-deciding-what-to-learn"},"nextItem":{"title":"What I Ask Myself: About How I Learn","permalink":"/thoughts/questions-for-how-you-learn"}},"content":"Growth starts with an honest map of where I stand. Before I can pick what to work on, I have to name the gaps, notice the openings, and decide what change I actually want. These are the questions I return to when I want to figure out where to improve next.\\n\\n\x3c!-- truncate --\x3e\\n\\n## How to use these\\n\\n<SectionBanner why=\\"These work best in rough order: first surface gaps and weaknesses, then spot growth opportunities, then prioritize what\'s most valuable and aligned with my goals, and finally plan how I\'ll actually improve. The sections below mirror those steps.\\" />\\n\\n## Identifying gaps and weaknesses\\n\\n<SectionBanner why=\\"I can\'t fix what I won\'t name. This section is the honest inventory of where I\'m weak, including a concrete checklist of specific areas to rate myself against so the gaps can\'t hide behind vagueness.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Naming weaknesses out loud is uncomfortable, which is exactly why it works. Asking where I can improve, what my weaknesses are, and which ones I need to work on turns a vague unease into a list I can act on.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"During an honest self-assessment\\"\\n  record=\\"Write the weaknesses plainly; mark the ones that need work now\\">\\n  Where can I improve? What are my weaknesses? What weaknesses of mine do I need to work on?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Weaknesses only matter relative to where I\'m trying to go. Lining up my goals against what I\'m not yet ready for shows me which gaps actually block the path.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When tying gaps back to goals\\"\\n  record=\\"List your goals, then note what you\'re not ready for yet\\">\\n  What are my goals? What am I not ready for?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"A concrete checklist beats a vague sense of inadequacy. Running down specific areas and answering honestly where I\'m weak turns self-criticism into a precise, actionable map.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I need a concrete, specific gap inventory\\"\\n  record=\\"Rate yourself honestly on each area; circle the weakest few to target\\">\\n  Run down a checklist of specific areas and ask honestly where you are weak: Scaling? Performance? Security (SSL/TLS, vulnerability scanning, OAuth)? Agile? Business models? Product offerings? Web dev beyond the basics (CSS)? Experience with databases? Can\'t show my work (no repos, no docs)? Design, color, palette? Cloud development? Functional programming?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Growth opportunities\\n\\n<SectionBanner why=\\"Gaps tell me where I\'m behind; opportunities tell me where I could stretch. This section looks forward, toward the new and uncomfortable, because growth lives where I\'m willing to be a beginner.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Growth happens at the edge of comfort. Asking how I can evolve, what new things I can do, and where I can accept being uncomfortable points me toward the stretch instead of the safe.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When looking for the next place to stretch\\"\\n  record=\\"Name a new thing to try and the discomfort you\'ll accept\\">\\n  How can I evolve? What new things can I do? Where can I accept being uncomfortable? What should I push myself to do?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"One-off growth is easy; a mindset that always grows is the real goal. Asking how I establish that mindset, anchored by simple commitments to always read and always study, turns growth from an event into a default.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When building the habit of continuous growth\\"\\n  record=\\"Write the mindset and the standing habits, like always read and always study, that keep momentum\\">\\n  How do I ensure I always grow? How do I establish a mindset that pushes me to always grow?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Desiring change\\n\\n<SectionBanner why=\\"Improvement starts with actually wanting it. This short section checks whether I have a real desire to change, because effort without genuine want rarely sticks.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Change requires desire, not just diagnosis. Naming the change I desire and what about myself I want to change is the difference between knowing my flaws and actually moving on them.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When deciding what about myself to change\\"\\n  record=\\"Write the change you genuinely want, in your own words\\">\\n  What change do I desire? What about myself do I want to change?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Learning from others\\n\\n<SectionBanner why=\\"Other people are a mirror for my own gaps. Spotting skills in them that I lack is one of the fastest ways to see what I should work on, and who I should learn it from.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The skills I admire in others are often the ones I\'m missing. Naming those, and who I can learn each from, turns vague envy into a concrete learning plan.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I notice a skill in someone I wish I had\\"\\n  record=\\"List skills you\'ve spotted in others that you lack; note who to learn each from\\">\\n  What skills have I spotted in others that I lack myself? Who can I learn from?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Your improvement approach\\n\\n<SectionBanner why=\\"Knowing where to improve is useless without a plan to do it. This section turns the gaps into a concrete approach: the actions, the habits, and how it all ties back to my goals and learning.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"An approach is what makes improvement happen on purpose. Asking how I\'ll improve, what I need to do, and how it overlaps with my goals and learning keeps the effort coherent instead of scattered.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When turning gaps into an actual plan\\"\\n  record=\\"Write the improvement actions and how each overlaps with your goals and learning\\">\\n  How will I improve? What do I need to do to improve? How does this overlap with my goals? How does this overlap with things I want to learn?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Improvement compounds over years, and habits are the mechanism. Planning how I\'ll improve this year and next, what I\'ll learn, and which habits I\'ll start, stop, and commit to is what makes the change durable.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"During annual planning of growth and habits\\"\\n  record=\\"Write what you\'ll learn and the habits you\'ll start, stop, and commit to\\">\\n  How will I improve this year? Next year? What things will I learn? What habits will I start or stop? What habits am I willing to commit to?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Technical gaps\\n\\n<SectionBanner why=\\"Beyond general growth, there are specific technical things I want to understand better. This section names the concrete frameworks, tools, and processes on my list, like rasa, spaCy, Google Analytics, Spark, the Critical Path Method, and a Gantt-style view for ordering work.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming specific frameworks and processes turns \'get better technically\' into something I can actually schedule. Concrete targets, like the frameworks and process enhancements on my own list, are learnable; vague ambition isn\'t.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When choosing the next technical thing to learn\\"\\n  record=\\"List the frameworks, tools, and processes you want to understand better\\">\\n  What frameworks do I want to learn more about? What processes do I need to understand better?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The underlying skillset is where the deepest gaps usually live. Admitting I need to get better at architecting, at understanding the phases of software development, and at the tools at my disposal is the kind of honesty that actually directs growth.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When assessing core skills, not just surface frameworks\\"\\n  record=\\"Name the foundational skills that need work, like architecting and understanding the development phases\\">\\n  Which skills of mine need work?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Expanding your roles\\n\\n<SectionBanner why=\\"Growth isn\'t only about getting better at what I already do; it\'s about taking on new activities and roles. This section looks at widening the kinds of things I do, not just deepening them.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"New roles stretch me in directions skill-deepening can\'t. Asking what new activities and roles I should take on opens growth sideways, into capabilities I don\'t yet have.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When considering taking on something genuinely new\\"\\n  record=\\"Name the new activities and roles you want to step into\\">\\n  What new activities should I take on? What new roles should I play?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Enhancing your skills\\n\\n<SectionBanner why=\\"Some of the most valuable skills are the soft and structural ones I tend to neglect: persuasion, negotiation, showing my value, and modeling cleanly. This section targets those underinvested capabilities.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Influence skills, swaying people, negotiating, showcasing my value, often matter more than technical depth and get practiced less. Naming them as things to improve keeps me from neglecting the skills that actually move outcomes.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When working on the people-facing side of my skillset\\"\\n  record=\\"Note where you want to improve at persuasion, negotiation, and showing your value\\">\\n  How do I sway people? How do I negotiate? How do I showcase my value?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"How I model and where I spend attention shapes the quality of my work. Asking whether I can model in ADTs more and focus less on processes and more on capabilities sharpens how I actually think and build.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When refining how I model and where I focus\\"\\n  record=\\"Note where you can lean more on ADTs and focus on capabilities over processes\\">\\n  Can I model in ADTs as much as possible? Can I focus less on processes and more on capabilities?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-how-you-learn","metadata":{"permalink":"/thoughts/questions-for-how-you-learn","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-13-questions-for-how-you-learn.mdx","source":"@site/blog/2017-02-13-questions-for-how-you-learn.mdx","title":"What I Ask Myself: About How I Learn","description":"The questions I ask to understand and sharpen how I learn: my style, my process, and how I keep myself in motion.","date":"2017-02-13T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":10.31,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-how-you-learn","title":"What I Ask Myself: About How I Learn","kind":"question-set","sidebar_label":"How I Learn","description":"The questions I ask to understand and sharpen how I learn: my style, my process, and how I keep myself in motion.","authors":["oeid"],"tags":["productivity","question-set"],"date":"2017-02-13T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Find Where to Improve","permalink":"/thoughts/questions-for-finding-where-to-improve"},"nextItem":{"title":"What I Ask Myself: To Manage My Tasks","permalink":"/thoughts/questions-for-managing-your-tasks"}},"content":"Most of us were taught *what* to learn, but rarely *how* we ourselves learn best. Getting deliberate about my own process changes everything: how I find a topic, how I absorb it, and how I know when I\'ve actually got it. The questions below walk through learning style, process, seeking knowledge, expanding it, the methods worth studying, and how to keep the whole thing in motion.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Your learning style\\n\\n<SectionBanner why=\\"I learn differently than the next person, and naming how I actually take things in lets me lean into it instead of fighting it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I don\'t know what my brain needs to absorb something, I keep reaching for methods that work for other people and not for me.\\"\\n  howOften=\\"Whenever I pick up a new field and notice I\'m struggling to make progress\\"\\n  when=\\"At the start of learning something new, or when a method clearly isn\'t sticking\\"\\n  record=\\"A short note on what conditions help me learn (time of day, format, environment)\\">\\n  How do I learn? What do I need to personally do to learn something?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"My resources shape my ceiling. If I only ever use one kind of source, I inherit its blind spots.\\"\\n  howOften=\\"When starting a new topic, and periodically as I find better sources\\"\\n  when=\\"At the research stage of any new subject\\"\\n  record=\\"Keep a running list of go-to resources by type (books, courses, people)\\">\\n  What resources do I use to learn?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"There\'s no magic number, but asking the question keeps me from both stopping too early and over-reading without ever applying anything.\\"\\n  howOften=\\"When I\'m tempted to call a topic \'done\'\\"\\n  when=\\"Midway through studying a subject, when deciding whether to keep going\\"\\n  record=\\"Note how many sources it actually took before I felt competent, for next time\\">\\n  How many books do I need to read on a topic before I have learned it?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing where I can teach myself versus where I genuinely need help saves me from wasting time stuck on the wrong things.\\"\\n  howOften=\\"When evaluating whether to find a course or teacher\\"\\n  when=\\"Before committing to self-study on something hard\\"\\n  record=\\"A short list of the kinds of topics I reliably learn solo\\">\\n  Can I really learn on my own? What am I good at learning on my own?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"The questions I default to in a new field reveal my real mental model. Seeing them written down lets me improve the set.\\"\\n  howOften=\\"After learning a few new fields, look for the repeating pattern\\"\\n  when=\\"Whenever I notice myself asking the same opening questions again\\"\\n  record=\\"Collect my recurring first questions into a reusable checklist\\">\\n  What are the common questions I ask when attempting to learn a new field?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Your learning process\\n\\n<SectionBanner why=\\"A learning style is how I take things in; a process is the repeatable sequence I run so I\'m always learning something on purpose. The bullets below are a starting shape for mine.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Learning decays if I leave it to chance. A defined process is what keeps me in a state of learning instead of drifting in and out of it.\\"\\n  howOften=\\"Monthly, as a check that the process is still running\\"\\n  when=\\"During a monthly review of how I\'ve been spending my attention\\"\\n  record=\\"Document my process as steps, and revise it when a step stops earning its place\\">\\n  What do I need to continually do to ensure that I am always in a state of learning? What does my personal learning process look like?\\n</Question>\\n\\n</QuestionSection>\\n\\nA starting shape for that process:\\n\\n- Capture a whole bunch of questions that intrigue me around a topic\\n- Formulate a backlog to learn more about the topic\\n- Come up with fun projects that may overlap with learning about one or more topics\\n- As needed, come up with a plan for longer backlogs\\n- Capture repetitive tasks\\n\\n## Seeking knowledge effectively\\n\\n<SectionBanner why=\\"A guiding principle for this section: employ the scientific method as much as possible. Treat curiosity as a hypothesis to test, not just a feeling to follow.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Hunger is a signal. If I can trace it to a real intellectual or spiritual gap, I learn the right thing instead of chasing whatever is shiny.\\"\\n  howOften=\\"When a strong urge to learn something shows up, before acting on it\\"\\n  when=\\"At the moment I feel pulled toward a new topic\\"\\n  record=\\"Write the gap the hunger points to (intellectual, spiritual), then decide if it\'s worth filling now\\">\\n  Why do I hunger for a certain piece of knowledge? (Identify my intellectual gaps and my spiritual gaps.)\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Studying the big names in a field is the fastest way to inherit its hard-won structure instead of rediscovering it slowly on my own.\\"\\n  howOften=\\"At the start of any serious dive into a new field\\"\\n  when=\\"Right after I\'ve chosen a topic and before I start consuming randomly\\"\\n  record=\\"List the key figures, then collect what they wrote and worked on\\">\\n  After figuring out a topic I wish to learn more about, who are the big names in the field? (Find books they wrote, projects in the same context, lectures and videos to watch.)\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"What I do while observing decides what I retain. Notes, structure, and graphs turn passive consumption into something I can actually use later.\\"\\n  howOften=\\"Every time I sit down to study something\\"\\n  when=\\"While reading, listening, or watching\\"\\n  record=\\"Take notes, structure them, make graphs, and learn the setup even when I don\'t like it\\">\\n  While observing, how do I capture what I\'m taking in? (Take notes and document ideas, structure them into graphs, and learn the setup even if I don\'t like it.)\\n</Question>\\n\\n</QuestionSection>\\n\\n## Expanding your knowledge\\n\\n<SectionBanner why=\\"Seeking knowledge gets me started; expanding it is the deliberate work of mapping, classifying, and connecting what I take in so it compounds. The list below is the sequence I run.\\" />\\n\\nA sequence for expanding what I know:\\n\\n1. Map what I know and what I don\'t\\n2. Identify all the areas of research that overlap with my interests\\n3. Classify all the books I run into\\n4. Figure out what I intend to read and for what purpose\\n5. Identify an area in which I wish to grow and identify the books that will best help me achieve that goal\\n6. Take notes while reading\\n7. Expand the concepts I am aware of\\n8. Track all the books I\'ve read, and mark the pages that stand out\\n\\n## Learning methods\\n\\n<SectionBanner why=\\"There\'s more than one way to learn, and knowing the named methods lets me pick the right tool instead of always defaulting to \'read more.\'\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"If I only know one way to learn, I\'ll force every topic through it. Naming alternatives gives me options for the ones that don\'t fit.\\"\\n  howOften=\\"When a topic isn\'t sticking with my usual approach\\"\\n  when=\\"Before starting a subject that feels unfamiliar in shape\\"\\n  record=\\"Keep a list of learning methods and which kinds of material each suits\\">\\n  What are different ways in which I can learn?\\n</Question>\\n\\n</QuestionSection>\\n\\nTopics worth learning more about:\\n\\n- Socratic Method of Learning (ask questions and find answers)\\n- Instructional Design (crafting courseware to maximize how people learn)\\n- Bloom\'s Taxonomy: kinesthetic (do), knowledge (know), affective (feel)\\n- \\"Education is to understand complexity; training is to understand function\\"\\n\\n## Maintaining a learning mindset\\n\\n<SectionBanner why=\\"The hardest part isn\'t starting to learn, it\'s not stopping. These questions check whether I\'m still a sponge or have quietly gone stale.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A learning mindset is a habit that erodes silently. Checking on it regularly catches the drift before it becomes a rut.\\"\\n  howOften=\\"Weekly, as part of a lightweight reflection\\"\\n  when=\\"During a weekly review, when assessing my energy and curiosity\\"\\n  record=\\"Note whether I learned anything new this week, and what dulled my curiosity if I didn\'t\\">\\n  How do I stay in a state of continuous learning? Am I always being a sponge, making sure to never stop learning?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Boredom is data. The point where I get bored is usually the point where my learning method stopped fitting the material.\\"\\n  howOften=\\"Whenever I notice I\'ve checked out of something I was learning\\"\\n  when=\\"When my attention on a topic starts to fade\\"\\n  record=\\"Write down what was happening right before I lost interest\\">\\n  When do I get bored, and when do I stop learning?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Self-teaching vs needing a teacher\\n\\n<SectionBanner why=\\"Some things I can figure out alone; others need a guide. Knowing which is which keeps me from either struggling needlessly or outsourcing what I should own.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"A teacher is leverage, but also a dependency. Drawing the line tells me where to invest in help and where to build self-reliance.\\"\\n  howOften=\\"When deciding how to approach a new, difficult subject\\"\\n  when=\\"Before committing to either self-study or a course\\"\\n  record=\\"Note which topics I genuinely need a teacher for and why\\">\\n  What do I need a teacher to learn versus what can I learn on my own? Why do I need a teacher?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Understanding knowledge\\n\\n<SectionBanner why=\\"Fields aren\'t islands. Seeing where the sciences intersect and where they share tools makes everything I learn reinforce everything else.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"The intersections between fields are where the most transferable insights live. Asking about them turns isolated knowledge into a web.\\"\\n  howOften=\\"Occasionally, when I have enough across a few fields to compare\\"\\n  when=\\"During deeper reflection on how my subjects relate\\"\\n  record=\\"Sketch where my fields overlap and what tools cross between them\\">\\n  Where do the different sciences intersect? What is the ultimate goal of each? How can some benefit from others, and what tools can be used across them?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Capturing your learnings\\n\\n<SectionBanner why=\\"Knowledge I don\'t capture leaks away. These questions are about building the storehouse so what I learn stays findable and reusable.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I can\'t find what I learned, I didn\'t really keep it. A capture-and-organize habit is what makes learning compound over years.\\"\\n  howOften=\\"Weekly, to keep the capture habit alive\\"\\n  when=\\"After finishing a study session or a project\\"\\n  record=\\"A note system where each learning has a home, organized so I can retrieve it\\">\\n  How do I capture my learnings, and where? How will I organize and keep track of what I want to learn?\\n</Question>\\n\\n<Question\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Taking stock of what I\'ve already learned and noted keeps me from relearning the same things and shows me how far I\'ve come.\\"\\n  howOften=\\"Monthly, as a review of accumulated notes\\"\\n  when=\\"During a monthly reflection on progress\\"\\n  record=\\"Review my captured notes and the gotchas I\'ve collected\\">\\n  What have I already learned? What notes have I captured? What gotchas have I encountered?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"Diagrams force me to structure understanding, and they\'re far faster to revisit later than a wall of prose.\\"\\n  howOften=\\"When a learning is complex enough that a picture would help\\"\\n  when=\\"While capturing something with many moving parts\\"\\n  record=\\"Create the diagram and store it alongside the related notes\\">\\n  What diagrams will I create to capture my learnings?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"Tool and component knowledge is easy to lose between projects. A dedicated home for it saves me from rediscovering the same setup details.\\"\\n  howOften=\\"Whenever I learn something useful about a tool or component\\"\\n  when=\\"Right after wrestling with a tool\'s quirks\\"\\n  record=\\"A place to log lessons per tool and per software component\\">\\n  Where do I capture the things I learned about the different tools I have used, and about different software components?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-managing-your-tasks","metadata":{"permalink":"/thoughts/questions-for-managing-your-tasks","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-13-questions-for-managing-your-tasks.mdx","source":"@site/blog/2017-02-13-questions-for-managing-your-tasks.mdx","title":"What I Ask Myself: To Manage My Tasks","description":"The questions I ask to capture, track, and automate my tasks: their dependencies, triggers, and the recurring ones.","date":"2017-02-13T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":12.99,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-managing-your-tasks","title":"What I Ask Myself: To Manage My Tasks","kind":"question-set","sidebar_label":"My Tasks","description":"The questions I ask to capture, track, and automate my tasks: their dependencies, triggers, and the recurring ones.","authors":["oeid"],"tags":["productivity","question-set"],"date":"2017-02-13T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: About How I Learn","permalink":"/thoughts/questions-for-how-you-learn"},"nextItem":{"title":"What I Ask Myself: To Plan Across Horizons","permalink":"/thoughts/questions-for-planning-across-horizons"}},"content":"Tasks are the atoms of my work: the individual things that make up my plans and initiatives. But how I capture, track, and structure them determines whether my system actually serves me or just collects clutter. The questions below are prompts to interrogate my own task process: how tasks get in, how they move, what they depend on, and what could be automated.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Capturing tasks\\n\\n<SectionBanner why=\\"A task system is only as good as what makes it in. If capture is hard or unclear, half my work never reaches the list and lives in my head instead.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I\'m fuzzy on what my process is even supposed to do, I\'ll keep bolting on tools that don\'t fit the actual job.\\"\\n  howOften=\\"When setting up or overhauling my task system\\"\\n  when=\\"Before adopting a new tool or workflow\\"\\n  record=\\"A short spec of what my task process must let me do\\">\\n  What should I be able to do through my task-tracking process? How do I capture tasks and things that need to be done?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Without a clear model of what a \'task\' even is to me, my list ends up mixing thoughts, errands, and goals into mush.\\"\\n  howOften=\\"When my list feels chaotic or hard to scan\\"\\n  when=\\"During a cleanup of my task system\\"\\n  record=\\"Write down my model of a task and what tools it needs\\">\\n  What is my personal model of tasks? What tools do I need to better manage my tasks?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I only capture tasks when I\'m in planning mode, everything I think of in the moment slips away. Worth checking why capture happens at all.\\"\\n  howOften=\\"Occasionally, when reviewing how things enter my system\\"\\n  when=\\"When I notice tasks only appear during dedicated planning\\"\\n  record=\\"Note what actually triggers me to capture a task\\">\\n  Do I only capture tasks as \\"a planner\\"? Is planning the main reason tasks get captured?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Tracking tasks\\n\\n<SectionBanner why=\\"Capture gets tasks in; tracking is how I know where each one stands and what to touch next. Without it, the list rots into a pile I avoid.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Tracking tools and a clear progress signal are what let me trust the list instead of re-deriving my workload from memory each day.\\"\\n  howOften=\\"Weekly, as part of reviewing the system\\"\\n  when=\\"During a weekly review of progress\\"\\n  record=\\"Note the tools I use and how I read progress at a glance\\">\\n  What tools do I use to track what I have to do? How do I track my progress?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"daily\\"\\n  depth=\\"quick\\"\\n  why=\\"The daily question is the one that matters most: from everything on the list, what should I actually pick up today?\\"\\n  howOften=\\"Daily, when starting work\\"\\n  when=\\"At the start of each day, and when assigning myself something new\\"\\n  record=\\"A simple way to surface today\'s candidates from the full list\\">\\n  How do I figure out what I should be working on today? How do I assign myself a new task to do?\\n</Question>\\n\\n<Question\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A task system drifts toward clutter unless I actively maintain it. Asking how to keep it healthy is what prevents bankruptcy of the list.\\"\\n  howOften=\\"Monthly, as a maintenance pass\\"\\n  when=\\"During a monthly review of the system itself\\"\\n  record=\\"Capture the maintenance habits that keep the list usable over time\\">\\n  How will I better manage and maintain my tasks over time?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"A consistent tagging method is what lets me pull together scattered items, like every \'thought\' I\'ve had across many days, into one view.\\"\\n  howOften=\\"When refining how I categorize and retrieve tasks\\"\\n  when=\\"When I want a cross-cutting view of one kind of item\\"\\n  record=\\"Define my tags and how I\'d query across them\\">\\n  What is my tagging method? If I tag something as a \\"thought,\\" I want to see all the thoughts I\'ve had scattered across the days. Could I auto-derive all my tag lists scattered across the days?\\n</Question>\\n\\n<Question\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing how long tagged items take to finish tells me which kinds of work I underestimate, and where my process keeps leaking time.\\"\\n  howOften=\\"Monthly, when looking for ways to improve the process\\"\\n  when=\\"During a retrospective on how the system is serving me\\"\\n  record=\\"Track completion time per tag list, and log improvement ideas as they come\\">\\n  For things I append to a tag list, how long does it take me to complete them? How can I improve my task-tracking process, and what ideas have I had to improve it?\\n</Question>\\n\\n### Immediate tasks\\n\\n<SectionBanner why=\\"Underneath tracking sits the now: the small set I can act on this instant. These keep me anchored to the next concrete action instead of the whole pile.\\" />\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"daily\\"\\n  depth=\\"quick\\"\\n  why=\\"Most stuckness comes from staring at everything at once. Narrowing to the immediate list and the next action per project is what unblocks me.\\"\\n  howOften=\\"Daily, and whenever I feel stuck\\"\\n  when=\\"At the start of a work session\\"\\n  record=\\"A short immediate list with the next action named for each project\\">\\n  What do I need to do right now? What is my immediate task list? What is the next action for each project?\\n</Question>\\n\\n### Desire to do\\n\\n<SectionBanner why=\\"Not everything I want to do has earned a task yet. Surfacing those wants keeps the wishlist honest and shows me when a desire has quietly died.\\" />\\n\\n<Question\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The gap between what I want to do and what I\'ve captured is where good ideas go to be forgotten. Naming it brings them back into view.\\"\\n  howOften=\\"Weekly, as a sweep of uncaptured wants\\"\\n  when=\\"During a weekly review of my backlog\\"\\n  record=\\"A list of wants not yet turned into tasks, with when each one started\\">\\n  What do I want to do but haven\'t captured as a task? What are all the different things I want to do? When did I want to do these different things?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"When a desire fades, that\'s worth noticing. The reason I stopped wanting something often reveals what actually matters to me now.\\"\\n  howOften=\\"Monthly, when pruning the wishlist\\"\\n  when=\\"When I catch myself no longer wanting something I once did\\"\\n  record=\\"Note what I stopped wanting and why\\">\\n  Did I ever stop wanting to do something? Why?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Capturing triggers\\n\\n<SectionBanner why=\\"Some tasks shouldn\'t live on a fixed date but should fire when something happens in the world. These questions are about catching those event-driven needs.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Trigger-based reminders match a task to the moment it\'s actually relevant, which beats a calendar date I\'ll ignore when the context is wrong.\\"\\n  howOften=\\"When designing reminders, or when a date-based one keeps failing\\"\\n  when=\\"When I notice a task really belongs to an event, not a date\\"\\n  record=\\"List the events and conditions that should spawn a task\\">\\n  What triggers or events lead to me needing to do something? Could I have trigger-based reminders, such as when a store has a sale, when I get my paycheck, when I arrive somewhere, when I check my phone, or when I go too long without doing something?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Recurring tasks\\n\\n<SectionBanner why=\\"A surprising share of my work repeats. Naming the recurring tasks (and dreaming up ways to regenerate them) keeps me from re-entering the same things forever.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Recurring tasks are the backbone of a routine. If I don\'t name them, I either forget them or waste effort recreating them by hand each cycle.\\"\\n  howOften=\\"Weekly, when the recurring set comes due\\"\\n  when=\\"During a weekly review of routines\\"\\n  record=\\"A list of recurring tasks, plus ideas for scripting their recreation\\">\\n  What recurring tasks do I have? Could a script recreate tasks based on hashtags like a recurring \\"weekly\\" marker?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Predicting potential tasks\\n\\n<SectionBanner why=\\"Beyond what already recurs, there\'s work I can see coming. These questions explore predicting tasks before they\'re due so they appear at the right moment on their own.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"If my system could spot recurring patterns from how I phrase things and predict the next occurrence, I\'d offload the remembering entirely.\\"\\n  howOften=\\"When thinking about how to make the system smarter\\"\\n  when=\\"During design work on the task tooling itself\\"\\n  record=\\"Sketch how auto-detection of recurring tasks would work\\">\\n  How do I predict potential tasks? Could task tracking auto-detect recurring tasks from similar wordings and predict when I\'ll have to do the task next?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"A named, dynamic date (like \'NextFinancialReview\') is more durable than a hard-coded one: it always lands on the right day even as the schedule shifts.\\"\\n  howOften=\\"When designing scheduling features\\"\\n  when=\\"When a fixed date keeps needing manual adjustment\\"\\n  record=\\"Define the dynamic dates I\'d want and their frequencies\\">\\n  Could I have dynamic dates? Instead of specifying an exact date, I specify something like \\"NextFinancialReview\\" and the task appears on the appropriate day, with configurable frequencies per dynamic date and the ability to postpone to the next occurrence.\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"A date range, rather than a single day, lets a long-running goal show up every day it\'s active so I don\'t lose track of it mid-span.\\"\\n  howOften=\\"When a goal spans a period rather than a single deadline\\"\\n  when=\\"When setting up a multi-day or multi-week goal\\"\\n  record=\\"Note where range-based goals would help and how they\'d display\\">\\n  Could I specify a date range for a goal (a start and end date) so the goal applies for the whole period and shows up on every day in that span?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Task dependencies\\n\\n<SectionBanner why=\\"Tasks rarely stand alone. Many can\'t start until something else finishes or some event occurs, and modeling that is what keeps me from working things in the wrong order.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"If I can\'t express that task B waits on task A (or on an event), my list lies to me about what\'s actually workable right now.\\"\\n  howOften=\\"When planning work with real ordering constraints\\"\\n  when=\\"When sequencing a project with prerequisites\\"\\n  record=\\"Map the dependency graph: what blocks what, and the order to do them\\">\\n  How do I declare that some tasks cannot be started until other events finish? What tasks depend on other tasks? What is blocking my tasks? In what order should tasks be done?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Knowing the exact criterion that makes a task active keeps me from picking up work that isn\'t ready, which is a quiet waste of effort.\\"\\n  howOften=\\"When defining when a blocked task becomes workable\\"\\n  when=\\"When a task depends on a condition rather than a date\\"\\n  record=\\"Write the activation criteria and how dependencies are represented\\">\\n  What triggers a task to become active and ready to be worked on? How do I represent dependencies between tasks and events? What is the criteria for beginning work on a task?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Being able to say \'when A completes, start B\' or \'when A starts, start B\' captures the real shapes of dependency, not just a single naive one.\\"\\n  howOften=\\"When the dependency is more nuanced than simple completion\\"\\n  when=\\"When designing how dependencies are declared\\"\\n  record=\\"Note the dependency types I need (on-complete, on-start, on-event) and what else a task can depend on\\">\\n  How do I declare task dependencies, including tasks that depend on events occurring and tasks that depend on other tasks (e.g. when task A *completes* start task B, or when task A *starts* start task B)? What else can a task depend on?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Extracting events from my todos and templating their annotations would let a due date appear automatically the moment a condition is met.\\"\\n  howOften=\\"When building event handling into the tooling\\"\\n  when=\\"During deeper design of the task system\\"\\n  record=\\"Sketch event extraction and templated annotations like \'beforeEarningX\'\\">\\n  Could I extract a list of events from these kinds of todos, and template-ize event annotations (like \\"beforeEarningX\\")? Could I auto-add a due date as soon as the `@when` condition is met?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Automating tasks\\n\\n<SectionBanner why=\\"The least valuable work is the bookkeeping of tasks themselves. These questions hunt for what a script could create, recreate, or remind me of without my touch.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Every bit of task creation and reminding I can script is effort I get back. Automation is what keeps the system from becoming its own chore.\\"\\n  howOften=\\"When looking for friction to remove from the process\\"\\n  when=\\"When a piece of task admin keeps repeating by hand\\"\\n  record=\\"List what can be automated: creation, recurring management, reminders\\">\\n  What task creation can be automated? What repetitive task management can be scripted? How can I automate reminders and recurring tasks?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"Tying todo creation to things I already do (stashing commits, photographing a product, adding to a cart) catches intentions at the exact moment they form.\\"\\n  howOften=\\"When designing automatic capture hooks\\"\\n  when=\\"When I notice a real-world action that implies a task\\"\\n  record=\\"Note the action-to-todo hooks worth building\\">\\n  Should I create todos for the number of stashed commits I have (implying a backlog, since it hasn\'t been committed)? Should I create a todo for things I want to buy when I take a picture of a product, or when I add an item to my Amazon cart?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Breaking down work\\n\\n<SectionBanner why=\\"Some work is bigger than a task and deserves to be a story with a reason behind it. These questions are about decomposing effort and knowing why it\'s worth doing.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Stories carry the \'why\' and the shape of a feature; tasks alone can hide the purpose. Knowing when to use which keeps work meaningful, not just numerous.\\"\\n  howOften=\\"When deciding how to break down a larger piece of work\\"\\n  when=\\"At the start of a feature or initiative\\"\\n  record=\\"Note the why, the ordered steps, and the resources each task needs\\">\\n  What is the advantage of using stories over tasks? Reduced number of tickets? Why (as a company) are we working on this feature? What needs to be done to accomplish this feature, and in what order? Which resources should I allocate to perform a specific task?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Structuring your tasks\\n\\n<SectionBanner why=\\"Tasks nest: subtasks roll up into tasks, tasks into projects, projects into goals. Seeing that hierarchy is what keeps a flat list from hiding the bigger picture.\\" />\\n\\n*Note: if weight is at least 1, the task is repetitive: it should happen around once a week.*\\n\\nThe structure of my tasks is as follows:\\n\\n```\\nGoal A\\n     Project A for Goal A\\n          Research A for Project A\\n          Task A for Project A\\n              Subtask A for Task A\\n         Subtask B for Project A\\n     Task B for Goal A\\n     Research B for Goal A\\n    Subtask C for Goal A\\n```"},{"id":"questions-for-planning-across-horizons","metadata":{"permalink":"/thoughts/questions-for-planning-across-horizons","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-13-questions-for-planning-across-horizons.mdx","source":"@site/blog/2017-02-13-questions-for-planning-across-horizons.mdx","title":"What I Ask Myself: To Plan Across Horizons","description":"The questions I ask to turn my priorities into time-bound plans, from today and this week all the way out to a lifetime.","date":"2017-02-13T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":9.79,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-planning-across-horizons","title":"What I Ask Myself: To Plan Across Horizons","kind":"question-set","sidebar_label":"Planning Horizons","description":"The questions I ask to turn my priorities into time-bound plans, from today and this week all the way out to a lifetime.","authors":["oeid"],"tags":["productivity","question-set"],"date":"2017-02-13T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Manage My Tasks","permalink":"/thoughts/questions-for-managing-your-tasks"},"nextItem":{"title":"What I Ask Myself: To Prioritize My Work","permalink":"/thoughts/questions-for-prioritizing-your-work"}},"content":"Priorities only become real when they meet a calendar. Planning is how I translate \\"what matters\\" into time-bound action across horizons: today, this week, this quarter, this year, and the whole arc of a life. Use the questions below as prompts. Pick the horizon you\'re working in, and answer honestly rather than aspirationally.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Understanding time and planning\\n\\n<SectionBanner why=\\"Before I plan a single day, I need to understand what planning even is and how I actually spend my time, not how I imagine I do.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"There\'s a sharp difference between what I think I should spend time on and what I actually spend it on. Facing the real answer is where honest planning starts.\\"\\n  howOften=\\"Weekly, as an honest audit of where time went\\"\\n  when=\\"During a weekly review of the past week\\"\\n  record=\\"Write where my time actually went, not where I meant it to go\\">\\n  This is NOT *what should I spend my time on*, but rather *what do I actually spend my time on*. How am I spending my time?\\n</Question>\\n\\n<Question\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I don\'t know what makes a good plan or how often to make one, every plan I write is a guess about its own quality.\\"\\n  howOften=\\"When establishing or revisiting my planning cadence\\"\\n  when=\\"When deciding what and how often to plan\\"\\n  record=\\"Note what a good plan must address and how often I replan\\">\\n  What should be planned? How are we planning for the future? What makes a good plan? What questions should a plan address? How often should I plan?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Untangling whether prioritizing is part of planning, or a step before it, clarifies the whole pipeline from wants to scheduled action.\\"\\n  howOften=\\"When my planning and prioritizing feel tangled together\\"\\n  when=\\"During reflection on how my process fits together\\"\\n  record=\\"Write my own definition of planning and where prioritizing sits in it\\">\\n  Is prioritizing a part of planning? Or do I figure out my priorities first, and then figure out how to collectively realize them? As a do-er, I grow a list of things I want to do; as a planner, I figure out what I should do first. What is planning? What does it mean to plan?\\n</Question>\\n\\n</QuestionSection>\\n\\nA few framing ideas worth holding onto:\\n\\n- Planning is part of time management; it is preparing for a future.\\n- A plan is a sequential set of steps to help everyone reach a common goal.\\n- If we don\'t all adhere to the same plan, we may step on each other\'s toes.\\n- A plan considers priorities and chains them together.\\n\\n*Further reading:* [Time management vs. task management](https://toggl.com/blog/time-management-vs-task-management) and [Planning in time management](https://www.managementstudyguide.com/planning-in-time-management.htm).\\n\\n## Knowing why you\'re doing what you\'re doing\\n\\n<SectionBanner why=\\"A plan without a reason behind each item is just a schedule. I want to always be able to justify what I\'m doing and what I\'m choosing not to do.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"daily\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I can\'t justify why I\'m doing this and not something else, I\'m probably running on autopilot rather than intention.\\"\\n  howOften=\\"Daily, and any time someone could reasonably ask for a status\\"\\n  when=\\"At any point during the day when I question my focus\\"\\n  record=\\"Be able to state, in a sentence, what I\'m working on and why\\">\\n  Why am I doing what I am doing, and can I justify why I am not doing something else? At a given point in time, what am I working on? As a programmer, what features am I working on? As a learner, what am I learning? As a doer, what projects am I working on?\\n</Question>\\n\\n</QuestionSection>\\n\\nI don\'t know when I\'ll be asked for a status update, but I need to be confident and clear, because I should always know what I am doing and why I am doing it.\\n\\n## Recurring activities\\n\\n<SectionBanner why=\\"Across all my horizons, the same handful of activities keep showing up. Naming them tells me what my time really goes toward, week after week.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"The things I constantly find myself doing are the true shape of my life. Sorting them by type shows whether I\'m growing, fixing, or just spinning.\\"\\n  howOften=\\"Weekly, when reviewing how I spent my effort\\"\\n  when=\\"During a weekly reflection\\"\\n  record=\\"Tally my recurring activities by category (learning, doing, organizing, fixing, marketing)\\">\\n  What are the things I constantly find myself doing? Which of these am I doing: learning something new, doing something interesting, organizing myself, fixing a gap or weakness, or marketing myself?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Daily planning\\n\\n<SectionBanner why=\\"The shortest horizon. A day is where intention either turns into action or quietly evaporates, so I name what today is actually for.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"daily\\"\\n  depth=\\"quick\\"\\n  why=\\"A day without a named plan defaults to whatever\'s loudest. Stating today\'s intent keeps me steering instead of reacting.\\"\\n  howOften=\\"Daily, first thing\\"\\n  when=\\"At the start of each day\\"\\n  record=\\"A short, concrete plan for the day\\">\\n  What should I accomplish today? What is my plan for today?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Weekly planning\\n\\n<SectionBanner why=\\"A week is the unit where I can both refine the last stretch and set up the next. It\'s the rhythm where most of my real adjustments happen.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Planning a week as a connected arc (refine, introduce, align toward next week) is what keeps weeks from being seven disconnected days.\\"\\n  howOften=\\"Weekly, on the weekend\\"\\n  when=\\"When kicking off the upcoming week\\"\\n  record=\\"Note what to refine, what to introduce, and how this week sets up the next\\">\\n  What should we refine from last week? What should we introduce this week? What are we planning on doing next week? How should we align what we do this week to make next week easier to work with?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Quarterly planning\\n\\n<SectionBanner why=\\"A quarter is long enough to make real progress and short enough to course-correct. It\'s where weekly motion connects to yearly ambition.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Quarterly objectives are the bridge between this week and this year. If a quarter doesn\'t ladder up to the year, the year won\'t happen by accident.\\"\\n  howOften=\\"Quarterly, at the start of each quarter\\"\\n  when=\\"When setting objectives for the new quarter\\"\\n  record=\\"Name the quarter\'s objectives and how they feed the yearly goals; snapshot my learning plans\\">\\n  What should I accomplish this quarter? What are my quarterly objectives? How does this quarter contribute to my yearly goals? Have I snapshotted my learning plans so I know what I\'ve committed myself to learn over time?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Yearly planning\\n\\n<SectionBanner why=\\"A year is long enough to change who I am, not just what I finish. This horizon is where I name what I want to be different by next year.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"What I commit to this year, and what I deliberately do differently, shapes the person I become. A vague year produces a vague version of me.\\"\\n  howOften=\\"Once a year, during annual planning\\"\\n  when=\\"At the start of a new year\\"\\n  record=\\"Write the year\'s must-do list: books, scripts, topics, and what I\'ll do differently\\">\\n  What must I accomplish this year? What will I do differently this year? What books will I read, scripts will I write, and topics will I learn this year? This year, it will be valuable if I\u2026\\n</Question>\\n\\n</QuestionSection>\\n\\n## Lifetime timeline\\n\\n<SectionBanner why=\\"The widest horizon. Zooming out to decades reveals the trajectory my daily choices are quietly drawing, and whether it points where I want to go.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Most people never look this far out, so their life\'s arc is set by default. Naming the trajectory and its milestones turns drift into direction.\\"\\n  howOften=\\"Once a year, as a dedicated long-view exercise\\"\\n  when=\\"During deep annual reflection\\"\\n  record=\\"Sketch where I see myself across 30, 20, 10, 5, and 1 year, and the milestones in between\\">\\n  Where do I see myself in 30 years, 20 years, 10 years, 5 years, 1 year? What is the trajectory of my life? What major milestones do I want to hit?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Planning techniques\\n\\n<SectionBanner why=\\"Knowing the horizons isn\'t enough; I need techniques for replanning and for sizing a learning plan. These are the mechanics that make the horizons usable.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A replanning rhythm (weekly kickoffs, a carry-over versus new-work view, quarterly work-and-learning plans) keeps plans alive instead of stale on day three.\\"\\n  howOften=\\"Weekly for replanning, quarterly for the deeper plan\\"\\n  when=\\"On the weekend for the week, and at quarter start for the bigger plan\\"\\n  record=\\"Keep a weekly Venn of new versus carried-over work, and publish what I do each week\\">\\n  How often do I \\"replan\\"? (Weekly: put together weekly plans and kick them off on the weekend. Keep a Venn diagram each week of how much new stuff versus how much carries over. Publish the things I do weekly. Quarterly: plan for work and learnings.)\\n</Question>\\n\\n<Question\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Sizing a learning plan into fixed chunks (10-week blocks, with a daily time budget) makes \'I want to learn X\' into something a calendar can actually hold.\\"\\n  howOften=\\"Quarterly, when building a learning plan\\"\\n  when=\\"When committing to learn something over a real stretch of time\\"\\n  record=\\"Define the chunk size, what I can learn in 10 weeks, and the daily time I\'ll spend\\">\\n  How much time should be considered in each chunk of the plan? A learning plan should be in 10-week chunks: what can I learn in 10 weeks? How much time will I spend each day?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Reflecting on and assessing plans\\n\\n<SectionBanner why=\\"A plan I never check against reality is a wish. These questions close the loop: am I on track, and when do I adjust, re-prioritize, or change course entirely?\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Without periodic honesty about whether I\'m on track, I can stay busy on a path that no longer serves me. Reflection is the steering, not the trip.\\"\\n  howOften=\\"Monthly for progress, quarterly for trajectory\\"\\n  when=\\"During monthly review and quarterly re-evaluation\\"\\n  record=\\"Note whether I\'m on track, what to adjust, and how often I\'ll re-check\\">\\n  Am I on track with my plan? What adjustments need to be made? How do I reflect on my plans? How often are my learning checkpoints, and how often do I re-evaluate my learnings, assess my trajectory, generate progress reports, and re-prioritize?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The hardest planning question is when to abandon a path for a better one. Asking it deliberately keeps sunk cost from steering my future.\\"\\n  howOften=\\"Quarterly, or whenever a path stops paying off\\"\\n  when=\\"When deciding whether to continue or switch direction\\"\\n  record=\\"Write the case for staying versus switching, judged against everything else I could do\\">\\n  When do I decide whether to continue down this path, or switch to something more beneficial for the time? Are the things I am pursuing the best things to learn right now, considering all the things I could be doing? What functionality is valuable, what is my function to society, and what am I passionate about producing versus consuming?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-prioritizing-your-work","metadata":{"permalink":"/thoughts/questions-for-prioritizing-your-work","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-13-questions-for-prioritizing-your-work.mdx","source":"@site/blog/2017-02-13-questions-for-prioritizing-your-work.mdx","title":"What I Ask Myself: To Prioritize My Work","description":"The questions I ask to decide what to work on now: my prioritization factors, what to deprioritize, and how to build a roadmap.","date":"2017-02-13T00:00:00.000Z","tags":[{"inline":true,"label":"productivity","permalink":"/thoughts/tags/productivity"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":12.37,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-prioritizing-your-work","title":"What I Ask Myself: To Prioritize My Work","kind":"question-set","sidebar_label":"Prioritizing Work","description":"The questions I ask to decide what to work on now: my prioritization factors, what to deprioritize, and how to build a roadmap.","authors":["oeid"],"tags":["productivity","question-set"],"date":"2017-02-13T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Plan Across Horizons","permalink":"/thoughts/questions-for-planning-across-horizons"},"nextItem":{"title":"What I Ask Myself: To Align Action and Ambition","permalink":"/thoughts/questions-for-aligning-actions-with-ambitions"}},"content":"Capturing every idea is the easy part. The hard part is deciding what to do *now* from a pile of initiatives, projects, and things I want to learn. These are the questions I ask myself to focus, weigh trade-offs, deprioritize what no longer matters, and lay it all out on a roadmap. Read them slowly and answer the ones that snag on something.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Current focus\\n\\n<SectionBanner why=\\"Everything starts with \'now.\' Before any framework, I name the single thing I most need to be working on at this moment.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"daily\\"\\n  depth=\\"quick\\"\\n  why=\\"From a pile of possible work, only one thing can be the most valuable right now. Naming it cuts through the paralysis of too many options.\\"\\n  howOften=\\"Daily, when choosing what to work on\\"\\n  when=\\"At the start of a work session\\"\\n  record=\\"Name the single most valuable thing I can do now, and what I genuinely need to be doing\\">\\n  What question(s) am I focused on answering now? What initiatives have I decided to work on now? What projects should I work on, and what things should I learn now? What\'s the most valuable thing I can do now? What do I **need** to be working on right now?\\n</Question>\\n\\n</QuestionSection>\\n\\n## How I prioritize\\n\\n<SectionBanner why=\\"Naming the now is easy; defending it is the work. This is the method underneath the choice: how I actually decide what\'s important and what wins.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"deep\\"\\n  why=\\"If I can\'t articulate how I decide what\'s important, my priorities are really just whatever feels urgent or appealing in the moment.\\"\\n  howOften=\\"Weekly, when setting the week\'s focus\\"\\n  when=\\"When choosing one initiative over another\\"\\n  record=\\"Write the basis I\'m deciding on and which goals each candidate serves\\">\\n  How do I prioritize my initiatives? How do I determine what I should and shouldn\'t do? How do I decide what is important? On what basis do I decide to work on one thing over another? What goals do each of the priorities at hand help me attain?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Desire quietly tilts what I call \'important.\' Naming that pull keeps me honest about when I\'m choosing on merit versus on mood.\\"\\n  howOften=\\"Weekly, and whenever a choice feels driven by impulse\\"\\n  when=\\"When I notice I\'m leaning toward what I feel like doing\\"\\n  record=\\"Note where my desires are steering my goals, and whether that\'s the right call\\">\\n  How are my desires influencing the goals I focus on? What do I feel like doing right now? When do I actually decide to work on something?\\n</Question>\\n\\n<Question\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Sorting what I need to learn from what I merely want to learn, and seeing each candidate\'s dependencies, turns a flat list into a ranked one.\\"\\n  howOften=\\"Weekly, when ordering learning objectives\\"\\n  when=\\"When my learning backlog gets too long to act on\\"\\n  record=\\"Sort objectives by need-vs-want and note what each depends on\\">\\n  What do my candidates depend on, and what are the ultimate goal(s) I\'m prioritizing against? How will I sort my learning objectives/initiatives? Which do I NEED to learn vs WANT to learn? Which ones have I recently started?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Prioritization factors\\n\\n<SectionBanner why=\\"A good priority decision rests on factors I can name and weigh. These questions make those factors explicit so the call isn\'t pure gut feel.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"If I can\'t name the factors I weigh, or which factor outranks which, I can\'t make a consistent decision twice. Explicit factors make priority repeatable.\\"\\n  howOften=\\"When refining how I make priority calls\\"\\n  when=\\"When two candidates feel equally worthy\\"\\n  record=\\"List my prioritization factors and rank them against each other\\">\\n  What factors should I consider when prioritizing? What must I consider? How do the factors compare, and which factor is more important than the others? How do I determine this?\\n</Question>\\n\\n<Question\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Ease, urgency, and interest are quick, practical tiebreakers when the deeper factors come out even. They keep me moving instead of stalling on analysis.\\"\\n  howOften=\\"When breaking a tie between candidates\\"\\n  when=\\"When several options pass the main filters\\"\\n  record=\\"Note which is easiest, which is most urgent, and which I\'m most drawn to\\">\\n  Which one is easier to do? Which one needs to be done now? Which ones am I most interested in doing? How often should I address each of these concerns? What\'s the difference between a factor and a concern?\\n</Question>\\n\\n</QuestionSection>\\n\\nPrinciples:\\n\\n- A task is higher in priority if it overlaps with many of my goals.\\n- A task is higher in priority if it needs to be done immediately and is important.\\n\\n## By life category\\n\\n<SectionBanner why=\\"Priorities aren\'t only about work. Sweeping across career, growth, organization, learning, and family makes sure no whole area of life gets silently dropped.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Looking at \'now\' through each life category catches the area I\'ve been neglecting, which a single work-only list would quietly hide.\\"\\n  howOften=\\"Weekly, as a balance check across life areas\\"\\n  when=\\"During a weekly review of all my roles\\"\\n  record=\\"Note the one thing to do now in each category: career, growth, organization, learning, family, marketing\\">\\n  What do I need to be doing now to advance my career, become more organized, learn, grow, advance our family, and better market myself? What projects do I need to work on now?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Balancing priorities\\n\\n<SectionBanner why=\\"Two things constantly compete for my time: doing and learning. This question is about holding that balance instead of letting one starve the other.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I only ever do, I stop growing; if I only ever learn, I stop shipping. Naming the balance keeps both in play.\\"\\n  howOften=\\"Weekly, when allocating time\\"\\n  when=\\"When learning and doing are competing for the same hours\\"\\n  record=\\"Note the split between learning and projects, and what I must learn before I can do new things\\">\\n  How do I balance learnings and projects? What can I do now vs what do I need to learn to do new things?\\n</Question>\\n\\n</QuestionSection>\\n\\n## What gets prioritized\\n\\n<SectionBanner why=\\"Before prioritizing, it helps to know what\'s even in the running and where it lives. This question is about taking inventory across roles and tools.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"I can\'t prioritize what I can\'t see. If candidates are scattered across Jira, roles, and a roadmap, taking inventory is the prerequisite to any ranking.\\"\\n  howOften=\\"Monthly, as an inventory sweep\\"\\n  when=\\"When my candidates feel scattered or incomplete\\"\\n  record=\\"List what I\'m prioritizing and where each item lives; decide what goes on the roadmap vs the task manager\\">\\n  What goes on the roadmap, and what goes straight to my task manager? What do I prioritize, and what don\'t I prioritize? What are the things I am prioritizing, and where are they found? Are these in Jira? Are they scattered across roles? What initiatives am I prioritizing?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Prioritizing projects\\n\\n<SectionBanner why=\\"Projects are the big bets, so they deserve their own filter. These questions check a project against what I\'ll learn, enjoy, and can share before I commit.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A project is a large commitment of time, so it should clear a bar: does it teach me something, overlap with what I enjoy, and is it worth doing first?\\"\\n  howOften=\\"Monthly, or when choosing the next project\\"\\n  when=\\"When deciding which project to start\\"\\n  record=\\"Score each project against learning, enjoyment, marketability, and distributability\\">\\n  How do I figure out what project(s) I should work on? How many of these does it check off: will it help me learn what I want to learn, does it overlap with what I enjoy, do I want to work on it? How marketable is this project? How distributable is it? What else should I consider? What projects am I passionate about? Of all the things I want to do, what should I do first?\\n</Question>\\n\\n</QuestionSection>\\n\\nI generally work on projects for one of two reasons: to learn something new, or to save myself time.\\n\\n### Aligning projects to objectives\\n\\n<SectionBanner why=\\"A project earns its place by advancing a real objective. These questions force each project to declare which goal it serves and what it\'ll teach me.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A project that doesn\'t advance an objective is a hobby wearing a work costume. Mapping each one to a goal keeps my effort pointed somewhere.\\"\\n  howOften=\\"Monthly, when reviewing the project slate\\"\\n  when=\\"When justifying why a project is on the list\\"\\n  record=\\"For each project, name the objective it advances, the result, and what it\'ll teach me\\">\\n  What projects help me advance specific objectives, and what objectives does each project help me meet? Why should I work on specific projects? What is the result of working on each, and what will each teach me? What projects can advance my self-marketing objective (are any in a repo I can share, will any help me learn what I want to learn)?\\n</Question>\\n\\n</QuestionSection>\\n\\n### Projects reflecting priorities\\n\\n<SectionBanner why=\\"My projects should be a mirror of my priorities. When they aren\'t, that mismatch is the signal that I\'m working on the wrong things.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"If my actual projects don\'t reflect my stated priorities, one of them is lying. Catching that gap is how I realign action with intent.\\"\\n  howOften=\\"Monthly, as an alignment check\\"\\n  when=\\"When I suspect my work has drifted from my priorities\\"\\n  record=\\"Note whether my projects reflect my priorities, and where they diverge from what I want to learn\\">\\n  How do my priorities affect the projects I actually work on? Do my projects reflect my priorities? Am I working on projects that push me to explore the things I want to do and learn? How do the things I work on align with what I want to learn? Can I commit to a personal project where I apply the things I learn?\\n</Question>\\n\\n</QuestionSection>\\n\\n### Evaluating projects\\n\\n<SectionBanner why=\\"Once a project is in motion, it still needs a rubric. These questions are how I judge each project\'s benefit, alignment, and what it showcases about me.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A consistent evaluation rubric (benefit, interest-alignment, learning overlap, what it showcases) keeps me from overrating projects just because they\'re already underway.\\"\\n  howOften=\\"Monthly, when reviewing active projects\\"\\n  when=\\"When deciding whether a project still deserves my time\\"\\n  record=\\"Score each project on benefit, alignment, learning overlap, and the skills it showcases\\">\\n  How will I evaluate each project? Why do I want to work on each, and what are the benefits? Which do I want to work on the most? How much does each align with my interests, overlap with what I want to learn, and reflect how I market myself? What does each project showcase about my skills, technical capabilities, and product design capabilities?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Deprioritizing\\n\\n<SectionBanner why=\\"Prioritizing is also about subtraction. These questions are the hard ones: what do I stop, drop, or admit I no longer actually want?\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A list only stays meaningful if things leave it. Naming what to stop is what makes room for what matters; deprioritizing is half of prioritizing.\\"\\n  howOften=\\"Weekly, as a pruning pass\\"\\n  when=\\"When my list has grown faster than I can act on it\\"\\n  record=\\"List what to stop, what to deprioritize, and the wants I\'ve outgrown\\">\\n  What should I stop doing? What should I deprioritize? What am I spending time on that isn\'t important? What are the things I wanted to do at some point that I no longer want to do?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Constructing a roadmap\\n\\n<SectionBanner why=\\"Priorities laid on a timeline become a roadmap. These questions place my goals in time and short-vs-long-term order so I can see the whole arc at once.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"A roadmap turns a flat list of goals into a sequence across time. Seeing where goals intersect, and which must come first, is what makes a long-term vision achievable.\\"\\n  howOften=\\"Quarterly, when laying out the bigger picture\\"\\n  when=\\"When planning across months and years\\"\\n  record=\\"Plot goals on a timeline, classified short vs long term, with their intersections and ordering\\">\\n  Can I see my goals over time, on a timeline? Can I classify my goals into short-term and long-term, and see timelines for each type? What are my desired end-goals by end of year and next year? Where do I see myself in 30 years, 20 years, 10 years? What is my vision for myself, and where do I want my goals to take me? How and where do all of my goals and milestones intersect? What goals are more important to complete than others? Given dependencies between goals, which should be prioritized first to attain them all in a timely fashion? Which activities should I focus on to collectively attain my goals?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Tracking dependencies\\n\\n<SectionBanner why=\\"Goals lean on other goals. Knowing which depend on which, and what\'s in the way, keeps me from chasing a goal whose prerequisites aren\'t ready.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A goal blocked by an unmet dependency isn\'t workable yet, no matter how much I want it. Mapping that keeps me from pushing on what can\'t move.\\"\\n  howOften=\\"Monthly, when reviewing goal progress\\"\\n  when=\\"When a goal feels stuck or out of reach\\"\\n  record=\\"Note which goals depend on others, and the obstacles in the way of each\\">\\n  What goals depend on other goals/activities? What obstacles are hindering me from accomplishing my goals?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Retrospecting\\n\\n<SectionBanner why=\\"Prioritization is a skill, and skills improve by review. These questions close the loop: how well did my last set of choices actually serve me?\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"The only way to prioritize better is to grade how I prioritized before. Naming what I shouldn\'t have done, and what I missed, is how the skill compounds.\\"\\n  howOften=\\"Monthly, as a retrospective\\"\\n  when=\\"At the end of a month or a project cycle\\"\\n  record=\\"Write what worked, what I wrongly prioritized, what I missed, and how to get better\\">\\n  How well did my prioritization work? What did I prioritize that I shouldn\'t have? What did I miss? How can I get better at prioritizing? What shortcomings have I observed?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-aligning-actions-with-ambitions","metadata":{"permalink":"/thoughts/questions-for-aligning-actions-with-ambitions","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-aligning-actions-with-ambitions.mdx","source":"@site/blog/2017-02-11-questions-for-aligning-actions-with-ambitions.mdx","title":"What I Ask Myself: To Align Action and Ambition","description":"The questions I return to when I want to check whether my actions match my ambitions, and decide what to stop, start, or do more of.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":12.27,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-aligning-actions-with-ambitions","title":"What I Ask Myself: To Align Action and Ambition","kind":"question-set","sidebar_label":"Aligning Action","description":"The questions I return to when I want to check whether my actions match my ambitions, and decide what to stop, start, or do more of.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Prioritize My Work","permalink":"/thoughts/questions-for-prioritizing-your-work"},"nextItem":{"title":"What I Ask Myself: To Challenge My Own Assumptions","permalink":"/thoughts/questions-for-challenging-your-own-assumptions"}},"content":"Ambitions are easy to declare and hard to live up to. The gap between the two shows\\nup in what I actually do all day. These are the questions I use to close that gap: to\\nnotice where my actions drift from what I claim to want, and to decide what to stop,\\nwhat to start, and what to double down on. I pick the ones that make me a little\\nuncomfortable.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Action-ambition alignment\\n\\n<SectionBanner why=\\"My calendar tells the truth my intentions don\'t. These questions hold my daily actions up against my stated ambitions and name the gap, which is the whole reason the rest of the work exists.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"This is the whole question in one line: do the things I actually do line up with what I say I want? Most of the gap between ambition and outcome lives here, and naming it is the first honest step to closing it.\\"\\n  howOften=\\"Monthly, as the core alignment check\\"\\n  when=\\"When I feel busy but not like I\'m moving toward what I claim to want\\"\\n  record=\\"Write a plain yes or no, then the single biggest place my actions and ambitions diverge\\">\\n  Do your actions match your ambitions?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Laying my current actions next to my ambitions makes the misalignment visible instead of vaguely felt. Seeing them side by side turns \'something\'s off\' into a specific gap I can actually act on.\\"\\n  howOften=\\"Monthly, alongside the question above\\"\\n  when=\\"When I want to locate exactly where my effort and my aims part ways\\"\\n  record=\\"Two columns, actions and ambitions; draw lines between matches and circle the orphans on each side\\">\\n  What are your current actions, and what are your ambitions? Where is the misalignment? What actions actually align with your ambitions?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Alignment is diagnosis; this is the prescription. Naming what I\'m actually going to do to succeed turns the gap I\'ve found into a concrete plan instead of just a clearer picture of being stuck.\\"\\n  howOften=\\"Monthly, after diagnosing the misalignment\\"\\n  when=\\"Once I\'ve seen the gap and need to commit to closing it\\"\\n  record=\\"Write the specific actions I\'ll take to succeed, with the first one starting this week\\">\\n  What are you going to do to be successful?\\n</Question>\\n\\n</QuestionSection>\\n\\n## What to stop doing\\n\\n<SectionBanner why=\\"Progress is often subtraction, not addition. The quiet \'why do I have to do this?\' that surfaces when I\'m resisting something is a useful signal that it may need to stop, so these questions hunt for what to cut.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"That flash of \'why do I have to do this?\' is data, not just complaint. The resistance often points at something that doesn\'t serve my ambitions and should be cut, so this question reads the resistance instead of ignoring it.\\"\\n  howOften=\\"Monthly, and any time that resentment flares up\\"\\n  when=\\"When I catch myself resisting a task and want to know what the resistance is telling me\\"\\n  record=\\"Note what triggered the resistance, then ask whether the task actually serves anything I want\\">\\n  Why do you have to do this? What does that resistance tell you?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming what I do that doesn\'t serve my ambitions, and then committing to stop it, is the highest-leverage move I can make, because every hour freed is an hour returned to what matters. Identifying the dead weight is harder than it sounds; it usually hides as \'normal.\'\\"\\n  howOften=\\"Monthly, as a deliberate subtraction pass\\"\\n  when=\\"When my days are full but my ambitions aren\'t moving\\"\\n  record=\\"List what doesn\'t serve my ambitions, then pick the one thing I\'ll actually stop this month\\">\\n  What are you doing that doesn\'t serve your ambitions? What should you stop doing?\\n</Question>\\n\\n</QuestionSection>\\n\\n## What to start doing\\n\\n<SectionBanner why=\\"The most useful starting questions begin with \'why,\' because they surface the thing I keep avoiding. These questions name what I\'ve been putting off and turn it into something I\'ll actually begin.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Stacking \'why haven\'t you,\' \'why can\'t you,\' and \'why don\'t you\' wears down the excuse until the real reason shows. The thing I keep avoiding is usually the thing that would move me most, which is exactly why I avoid it.\\"\\n  howOften=\\"Monthly, when something keeps not getting started\\"\\n  when=\\"When I\'ve been meaning to begin something and keep not\\"\\n  record=\\"Answer each \'why\' honestly; the answer I least want to write is the one to act on\\">\\n  Why haven\'t you done it? Why can\'t you? Why don\'t you?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Once I know what I\'ve been avoiding, this names the concrete thing to begin that would actually close the gap. Starting something new is how alignment becomes forward motion instead of just a cleaner diagnosis.\\"\\n  howOften=\\"Monthly, paired with the avoidance question above\\"\\n  when=\\"When I\'ve surfaced what I\'m avoiding and need to commit to starting it\\"\\n  record=\\"Write the one new thing I\'ll start, and the specific first action that begins it\\">\\n  What should you start doing to align with your ambitions?\\n</Question>\\n\\n</QuestionSection>\\n\\n## What to increase doing\\n\\n<SectionBanner why=\\"Alignment isn\'t only about stopping and starting; it\'s also about feeding what\'s already working. These questions find the things I should simply do more of, especially the gift-developing ones that need more time than they get.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"The things already working that I should do more of are the easiest wins, since the hard part of starting is done. The trap is that I under-feed them while chasing new things, so this question protects what\'s already paying off.\\"\\n  howOften=\\"Monthly, as a quick amplification check\\"\\n  when=\\"When I want to grow what\'s working instead of only fixing what isn\'t\\"\\n  record=\\"Name what\'s working and deserves more of me; block real time for it next month\\">\\n  What are you doing that you should do more of?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Some aligned activities are starved of the time and energy they need to matter. Naming them is how I move them from \'nice when I get to it\' to a real, protected slot, because alignment without time invested is just good intentions.\\"\\n  howOften=\\"Monthly, when allocating my time\\"\\n  when=\\"When something that genuinely serves my ambitions keeps getting squeezed out\\"\\n  record=\\"List the under-fed aligned activities; assign each a concrete time and energy budget\\">\\n  What activities align with your ambitions but need more time and energy?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Fully using my talents and developing my gifts is where doing more compounds over time. Asking it directly keeps me from leaving my best abilities idle while I stay busy with lesser things, which is the most expensive kind of misalignment.\\"\\n  howOften=\\"Quarterly, as a stewardship check\\"\\n  when=\\"When I notice a strength I keep neglecting while busy elsewhere\\"\\n  record=\\"Write whether I\'m fully using my talents, then one concrete way I\'ll develop a neglected gift\\">\\n  How will you fully utilize your talents? Are you developing your gifts?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Challenging yourself\\n\\n<SectionBanner why=\\"Alignment without stretch turns into a comfortable rut. These questions check whether I\'m actually at the edge of my comfort zone, and whether the pressure I\'m putting on myself is the kind that forms a diamond or just wears me down.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I\'m not at the edge of my comfort zone, I\'m probably coasting, and coasting feels like alignment but isn\'t growth. This question checks whether my actions are actually stretching me toward my ambitions or just keeping me comfortable.\\"\\n  howOften=\\"Monthly, as a stretch check\\"\\n  when=\\"When things feel a little too easy and I suspect I\'ve stopped growing\\"\\n  record=\\"Answer honestly whether I\'m at my edge; if not, name the next thing that would put me there\\">\\n  Are you challenging yourself? Are you at the edge of your comfort zone? How are you challenging yourself?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Where I fall short of my own expectations is where my self-knowledge sharpens fastest. The pressure-into-a-diamond framing reminds me that the right kind of pressure forms me, while the wrong kind just grinds, and the why behind the shortfall tells which it is.\\"\\n  howOften=\\"Quarterly, when reviewing where I missed my own mark\\"\\n  when=\\"When I\'ve fallen short of what I expected of myself and want to understand why\\"\\n  record=\\"Write where and why I fell short; decide whether the fix is more pressure or a kinder, smarter kind\\">\\n  Where and why do you fall short of your expectations? How do you pressure yourself to become a diamond?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Progress and purpose alignment\\n\\n<SectionBanner why=\\"It\'s possible to be busy, even challenged, and still drifting away from my purpose. These questions zoom out to ask whether all the motion is actually forward, and whether it\'s pointed at what I\'m here to do.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Actions can align with my ambitions and still miss my purpose, which is the deeper alignment. This question checks the highest level: not just whether I\'m productive, but whether the productivity is pointed at what I\'m actually here to do.\\"\\n  howOften=\\"Quarterly, as the deepest alignment check\\"\\n  when=\\"When my work is going well but feels disconnected from why I started\\"\\n  record=\\"Write whether the work serves my purpose; if not, name what\'s pulling it off course\\">\\n  Is what you are doing in tune with your purpose?\\n</Question>\\n\\n<Question\\n  power={[\'chisel\', \'anvil\']}\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The stop-X-start-Y question makes the cost of misalignment vivid by naming who I could become if I traded the wrong activity for the right one. It turns a vague sense of waste into a concrete, motivating swap.\\"\\n  howOften=\\"Quarterly, when weighing a real trade\\"\\n  when=\\"When I sense one activity is crowding out something far more worthwhile\\"\\n  record=\\"Name the specific X to drop and Y to take up, and the version of me that swap creates\\">\\n  What could you be if you stopped doing X and started doing Y?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Motion and progress aren\'t the same; I can be active and still slipping backward. Asking whether I\'m moving forward or back, progressing or stagnating, cuts through the comfort of mere busyness to ask if it\'s actually getting me anywhere.\\"\\n  howOften=\\"Monthly, as a direction check\\"\\n  when=\\"When I\'m active but unsure whether I\'m actually advancing\\"\\n  record=\\"Answer plainly forward or back, progressing or stagnant, and the evidence for which\\">\\n  Are you moving forward, or moving back? Are you making progress, or are you stagnated?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Effort and values\\n\\n<SectionBanner why=\\"Alignment has two tests: am I giving it everything I\'ve got, and does what I\'m doing actually reflect what I believe? These questions check both my effort and my integrity at once.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"\'All you can with what you have\' is the effort test, stripped of excuses about what I lack. It asks whether I\'m fully using my actual circumstances rather than waiting for better ones, which is where most wasted potential hides.\\"\\n  howOften=\\"Monthly, as an honest effort check\\"\\n  when=\\"When I\'m tempted to blame my circumstances for what I haven\'t done\\"\\n  record=\\"Write whether I\'m truly using what I have, then the one resource I\'m leaving idle\\">\\n  Are you doing all you can with what you have?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Actions that clash with my values create a quiet friction that drains me even when I\'m succeeding. This is the integrity test of alignment: not just whether my actions serve my ambitions, but whether they honor what I actually believe.\\"\\n  howOften=\\"Monthly, as an integrity check\\"\\n  when=\\"When I feel an unease about how I\'m achieving something, even though it\'s working\\"\\n  record=\\"Name where my actions and values clash; decide what to change so they stop fighting\\">\\n  Do your actions resonate with your values?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Intentions\\n\\n<SectionBanner why=\\"Before action comes intention, and a muddy intention produces scattered action. Naming clearly what I intend to do is what gives everything downstream a direction to point at.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Stating my intentions plainly is what separates deliberate action from drift. A clear intention is the seed every aligned action grows from, so naming it precisely keeps the rest of the day from running on autopilot.\\"\\n  howOften=\\"Monthly, and at the start of anything significant\\"\\n  when=\\"When I\'m about to begin something and want it pointed on purpose\\"\\n  record=\\"Write the intention in one clear sentence; check later whether my actions actually carried it out\\">\\n  What are your intentions? What do you intend to do?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Taking action\\n\\n<SectionBanner why=\\"All the reflection only matters if it ends in a move. These questions close the loop: naming the concrete thing I\'ll do toward my goals and the plan that carries it into tomorrow.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"This converts everything above into a committed move, because alignment that never reaches action is just well-organized wishing. Naming exactly what I\'ll do to achieve my goals is where reflection finally becomes momentum.\\"\\n  howOften=\\"Monthly, as the closing commitment\\"\\n  when=\\"At the end of any alignment review, before I let myself stop\\"\\n  record=\\"Write the specific actions toward my goals, each with a date or trigger attached\\">\\n  What will you do to achieve your goals?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Change has a price, and a plan for tomorrow is how I actually pay it instead of admiring the idea. Asking what it takes keeps me honest about the cost, and turns \'I should change\' into a concrete plan I can start on in the morning.\\"\\n  howOften=\\"Weekly, when setting up the next stretch\\"\\n  when=\\"When I\'ve decided to change something and need it to survive contact with tomorrow\\"\\n  record=\\"Write tomorrow\'s specific plan and the one habit or choice the change actually requires\\">\\n  What does it take to change, to set a plan for tomorrow?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-challenging-your-own-assumptions","metadata":{"permalink":"/thoughts/questions-for-challenging-your-own-assumptions","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-challenging-your-own-assumptions.mdx","source":"@site/blog/2017-02-11-questions-for-challenging-your-own-assumptions.mdx","title":"What I Ask Myself: To Challenge My Own Assumptions","description":"The questions I use to turn the lens on my own thinking, surface what I\'m assuming, and steelman the side I disagree with.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":6.76,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-challenging-your-own-assumptions","title":"What I Ask Myself: To Challenge My Own Assumptions","kind":"question-set","sidebar_label":"My Assumptions","description":"The questions I use to turn the lens on my own thinking, surface what I\'m assuming, and steelman the side I disagree with.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Align Action and Ambition","permalink":"/thoughts/questions-for-aligning-actions-with-ambitions"},"nextItem":{"title":"What I Ask Myself: To Discover What Interests Me","permalink":"/thoughts/questions-for-discovering-your-interests"}},"content":"Most of the time we use questions to learn about the world. This set turns the lens\\naround and points it at your own reasoning. The goal isn\'t to win an argument with\\nyourself, it\'s to notice where you\'ve stopped looking. Use these when you feel\\nunusually certain, when you\'re defending a position hard, or when you suspect you\'re\\nonly collecting evidence that flatters what you already believe. Pick the ones that\\nmake you a little uncomfortable.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Identifying what to question\\n\\n<SectionBanner why=\\"Before you can challenge a belief you have to catch it in the act. These questions help me notice where my certainty is sitting so I know where to aim.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"You can\'t examine a belief you haven\'t named. This question makes me slow down and say out loud what I\'m actually assuming, which is half the work.\\"\\n  howOften=\\"Weekly, or any time I notice I feel certain\\"\\n  when=\\"When I\'m about to make a decision based on something I\'ve never questioned\\"\\n  record=\\"Jot the assumption in a sentence so it stops being invisible\\">\\n  How do you question yourself? In what context are you questioning your life, your growth?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming the position I\'m holding right now turns a vague feeling of certainty into something I can actually inspect. Most bad reasoning hides in assumptions I never bothered to state.\\"\\n  howOften=\\"Whenever I catch myself defending something hard\\"\\n  when=\\"In the middle of a disagreement, or before committing to a plan\\"\\n  record=\\"Write the position as a clear claim, then list what it quietly assumes\\">\\n  What are you assuming right now? What arguments or positions are you currently holding?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Challenging your thinking\\n\\n<SectionBanner why=\\"It is easy to collect evidence that flatters what I already believe. This cluster forces me to go looking for the parts that hurt.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I\'m only finding evidence that agrees with me, I\'m not thinking, I\'m decorating. Actively hunting for discomforting evidence is the cheapest way to catch a blind spot before it costs me.\\"\\n  howOften=\\"Any time I feel a strong conviction forming\\"\\n  when=\\"When the evidence has been suspiciously one-sided\\"\\n  record=\\"List the strongest piece of evidence against your own view\\">\\n  Are you looking for discomforting evidence?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"core\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Assuming I might be wrong is the single most useful habit I have. It keeps me curious instead of defensive, and it is the difference between learning and just being loud.\\"\\n  howOften=\\"On any decision that matters\\"\\n  when=\\"Before I commit, especially when I\'m most sure\\"\\n  record=\\"Write the specific way you could be wrong, not a vague disclaimer\\">\\n  Are you considering where you are wrong? How might you be wrong?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"My conclusions are only as good as my inputs. Interrogating the information itself (its source, its freshness, its bias) catches errors upstream of my reasoning.\\"\\n  howOften=\\"When a conclusion rests on a single source or stat\\"\\n  when=\\"Before citing or acting on information I haven\'t vetted\\"\\n  record=\\"Note where the information came from and what it might be missing\\">\\n  What problems do you have with the information you\'re relying on?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Attachment to an argument is usually about ego, not truth. Asking why I\'m so adhered to it separates \'this is correct\' from \'I don\'t want to lose.\'\\"\\n  howOften=\\"When I notice I\'m getting heated\\"\\n  when=\\"When defending a position feels personal\\"\\n  record=\\"Write the honest reason you\'re holding on, then ask if it\'s a reason or an excuse\\">\\n  Why are you so adhered to your argument?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Considering opposing views\\n\\n<SectionBanner why=\\"The fastest way to test a belief is to genuinely understand its opposite. These questions make me argue the other side as if I meant it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"If I can\'t state the opposite side fairly, I don\'t actually understand my own position, I just inherited it. Steelmanning the other view is the real test of whether I\'ve thought it through.\\"\\n  howOften=\\"On any contested belief\\"\\n  when=\\"Before I dismiss a view I disagree with\\"\\n  record=\\"Write the best version of the opposing argument, not the weakest\\">\\n  Have you heard the opposite side of the argument?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"A position can feel right and still be built on a logical gap. Hunting for flaws in my own structure is more reliable than waiting for someone else to find them for me.\\"\\n  howOften=\\"When the stakes of being wrong are high\\"\\n  when=\\"Before presenting or acting on a conclusion\\"\\n  record=\\"Name the weakest link in your own reasoning chain\\">\\n  Does your position contain any logical flaws?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Looking directly at the evidence that contradicts me is uncomfortable, which is exactly why it works. The contradicting evidence is where I\'m most likely to be wrong and least likely to look.\\"\\n  howOften=\\"On any strong conviction\\"\\n  when=\\"When I\'ve been avoiding a particular fact or counterexample\\"\\n  record=\\"Write down the contradicting evidence plainly, without softening it\\">\\n  What evidence contradicts or challenges your position?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"If a single honest conversation couldn\'t move me at all, my belief isn\'t a conclusion, it\'s a wall. This question measures how open I actually am versus how open I claim to be.\\"\\n  howOften=\\"When I notice I\'m unwilling to budge\\"\\n  when=\\"In the middle of a disagreement that feels stuck\\"\\n  record=\\"Estimate the odds honestly, then ask what evidence would actually change them\\">\\n  What are the odds of your mind changing through a simple conversation?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Examining your reasoning\\n\\n<SectionBanner why=\\"These overlap on purpose: assumptions, evidence, and error are the three places reasoning quietly fails. Returning to them is a deliberate audit of the foundation.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Every conclusion sits on assumptions I usually never state. Dragging them into the open is the only way to check whether the foundation actually holds the weight I\'ve put on it.\\"\\n  howOften=\\"On any belief that drives a real decision\\"\\n  when=\\"When I\'m reasoning from something that \'everyone knows\'\\"\\n  record=\\"List the assumptions explicitly, then mark which ones you\'ve actually tested\\">\\n  What assumptions underlie your thinking?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Holding the supporting and the challenging evidence side by side keeps me honest. It stops me from counting the wins and ignoring the losses.\\"\\n  howOften=\\"Before reaching a firm conclusion\\"\\n  when=\\"When I\'ve only tallied the evidence on one side\\"\\n  record=\\"Make two columns: what supports the view and what challenges it\\">\\n  What evidence supports your position, and what evidence challenges it?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"core\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"This is the question I most want to skip, which is why I keep it. Genuinely sitting with how I might be wrong is the practice that keeps everything else honest.\\"\\n  howOften=\\"On every belief that matters\\"\\n  when=\\"When I feel most certain\\"\\n  record=\\"Write the most plausible way you\'re wrong, and what you\'d do if you were\\">\\n  How might you be wrong about this?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Categories worth questioning\\n\\n<SectionBanner why=\\"When I can\'t tell what I\'ve taken for granted, I run my thinking through these lenses one by one. Each one surfaces assumptions I\'d otherwise never notice.\\" />\\n\\nWhen you\'re not sure where to aim, run through these lenses and ask what you\'ve taken\\nfor granted in each.\\n\\n- Setting: the story you\'re telling, the location, the interactions\\n- Subjects: people and relationships\\n- Role models and the abstractions you\'re reasoning from\\n- Mood, emotions, celebration, kindness\\n- Necessity and circumstances\\n- Action, habits, time, buying habits, change\\n- Improvement and growth\\n- Concerns and worries\\n- Usability, accessibility, affordability\\n- Experience and memories\\n- Assumptions, false assumptions, problems, issues, insecurities\\n- Motivation and inspiration\\n- Likes, desires, dislikes"},{"id":"questions-for-discovering-your-interests","metadata":{"permalink":"/thoughts/questions-for-discovering-your-interests","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-discovering-your-interests.mdx","source":"@site/blog/2017-02-11-questions-for-discovering-your-interests.mdx","title":"What I Ask Myself: To Discover What Interests Me","description":"I can\'t list my interests on command, so I infer them from what I do. These are the questions I use to reverse-engineer my own curiosity.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":13.13,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-discovering-your-interests","title":"What I Ask Myself: To Discover What Interests Me","kind":"question-set","sidebar_label":"My Interests","description":"I can\'t list my interests on command, so I infer them from what I do. These are the questions I use to reverse-engineer my own curiosity.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Challenge My Own Assumptions","permalink":"/thoughts/questions-for-challenging-your-own-assumptions"},"nextItem":{"title":"What I Ask Myself: When I Face My Fears","permalink":"/thoughts/questions-for-facing-your-fears"}},"content":"Here\'s the trap with \\"what are you interested in?\\" you can\'t list your interests\\non command. You don\'t magically know them. The honest way in is to *infer* them\\nfrom what you already do, read, build, and avoid. These are the questions I use to\\nreverse-engineer my own curiosity: what draws me, what I\'m done with, and what\\nproblems I keep circling back to.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Inferring interests from what you do\\n\\n<SectionBanner why=\\"I can\'t recite my interests on demand, but my behavior leaks them constantly. These questions read the evidence I\'m already producing instead of waiting for a list to appear.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"What I actually do is more honest than what I say I\'m into. Reading my interests off my behavior bypasses the wishful thinking and shows me what genuinely pulls me.\\"\\n  howOften=\\"Monthly, as a review of how I spent my free attention\\"\\n  when=\\"When I want a true read on my interests, not an aspirational one\\"\\n  record=\\"List what you actually did this month, then name the interest each action implies\\">\\n  How can you infer what you\'re interested in from what you actually do?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A blank-page list of interests reflects who I think I should be. My actions reflect who I am. Mining my behavior closes that gap.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When the obvious list of interests feels stale or borrowed\\"\\n  record=\\"Track recurring behaviors and let the pattern name the interest\\">\\n  You can\'t list your interests on command, so what do your actions and behaviors reveal?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Interests hide in the things I do so automatically I forget they\'re choices. Deliberately scanning for the overlooked ones keeps my self-picture from going stale.\\"\\n  howOften=\\"Quarterly, when taking stock\\"\\n  when=\\"When I suspect I\'ve boxed myself into a too-narrow set of interests\\"\\n  record=\\"Note the interests you almost forgot to count, the quiet ones\\">\\n  How do you make sure you\'re not overlooking an interest when you take stock?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Topics and interests\\n\\n<SectionBanner why=\\"The obvious layer is still worth naming: what topics actually draw me, and which ones have quietly stopped. Tracking the change tells me where I\'m heading.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"quick\\"\\n  why=\\"Naming the topics I\'m drawn to gives me a map of where my attention wants to go, which is the raw material for everything from reading lists to projects.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When planning what to learn next\\"\\n  record=\\"Keep a running list of topics that genuinely pull you\\">\\n  What interests you? What topics, what learning topics?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"What I\'ve lost interest in is as revealing as what I\'ve gained. The why behind a faded interest often points at what I actually wanted from it all along.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I notice an old interest no longer pulls me\\"\\n  record=\\"Write what faded and what need it used to meet\\">\\n  What no longer interests you, and why were you once drawn to it?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"The \'want to check out\' list is a low-stakes way to follow curiosity before it has to justify itself. Some of these turn into real interests; most don\'t, and that\'s fine.\\"\\n  howOften=\\"Monthly, as a quick capture\\"\\n  when=\\"Any time something catches my eye\\"\\n  record=\\"Keep a tinker list of things to try with no commitment attached\\">\\n  What are you interested in tinkering with, learning more about, or checking out?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Problems and questions\\n\\n<SectionBanner why=\\"My deepest interests tend to show up as problems I can\'t stop poking at. These questions look for the puzzles I\'m drawn to solve, which is often the most durable signal.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The problems I genuinely want to solve are a stronger compass than the topics I find pleasant. Energy for a hard problem is the real signal of interest.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When deciding where to spend serious effort\\"\\n  record=\\"List the problems you\'d work on even if no one asked you to\\">\\n  What problems do you want to deal with or solve?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Liking the act of answering a question (not just wanting the answer) is what sustains me through the hard middle of any pursuit. That enjoyment is the interest itself.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When choosing what to dig into\\"\\n  record=\\"Note which questions you enjoy chasing, separate from the answers\\">\\n  What questions do you want to answer? Which do you *like* answering?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Curiosity spikes are involuntary, which makes them honest. The problems I naturally reach for, without being told to, mark the territory I\'m actually built for.\\"\\n  howOften=\\"Whenever I notice a sudden spike of curiosity\\"\\n  when=\\"In the moment a problem grabs me unprompted\\"\\n  record=\\"Capture what triggered the spike and what kind of problem it was\\">\\n  What problems spike your curiosity? What kinds of problems do you naturally solve?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Resources and tools\\n\\n<SectionBanner why=\\"What I want to read and which tools I reach for are quiet votes for my interests. These questions surface the resources my curiosity is already pointing at.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"The resources I keep meaning to explore are a backlog of interest. Naming them turns vague intention into something I can actually act on.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When building a learning or reading queue\\"\\n  record=\\"Maintain an explore list of resources you keep circling back to\\">\\n  What resources do you want to explore?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"What I want to read points at what I want to become. Books and blogs I\'m drawn to are interests in slow motion.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When my reading list feels aimless\\"\\n  record=\\"Keep a list of books and blogs that pull you, and revisit which ones you finish\\">\\n  What books interest you? What blogs?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"The tools I\'m itching to use often reveal the kind of work I want to do. Wanting to learn a tool is a hint about the problems I want it for.\\"\\n  howOften=\\"Whenever a new tool catches my attention\\"\\n  when=\\"When I feel the pull to try a new tool or library\\"\\n  record=\\"Note the tool and the work you imagine doing with it\\">\\n  What tools or software components are you interested in using?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Projects and research\\n\\n<SectionBanner why=\\"Projects are where interests get tested against reality. These questions help me pick the ones that pull several threads together and actually move me toward my goals.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A project I\'m drawn to that also serves a goal is rare and worth protecting. It is where genuine interest and real progress overlap, so it rarely fizzles out.\\"\\n  howOften=\\"Quarterly, when choosing what to build\\"\\n  when=\\"When deciding which project to commit to next\\"\\n  record=\\"Mark which candidate projects you actually want AND which serve a goal\\">\\n  What projects are you interested in, especially ones that help you reach your goals?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The projects that braid several interests together teach me the most per hour and reveal the connective tissue between things I care about. Those connections often are the real interest.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I\'m tempted by a single-purpose project\\"\\n  record=\\"Note which concepts a project would let you learn at once\\">\\n  What projects touch multiple concepts you want to learn, or tie a few together?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Research is interest with direction. Asking what I should study, especially in service of a project, keeps my curiosity productive instead of just endlessly browsing.\\"\\n  howOften=\\"Quarterly, when scoping a project\\"\\n  when=\\"At the start of a new project\\"\\n  record=\\"List what to research and which books would directly help\\">\\n  What should you research? What books would help with your projects?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Identifying your passions\\n\\n<SectionBanner why=\\"Passions are interests that have hardened into something I\'ll return to without prompting. These questions help me tell a real passion apart from a passing enthusiasm.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"A passion is what survives boredom, difficulty, and a lack of applause. Pinning down what makes something a passion (not just a hobby) tells me where to point a life, not just an afternoon.\\"\\n  howOften=\\"Once a year, as a deep reflection\\"\\n  when=\\"When deciding what to organize my life around\\"\\n  record=\\"Write your definition of a passion, then test your candidates against it\\">\\n  How can you pinpoint your different passions? What makes a passion a passion?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"\'What do you love?\' is easy to answer wishfully, so I need a way to be sure. Loving the practice and not just the idea is the test that separates a passion from a fantasy.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When I\'m tempted to call something a passion prematurely\\"\\n  record=\\"Write what you love, then look for evidence you keep returning to it\\">\\n  What do you love? How can you be sure you\'ve found a passion?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"My actions are the most reliable witness to my passions. Reflecting on what I repeatedly chose to do reveals passions I might never name on a blank page.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When my stated passions and my behavior seem to disagree\\"\\n  record=\\"Trace your recurring actions back to the passion driving them\\">\\n  Can you determine your passions by reflecting on your actions?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The books I read, the things I want to study, and the projects I finish form a portfolio of evidence. Reading my passion off that portfolio is more honest than guessing.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When I want proof, not a hunch, about a passion\\"\\n  record=\\"Inventory your books, studies, and finished projects and look for the through-line\\">\\n  Is your passion captured in the books you read, the things you want to study, the\\n  projects you\'ve completed?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Identifying your hatreds\\n\\n<SectionBanner why=\\"My aversions point at my interests from the other side. I hate wasting time on redundant work, which is probably exactly why I\'m drawn to automation, so what I can\'t stand is worth reading just as carefully as what I love.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"What I hate is a fast, honest signal. My aversions tend to be the mirror image of my interests, so naming them often reveals the interest hiding behind the irritation.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I notice a strong recurring aversion\\"\\n  record=\\"List what you hate, then ask what interest each aversion implies\\">\\n  What do you hate, and what interest does each aversion point at?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Activities and themes that recur\\n\\n<SectionBanner why=\\"When I look across what I keep doing, the themes repeat. I want to build, to identify and solve problems and puzzles. I\'m passionate about composing meaning, which may be why I\'m pulled toward both engineering and arts and crafts. I like designing things I think are valuable and seeing if they work. Part of my passion is pioneering, mixing and matching ideas, being creative. The recurring theme is structuring and organizing a thinking process so it can help others structure their own thoughts.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"The themes that recur across years, no matter the project, are the closest thing I have to a fixed interest. Naming the recurring theme tells me what I\'d care about in almost any context.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When reviewing a long stretch of work for patterns\\"\\n  record=\\"Write the one theme that shows up in most of what you choose to do\\">\\n  What theme keeps recurring across everything you choose to do?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Problems worth dedicating yourself to\\n\\n<SectionBanner why=\\"Some problems are big enough to organize a life around. These questions stress-test a problem against whether it\'s truly mine and whether enough people share it to matter.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"A problem worth a life is a different category from a problem worth an afternoon. Asking which one I\'d dedicate myself to forces me to find the interest that\'s load-bearing enough to build on.\\"\\n  howOften=\\"Yearly, as a long-horizon question\\"\\n  when=\\"During deep reflection on direction\\"\\n  record=\\"Name the one problem you\'d give years to, and why it stays interesting\\">\\n  What problem will you dedicate your life to solving?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Framing interests as challenges to overcome, for myself or others, turns curiosity into something with stakes. The challenges I\'m willing to take on reveal what I actually value enough to fight for.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When choosing what hard thing to take on\\"\\n  record=\\"List the challenges you\'d accept for yourself and for others\\">\\n  What challenges do you want to overcome, for yourself or for others?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The emotion I want my work to produce in others is a hidden statement of interest. It tells me what kind of impact I\'m actually chasing underneath the topic.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When defining the point of a project, not just its mechanics\\"\\n  record=\\"Name the feeling you want your work to leave in people\\">\\n  What emotions do you want people to feel from your work?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Not every problem I find interesting is worth solving. Evaluating how many people share a problem keeps my interest tethered to something that matters beyond me.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When deciding whether a problem deserves serious investment\\"\\n  record=\\"Estimate how widely shared the problem is, then weigh it against your interest\\">\\n  How do you evaluate your problems? How many people share them?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Narrowing down\\n\\n<SectionBanner why=\\"Eventually a wide field of interests has to collapse into a direction. These questions help me find the roles, works, and domains where my interests concentrate.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Roles carry pieces of purpose, not just tasks. Finding the ones that deeply interest me narrows a sprawling set of curiosities into something I could actually step into.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When considering a role, path, or specialization\\"\\n  record=\\"List the roles that pull you and which fragment of your purpose each carries\\">\\n  What roles deeply interest you, and which carry pieces of your purpose?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Specific works (not vague fields) are concrete enough to commit to. Identifying the works that genuinely interest me converts abstract interest into a real next step.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When choosing a concrete body of work to pursue\\"\\n  record=\\"Name the specific works, not categories, that hold your interest\\">\\n  What works deeply interest you?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Domains are where passion meets a place to apply it. Finding the domains that align with my passions tells me where my interests have the most room to grow into something real.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When deciding which field to commit to\\"\\n  record=\\"Map your passions to the domains where they fit best\\">\\n  What domains most align with your passions?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-facing-your-fears","metadata":{"permalink":"/thoughts/questions-for-facing-your-fears","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-facing-your-fears.mdx","source":"@site/blog/2017-02-11-questions-for-facing-your-fears.mdx","title":"What I Ask Myself: When I Face My Fears","description":"The questions I return to when I want to drag a fear into the open, see what\'s really threatening me, and find the courage to act anyway.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":8.43,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-facing-your-fears","title":"What I Ask Myself: When I Face My Fears","kind":"question-set","sidebar_label":"Facing Fears","description":"The questions I return to when I want to drag a fear into the open, see what\'s really threatening me, and find the courage to act anyway.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Discover What Interests Me","permalink":"/thoughts/questions-for-discovering-your-interests"},"nextItem":{"title":"What I Ask Myself: To Find Purpose","permalink":"/thoughts/questions-for-finding-your-purpose"}},"content":"Fear rarely announces itself honestly. It hides behind hesitation, busyness, and good excuses. These are the questions I return to when I want to drag a fear into the open and see it clearly, grouped by what they\'re really asking. Sit with the ones that make you flinch.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Core fears\\n\\n<SectionBanner why=\\"Most fear runs in the background, unnamed. These questions force me to say out loud what I\'m actually afraid of, because a fear I can name is one I can finally examine.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"core\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"A fear stays in control as long as it stays vague. Naming exactly what I\'m afraid of strips away its power to run me from the shadows, and it\'s the first move in every other question here.\\"\\n  howOften=\\"Whenever hesitation shows up without a clear reason\\"\\n  when=\\"When I notice I\'m avoiding something and don\'t quite know why\\"\\n  record=\\"Write the fear in one plain sentence, with no euphemism\\">\\n  What are you afraid of?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Some fears don\'t just scare me, they steer me. Identifying the ones actively holding me back separates the harmless fears from the ones quietly shrinking my life.\\"\\n  howOften=\\"When I feel stuck or smaller than I want to be\\"\\n  when=\\"When I catch myself not pursuing something I clearly want\\"\\n  record=\\"List the fears that are costing you specific opportunities\\">\\n  What fears are holding you back?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Most fear is really fear of loss. Naming what I\'m afraid to lose (status, safety, an identity, a person) exposes what I\'m actually protecting, which is usually more telling than the fear itself.\\"\\n  howOften=\\"When a fear feels disproportionate to the situation\\"\\n  when=\\"When I\'m clinging to something harder than it deserves\\"\\n  record=\\"Write what you\'re afraid to lose, then ask if it\'s really at risk\\">\\n  What do you fear losing?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"There\'s a difference between moving toward something and fleeing from something. Asking what I\'m running from catches the avoidance dressed up as motion, which is the hardest fear to see.\\"\\n  howOften=\\"When I\'m unusually busy but not at peace\\"\\n  when=\\"When my drive feels more like escape than pursuit\\"\\n  record=\\"Name what you\'re avoiding and what you\'d have to face if you stopped running\\">\\n  What are you running from?\\n</Question>\\n\\n</QuestionSection>\\n\\n## What threatens you\\n\\n<SectionBanner why=\\"Once I know my fears, I look at what\'s actually behind them. These questions separate real threats from imagined ones so I can spend my courage where it counts.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Once the fear of dying loses its grip, almost every smaller threat shrinks too. This question recalibrates the whole hierarchy of what I let scare me.\\"\\n  howOften=\\"Rarely, during deep reflection on mortality\\"\\n  when=\\"After a brush with loss, or in a season of unusual courage\\"\\n  record=\\"Write what still threatens you once the biggest fear is set aside\\">\\n  When you no longer fear dying, what else can threaten you?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming my opposition makes it concrete instead of looming. A clearly identified obstacle is something I can strategize against; a vague dread is not.\\"\\n  howOften=\\"When facing resistance to a goal\\"\\n  when=\\"When something or someone is standing between me and where I\'m trying to go\\"\\n  record=\\"Name the specific opposition, person, force, or circumstance\\">\\n  What opposition do you face?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing what threatens my goals lets me defend them on purpose. Most dreams don\'t die from one big attack; they erode from threats I never named and so never guarded against.\\"\\n  howOften=\\"When setting or reviewing a serious goal\\"\\n  when=\\"When I want to protect something I care about achieving\\"\\n  record=\\"List the real threats to your goals and one guard for each\\">\\n  What threatens your goals and dreams?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Overcoming fear\\n\\n<SectionBanner why=\\"Naming fear is only half the work. This cluster is about the move from fear to action: what dissolves the fear, what I\'d do without it, and how I pressure myself to grow through it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Fear of opposition usually rests on a few specific beliefs. Finding what actually removes that fear (preparation, faith, a reframe) gives me something to reach for instead of just bracing.\\"\\n  howOften=\\"When facing a specific opposition\\"\\n  when=\\"When fear of an obstacle is keeping me from acting\\"\\n  record=\\"Note what reliably shrinks your fear, then use it deliberately\\">\\n  What removes your fear of your opposition?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Pressure is what turns coal into diamond. Reframing fear as the pressure that forms me changes it from something to escape into something to use, as long as I choose the pressure on purpose.\\"\\n  howOften=\\"When I want to grow through a hard thing rather than around it\\"\\n  when=\\"When facing a challenge that could either crush me or make me\\"\\n  record=\\"Write how you\'ll apply pressure intentionally instead of letting it just happen\\">\\n  How do you pressure yourself to become a diamond?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'spark\']}\\n  priority=\\"core\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"This is the question that cuts straight to it. Imagining what I\'d do without the fear reveals what I actually want, and exposes how much of my current path is shaped by avoidance rather than desire.\\"\\n  howOften=\\"At any real decision point clouded by fear\\"\\n  when=\\"When I\'m choosing and can feel fear tilting the scale\\"\\n  record=\\"Write what you\'d do fearlessly, then ask what\'s truly stopping you\\">\\n  What would you do if you weren\'t afraid?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Fear left alone just loops. The move from fear to action is a skill, and asking how I make that move turns a paralyzing feeling into a concrete next step.\\"\\n  howOften=\\"Whenever fear has me frozen\\"\\n  when=\\"When I\'ve sat in fear long enough and need to break out of it\\"\\n  record=\\"Write the smallest action that moves you from frozen to moving\\">\\n  How do you move from fear to action?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Courage and faith\\n\\n<SectionBanner why=\\"Courage isn\'t the absence of fear, it\'s having something stronger to draw on. These questions find the source of my strength so I can reach for it when sight runs out.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Courage isn\'t a constant; it has sources. Knowing what gives me courage (a person, a purpose, a belief) lets me return to the well deliberately instead of hoping bravery shows up on its own.\\"\\n  howOften=\\"When I need to act despite fear\\"\\n  when=\\"Before facing something that frightens me\\"\\n  record=\\"Name your sources of courage and keep them close\\">\\n  What gives you courage?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Strength to continue is different from courage to start. Naming what keeps me going under sustained pressure tells me what to lean on when the fear is a long grind rather than a single leap.\\"\\n  howOften=\\"In long, hard stretches\\"\\n  when=\\"When I\'m worn down and tempted to quit\\"\\n  record=\\"Write what keeps you moving when it would be easier to stop\\">\\n  What gives you strength to keep going?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Acting without guarantees is the heart of facing fear. Walking by faith and not by sight is the practice of moving forward when I can\'t see the outcome, which is exactly when fear is loudest.\\"\\n  howOften=\\"When the path forward is uncertain\\"\\n  when=\\"When I have to commit before I can see how it turns out\\"\\n  record=\\"Note where you\'re demanding certainty before you\'ll move, and act anyway\\">\\n  How do you walk by faith and not by sight?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Trusting the process is what lets me keep working when results aren\'t visible yet. Knowing what helps me trust it keeps fear of wasted effort from pulling me off course early.\\"\\n  howOften=\\"When progress feels invisible\\"\\n  when=\\"When I\'m tempted to abandon something because I can\'t yet see it working\\"\\n  record=\\"Write what helps you trust the process when doubt creeps in\\">\\n  What helps you trust the process?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Facing opposition\\n\\n<SectionBanner why=\\"Opposition, rejection, and setbacks are where fear becomes real and unavoidable. These questions prepare me to meet them on purpose instead of being caught off guard.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"How I face opposition determines whether it stops me or sharpens me. Having a deliberate way to meet resistance keeps me from defaulting to flight or freeze in the moment.\\"\\n  howOften=\\"When opposition shows up\\"\\n  when=\\"When I\'m actively up against a person or force resisting me\\"\\n  record=\\"Write your approach to opposition before you\'re in the heat of it\\">\\n  How do you face your opposition?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Adversity is far less frightening when I\'ve prepared for it. Asking what prepares me converts a vague dread of hard times into a concrete readiness I can build in advance.\\"\\n  howOften=\\"During calm stretches, in preparation\\"\\n  when=\\"Before entering a season I expect to be difficult\\"\\n  record=\\"List what you can do now to be ready for the adversity you can see coming\\">\\n  What prepares you for adversity?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Fear of rejection stops more action than rejection itself ever does. Building a real way to handle rejection and setbacks defuses that fear, because I know I can survive the thing I\'m dreading.\\"\\n  howOften=\\"When risking rejection\\"\\n  when=\\"After a rejection or setback, and before risking another\\"\\n  record=\\"Write how you recover from a no, so the fear of one loses its grip\\">\\n  How do you handle rejection and setbacks?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-finding-your-purpose","metadata":{"permalink":"/thoughts/questions-for-finding-your-purpose","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-finding-your-purpose.mdx","source":"@site/blog/2017-02-11-questions-for-finding-your-purpose.mdx","title":"What I Ask Myself: To Find Purpose","description":"The questions I return to when I want to understand why I exist, what gives life meaning, and how I want to be remembered.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":27.89,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-finding-your-purpose","title":"What I Ask Myself: To Find Purpose","kind":"question-set","sidebar_label":"Finding Purpose","description":"The questions I return to when I want to understand why I exist, what gives life meaning, and how I want to be remembered.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: When I Face My Fears","permalink":"/thoughts/questions-for-facing-your-fears"},"nextItem":{"title":"What I Ask Myself: To Keep Growing","permalink":"/thoughts/questions-for-growing-yourself"}},"content":"I don\'t think purpose is something you find once and file away. It\'s something you\\ninterrogate. Over the years I\'ve collected the questions that actually move me when\\nI sit with them, and grouped them by what they\'re really asking. This is that\\ncollection: a menu of prompts for reflecting on why you exist, what gives you\\nmeaning, and how you want to be remembered. Pick the ones that sting a little.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Core purpose\\n\\n<SectionBanner why=\\"These are the hardest questions to answer and the most important to keep asking. Most people live their whole lives without a clear answer, and that gap shows up as restlessness, drift, and doing things for the wrong reasons.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Without a clear answer, every decision defaults to what feels comfortable or what others expect. This question is the foundation. Everything else you build on top of it inherits its quality.\\"\\n  howOften=\\"Once per year, and any time you feel like you\'re going through the motions\\"\\n  when=\\"During quiet periods of reflection, journaling sessions, or spiritual retreats\\"\\n  record=\\"Write a paragraph-length answer; revisit it annually to see how your answer has shifted\\">\\n  What is the purpose of your life?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"\'Purpose\' and \'objective\' aren\'t the same thing. Your objective is what you\'re working toward right now; your purpose is the reason any of it matters. Knowing the difference keeps you from confusing activity with meaning.\\"\\n  howOften=\\"Quarterly: objectives change; purpose should be more stable\\"\\n  when=\\"At the start of a new season, a new role, or when you feel scattered\\"\\n  record=\\"Keep it in one sentence. Update it when you genuinely believe it has changed.\\">\\n  What is your main objective?\\n</Question>\\n\\n<Question\\n  power={[\'spark\', \'fire\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"\'Meaning\' is the word that survives the reduction: when you strip away achievement, status, and comfort, what\'s left that still matters to you? This question goes deeper than purpose; it asks what you\'d still care about if you lost everything else.\\"\\n  howOften=\\"Once or twice a year, especially after loss or disruption\\"\\n  when=\\"After a major failure, a transition, or any moment that forces perspective\\"\\n  record=\\"Write freely without editing; the first answer is often the truest\\">\\n  What\'s the meaning of your life?\\n</Question>\\n\\n</QuestionSection>\\n\\n## What gives you meaning\\n\\n<SectionBanner why=\\"Knowing what drives you is a navigational tool. When you can name your motivators specifically, you can design your life to include more of them, and notice faster when they\'re missing.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"These four words point to different things. What gives you meaning is bigger than what motivates you today. Separating them reveals the layers, and shows you which ones are deep roots versus temporary fuel.\\"\\n  howOften=\\"Monthly: your answer will shift as your circumstances change\\"\\n  when=\\"When you feel energized, note what caused it. When you feel drained, note what\'s missing.\\"\\n  record=\\"Keep a running list of specific situations where you felt genuinely driven; the pattern IS the answer\\">\\n  What gives you meaning? What drives you? What motivates you? What moves you?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"This question finds your anchor point. When everything is hard, what is the thing that keeps you going? The answer is usually connected to something larger than yourself: a person, a belief, a commitment.\\"\\n  howOften=\\"Ask this in difficult stretches, not just in calm ones; the honest answer emerges under pressure\\"\\n  when=\\"When you\'re tired, discouraged, or seriously considering quitting something\\"\\n  record=\\"Note it in moments of real difficulty; revisit when you need to remind yourself\\">\\n  What gives you the strength to keep going forward?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Why you do what you do\\n\\n<SectionBanner why=\\"Most people act on autopilot: their reasons are inherited, unconscious, or borrowed from someone else. These questions surface the actual drivers so you can decide whether to keep them.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"Reasons matter because they determine sustainability. You can do anything for a while out of fear, pressure, or habit, but only the things you can articulate real reasons for will survive the hard stretches.\\"\\n  howOften=\\"Every six months, and any time you make a significant choice\\"\\n  when=\\"Before starting a new project, relationship, or commitment, and when evaluating whether to continue one\\"\\n  record=\\"Write the honest answer, not the socially acceptable one\\">\\n  Why do you do what you do? What are your reasons?\\n</Question>\\n\\n<Question\\n  why=\\"Beliefs and values are the code your decisions run on. Most people never examine this code; they just execute it. Making it explicit lets you update it intentionally instead of being quietly governed by values you inherited by accident.\\"\\n  howOften=\\"Once a year. Values shift slowly, but they do shift\\"\\n  when=\\"During annual reflection, after a major change in perspective, or when you notice a conflict between what you say you believe and how you act\\"\\n  record=\\"Write them out as a list; compare across years to see what\'s deepened and what\'s faded\\">\\n  What are your beliefs? What are your values?\\n</Question>\\n\\n<Question\\n  why=\\"This is the ROI question for your inner life. Goals, values, convictions, decisions, and plans are only worth what they actually produce in your character and your world. Asking the question forces an honest audit.\\"\\n  howOften=\\"Annually. This is a year-in-review question\\"\\n  when=\\"At the end of a year, a chapter, or a long-running commitment\\"\\n  record=\\"Write the honest answer. If the answer is \'not much,\' that\'s the most valuable data you can have.\\">\\n  What are your goals, values, convictions, decisions, and plans worth?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Legacy and remembrance\\n\\n<SectionBanner why=\\"Legacy questions are useful not because you should live for posterity, but because they clarify what actually matters to you when you zoom out far enough to escape the noise of the immediate.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"The refusal to be forgotten is often the most honest signal of what you think your life was for. But it\'s worth interrogating: do you want to be remembered for who you were, or for what you did? The answer shapes everything.\\"\\n  howOften=\\"Once a year; answers often change across decades of life\\"\\n  when=\\"During deep reflection periods, after experiencing the death of someone you admired\\"\\n  record=\\"Write it down and date it. Your answer at 30 will be different from your answer at 50\\">\\n  Why do you want to be remembered? Why do you refuse to be forgotten?\\n</Question>\\n\\n<Question\\n  why=\\"Wanting to be great is natural. But the reason behind that want determines whether it makes you better or just more anxious. Greatness for its own sake is a treadmill. Greatness in service of something real is a foundation.\\"\\n  howOften=\\"Annually, or when you notice competitive impulses driving your choices\\"\\n  when=\\"When you feel the pull of status or recognition, ask why it matters to you\\"\\n  record=\\"Write the honest answer, not the humble one\\">\\n  Why do you want to be great? Why do you want to be known?\\n</Question>\\n\\n<Question\\n  why=\\"Blessings (time, talent, opportunity, faith, relationships) aren\'t neutral gifts. They carry responsibility. This question reframes your life as stewardship rather than ownership, which changes how you evaluate your choices.\\"\\n  howOften=\\"Quarterly. Your blessings change as your life changes\\"\\n  when=\\"When taking stock of what you have, especially after periods of growth or provision\\"\\n  record=\\"List the blessings first, then write what difference you\'re actually making with each one\\">\\n  What difference will you make with the blessings you\'ve been given?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Vision and story\\n\\n<SectionBanner why=\\"You are writing a story whether you intend to or not. These questions ask you to become the author rather than just a character: to choose the arc, not just react to the events.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"A vision without a story is just a wish. Your story gives your vision context: where it came from, what it cost, who it\'s for. Most people have neither; the ones who lead something tend to have both.\\"\\n  howOften=\\"Annually. Your vision should evolve, and your story should deepen\\"\\n  when=\\"During long periods of reflection, writing retreats, or when preparing to share your work with others\\"\\n  record=\\"Write a narrative version, not a bulleted list. The story form reveals things the list hides\\">\\n  What is your vision? What is your own story?\\n</Question>\\n\\n<Question\\n  why=\\"Most people have stories that happened TO them. This question asks you to take the author\'s chair: to decide what the next chapter is, how the conflicts resolve, and what the ending means. Design is an act of agency.\\"\\n  howOften=\\"Once a year, as a dedicated writing exercise\\"\\n  when=\\"At major transitions: a new decade, a career change, a season ending\\"\\n  record=\\"Write it as a story, not a plan. The narrative form forces honesty about what you actually want.\\">\\n  How will you design your story? How does your story end?\\n</Question>\\n\\n<Question\\n  why=\\"Having a vision for humanity sounds ambitious, but it\'s actually clarifying. It tells you what problem you think is worth solving at the largest scale. Even a small answer is better than no answer; it gives you a direction to point your work.\\"\\n  howOften=\\"Once a year; this should deepen over time as you learn more about the world\\"\\n  when=\\"During big-picture reflection, when reading about history or social change, or when deciding what to commit to\\"\\n  record=\\"Write it in one or two sentences. If you can\'t compress it, you haven\'t found it yet\\">\\n  What vision do you have for humanity? Have you found your vision?\\n</Question>\\n\\n<Question\\n  why=\\"Believing your story is a form of self-respect. If you don\'t believe it, if you secretly think it\'s less important than other people\'s, you\'ll constantly underinvest in it. This question checks for that quiet undermining.\\"\\n  howOften=\\"Ask this whenever you catch yourself minimizing your work or path\\"\\n  when=\\"When comparing yourself to others, when you feel like your story isn\'t \'enough\'\\"\\n  record=\\"A yes/no with a sentence of honest explanation; the explanation is what matters\\">\\n  Do you believe your story? Is it as valuable as you think it is?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Mortality and finite time\\n\\n<SectionBanner why=\\"Mortality is the sharpest clarifier we have. Not to be morbid, but because the finite nature of time is what makes choices matter at all. These questions use that pressure productively.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"Most people act as though they have unlimited time. They don\'t, and deep down they know it. This question confronts the gap between knowing time is limited and actually living that way.\\"\\n  howOften=\\"Monthly. Keep it present, not just as a once-a-year thought\\"\\n  when=\\"At the start of any significant period: a new year, a new month, a new project\\"\\n  record=\\"Write a short answer and check whether your current week reflects it\\">\\n  Life is temporary: what will you do with the time you have?\\n</Question>\\n\\n<Question\\n  why=\\"Death isn\'t depressing when you use it as a teacher. It clarifies priorities faster than any other lens. Things that feel urgent stop feeling urgent, and things you\'ve been postponing suddenly seem urgent in a better way.\\"\\n  howOften=\\"A few times a year. Enough to keep it alive, not so often that it becomes abstract\\"\\n  when=\\"When you\'re stuck on small decisions, when you\'re anxious about what others think, when you feel like you\'ve lost perspective\\"\\n  record=\\"Write a paragraph on what it changes when you hold this in mind\\">\\n  You will die. How does that shape what matters?\\n</Question>\\n\\n<Question\\n  why=\\"The one-year constraint strips away social expectation, comfort-seeking, and long-game rationalization. What remains is what you actually care about. It\'s not a morbid exercise; it\'s a clarifier.\\"\\n  howOften=\\"Once a year, as a dedicated thought experiment\\"\\n  when=\\"During annual reflection, or any time you feel like you\'re living someone else\'s priorities\\"\\n  record=\\"Write the answer seriously. Not what you think sounds right, but what you\'d actually do\\">\\n  What would you do if you knew you only had one year left?\\n</Question>\\n\\n<Question\\n  why=\\"Most people say they know time is limited, but they don\'t behave that way. This question checks for the gap between belief and behavior. The answer is usually uncomfortable, which makes it useful.\\"\\n  howOften=\\"Monthly. Check it against your current calendar and commitments\\"\\n  when=\\"When reviewing how you\'ve spent the past month, when you feel like you\'re drifting\\"\\n  record=\\"A yes/no, then a specific example that proves it\\">\\n  Are you living as if your time is limited?\\n</Question>\\n\\n<Question\\n  why=\\"These two questions are different in a useful way. What will remain is about contribution; how knowing it ends changes how you live is about urgency. Together they push toward intentional living without tipping into anxiety.\\"\\n  howOften=\\"Annually. This is the year-in-review version of the mortality question\\"\\n  when=\\"At the end of a year, at a significant birthday, after losing someone\\"\\n  record=\\"Write both answers. The gap between them is often where the real work lives.\\">\\n  What will remain when you\'re gone? How does knowing life ends change how you live today?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Divine creation and becoming your best\\n\\n<SectionBanner why=\\"These questions assume that you were made with intention: that your capacity, your gifts, and your potential aren\'t accidents. Sitting with that assumption raises the stakes in a productive way.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"This question reframes your existence as purposeful at the source. Even if you\'re uncertain about faith, the question is useful: what would it mean to live as though you were made for something specific? The answer changes how you use your time.\\"\\n  howOften=\\"Annually, and during seasons of doubt or searching\\"\\n  when=\\"During prayer, spiritual retreat, or any moment of deep introspection about your path\\"\\n  record=\\"Write the answer as a personal conviction, not a theological argument\\">\\n  Why did God create you? What were you created to do?\\n</Question>\\n\\n<Question\\n  why=\\"\'Best version of yourself\' is not a marketing phrase; it\'s an honest benchmark. Most people know what it would look like for them to be operating at their best. The question is whether they\'re moving toward it or away from it.\\"\\n  howOften=\\"Monthly. This should be a regular check, not an annual abstraction\\"\\n  when=\\"When reviewing your habits, relationships, and outputs for the past month\\"\\n  record=\\"Write a specific gap: here is what my best self looks like; here is where I actually am\\">\\n  Are you becoming the best version of yourself?\\n</Question>\\n\\n<Question\\n  why=\\"Potential isn\'t the same as talent. Fulfilling your God-given potential is about full expression, not just of what you\'re good at, but of what you were made to offer. This question asks whether you\'re leaving any of that on the table.\\"\\n  howOften=\\"Quarterly. Potential is long-horizon, but the inputs are monthly\\"\\n  when=\\"When evaluating whether to take on something new, when you feel underused or overextended\\"\\n  record=\\"Write what full expression would look like, then write what you\'re actually doing\\">\\n  What does it mean to fulfill your God-given potential?\\n</Question>\\n\\n<Question\\n  why=\\"Stewardship is a more useful frame than ownership for gifts. If they\'re given to you, then using them well is a responsibility, not just an option. This question makes underuse feel like what it is: a failure to honor what you\'ve been entrusted with.\\"\\n  howOften=\\"Twice a year\\"\\n  when=\\"During spiritual reflection, during performance reviews of your own life\\"\\n  record=\\"List the gifts, then write one honest sentence about whether you\'re honoring each one\\">\\n  What gifts were you given to steward? Are you living up to what you were made for?\\n</Question>\\n\\n<Question\\n  why=\\"\'Best version\' needs to be specific to be useful. This question asks you to paint the picture clearly, and then to name the actual obstacle: not a vague one, but the specific thing standing between you and that version.\\"\\n  howOften=\\"Quarterly. The obstacle changes; the vision should stay relatively stable\\"\\n  when=\\"When you feel stuck, when you\'re about to make a significant decision about your time\\"\\n  record=\\"Write both: the vision AND the specific obstacle. The second one is where the work is.\\">\\n  What would the best version of you look like? What\'s stopping you from becoming who you were meant to be?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Discovering your calling\\n\\n<SectionBanner why=\\"Calling isn\'t usually announced; it\'s discovered by noticing patterns. What you keep returning to, what you can\'t help caring about, what feels effortless to you and impossible to others: these are the signals. These questions help you read them.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"\'Better than everyone else\' sounds arrogant, but it\'s a useful thought experiment. Not literally, but what is it that you bring that\'s yours? What have you cultivated that others haven\'t? That asymmetry often points to calling.\\"\\n  howOften=\\"Annually. Your answer should deepen and sharpen over time\\"\\n  when=\\"When considering what to invest in, what to offer, what to double down on\\"\\n  record=\\"Write a specific list. Not general traits, but specific capabilities\\">\\n  What makes you unique? What can you do better than everyone else?\\n</Question>\\n\\n<Question\\n  why=\\"Love is a better signal than skill alone. What you love more than anyone else is what you\'ll pursue without needing external motivation. That self-sustaining energy is what calling is built on.\\"\\n  howOften=\\"Annually, and whenever you\'re evaluating how to spend a significant chunk of time\\"\\n  when=\\"When choosing between opportunities, when wondering whether to specialize or generalize\\"\\n  record=\\"Write the intersection: what you love AND what the world needs. The overlap is the callout.\\">\\n  What do you love more than anyone else? What does the world need you to do?\\n</Question>\\n\\n<Question\\n  why=\\"The problems you always want to solve are the ones you\'ll work on longest without burning out. Most people chase problems that are prestigious or profitable, but calling tends to be the problems you\'d work on even if no one was watching.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"When evaluating whether to start something new, when you feel pulled toward a problem unprompted\\"\\n  record=\\"Write a specific list of problem types. Not industries, but actual problem patterns\\">\\n  What kinds of problems do you always want to solve?\\n</Question>\\n\\n<Question\\n  why=\\"A question you want to dedicate your life to answering is a different level of commitment than a career. It\'s the level where calling lives. Most people never identify it, but the ones who do tend to produce work that outlasts them.\\"\\n  howOften=\\"Once a year; this is a long-horizon question that should refine slowly\\"\\n  when=\\"During extended reflection periods, when you\'re evaluating the next chapter of your life\\"\\n  record=\\"Write it as a single question. If you can\'t compress it to one, you haven\'t found it yet\\">\\n  What question(s) do you want to dedicate your life to answering?\\n</Question>\\n\\n<Question\\n  why=\\"\'Only you\' and \'love answering\' are two different filters. The first looks for your unique combination of experience and perspective. The second looks for genuine energy. Questions that pass both filters are your strongest signal of calling.\\"\\n  howOften=\\"Annually. This is a refining question, not a weekly check\\"\\n  when=\\"After periods of deep work, when you notice where your energy peaks\\"\\n  record=\\"Write both answers separately, then look for the overlap\\">\\n  What question(s) can only you answer? What question do you love answering?\\n</Question>\\n\\n<Question\\n  why=\\"Sweet spot is where your unique strength meets what the world actually needs and will pay for. Most people are somewhere off-center: too internal (pure passion, no demand) or too external (pure demand, no energy). This question finds the center.\\"\\n  howOften=\\"Annually, and whenever you\'re considering a major pivot\\"\\n  when=\\"During career reflection, when evaluating whether current work is sustainable long-term\\"\\n  record=\\"Draw the three circles (what you love, what you\'re great at, what the world needs) and write where you actually are\\">\\n  What is your sweet spot? What does the world demand?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Believing in purpose\\n\\n<SectionBanner why=\\"Purpose requires belief to become action. If you don\'t believe your life is for something, you won\'t do the hard work of finding out what. These questions check whether your beliefs are actually load-bearing.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"Belief shapes action more than information does. What you believe is possible determines what you attempt. Luck favoring the believers isn\'t superstition; it\'s the observation that people who believe in something take more shots and persist longer.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"Before starting something difficult, when doubt shows up, when you\'re evaluating whether to commit to something\\"\\n  record=\\"Write your core beliefs as statements, not aspirations. Things you actually act on\\">\\n  Luck favors the believers: what do you believe in?\\n</Question>\\n\\n<Question\\n  why=\\"Capability beliefs are often more limiting than actual capability. Most people underestimate what they can do because they\'ve never been pushed far enough to find out. This question asks you to honestly assess, and then challenge, that ceiling.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When facing something that feels too hard, when evaluating your own potential in a new domain\\"\\n  record=\\"Write what you believe you\'re capable of, then write what evidence you\'d need to believe more\\">\\n  What do you believe you are capable of doing?\\n</Question>\\n\\n<Question\\n  why=\\"Believing in something bigger than yourself is what makes sustained effort possible. Self-interest alone doesn\'t sustain people through difficulty, but belief in a cause, a person, or a God can. This question checks whether you\'ve found that.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"During spiritual reflection, during periods of sustained effort or sacrifice\\"\\n  record=\\"Write what it is. If you can\'t name it, that\'s the signal to keep searching.\\">\\n  What is bigger than you that you believe in?\\n</Question>\\n\\n<Question\\n  why=\\"Willingness to fail is the real test of belief. Most people believe in their purpose in theory but aren\'t willing to fail for it in practice. The number of times you\'re willing to get up tells you how real the belief actually is.\\"\\n  howOften=\\"Ask this before starting something where failure is possible, which is everything worth doing\\"\\n  when=\\"When evaluating whether to take a risk, when you\'re recovering from a failure\\"\\n  record=\\"Write a specific number or range, and then note whether your behavior matches it\\">\\n  How many times are you ready to fail?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Championing a cause\\n\\n<SectionBanner why=\\"A cause is bigger than a goal. It\'s what you\'re for in the world: what you\'d put your name on, what you\'d sacrifice for. These questions ask whether you\'ve found yours.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"A cause you champion is different from a cause you agree with. Championing means actively advancing it, with time, voice, and resources. Most people have opinions about causes; fewer have commitments. This question checks which category you\'re in.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"When evaluating where to volunteer, donate, or invest your advocacy energy\\"\\n  record=\\"Name the cause specifically, then write one concrete thing you\'re actively doing for it\\">\\n  What cause do you believe in? What cause do you champion?\\n</Question>\\n\\n<Question\\n  why=\\"Advancing humanity sounds grandiose until you break it down: what specific problem will you help solve? What specific status quo will you push against? The scale of the question is meant to lift your eyes beyond personal benefit.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"During long-horizon reflection, when deciding where to put your most serious effort\\"\\n  record=\\"Write the specific answer. Not \'I want to make the world better\' but \'I will advance X by doing Y\'\\">\\n  How will you advance humanity? How will you challenge the status quo?\\n</Question>\\n\\n<Question\\n  why=\\"The human spirit responds to inspiration, not just information. What is it about your work, your story, or your example that could wake something up in someone else? Asking this turns your personal purpose into a relational one.\\"\\n  howOften=\\"Annually, or when preparing to share your work or story with others\\"\\n  when=\\"Before speaking, writing, or leading in any public way\\"\\n  record=\\"Write a specific answer, then see whether your current work actually does that\\">\\n  What will excite the human spirit of those around you?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Knowing you\'re getting closer\\n\\n<SectionBanner why=\\"Purpose isn\'t just about finding it; it\'s about tracking it. These questions build a feedback loop so you can tell when you\'re aligned and when you\'ve drifted, rather than waiting for the feeling to hit you.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"Without signals, you\'re navigating blind. This question asks you to define what alignment feels like so you can notice it when it\'s happening and notice its absence when it\'s not.\\"\\n  howOften=\\"Monthly. Build it into your review practice\\"\\n  when=\\"During monthly reflection, when assessing whether current work feels right\\"\\n  record=\\"Write the signals you notice, not the theory. Specific feelings, moments, or patterns\\">\\n  How do you know you\'re getting closer to your purpose?\\n</Question>\\n\\n<Question\\n  why=\\"Milestones make the abstract tangible. If you can name the specific markers that would tell you you\'re on the path, you have a way to evaluate your choices. Without them, every path looks equally valid or invalid.\\"\\n  howOften=\\"Quarterly. Review your milestones and update them as you learn more\\"\\n  when=\\"When setting goals for a new quarter or year, when evaluating progress\\"\\n  record=\\"Write 3-5 specific milestones. Not outcomes, but leading indicators that you\'re moving in the right direction.\\">\\n  What milestones will inch you closer?\\n</Question>\\n\\n<Question\\n  why=\\"Passions can mislead. You can be passionate about something that isn\'t your calling. It might just be enjoyable, ego-boosting, or familiar. Testing your passions against your purpose is how you distinguish between the two.\\"\\n  howOften=\\"When you\'re evaluating whether a new passion deserves significant time investment\\"\\n  when=\\"Before committing significant resources to a new interest or direction\\"\\n  record=\\"Write the test you\'d run and what the pass/fail criteria are\\">\\n  How can you litmus-test your passions to see if they align with your purpose?\\n</Question>\\n\\n<Question\\n  why=\\"\'True calling\' signals are often quieter than the dramatic revelation people expect. This question asks you to define the signals in advance so you don\'t miss them or mistake lesser things for them.\\"\\n  howOften=\\"Annually. Refine your criteria as you have more experience to draw from\\"\\n  when=\\"When something feels like it might be the thing, use this question to check rigorously\\"\\n  record=\\"Write the criteria, not just the feeling\\">\\n  How do you know you\'ve found your true calling?\\n</Question>\\n\\n<Question\\n  why=\\"There\'s a version of \'seeking purpose\' that becomes avoidance. At some point, you have to commit to a direction based on the best information you have and stop waiting for certainty. This question asks when that moment is.\\"\\n  howOften=\\"Ask this when you\'ve been in seeking mode for a while without committing\\"\\n  when=\\"When you\'ve been exploring for more than a year without landing, or when you\'re using \'searching\' as a reason to avoid commitment\\"\\n  record=\\"Write your honest answer, and if you\'ve been seeking too long, write what you\'d commit to today if you had to\\">\\n  When should you stop seeking purpose?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Avoiding regret\\n\\n<SectionBanner why=\\"Regret is information about what actually mattered to you. These questions use the threat of regret as a forward-looking tool, not to generate anxiety, but to clarify what deserves your effort now.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"Skills that live only in you and die with you are gifts withheld from the world. This question is a sharp form of accountability: what have you developed that no one else will ever benefit from if you don\'t act?\\"\\n  howOften=\\"Annually. This is a legacy question\\"\\n  when=\\"During year-end reflection, when you\'re deciding what to write, teach, or share\\"\\n  record=\\"Write the specific list. Then write what you\'d do with each if you committed to sharing it.\\">\\n  What skills will die with you?\\n</Question>\\n\\n<Question\\n  why=\\"Regret about inaction is consistently worse than regret about action, according to most research and most people\'s experience. This question takes that finding seriously and applies it to your current hesitations.\\"\\n  howOften=\\"Quarterly. Things you\'re not acting on tend to accumulate without notice\\"\\n  when=\\"When you\'re hesitating on something significant, when you\'ve been putting something off for more than a few months\\"\\n  record=\\"Write the honest answer. If you\'re not ready to act, write why, and whether that reason will still feel valid in five years.\\">\\n  If you don\'t act now, what will you end up regretting?\\n</Question>\\n\\n<Question\\n  why=\\"Knowing what you don\'t want to be is sometimes clearer than knowing what you do want to be, and it\'s just as useful. Negative clarity points you toward the positive almost as reliably as positive clarity does.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"When you\'re evaluating a direction and unsure whether it\'s right, when you feel like you\'re becoming someone you don\'t respect\\"\\n  record=\\"Write a specific list. Not abstract vices, but specific patterns or tendencies you refuse to cultivate\\">\\n  What do you not want to be?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Listening to your inner voice\\n\\n<SectionBanner why=\\"Your inner life is constantly giving you information about whether you\'re aligned with your purpose. The problem isn\'t that the signal is absent; it\'s that most people have never learned to read it.\\" />\\n\\nYou possess an inner force trying to guide you to your full potential. It makes you\\nfeel unhappy when you stray from your purpose, and successful when you don\'t.\\nLearning to recognize when you\'re near your purpose, and when you\'ve drifted from\\nit, is most of the work.\\n\\n## Understanding your uniqueness\\n\\n<SectionBanner why=\\"Your uniqueness isn\'t about being special; it\'s about being irreplaceable in a specific way. These questions help you identify the signature you leave on everything you touch, which is the practical definition of your calling.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"Transcribing a message means you\'re a conduit for something specific, not just a content producer. What others feel in your presence is a signal about what you\'re actually communicating beneath the words. Both questions point to your signature.\\"\\n  howOften=\\"Annually, and after significant pieces of work or interactions\\"\\n  when=\\"After giving a talk, publishing something, or ending a meaningful conversation. What did people take away?\\"\\n  record=\\"Collect actual feedback; the patterns across many instances are more reliable than your own perception\\">\\n  What message are you transcribing? What do you make people feel?\\n</Question>\\n\\n<Question\\n  why=\\"Stirring thoughts in others and making people think are forms of impact that outlast you. If you\'re not clear on what those thoughts are, you\'re producing influence without aim. This question gives it direction.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"When preparing to share work publicly, when evaluating the impact of something you\'ve already shared\\"\\n  record=\\"Write the thoughts you\'d want someone to leave with. Then ask whether your current work is producing them.\\">\\n  What thoughts will you stir in the minds of others? How do you make people think?\\n</Question>\\n\\n<Question\\n  why=\\"\'What makes you you\' is worth knowing precisely because it\'s the thing you can\'t outsource or replicate. And the question of why someone would want to know you is the relational version of uniqueness, which is where it actually matters.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"When introducing yourself to a new audience, when evaluating whether you\'re showing your real self or a curated version\\"\\n  record=\\"Write both answers. The gap between them is usually where your best work is hiding.\\">\\n  What makes you you? Why would someone else want to get to know you?\\n</Question>\\n\\n<Question\\n  why=\\"This is the most direct version of the uniqueness question. What can you say is genuinely, irreversibly yours? Not just your fingerprints, but your combination of experience, perspective, and craft. That\'s where calling and identity converge.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"During deep reflection, when you feel like what you\'re doing could be done by anyone\\"\\n  record=\\"Write a specific answer. If you can\'t, that\'s the signal that you haven\'t developed your uniqueness enough yet, and that\'s useful information too.\\">\\n  In what can you truly say \\"there will never be anyone else like me\\"?\\n</Question>\\n\\n</QuestionSection>\\n\\nThe people who are closest to their nature will lead the world.\\n\\n## Purifying intentions\\n\\n<SectionBanner why=\\"Motivation matters even when the action is good. These questions check whether you\'re doing what you do for the right reasons, because the reason determines what the work costs you and what it actually produces.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  why=\\"Service for reciprocity is transactional, and will eventually disappoint. Service for legacy is ego-driven, and leads to burnout or resentment when the recognition doesn\'t come. Purifying intention means finding the reason to serve that doesn\'t depend on a return.\\"\\n  howOften=\\"Annually, and any time you feel resentful or unappreciated\\"\\n  when=\\"When you notice bitterness, entitlement, or ego in your motivations\\"\\n  record=\\"Write your honest answer. Most people\'s motivations are mixed, and that\'s fine. The goal is to know which ones are driving.\\">\\n  Do you want to serve humanity for humanity to serve you back? To be remembered?\\n</Question>\\n\\n<Question\\n  why=\\"Digging into purpose tends to surface things you weren\'t expecting, including motivations you\'d rather not acknowledge. This question invites that excavation without judgment. The deeper you go, the more honest your actions become.\\"\\n  howOften=\\"Annually, and as a closing question after a season of purposeful work\\"\\n  when=\\"During deep reflection sessions, at the end of a significant chapter\\"\\n  record=\\"Write the layers: the surface reason and what you find when you keep digging. The deepest honest answer is the one worth acting from.\\">\\n  Why do I do what I do? As I dig deeper into my purpose, I become more aware of the things I do, and why.\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-growing-yourself","metadata":{"permalink":"/thoughts/questions-for-growing-yourself","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-growing-yourself.mdx","source":"@site/blog/2017-02-11-questions-for-growing-yourself.mdx","title":"What I Ask Myself: To Keep Growing","description":"The questions I sit with when I want to know whether I\'m truly improving, where I\'m investing my energy, and if I\'m living up to my potential.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":12.99,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-growing-yourself","title":"What I Ask Myself: To Keep Growing","kind":"question-set","sidebar_label":"Growing","description":"The questions I sit with when I want to know whether I\'m truly improving, where I\'m investing my energy, and if I\'m living up to my potential.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Find Purpose","permalink":"/thoughts/questions-for-finding-your-purpose"},"nextItem":{"title":"What I Ask Myself: To Operate Better","permalink":"/thoughts/questions-for-improving-how-you-operate"}},"content":"Growth is easy to assume and hard to verify. It\'s possible to stay busy for years without getting meaningfully better at anything. These are the questions I sit with when I want to know whether I\'m truly improving, where I\'m investing my energy, and whether I\'m living up to what I\'m capable of. Pick the ones that make you a little uncomfortable.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Growth mindset\\n\\n<SectionBanner why=\\"Growth starts as a posture before it shows up as progress. These questions check whether I actually want to get better, or just want to feel like I am.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"core\\"\\n  cron=\\"daily\\"\\n  depth=\\"quick\\"\\n  why=\\"The daily intention to improve compounds in a way that occasional bursts never do. Wanting to get a little better every single day is the simplest engine of real growth.\\"\\n  howOften=\\"Daily, as a standing commitment\\"\\n  when=\\"At the start of each day\\"\\n  record=\\"Note one thing you got better at today, however small\\">\\n  Do you want to get better, every single day?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Busy is not the same as growing. Distinguishing real change from mere activity catches the years that feel productive but leave me exactly where I started.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I feel busy but can\'t point to what\'s actually changed\\"\\n  record=\\"Write concrete evidence that you\'re different than last month\\">\\n  Are you changing? Are you growing? Are you improving?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Growth has a price, and naming the hard work I\'m willing to do separates ambition from wishful thinking. The work I\'ll actually commit to is the real measure of how much I want it.\\"\\n  howOften=\\"Weekly, when planning effort\\"\\n  when=\\"When setting goals that sound nice but require real labor\\"\\n  record=\\"Name the specific hard work, not the comfortable version\\">\\n  What hard work will you do?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"At the end of any chapter, the question is whether I gained more than I started with. Asking it in advance keeps me from coasting through a season and arriving empty-handed.\\"\\n  howOften=\\"Yearly, or at the end of a chapter\\"\\n  when=\\"When wrapping up a long effort or period\\"\\n  record=\\"Project what you\'ll walk away with, then check it against reality later\\">\\n  When it\'s all over, will you walk away with more than what you had?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Reaching your potential\\n\\n<SectionBanner why=\\"There\'s a gap between what I\'m capable of and what I\'m actually doing. These questions press on that gap, because unused potential is the quietest kind of regret.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Letting myself down is the failure no one else sees, which makes it the easiest to ignore and the most corrosive. This question holds me to my own standard, not anyone else\'s.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I sense I\'m settling for less than I\'m capable of\\"\\n  record=\\"Write where you\'re falling short of your own standard, honestly\\">\\n  Are you letting yourself down?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"\'I made it\' needs a definition or it stays a feeling I\'ll never reach. Naming the concrete steps to get there turns a vague aspiration into a plan I can actually follow.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When my goals feel real but the path to them is fuzzy\\"\\n  record=\\"List the specific steps that would let you honestly say you made it\\">\\n  What steps must you take to be able to say \\"I made it\\"?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Dormant greatness is potential that never gets expressed, and it\'s easy to let it sleep under the weight of comfort. This question is a deliberate alarm against quietly settling.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I feel myself coasting on what\'s comfortable\\"\\n  record=\\"Name where you\'re letting your greatness sleep and one way to wake it\\">\\n  Don\'t let your greatness sleep: are you?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"If today\'s problems are solved tomorrow, my value can\'t rest on them alone. This question pushes me toward growth that stays relevant, not skills that expire with the moment.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I notice my value is tied to a problem that won\'t last\\"\\n  record=\\"Write what you offer that outlasts today\'s specific problems\\">\\n  What good are you if the problems you live to solve today will be solved tomorrow?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Investing in yourself\\n\\n<SectionBanner why=\\"Growth requires deliberate inputs, not just effort. These questions audit what I\'m actually putting into myself: knowledge, techniques, and the results I\'m aiming at.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Investing in myself is the highest-return investment I control, but only if it\'s deliberate. Asking how I\'ll invest turns growth from something that happens to me into something I direct.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When planning where my time and money go\\"\\n  record=\\"Name a specific investment in yourself for the coming month\\">\\n  How will you invest in you?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Output depends on input. Tracking how much knowledge I\'m actually taking in catches the weeks where I\'m producing constantly but learning nothing new.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When I feel intellectually stagnant\\"\\n  record=\\"Estimate what you genuinely learned this week, not just what you consumed\\">\\n  How much knowledge are you inputting into yourself?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing a technique and relying on one are different. Mapping what I\'m aware of against what I actually use reveals tools I\'ve collected but never put to work.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When my methods feel limited or stale\\"\\n  record=\\"List techniques you know versus the few you actually depend on\\">\\n  What techniques are you aware of? What techniques do you depend on?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Investment without a target is just expense. Naming the results I\'m looking for keeps my growth pointed at something specific instead of being effort for its own sake.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When setting the direction for a stretch of effort\\"\\n  record=\\"Define the concrete result you want from your investment\\">\\n  What results are you looking for?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Self-knowledge for growth\\n\\n<SectionBanner why=\\"I can\'t grow well in a direction I don\'t understand about myself. These questions map how I\'m wired so I can build on my real strengths and values.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"There are many ways to be smart, and knowing my particular kind lets me grow with the grain instead of against it. Forcing growth through a strength I don\'t have just wastes effort.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When choosing how to learn or where to specialize\\"\\n  record=\\"Name the specific ways you\'re smart, not the generic ones\\">\\n  Do you know how you are smart? In what ways are you smart?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"What I care about is the fuel for sustained growth. Growth in a direction I don\'t care about stalls; naming what I genuinely care about keeps the effort self-sustaining.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When deciding what\'s worth growing toward\\"\\n  record=\\"List what you actually care about, then check your effort goes there\\">\\n  What do you care about?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"My values quietly govern every choice, including how I grow. Making them explicit lets me grow on purpose instead of being steered by values I never examined.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"During deep reflection on my direction\\"\\n  record=\\"Write the values that actually drive your choices, not the aspirational ones\\">\\n  What are the values that motivate your choices?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Velocity, not just position, predicts where I\'ll end up. Knowing my rate of growth tells me whether I\'m accelerating or just maintaining, which matters more over time than where I am today.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I want to know my trajectory, not just my current state\\"\\n  record=\\"Estimate your rate of improvement, then check if it\'s rising or flat\\">\\n  What is your velocity?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Learning from masters\\n\\n<SectionBanner why=\\"I don\'t have to invent the path. These questions point me at the people who already walked it, so I can borrow their methods instead of rediscovering them slowly.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The people who already achieved what I\'m after left a trail of methods. Studying their techniques is the fastest shortcut I have to my own growth, far faster than figuring it out alone.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When starting on something others have clearly mastered\\"\\n  record=\\"List the techniques the masters used and which you could adopt\\">\\n  What techniques did the people who achieve what you\'re after use?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"quick\\"\\n  why=\\"Knowing who has mastered a thing gives me both a model and a measuring stick. Their example shows me what\'s possible and how far I still have to go.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When picking who to learn from in a new area\\"\\n  record=\\"Name the masters in your target area and what makes them masters\\">\\n  Who has mastered what you\'re trying to learn?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Measuring growth\\n\\n<SectionBanner why=\\"Growth I can\'t measure is growth I can\'t trust. These questions look for hard evidence that I\'m improving rather than just the comfortable feeling of it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Thoughts that never become action aren\'t growth, they\'re entertainment. Measuring how many of my ideas actually manifest as behavior is a brutal but honest gauge of real change.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I have lots of insight but little to show for it\\"\\n  record=\\"Count how many recent thoughts turned into actual actions\\">\\n  How many of your thoughts re-manifest themselves in actions?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Reading widely feels productive, but reading toward my goals is what actually grows me. This question audits whether my inputs are aimed or just pleasant.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When reviewing my reading or learning diet\\"\\n  record=\\"Check whether your reading list actually serves your goals\\">\\n  Are you truly reading books that will enable you to reach your goals?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Personal experimentation is how I learn what works for me specifically. Automating that process means I keep learning from my own life without relying on remembering to.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When my self-improvement feels haphazard\\"\\n  record=\\"Note whether your experiments run on a system or on willpower\\">\\n  Have you automated your personal experimentation process?\\n</Question>\\n\\n</QuestionSection>\\n\\n## The growth journey\\n\\n<SectionBanner why=\\"Two things keep me steady over the long haul: learning compounds like interest, so small consistent gains become large, and the visible competitions are the easy part while the real work happens behind the scenes. These questions keep me focused on that quiet, compounding work.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Getting more than I have requires doing something different than I\'m doing, or doing it for longer. This question forces me to name the actual mechanism of the next gain, not just wish for it.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I\'ve plateaued and want to climb again\\"\\n  record=\\"Write the specific change that would get you beyond where you are\\">\\n  How do you get more than you already have?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Understanding how growth works in general (how anything grows, compounding, feedback, stress and recovery) lets me design for it deliberately rather than hoping it happens. The mechanism is reusable across everything I want to grow.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"When I want to grow on purpose, not by accident\\"\\n  record=\\"Write your model of how growth actually works, then apply it to yourself\\">\\n  How do you grow? How do things grow?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Acknowledging limits\\n\\n<SectionBanner why=\\"Honest growth starts with an honest map of what I don\'t know. These questions keep me humble about the edges of my knowledge so I don\'t build on ground that isn\'t there.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The limits of my foreknowledge are where overconfidence lives. Naming what I can\'t actually predict keeps me from betting too much on a future I can\'t see clearly.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When making a confident prediction about the future\\"\\n  record=\\"Write what you genuinely can\'t foresee about this situation\\">\\n  What are the limits of your foreknowledge?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Acknowledging the limits of my knowledge is the prerequisite for filling them. Pretending to know more than I do quietly blocks the very learning that would close the gap.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I\'m tempted to act like I know more than I do\\"\\n  record=\\"Name the edges of your knowledge in this area, plainly\\">\\n  Are you acknowledging the limits of your knowledge?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"My actions have a reach, and knowing where it ends keeps my effort focused on what I can actually affect. Pushing against immovable limits just drains the energy I need for the movable ones.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I\'m spending effort on things outside my control\\"\\n  record=\\"Mark what\'s within your power to change and what isn\'t\\">\\n  Are you acknowledging the limits of your actions?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Key growth questions\\n\\n<SectionBanner why=\\"These are the questions I keep coming back to, the ones that most reliably move me forward. They turn the whole reflection into a concrete focus for what to learn next.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"The gap between what I know and what I need to know is the most actionable map of my growth. Naming it points me straight at the next thing worth learning instead of learning at random.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When deciding what to learn next\\"\\n  record=\\"Write the specific knowledge gap standing between you and your goal\\">\\n  What do you need to know that you don\'t know right now?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"A clear learning focus beats scattered curiosity. Naming what I\'m focused on learning keeps my limited attention pointed at one thing long enough to actually get good at it.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When my learning feels scattered across too many things\\"\\n  record=\\"State the one thing you\'re focused on learning right now\\">\\n  What are you focused on learning?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Learning is only worth it if it improves me and the systems I run. Asking how I convert learning into improvement closes the loop between taking knowledge in and actually getting better.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I\'ve learned something and want it to actually change how I operate\\"\\n  record=\\"Write how a recent lesson changed your behavior or your system\\">\\n  How do you use learning to improve yourself and your system?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"This is the accountability question I can\'t dodge. Asking whether I\'m doing everything I can with what I have strips away the excuses and shows me the gap between my circumstances and my effort.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I\'m tempted to blame circumstances for slow progress\\"\\n  record=\\"Write honestly whether you\'re maxing out what you actually have\\">\\n  Are you doing everything you can with what you have?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-improving-how-you-operate","metadata":{"permalink":"/thoughts/questions-for-improving-how-you-operate","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-improving-how-you-operate.mdx","source":"@site/blog/2017-02-11-questions-for-improving-how-you-operate.mdx","title":"What I Ask Myself: To Operate Better","description":"The questions I use to surface the invisible processes and systems I run on, so I can keep what works and retire what doesn\'t.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":7.26,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-improving-how-you-operate","title":"What I Ask Myself: To Operate Better","kind":"question-set","sidebar_label":"Operating Better","description":"The questions I use to surface the invisible processes and systems I run on, so I can keep what works and retire what doesn\'t.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Keep Growing","permalink":"/thoughts/questions-for-growing-yourself"},"nextItem":{"title":"What I Ask Myself: To Know What I Want","permalink":"/thoughts/questions-for-knowing-what-you-want"}},"content":"Most reflection focuses on what you\'re doing and why. This set is about the *how*:\\nthe processes, techniques, and systems you operate by without ever naming them. The\\nquestions below are meant to surface those invisible methods so you can evaluate\\nthem, reuse what works, and retire what doesn\'t. Pick a section and sit with it.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Core processes\\n\\n<SectionBanner why=\\"The methods you run on are usually invisible until you name them. Putting language to how you actually operate is the first step to improving any of it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"If you can\'t describe your own reflection process, you\'re reflecting by accident. Naming it lets you make it repeatable and reliable.\\"\\n  howOften=\\"Quarterly, or whenever your current way of reflecting stops producing insight\\"\\n  when=\\"During a planning session or a quiet review of how you actually think things through\\"\\n  record=\\"Write the steps out as a checklist you can follow next time\\">\\n  What is your self-reflection process?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Most problem-solving feels like improvisation, but there\'s usually a pattern underneath. Surfacing it lets you apply it on purpose instead of hoping it shows up.\\"\\n  howOften=\\"Quarterly, and after solving something hard, while it\'s fresh\\"\\n  when=\\"Right after you work through a tricky problem and can still see the moves you made\\"\\n  record=\\"Note the specific moves you made; the repeatable pattern is the technique\\">\\n  What is your problem-solving technique?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The mechanics of how you actually get to your outcomes are easy to leave unexamined. Naming the method tells you whether you\'re being deliberate or just lucky.\\"\\n  howOften=\\"Monthly, when reviewing what moved and what stalled\\"\\n  when=\\"When something went your way and you want to understand why it worked\\"\\n  record=\\"Write down the actual sequence that produced the result\\">\\n  How do you get what you want?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Your life runs on systems whether you designed them or not. Asking how it works lets you see the machinery instead of just living inside it.\\"\\n  howOften=\\"Quarterly, as a step back from the day to day\\"\\n  when=\\"During a season change or any time the routine feels off\\"\\n  record=\\"Sketch the loop: what comes in, what you do with it, what comes out\\">\\n  How does your life work?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"How you interpret a question shapes the answer you\'ll reach. If your understanding is sloppy, every downstream conclusion inherits the flaw.\\"\\n  howOften=\\"When a question feels confusing or you keep talking past someone\\"\\n  when=\\"Before answering anything that matters, especially when stakes are high\\"\\n  record=\\"Restate the question in your own words before you try to answer it\\">\\n  How do you understand questions?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Reusing and learning from the past\\n\\n<SectionBanner why=\\"Solutions you already found are wasted if you can\'t find them again. This section is about building a memory you can actually draw on.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Reinventing a solution you already discovered is pure waste. The leverage is in reaching back for what worked instead of starting from scratch.\\"\\n  howOften=\\"Monthly, when a new problem rhymes with an old one\\"\\n  when=\\"When you hit something that feels familiar but you can\'t quite place\\"\\n  record=\\"Keep a short log of solved problems and the approach that cracked each one\\">\\n  How will you reuse your solutions from previous problems to solve new ones?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"An answer you can\'t retrieve is the same as an answer you never had. Indexing is what turns past effort into a usable library.\\"\\n  howOften=\\"Monthly, as you accumulate notes and solutions\\"\\n  when=\\"When your notes pile up and you can no longer find what you need\\"\\n  record=\\"Pick a tagging or filing scheme and apply it consistently\\">\\n  How will you index your responses so you can find them again?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"quick\\"\\n  why=\\"Old solutions go stale as your situation changes. Scheduling a re-look keeps you from running on advice that no longer fits.\\"\\n  howOften=\\"Quarterly is a reasonable default; tune it to how fast your context shifts\\"\\n  when=\\"When setting your review cadence for the quarter\\"\\n  record=\\"Set a recurring reminder and note what you actually changed each time\\">\\n  How often will you re-evaluate your previous solutions?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Process evaluation\\n\\n<SectionBanner why=\\"A process is only worth keeping if it earns its place. These questions audit what you run on so you can add what\'s missing and drop what\'s dead weight.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Gaps in how you operate often hide in plain sight. Asking what you\'re missing invites the upgrade you wouldn\'t otherwise notice.\\"\\n  howOften=\\"Quarterly, when reviewing how things are running\\"\\n  when=\\"When something keeps slipping and no current process catches it\\"\\n  record=\\"List one or two processes worth trying and what problem each would solve\\">\\n  Are there any new processes you would benefit from?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"A process you skip is a process you don\'t have. This is an honest check on whether you\'re actually doing the things you decided matter.\\"\\n  howOften=\\"Weekly, as part of a regular review\\"\\n  when=\\"At the end of a week, looking back at what you intended versus what you ran\\"\\n  record=\\"Mark which processes you ran and which you quietly dropped\\">\\n  Are you completing all of your processes, or failing to do any of them?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Reflecting on your processes is the meta-layer that keeps the rest honest. Without it, broken methods just keep running.\\"\\n  howOften=\\"Monthly, set aside for the question itself\\"\\n  when=\\"During a monthly review or after a process clearly let you down\\"\\n  record=\\"Write what\'s working, what isn\'t, and one change to try\\">\\n  How will you reflect on your processes?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"quick\\"\\n  why=\\"Decisions about your processes tend to fade unless you record them. Tracking them keeps you from relitigating the same call over and over.\\"\\n  howOften=\\"Quarterly, when revisiting how you operate\\"\\n  when=\\"After you commit to changing or keeping a way of working\\"\\n  record=\\"Keep a running list of process decisions and the reason behind each\\">\\n  What decisions have you made regarding your processes?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing what to do is different from having a way to start doing it. A process for coming into action is what closes the gap between intent and motion.\\"\\n  howOften=\\"When you have a plan but keep failing to start on it\\"\\n  when=\\"When you\'re stalled at the threshold of a project you\'ve already decided to do\\"\\n  record=\\"Write the first concrete step and the trigger that kicks it off\\">\\n  What is your plan of action, your process for coming into action?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Artifacts and constraints\\n\\n<SectionBanner why=\\"A good process leaves something behind and runs inside limits. Naming the outputs and the boundaries keeps your methods grounded in something real.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"quick\\"\\n  why=\\"A process that produces nothing tangible is hard to trust or improve. Naming the artifact gives you something concrete to point at and refine.\\"\\n  howOften=\\"Quarterly, or when designing a new process\\"\\n  when=\\"When defining or revising how a piece of your work runs\\"\\n  record=\\"Name the artifact each process should produce\\">\\n  What artifacts will your process produce?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"Constraints aren\'t restrictions so much as guardrails that keep a process from sprawling. Choosing them on purpose makes the method sharper.\\"\\n  howOften=\\"When designing or tightening a process\\"\\n  when=\\"When a process keeps expanding past where it\'s useful\\"\\n  record=\\"Write the limits you\'ll hold the process to\\">\\n  What constraints will you impose on your process?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Automation\\n\\n<SectionBanner why=\\"Anything you do over and over by hand is a candidate for handing off to a system. This is where you reclaim time you didn\'t know you were spending.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"Repetitive manual work is a slow leak of time and attention. Spotting what repeats is the first step to letting a system carry it instead.\\"\\n  howOften=\\"Monthly, scanning for the same task showing up again\\"\\n  when=\\"When you catch yourself doing the same fiddly thing for the third time\\"\\n  record=\\"List the repeating actions and which one is worth automating first\\">\\n  What actions repeat in your life that you can automate?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-knowing-what-you-want","metadata":{"permalink":"/thoughts/questions-for-knowing-what-you-want","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-knowing-what-you-want.mdx","source":"@site/blog/2017-02-11-questions-for-knowing-what-you-want.mdx","title":"What I Ask Myself: To Know What I Want","description":"The questions I return to when I want to cut through the noise and name what I\'m really after, what I\'m chasing, and what I\'d regret not pursuing.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":11.14,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-knowing-what-you-want","title":"What I Ask Myself: To Know What I Want","kind":"question-set","sidebar_label":"What I Want","description":"The questions I return to when I want to cut through the noise and name what I\'m really after, what I\'m chasing, and what I\'d regret not pursuing.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Operate Better","permalink":"/thoughts/questions-for-improving-how-you-operate"},"nextItem":{"title":"What I Ask Myself: To Know Who I Am","permalink":"/thoughts/questions-for-knowing-who-you-are"}},"content":"Knowing what I want sounds simple until I actually try to answer it. I chase plenty\\nof things I never deliberately chose. These are the questions I return to when I want\\nto cut through the noise and name what I\'m really after, grouped by what they\'re\\ngetting at. I sit with the ones that make me uncomfortable.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Core desires\\n\\n<SectionBanner why=\\"Before I can chase anything well, I have to know what I actually want, and just as importantly what I don\'t. Naming both ends keeps me from spending a life pursuing things I never chose.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Most of what I want, I absorbed without choosing. Pairing \'what do you want\' with \'what do you not want\' forces the deliberate choice, because knowing what to refuse is half of knowing what to pursue.\\"\\n  howOften=\\"Once a year, and any time I feel like I\'m chasing something on autopilot\\"\\n  when=\\"During annual reflection, or when a goal I\'ve been chasing suddenly feels hollow\\"\\n  record=\\"Two lists, want and don\'t-want, written plainly; revisit and prune yearly\\">\\n  What do you want? What do you not want?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"This is the big, intimidating version of the question, and avoiding it is how decades slip by. Even a rough answer gives every smaller choice something to point at.\\"\\n  howOften=\\"Once a year, at minimum\\"\\n  when=\\"At major crossroads: a new chapter, a hard decision, a season ending\\"\\n  record=\\"Write a paragraph; it\'s allowed to change, but write something rather than nothing\\">\\n  What do you want to do with your life?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"\'Rather have\' is a trade-off question, and trade-offs are where real preferences show up. It cuts through wishful thinking by forcing me to give something up to get something else.\\"\\n  howOften=\\"Quarterly, when I\'m weighing competing options\\"\\n  when=\\"When I want two things and can\'t have both\\"\\n  record=\\"Write the trade pairs: I\'d rather have X than Y. The pattern reveals my real priorities\\">\\n  What would you rather have?\\n</Question>\\n\\n</QuestionSection>\\n\\n## What you\'re chasing\\n\\n<SectionBanner why=\\"There\'s a difference between what I claim to want and what I\'m actually running toward all day. These questions catch what\'s really pulling me, including the infatuations and turn-offs I don\'t usually admit.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"What I\'m chasing and what I\'m working toward aren\'t always the same thing, and the gap between them is worth noticing. Naming the chase honestly shows whether my daily effort is aimed at what I actually want.\\"\\n  howOften=\\"Monthly, as a check on where my energy is going\\"\\n  when=\\"When I feel busy but unsure whether the busyness is pointed anywhere\\"\\n  record=\\"Write what I\'m chasing this month and what I\'m building toward; check whether they match\\">\\n  What are you chasing? What are you working towards?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"Infatuation is a strong signal, even when it\'s a little embarrassing. What grabs me without my permission tells me something about my appetites that my considered goals won\'t admit.\\"\\n  howOften=\\"Whenever I notice I\'m fixated on something\\"\\n  when=\\"When I catch myself preoccupied with something I haven\'t consciously chosen\\"\\n  record=\\"Just name it honestly; the point is awareness, not judgment\\">\\n  What are you infatuated with?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"What turns me on and off is raw motivational data. Tracking what energizes and what repels me, without dressing it up, shows me where to point my life and what to steer away from.\\"\\n  howOften=\\"Monthly, as a quick energy audit\\"\\n  when=\\"When I want a gut-level read on what\'s actually pulling and pushing me\\"\\n  record=\\"Two short columns, turned-on and turned-off, noted as I feel them\\">\\n  What\'s got you turned on? What\'s got you turned off?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Regrets and wishes\\n\\n<SectionBanner why=\\"Future regret is information about what actually matters to me, arriving early enough to do something about it. These questions borrow my deathbed perspective and bring it back to today.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Regret about what I didn\'t do is consistently heavier than regret about what I did. Asking what I\'d be sorry I skipped pulls the most important things to the front before it\'s too late to act on them.\\"\\n  howOften=\\"Once a year, and any time I\'m hesitating on something that matters\\"\\n  when=\\"When I\'ve been putting off something significant for months\\"\\n  record=\\"Write the honest answer; if I\'m not ready to act, write why, and whether that reason will hold in ten years\\">\\n  What would you be sorry you didn\'t do?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Looking back from the end and asking what I\'d wish I had done is the same clarifier from a different angle. It bypasses my current excuses by speaking from the version of me who has run out of time to make them.\\"\\n  howOften=\\"Annually, as a deliberate thought experiment\\"\\n  when=\\"During year-end reflection, or after losing someone and feeling the shortness of time\\"\\n  record=\\"Write the wishes as a list, then circle the one I could start this month\\">\\n  What would you wish you did?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"\'Regret not pursuing\' is sharper than \'regret not doing,\' because pursuit is about commitment and direction, not just a single action. It names the paths I\'m quietly letting close without deciding to.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"When I notice a direction I keep almost-choosing but never commit to\\"\\n  record=\\"Name the pursuits I\'d regret abandoning; pick one to recommit to or consciously release\\">\\n  What would you regret not pursuing?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Dreams and aspirations\\n\\n<SectionBanner why=\\"Dreams point further than goals, and they carry a feeling I want others to share. These questions ask not just where I want to end up but whether I\'m actually living toward it or just longing for it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"A dream names the destination that goals only approximate. Pairing \'what is your dream\' with \'where do you want to end up\' keeps the dream from staying a vague feeling and makes it a place I can actually aim at.\\"\\n  howOften=\\"Once a year, written out fully\\"\\n  when=\\"During annual reflection, or when I feel like I\'m drifting without a horizon\\"\\n  record=\\"Write the dream as a vivid picture, not a bullet point; the detail is what makes it pull\\">\\n  What is your dream? Where do you want to end up?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A vision that only matters to me is small. Asking what I want others to feel when they see it connects my dream to other people, which is usually where it gets its real weight and staying power.\\"\\n  howOften=\\"Annually, when refining the vision\\"\\n  when=\\"When preparing to share the dream with others, or wondering whether it\'s bigger than me\\"\\n  record=\\"Write the specific feeling I want to create in others, then check whether my dream actually delivers it\\">\\n  What do you want others to feel upon realizing your vision?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"There\'s a difference between longing for a dream and living it, and this question is the gut-punch that checks which I\'m doing. \'Crying for a dream\' I\'m not living is a sign to change something, not just to keep wishing.\\"\\n  howOften=\\"Once a year, and any time the gap between my life and my dream aches\\"\\n  when=\\"When I feel the distance between the life I have and the life I want\\"\\n  record=\\"Answer honestly whether I\'m living the ideal or just mourning it; name one move to close the gap\\">\\n  Are you crying for a dream? Are you living your ideal life?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Emotions and triggers\\n\\n<SectionBanner why=\\"My strongest emotional reactions are arrows pointing at what I care about. What moves me to tears or sends a chill through me reveals desires my rational answers tend to hide.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"What makes me cry is rarely random; it touches something I deeply value. Tracking my emotional triggers is a back door into desires I can\'t always reason my way to.\\"\\n  howOften=\\"Whenever something moves me unexpectedly\\"\\n  when=\\"After a moment that hit me harder than I expected\\"\\n  record=\\"Note what triggered it and what value or longing sits underneath the reaction\\">\\n  What triggers your emotions? What has brought you to tears?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"low\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"A chill or a shiver is the body answering before the mind can edit it. Those involuntary reactions mark the things that genuinely resonate, which makes them an honest signal of what I want.\\"\\n  howOften=\\"Whenever I feel that physical jolt of resonance\\"\\n  when=\\"When a piece of music, an idea, or a moment gives me literal chills\\"\\n  record=\\"Just note what caused it; the body is pointing at something worth following\\">\\n  What gives you the chills? What sends shivers down your spine?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Mastery and likes\\n\\n<SectionBanner why=\\"Wanting to be good at something and being willing to pay for it are two different things. These questions separate what I\'d like to master from what I\'m actually ready to sacrifice for, and remind me to notice the small likes too.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"What I want to master is a long-horizon commitment, and naming it keeps me from scattering my effort across things I only half-want. Mastery only happens where I\'m willing to go deep, so the choice matters.\\"\\n  howOften=\\"Once a year; this should refine slowly rather than swing around\\"\\n  when=\\"When deciding where to invest serious, sustained time\\"\\n  record=\\"Name the craft I want to master; if I can\'t commit to one, that\'s useful information too\\">\\n  What do you want to master?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Mastery has a price, and wanting it isn\'t the same as being willing to pay. This question tests whether my desire to master something survives contact with what it actually costs in time, repetition, and discomfort.\\"\\n  howOften=\\"Annually, and before committing to a long climb\\"\\n  when=\\"When I\'m romanticizing being a master without facing the grind of becoming one\\"\\n  record=\\"Write what mastery would actually require, then a yes or no on whether I\'ll pay it\\">\\n  Are you ready to do what it takes to become a master? What does it mean to be a master?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"The small things I like are easy to overlook, but they add up to a life. Keeping a running list of what I genuinely enjoy makes sure I build more of them in rather than only chasing the big ambitions.\\"\\n  howOften=\\"Monthly, as a light inventory\\"\\n  when=\\"When I want to remember the simple things that make a day good\\"\\n  record=\\"A running list of things I like; revisit it to make sure my life includes them\\">\\n  What are the things you like?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Infatuation and bliss\\n\\n<SectionBanner why=\\"The clearest sign I\'m pointed at the right thing is the feeling of being lost in it. These questions check whether what I do actually absorbs me, or whether I just think it should.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"If I\'m not infatuated with what I do, no amount of discipline will fully carry me through it. This question checks whether my work draws me in on its own, or whether I\'m forcing an interest that isn\'t really there.\\"\\n  howOften=\\"Quarterly, as a check on my main work\\"\\n  when=\\"When my work feels like a grind with no pull, or I\'m questioning whether I\'m in the right thing\\"\\n  record=\\"Answer honestly; if the infatuation is gone, ask whether it ever existed or has just faded\\">\\n  Are you infatuated with what you do?\\n</Question>\\n\\n<Question\\n  power={[\'spark\', \'fire\']}\\n  priority=\\"core\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Following my bliss and noticing what I get lost in are the same signal: where my attention goes without being dragged. That self-sustaining absorption is the most honest evidence of what I actually want.\\"\\n  howOften=\\"Quarterly, and whenever I notice time disappearing on something\\"\\n  when=\\"When I want to find the activities that absorb me completely\\"\\n  record=\\"Note what I lose track of time doing; the list points straight at my bliss\\">\\n  Are you following your bliss? What are you lost in?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"It sounds basic, but I rarely stop to ask what actually makes me happy versus what I assume should. Checking it directly keeps my pursuit of big goals honest about whether they\'re delivering any joy along the way.\\"\\n  howOften=\\"Monthly, as a simple wellbeing check\\"\\n  when=\\"When I\'m chasing hard but can\'t remember the last time I felt genuinely happy\\"\\n  record=\\"List what actually made me happy recently, not what I think should have\\">\\n  What makes you happy?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-knowing-who-you-are","metadata":{"permalink":"/thoughts/questions-for-knowing-who-you-are","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-knowing-who-you-are.mdx","source":"@site/blog/2017-02-11-questions-for-knowing-who-you-are.mdx","title":"What I Ask Myself: To Know Who I Am","description":"The questions I return to when I want to understand who I actually am: my character, my values, and the forces quietly shaping me.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":14.08,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-knowing-who-you-are","title":"What I Ask Myself: To Know Who I Am","kind":"question-set","sidebar_label":"Knowing Myself","description":"The questions I return to when I want to understand who I actually am: my character, my values, and the forces quietly shaping me.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Know What I Want","permalink":"/thoughts/questions-for-knowing-what-you-want"},"nextItem":{"title":"What I Ask Myself: To Decide Better","permalink":"/thoughts/questions-for-making-better-decisions"}},"content":"Why do others often know more about me than I know about myself? I rarely sit down\\nand study the one subject I have the most data on. These are the questions I return\\nto when I want to examine who I actually am: my character, my values, the beliefs and\\nemotions quietly steering me, and the story I keep feeding myself.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Defining who you are\\n\\n<SectionBanner why=\\"If I can\'t name who I am in plain terms, every other answer rests on sand. Getting a working definition of myself is the foundation everything else builds on.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"This is the question underneath all the others. If I can\'t say who I am, I\'ll keep borrowing an identity from whoever is in the room. The \'why should anyone care\' part keeps the answer honest instead of flattering.\\"\\n  howOften=\\"Once a year, and any time I notice I\'m performing a version of myself\\"\\n  when=\\"During quiet reflection, journaling, or after a season that changed me\\"\\n  record=\\"Write a paragraph and date it; compare year over year to see who I\'m becoming\\">\\n  Who are you? Who should you be? Why should anyone care?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"A definition forces me to compress myself into something I can actually hold. \'The gist of you\' and \'your reality\' push past the resume and toward the thing that\'s actually true.\\"\\n  howOften=\\"Annually, alongside the question above\\"\\n  when=\\"When I\'m tempted to describe myself by titles and roles instead of substance\\"\\n  record=\\"Write one or two sentences. If I need a paragraph, I haven\'t found the gist yet\\">\\n  How do you define yourself? What is the gist of you? What is your reality?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Examining your character\\n\\n<SectionBanner why=\\"Character is what\'s left when the performance stops, and the story I tell myself about myself quietly becomes that character. Watching the inner dialog is how I stay the author of it instead of the product of it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming the vital elements of my character tells me what to protect and what to grow. Without that list, I improve at random instead of on purpose.\\"\\n  howOften=\\"Quarterly: character moves slowly, but the check keeps it in view\\"\\n  when=\\"When reviewing how I actually behaved this season, not how I meant to\\"\\n  record=\\"List the core traits, then mark which ones I lived up to and which I didn\'t\\">\\n  What are the vital elements of your character?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The story I feed myself becomes the script I act out. If it\'s a story of limitation or resentment, I\'ll live it without noticing. Catching the story is how I get to rewrite it.\\"\\n  howOften=\\"Monthly, and any time I notice a familiar negative loop\\"\\n  when=\\"When I catch myself repeating the same explanation for why things are the way they are\\"\\n  record=\\"Write down the story in one line, then write the truer version next to it\\">\\n  What story do you feed yourself?\\n</Question>\\n\\n</QuestionSection>\\n\\nPay attention to your inner dialog. It\'s writing you whether you watch it or not.\\n\\n## Values and beliefs\\n\\n<SectionBanner why=\\"My values and beliefs are the code my decisions quietly run on. Making them explicit lets me update them on purpose instead of being governed by ones I inherited by accident.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Values and beliefs are the operating system underneath every choice I make. Most people never read their own code; they just execute it. Writing it out lets me see what I\'m actually running on.\\"\\n  howOften=\\"Once a year. Values shift slowly, but they do shift\\"\\n  when=\\"During annual reflection, or when I notice a gap between what I claim to believe and how I act\\"\\n  record=\\"Write them as a list; compare across years to see what deepened and what faded\\">\\n  What are your values? What are your beliefs?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"What\'s important to me right now is a moving target, and naming it stops me from defaulting to whatever is loudest. It\'s a quick gut-check that keeps my attention pointed where I actually want it.\\"\\n  howOften=\\"Monthly: priorities drift faster than values do\\"\\n  when=\\"At the start of a month, or when I feel scattered across too many things\\"\\n  record=\\"A short list of what genuinely matters this month, in order\\">\\n  What is currently important to you?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The 100-year lens separates the beliefs that are really mine from the ones that are just reactions to my moment. What survives that filter is closer to a conviction than an opinion.\\"\\n  howOften=\\"Once a year, as a perspective reset\\"\\n  when=\\"When I\'m worked up over something that feels urgent but may not be lasting\\"\\n  record=\\"Write which beliefs I\'d still stand behind in a century and which I\'d let go\\">\\n  Will your thoughts and beliefs matter in 100 years?\\n</Question>\\n\\n</QuestionSection>\\n\\n## What controls and shapes you\\n\\n<SectionBanner why=\\"I\'m being steered by needs, fears, and constraints I didn\'t consciously choose, and some of them I\'ve gotten too comfortable inside. Naming what controls me is the first step to deciding what I\'ll actually allow.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The needs and emotions I haven\'t named are the ones running me. Naming what controls me is how I take back the wheel. The uncomfortable answers here are usually the truest.\\"\\n  howOften=\\"Quarterly, and any time I react in a way that surprises me\\"\\n  when=\\"After an outsized emotional reaction, or when I feel driven by something I can\'t name\\"\\n  record=\\"Write the honest list, even the parts I\'d rather not admit are steering me\\">\\n  What needs, beliefs, and emotions are controlling you?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Some of my limits are real and some I built myself, and I can\'t tell them apart until I separate the two. The ones others imposed I can negotiate; the ones I imposed I can simply choose to drop.\\"\\n  howOften=\\"Quarterly, when I feel boxed in\\"\\n  when=\\"When I catch myself saying \'I can\'t\' before checking whether that\'s actually true\\"\\n  record=\\"Two columns: constraints I put on myself, constraints others put on me. Then mark which are real\\">\\n  What constraints have you imposed on yourself? What constraints have others imposed on you?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"I can\'t control what I feel, but I can decide what I\'ll let affect me. The word \'let\' is the whole point: it moves me from passenger to driver of my own influences.\\"\\n  howOften=\\"Monthly, as a check on what I\'m absorbing\\"\\n  when=\\"When I notice I\'ve taken on someone else\'s mood, opinion, or fear\\"\\n  record=\\"List the influences I\'ll keep, and the ones I\'m choosing to stop feeding\\">\\n  Which influences, motivators, de-motivators, and emotions will you *let* affect you?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Comfort in the darkness is the most dangerous kind, because it doesn\'t feel like a problem. This question asks why I\'ve made peace with a place I shouldn\'t stay, which is usually the first honest step out of it.\\"\\n  howOften=\\"Quarterly, and whenever I notice I\'ve stopped trying to leave a bad place\\"\\n  when=\\"When something painful has started to feel normal and I\'ve stopped fighting it\\"\\n  record=\\"Write what the darkness gives me that I\'m afraid to give up; that\'s what keeps me there\\">\\n  Why have you gotten comfortable in the darkness?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Becoming self-aware\\n\\n<SectionBanner why=\\"Self-awareness is the one study I keep postponing on the subject I know least. These questions push me to start the work and to define what \'aware\' would even look like, so it\'s a destination and not a vague intention.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"I keep treating self-study as something I\'ll get to later. This question asks why later never comes. The honest answer is usually that I\'m a little afraid of what I\'ll find.\\"\\n  howOften=\\"Whenever I notice I\'ve been avoiding looking inward\\"\\n  when=\\"When I realize I\'ve analyzed everyone and everything except myself\\"\\n  record=\\"A one-line honest answer about what I\'m avoiding, then a date to actually start\\">\\n  When will you start analyzing yourself? Why don\'t you study yourself?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"It\'s strange that the people around me can read me better than I read myself. Sitting with that gap is humbling, and it points directly at the blind spots I most need to close.\\"\\n  howOften=\\"Once a year, as a humility check\\"\\n  when=\\"When someone close to me names a pattern in me I hadn\'t seen\\"\\n  record=\\"Note what others see that I miss; that list is a map of my blind spots\\">\\n  Why do others know more about you than you know about yourself?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"If I can\'t say what \'self-aware\' would look like, I can\'t tell whether I\'m getting there. Defining the destination and its stages turns a vague aspiration into something I can actually pursue.\\"\\n  howOften=\\"Annually, as I refine what the goal even is\\"\\n  when=\\"During deeper reflection, when I want a way to measure inner progress\\"\\n  record=\\"Write a working definition of self-awareness, then the stages I think it moves through\\">\\n  How do you become self-aware? What must you do to declare yourself self-aware? What is your process for reaching a full state of self-awareness, and what are its different states?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Capturing the essentials\\n\\n<SectionBanner why=\\"Sometimes I need a fast inventory of myself instead of a deep dive: what I think about, what I\'m good at, what stops me, and how I get past it. This compact battery takes that snapshot quickly.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"What I keep thinking about is data about who I am, and most of it slips by unexamined. Catching my recurring thoughts, interests, and strengths in one pass gives me a quick read on where my mind actually lives.\\"\\n  howOften=\\"Monthly, as a quick self-inventory\\"\\n  when=\\"When I want a fast snapshot rather than a long reflection session\\"\\n  record=\\"A short list under each prompt; the patterns across months matter more than any single answer\\">\\n  What do you always think about? What interests you? What are your strengths?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Purpose, goals, and dreams are the directional questions, and answering them together shows whether they actually point the same way. When they don\'t line up, that misalignment is the thing to fix.\\"\\n  howOften=\\"Quarterly, when I reset my direction\\"\\n  when=\\"At the start of a season, or when I feel like I\'m working hard without aim\\"\\n  record=\\"Write all three; check whether the goals and dreams actually serve the stated purpose\\">\\n  What is your purpose? What are your goals? What are your dreams?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing my obstacles and what pushes me past them turns being stuck into a solvable problem. The trick of overcoming thought X by remembering thought Y is a practical tool I can actually use in the moment.\\"\\n  howOften=\\"Monthly, and any time I hit a wall\\"\\n  when=\\"When I\'m blocked and want to remember what has gotten me unstuck before\\"\\n  record=\\"Pair each obstacle with the specific thought or move that breaks it\\">\\n  What are your obstacles? What motivates you? What thoughts push you past your obstacles? You can overcome thought X by remembering thought Y. How can you manage your emotions?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Learning about yourself through what\'s around you\\n\\n<SectionBanner why=\\"I\'m not the only mirror I have. Watching society, nature, and the divine reflects parts of me back that I can\'t see from the inside, and that outside view often teaches me more about myself than introspection alone.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"The tendencies I notice in society are often my own, magnified. Studying the crowd is a sideways way to study myself, since what I judge or admire in others usually lives in me too.\\"\\n  howOften=\\"Now and then, when I catch a strong reaction to how people behave\\"\\n  when=\\"When something in society repels or attracts me strongly\\"\\n  record=\\"Note what I react to in others, then ask honestly where that same thing lives in me\\">\\n  How can you learn more about yourself by studying the natural tendencies of society?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Looking at myself through the lens of God, and through the 99 names, reframes self-study as something larger than self-improvement. Asking whether I reflect even a little of those attributes turns abstract faith into a concrete mirror.\\"\\n  howOften=\\"During seasons of faith and searching, not on a fixed schedule\\"\\n  when=\\"During prayer, spiritual reflection, or when I want a higher reference point than myself\\"\\n  record=\\"Note which attributes I see faint traces of in myself and which I\'m furthest from\\">\\n  How can you learn more about yourself from God? How does that push you to become more self-aware? Do you minimally reflect any of the 99 names of God?\\n</Question>\\n\\n</QuestionSection>\\n\\n## \\"I am\\" statements\\n\\n<SectionBanner why=\\"The way I finish \'I am\' and \'I will\' quietly declares my identity, and I can be guessed by it. Checking whether those statements line up with what I claim to be passionate about is how I tell who I really am from who I say I am.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"My \'I am\' statements are the most compressed version of my identity I have. \'You are more than what you have become\' is the reminder that I get to declare who I am rather than settle for who I\'ve drifted into.\\"\\n  howOften=\\"Once a year, written deliberately\\"\\n  when=\\"During annual reflection, or when I feel like I\'ve shrunk into a lesser version of myself\\"\\n  record=\\"Write the full list of \'I am\' statements and read them back as a declaration, not a description\\">\\n  What are your \\"I am\\" statements? \\"Remember who you are. You are more than what you have become.\\"\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"If someone could guess me from my \'I am\'s\' and \'I will\'s\', then those statements are doing the work of defining me. Checking whether they align with what I say I\'m passionate about reveals where my words and my real self disagree.\\"\\n  howOften=\\"Annually, alongside writing the statements\\"\\n  when=\\"When I want to test whether my declared identity and my declared passion actually match\\"\\n  record=\\"Line up the \'I am\'s\' against the passion; circle every place they contradict\\">\\n  Can you guess who you are based on your \\"I am\'s\\" and your \\"I will\'s\\"? Do your \\"I am\\" statements align with what you believe your passion is?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Manifesting your beliefs\\n\\n<SectionBanner why=\\"Beliefs that stay inside my head don\'t shape anything. These questions push me to encode what I believe into something tangible, because the act of making values real is where identity stops being a feeling and starts being a contribution.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"What I truly believe in is the engine under everything I attempt. The conviction that I have something special to give the world isn\'t arrogance; it\'s the belief that has to come first, before I\'ll do the hard work of giving it.\\"\\n  howOften=\\"Once a year, and whenever doubt starts eroding the belief\\"\\n  when=\\"Before committing to something hard, or when I\'m tempted to play smaller than I should\\"\\n  record=\\"Write the belief as a flat statement I actually act on, not an aspiration I admire\\">\\n  What do you truly believe in? I believe I have something special to give this world.\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"A belief I never encode stays a private feeling. Turning values into something tangible, a habit, a creation, a commitment, is how belief becomes evidence. This question asks for the concrete \'how,\' not just the conviction.\\"\\n  howOften=\\"Quarterly, when I check whether my beliefs have produced anything\\"\\n  when=\\"When I notice I believe a lot but have little to show for it in the real world\\"\\n  record=\\"For each core belief, name one tangible thing it has produced or will produce\\">\\n  We have an opportunity to encode our beliefs, to make our values tangible. How will you do that?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-making-better-decisions","metadata":{"permalink":"/thoughts/questions-for-making-better-decisions","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-making-better-decisions.mdx","source":"@site/blog/2017-02-11-questions-for-making-better-decisions.mdx","title":"What I Ask Myself: To Decide Better","description":"The questions I return to when I look back on my decisions, separate good reasoning from lucky outcomes, and get sharper at the next call.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":12.46,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-making-better-decisions","title":"What I Ask Myself: To Decide Better","kind":"question-set","sidebar_label":"Deciding Better","description":"The questions I return to when I look back on my decisions, separate good reasoning from lucky outcomes, and get sharper at the next call.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Know Who I Am","permalink":"/thoughts/questions-for-knowing-who-you-are"},"nextItem":{"title":"What I Ask Myself: When Emotions Take Over","permalink":"/thoughts/questions-for-managing-your-emotions"}},"content":"Most of us make decisions and never look back at them. But the decisions already\\nbehind you are the cheapest teacher you\'ll ever have. These are the questions I\\nreturn to when I want to understand my own patterns, separate good reasoning from\\nlucky outcomes, and get a little better at the next call. Pick the ones that make\\nyou pause.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Reviewing past decisions\\n\\n<SectionBanner why=\\"The decisions already behind you are the cheapest data you have. Looking back deliberately is what turns a finished choice into a lesson.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"Big decisions slip by unexamined unless you make a point of naming them. Listing the recent ones is the raw material for every other question here.\\"\\n  howOften=\\"Monthly, as a quick inventory of what you\'ve decided\\"\\n  when=\\"During a monthly review or at the close of a busy stretch\\"\\n  record=\\"Keep a running list of significant decisions as you make them\\">\\n  What major decisions have you made recently?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Pride and regret are both signals about your values. Sorting decisions by how you feel about them reveals what you actually care about getting right.\\"\\n  howOften=\\"Quarterly, looking back across a longer arc\\"\\n  when=\\"During a seasonal review or after a chapter closes\\"\\n  record=\\"Two columns: proud of, would redo. Note the reason in each row\\">\\n  What decisions are you most proud of? Which do you wish you could redo?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A handful of decisions shape most of a life. Knowing which ones carried the most weight teaches you where to slow down next time.\\"\\n  howOften=\\"Quarterly, or during longer life reviews\\"\\n  when=\\"When reflecting on how you got to where you are\\"\\n  record=\\"Rank the highest-impact decisions and note what made each pivotal\\">\\n  Which decisions had the biggest impact on your life?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Understanding outcomes\\n\\n<SectionBanner why=\\"A decision and its outcome are two different things. Studying how a call actually played out is how you keep your expectations honest.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Comparing what happened to what you expected is the calibration loop. Without it, your predictions never get more accurate.\\"\\n  howOften=\\"After a decision has had time to play out\\"\\n  when=\\"Once the results of a choice are visible enough to judge\\"\\n  record=\\"Write your original expectation next to what actually happened\\">\\n  How did that decision turn out? Did reality match your expectations?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"What surprised you marks the edge of your model of the world. Surprises are where the real learning is hiding.\\"\\n  howOften=\\"After any outcome that didn\'t go how you pictured\\"\\n  when=\\"When a result lands differently than you assumed it would\\"\\n  record=\\"Note the specific surprise and what assumption it broke\\">\\n  What surprised you about the outcome?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Confusing a good outcome with a good decision is how you learn the wrong lesson. Separating skill from luck protects you from rewarding bad reasoning that happened to pay off.\\"\\n  howOften=\\"After any notable win or loss, before you draw conclusions\\"\\n  when=\\"When you\'re tempted to credit yourself, or blame yourself, for a result\\"\\n  record=\\"Judge the decision on what you knew at the time, not on how it ended\\">\\n  Was the outcome due to good decision-making or luck?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Learning from decisions\\n\\n<SectionBanner why=\\"A decision you don\'t learn from is one you\'ll likely repeat. These questions extract the lesson while the experience is still warm.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The lesson is the entire point of looking back. Naming what you\'d do differently is what makes the next decision better instead of identical.\\"\\n  howOften=\\"Monthly, and after any decision worth examining\\"\\n  when=\\"Once you can see how a choice turned out\\"\\n  record=\\"Write one concrete thing you\'d change and one you\'d keep\\">\\n  What did you learn from this decision? What would you do differently next time?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"The gap between what you knew and what you needed to know is where better decisions come from. Naming the missing information teaches you what to gather next time.\\"\\n  howOften=\\"After a decision, especially one that went sideways\\"\\n  when=\\"When reviewing a call that depended on incomplete information\\"\\n  record=\\"List what you had and what you wish you\'d had\\">\\n  What information did you have, and what were you missing?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Good reasoning can lead to bad results, and bad reasoning can get lucky. Judging the process apart from the outcome is the single most important habit for deciding well over time.\\"\\n  howOften=\\"After meaningful decisions, before you update your approach\\"\\n  when=\\"When a result tempts you to abandon a process that was actually sound\\"\\n  record=\\"Write whether the reasoning held up, independent of how it ended\\">\\n  Was your reasoning sound even if the outcome wasn\'t?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Decision patterns\\n\\n<SectionBanner why=\\"Your worst decisions tend to rhyme. Spotting the recurring shape of how you decide is how you stop repeating the same mistake in new clothes.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Patterns are where the leverage is. One fix to a recurring tendency improves every future decision that shares the shape.\\"\\n  howOften=\\"Quarterly, looking across many decisions at once\\"\\n  when=\\"When you have enough decisions logged to see the through-lines\\"\\n  record=\\"Name the patterns you keep repeating, good and bad\\">\\n  What patterns do you see in your decision-making?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Speed is a bias too. Knowing whether you rush or stall tells you which correction to apply before the next big call.\\"\\n  howOften=\\"Quarterly, as you review your decision patterns\\"\\n  when=\\"When you notice a decision went wrong on timing rather than substance\\"\\n  record=\\"Note your default tempo and where it has cost you\\">\\n  Do you tend to decide too quickly or too slowly?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Everyone leans on one faculty too hard. Naming your tilt and your biases is how you stop being quietly steered by them.\\"\\n  howOften=\\"Quarterly, and when a decision feels lopsided\\"\\n  when=\\"When you catch yourself defending a choice on feel alone, or on logic alone\\"\\n  record=\\"List the biases you recognize in yourself and where they show up\\">\\n  Do you over-rely on logic or emotion? What biases affect your decisions?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"You decide better under some conditions than others. Knowing when you\'re at your best lets you schedule important calls for those windows.\\"\\n  howOften=\\"Quarterly, mapping your conditions against your outcomes\\"\\n  when=\\"When reviewing where your strongest and weakest calls came from\\"\\n  record=\\"Note the conditions present during your best and worst decisions\\">\\n  When do you make your best decisions? Your worst?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Processing regrets\\n\\n<SectionBanner why=\\"Regret is information about what mattered to you, but it can also become a weight you carry past its usefulness. These questions mine the lesson and then let the rest go.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Regretting a bad process is fair; regretting a bad outcome you couldn\'t have foreseen is just self-punishment. Separating the two tells you what to actually fix.\\"\\n  howOften=\\"When a regret keeps surfacing and won\'t settle\\"\\n  when=\\"When you keep replaying a decision and can\'t tell why it stings\\"\\n  record=\\"Write whether you regret how you decided or just how it ended\\">\\n  What decisions do you regret? Is it the process or the outcome you regret?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"A regret you learn from converts a loss into tuition. The lesson is the only part worth keeping.\\"\\n  howOften=\\"When processing a regret, after the sting has cooled\\"\\n  when=\\"Once you can look at a painful decision without flinching\\"\\n  record=\\"Write the single lesson the regret is trying to teach you\\">\\n  What can you learn from these regrets?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Some decisions can\'t be reversed, and carrying them forever changes nothing but you. Making peace is what frees the energy that regret was eating.\\"\\n  howOften=\\"When an irreversible decision keeps draining you\\"\\n  when=\\"When you\'ve extracted the lesson but still can\'t set the decision down\\"\\n  record=\\"Write what you\'ve learned, then write your permission to release the rest\\">\\n  How do you make peace with decisions you can\'t undo?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Regret past its expiration is dead weight. Asking whether it still serves you is how you decide to put it down.\\"\\n  howOften=\\"When you notice an old regret still pulling at you\\"\\n  when=\\"When a regret has stopped teaching and started just hurting\\"\\n  record=\\"A yes or no, plus what you\'d reclaim by letting it go\\">\\n  Are you holding onto regret that\'s no longer serving you?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Decision quality over time\\n\\n<SectionBanner why=\\"The real measure isn\'t any single decision; it\'s whether you\'re getting better at deciding. These questions track the trend line.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Improvement is invisible without a baseline. Asking whether you\'re getting better forces you to compare your decisions across time instead of judging each in isolation.\\"\\n  howOften=\\"Quarterly, comparing recent calls to older ones\\"\\n  when=\\"During a longer review of your judgment over the year\\"\\n  record=\\"Note where your decision-making has clearly evolved\\">\\n  Are you getting better at making decisions? How has your decision-making evolved?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"You\'re better at some decisions than others. Knowing your strong and weak categories tells you where to lean on yourself and where to seek help.\\"\\n  howOften=\\"Quarterly, sorting your decisions by type\\"\\n  when=\\"When deciding whether to handle a call alone or get support\\"\\n  record=\\"Two lists: decision types you handle well, and ones you don\'t\\">\\n  What types of decisions are you good at? Which do you struggle with?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Reversals and course corrections\\n\\n<SectionBanner why=\\"Changing your mind is a skill, not a failure. These questions examine whether your reversals were wise and whether your timing on them was right.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"A reversal is itself a decision worth judging. Reviewing the ones you\'ve made teaches you when changing course is courage and when it\'s flinching.\\"\\n  howOften=\\"After you reverse a meaningful decision\\"\\n  when=\\"When you\'ve walked back a call and want to know if you were right to\\"\\n  record=\\"Note the reversal and whether, in hindsight, it was the right move\\">\\n  What decisions have you reversed? Was reversing the right call?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"The timing of a reversal matters as much as the reversal itself. Quitting too early wastes a good bet; quitting too late compounds a bad one.\\"\\n  howOften=\\"After a course correction, judging its timing\\"\\n  when=\\"When reviewing whether you changed direction at the right moment\\"\\n  record=\\"Write whether you reversed too early, too late, or on time\\">\\n  Did you reverse too early or too late?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"The stay-or-pivot question is one of the hardest in any decision. Building a way to answer it keeps you from confusing perseverance with stubbornness.\\"\\n  howOften=\\"When you\'re caught between holding the line and changing tack\\"\\n  when=\\"When a commitment is struggling and you can\'t tell if it needs more time or a new direction\\"\\n  record=\\"Write the signals that would tell you to stay versus pivot\\">\\n  How do you know when to stay the course versus change direction?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Decisions avoided\\n\\n<SectionBanner why=\\"The decisions you keep dodging cost you quietly, every day they stay open. These questions drag the avoided ones into the light.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Avoided decisions don\'t disappear; they accrue interest. Naming what you\'re ducking, and why, is the first step to finally facing it.\\"\\n  howOften=\\"Weekly, scanning for the decision you keep stepping around\\"\\n  when=\\"When something keeps showing up on your mind but never on your calendar\\"\\n  record=\\"List the decisions you\'re avoiding and the honest reason for each\\">\\n  What decisions have you been avoiding? Why?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Not deciding is a decision with its own price. Naming the cost of inaction often makes the choice feel less optional.\\"\\n  howOften=\\"Weekly, when an avoided decision lingers\\"\\n  when=\\"When you\'re tempted to keep an option open just to avoid the discomfort of closing it\\"\\n  record=\\"Write what indecision is costing you in time, energy, or options\\">\\n  What\'s the cost of not deciding?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Stuck decisions usually need one specific unlock. Asking what would help moves you from stewing to acting.\\"\\n  howOften=\\"When you\'re frozen on a particular decision\\"\\n  when=\\"When you\'ve named an avoided decision but still can\'t move on it\\"\\n  record=\\"Write the one thing, information, conversation, or deadline, that would unstick you\\">\\n  What would help you move forward?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Involving others, in retrospect\\n\\n<SectionBanner why=\\"Who you brought in, and whether you actually listened, shapes outcomes as much as the call itself. These questions audit how you used the people around you.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"The right input at the right time changes a decision; the wrong input, or none, distorts it. Reviewing who you involved teaches you who to consult next time.\\"\\n  howOften=\\"After a decision where others\' input mattered\\"\\n  when=\\"When reflecting on a call that other people touched\\"\\n  record=\\"Note who you consulted and whether you missed anyone you should have\\">\\n  Did you involve the right people? Should you have sought more input?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Seeking advice and ignoring it is worse than not asking. Checking whether you actually listened reveals whether you wanted input or just validation.\\"\\n  howOften=\\"After a decision where you asked for advice\\"\\n  when=\\"When you got counsel and want to know if you truly used it\\"\\n  record=\\"Write what advice you received and whether you acted on it\\">\\n  Did you listen to the advice you were given?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Others\' input can sharpen a decision or steer it off course. Tracing its effect on the outcome teaches you how much weight to give it next time.\\"\\n  howOften=\\"After a decision shaped by other people\'s views\\"\\n  when=\\"When reviewing how external input changed where you landed\\"\\n  record=\\"Note how each person\'s input moved the outcome, for better or worse\\">\\n  How did others\' input affect the outcome?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-managing-your-emotions","metadata":{"permalink":"/thoughts/questions-for-managing-your-emotions","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-managing-your-emotions.mdx","source":"@site/blog/2017-02-11-questions-for-managing-your-emotions.mdx","title":"What I Ask Myself: When Emotions Take Over","description":"The introspective questions I use to regulate my emotional state: which feelings to fuel, which to overcome, and how to stay steady.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":19.61,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-managing-your-emotions","title":"What I Ask Myself: When Emotions Take Over","kind":"question-set","sidebar_label":"My Emotions","description":"The introspective questions I use to regulate my emotional state: which feelings to fuel, which to overcome, and how to stay steady.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Decide Better","permalink":"/thoughts/questions-for-making-better-decisions"},"nextItem":{"title":"What I Ask Myself: To Measure My Progress","permalink":"/thoughts/questions-for-measuring-your-progress"}},"content":"Your emotions are signals, and they are also fuel. The skill is learning which feelings to lean into, which to overcome, and how to stay steady when frustration, fear, or hopelessness show up. The questions below are meant to be sat with, not skimmed. Pick the cluster that matches what you\'re feeling and let it interrogate you.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Understanding your emotions\\n\\n<SectionBanner why=\\"Before I can manage a feeling I have to know what it is and where it came from. These questions name the emotion and find its trigger, which is the start of any real regulation.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"core\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Managing feelings well starts with believing they can be managed at all. Asking how I should handle them reframes emotion as something I work with, not something that simply happens to me.\\"\\n  howOften=\\"Whenever a strong feeling takes hold\\"\\n  when=\\"In the moment an emotion starts steering me\\"\\n  record=\\"Note the feeling and one deliberate way to respond to it\\">\\n  How should I manage my feelings?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"daily\\"\\n  depth=\\"quick\\"\\n  why=\\"Naming what I\'m feeling right now creates just enough distance to respond instead of react. The act of labeling an emotion already begins to loosen its grip.\\"\\n  howOften=\\"Daily, as a quick check-in\\"\\n  when=\\"Any time I notice I\'m off but can\'t say why\\"\\n  record=\\"Write the specific feeling, not just \'good\' or \'bad\'\\">\\n  What feelings am I experiencing right now?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Every emotional reaction has a trigger, and finding it is where I regain agency. Once I know what set off the feeling, I can address the cause instead of just riding the wave.\\"\\n  howOften=\\"When a feeling spikes unexpectedly\\"\\n  when=\\"Right after a strong emotional reaction\\"\\n  record=\\"Trace the feeling back to the specific event or thought that triggered it\\">\\n  What triggered this emotional response?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Understanding the role emotions play in my life keeps me from either suppressing them or being run by them. They\'re information and energy; knowing their function lets me use both.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When reflecting on how I relate to my feelings overall\\"\\n  record=\\"Write what role your emotions actually serve in your decisions\\">\\n  What role do emotions play in my life?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"My emotional state shapes the quality of my prayer and focus. Examining the role feelings play there helps me bring my whole self to it instead of a distracted fragment.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When my prayer feels emotionally flat or scattered\\"\\n  record=\\"Note how your emotions help or hinder your prayer\\">\\n  What role do emotions play in my prayers?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Directing your emotions (fuel vs. overcome)\\n\\n<SectionBanner why=\\"Not every feeling should be suppressed and not every feeling should be obeyed. These questions sort my emotions into fuel to lean into and weight to overcome.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Some feelings are rocket fuel if I let them push me. Identifying which emotions to lean into means I stop wasting energy that could be propelling me forward.\\"\\n  howOften=\\"When a strong positive drive shows up\\"\\n  when=\\"When I feel motivated, inspired, or fired up\\"\\n  record=\\"Name the feelings worth amplifying and channel them deliberately\\">\\n  What feelings should I fuel and allow to push me?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Some feelings, left unchecked, quietly run my life into the ground. Naming the ones to overcome is the first step in refusing to be governed by them.\\"\\n  howOften=\\"When a feeling is dragging me down\\"\\n  when=\\"When an emotion is steering me somewhere I don\'t want to go\\"\\n  record=\\"List the feelings you need to overcome and your plan for each\\">\\n  What feelings should I overcome?\\n</Question>\\n\\n<Question\\n  power={[\'spark\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Emotion aimed at potential becomes a force for growth instead of a distraction. Asking how I\'ll harness my feelings turns raw energy into deliberate momentum toward who I want to become.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I want to convert emotional intensity into real progress\\"\\n  record=\\"Write how a current strong feeling could drive you toward your goals\\">\\n  How will I use my feelings to drive me to reach my full potential?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"There are feelings I\'ve decided I will not live with again, and naming them draws a line. That refusal becomes a standard that changes the choices I\'m willing to make.\\"\\n  howOften=\\"When I hit a feeling I\'ve sworn off\\"\\n  when=\\"When an old, unwanted feeling resurfaces\\"\\n  record=\\"Name the feeling you refuse to endure and what you\'ll change to avoid it\\">\\n  What feelings do I REFUSE to endure once more?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Controlling your emotions\\n\\n<SectionBanner why=\\"Regulation is a skill, not a mood. These questions are about the actual mechanics of influencing my own emotional state, including the hard ones like sorrow.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Believing I can influence my own emotions is what separates a passenger from a driver. Asking how I do it builds the actual toolkit instead of leaving me at the mercy of whatever I feel.\\"\\n  howOften=\\"When I want to shift my emotional state on purpose\\"\\n  when=\\"When I\'m caught in a feeling and want out of it\\"\\n  record=\\"Note the techniques that actually move your emotional state\\">\\n  How do I influence and control my own emotions?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Sorrow doesn\'t lift on its own; it has to be moved through. Having a way to work with grief keeps it from settling in and quietly running the rest of my life.\\"\\n  howOften=\\"During periods of grief or loss\\"\\n  when=\\"When sorrow is sitting heavy on me\\"\\n  record=\\"Write what genuinely helps you move through sorrow, not around it\\">\\n  How do I overcome my sorrow?\\n</Question>\\n\\n</QuestionSection>\\n\\n## When you feel frustrated\\n\\n<SectionBanner why=\\"Frustration is a signal pointing at something specific. These questions name what\'s actually frustrating me so I can address the cause instead of stewing in the feeling.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Frustration usually points at a thwarted value or goal. Naming exactly what frustrates me turns a diffuse irritation into a specific problem I can actually act on.\\"\\n  howOften=\\"When frustration builds up\\"\\n  when=\\"When I\'m irritated and can\'t quite place why\\"\\n  record=\\"List what specifically frustrates you, item by item\\">\\n  What frustrates me?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"What pulls me down is often subtle and cumulative. Identifying the specific things that deflate me lets me reduce my exposure to them on purpose.\\"\\n  howOften=\\"When my mood drops without obvious cause\\"\\n  when=\\"When I notice I\'m feeling low\\"\\n  record=\\"Name the things that reliably bring you down\\">\\n  What makes me feel down?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"De-motivators are quiet thieves of momentum. Spotting them lets me defend my drive instead of watching it leak away for reasons I never identified.\\"\\n  howOften=\\"When my motivation dips\\"\\n  when=\\"When I feel my energy for something draining\\"\\n  record=\\"Name what de-motivates you so you can guard against it\\">\\n  What de-motivates me?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Once I\'ve named the frustration and the de-motivation, the real work is moving through them. Asking how I overcome these feelings turns the diagnosis into an actual recovery.\\"\\n  howOften=\\"When stuck in a frustrated or low state\\"\\n  when=\\"After naming what\'s dragging me down\\"\\n  record=\\"Write your move for getting out of the low state, then use it\\">\\n  How do I overcome these feelings?\\n</Question>\\n\\n</QuestionSection>\\n\\n## When you feel like giving up\\n\\n<SectionBanner why=\\"At the edge of quitting, the right question can tip me back. These questions test whether the hope and the conviction are really gone, or just buried under fatigue.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Hopelessness often lies about how much hope is actually left. Deliberately looking for any hope in the situation can be enough to keep me in it one more day, which is often all it takes.\\"\\n  howOften=\\"When I\'m on the edge of quitting\\"\\n  when=\\"When the situation feels hopeless\\"\\n  record=\\"Write down any genuine reason for hope, however small\\">\\n  Is there any hope in this situation?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"core\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"If I still believe in the value of what I\'m doing, fatigue is the enemy, not the work. This question separates \'I\'m tired\' from \'this isn\'t worth it,\' which point to very different decisions.\\"\\n  howOften=\\"When tempted to abandon something\\"\\n  when=\\"When I\'m worn down and questioning the whole effort\\"\\n  record=\\"State plainly whether you still believe in the work, and why\\">\\n  Do you still believe in the value of what you\'re doing?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming what would make me want to continue surfaces the conditions for my own persistence. Sometimes I can actually create those conditions instead of waiting to feel like going on.\\"\\n  howOften=\\"When my will to continue is fading\\"\\n  when=\\"When I\'m deciding whether to keep going\\"\\n  record=\\"Write what would rekindle your desire to continue, then see if you can build it\\">\\n  What would make me want to continue?\\n</Question>\\n\\n</QuestionSection>\\n\\n## When you feel like speaking out\\n\\n<SectionBanner why=\\"Strong feelings often demand to be voiced, but not every expression helps. These questions check whether speaking out serves a purpose before I let the feeling do the talking.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"The pull to speak isn\'t the same as the wisdom to. Pausing to ask whether I should speak up creates the gap between feeling and action where good judgment lives.\\"\\n  howOften=\\"When I feel the urge to speak out\\"\\n  when=\\"When emotion is pushing me to say something\\"\\n  record=\\"Note whether the urge is about the issue or just about venting\\">\\n  Should I speak up about this?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"The same feeling can be expressed in a way that builds or one that burns. Finding the constructive form lets me honor the emotion without doing damage I\'ll regret.\\"\\n  howOften=\\"Before voicing a strong feeling\\"\\n  when=\\"When I\'ve decided to speak and want it to land well\\"\\n  record=\\"Draft the constructive version before you say the reactive one\\">\\n  What is the constructive way to express this feeling?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Speaking out should serve something beyond my own relief. Checking whether it serves a positive purpose keeps me from confusing catharsis with contribution.\\"\\n  howOften=\\"Before speaking out\\"\\n  when=\\"When I\'m about to say something charged\\"\\n  record=\\"Name the positive purpose, and if there isn\'t one, reconsider\\">\\n  Will speaking out serve a positive purpose?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Conducting others\' emotions\\n\\n<SectionBanner why=\\"My emotions don\'t stay inside me; they shape the people around me. These questions ask me to be intentional about the emotional journey I lead others through.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Everyone gives off a kind of music, a felt sense others pick up. Asking what mine is, and whether it points people toward something higher, makes my emotional influence a deliberate offering rather than an accident.\\"\\n  howOften=\\"Yearly, as a deep reflection\\"\\n  when=\\"When considering the effect I have on others\\"\\n  record=\\"Write what \'music\' you want people to feel from your presence\\">\\n  What is your music that points others to the divine?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Whether I mean to or not, I take the people around me through an emotional arc, and myself along with them. Naming the journey I want to lead lets me choose it instead of leaving it to chance.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I\'m leading or collaborating closely with others\\"\\n  record=\\"Map the emotional journey you intend for others and for yourself\\">\\n  What emotional journey will you take your co-workers through? What journey will you take yourself through?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"My reach into others\' emotions is a responsibility, not just an effect. Asking whose feelings I\'ll touch and how makes me accountable for the impact I\'m already having.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When I have influence over how others feel\\"\\n  record=\\"Name whose emotions you affect and the effect you want to have\\">\\n  Whose emotions will you touch? How?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Shaping others\' emotions well requires understanding the mechanics of how I do it. Examining how I mold what people feel keeps that influence honest and intentional.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When reflecting on how I move people emotionally\\"\\n  record=\\"Note the ways you actually shape what others feel\\">\\n  How do you mold the emotions of others?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Overcoming fear\\n\\n<SectionBanner why=\\"Fear masquerades as caution and shrinks my life one avoidance at a time. These questions confront whether fear is quietly running my days and stopping me from starting.\\" />\\n\\n<QuestionSection>\\n\\n> You are given an opportunity. You can deny it because you\'re afraid, afraid that you\'re too young, afraid of the unknown. Or you can take it. This is your choice.\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Living in daily fear and calling it caution is how a life quietly shrinks. Pairing the fear question with progress checks whether fear is costing me the very movement I claim to want.\\"\\n  howOften=\\"When I notice fear shaping my days\\"\\n  when=\\"When hesitation has become a habit\\"\\n  record=\\"Note whether fear is steering your days, and whether you\'re still moving\\">\\n  Do you live in fear every single day? Are you progressing?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'spark\']}\\n  priority=\\"core\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Most fear collapses at the moment of starting, which is exactly the moment fear works hardest to prevent. Naming what I\'m afraid to do, and whether it\'s really just fear of beginning, gets me past the hardest step.\\"\\n  howOften=\\"When I keep postponing something\\"\\n  when=\\"When I want to act but keep stalling\\"\\n  record=\\"Name the thing you\'re afraid to do and take the first small step\\">\\n  What are you afraid to do? Are you afraid to get started?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Overcoming negative emotions\\n\\n<SectionBanner why=\\"Negative emotions accumulate fastest when I don\'t track them. These questions and their specific subtypes build a strategy for facing each one head on instead of absorbing them silently.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"daily\\"\\n  depth=\\"moderate\\"\\n  why=\\"The negative emotions I minimize each day add up to a heavy quiet cost. Naming the ones I\'m absorbing brings that hidden tax into view so I can actually reduce it.\\"\\n  howOften=\\"Daily\\"\\n  when=\\"When I catch myself brushing off a bad feeling\\"\\n  record=\\"List the negative emotions you\'ve been quietly tolerating\\">\\n  What negative emotions am I minimizing on a daily basis?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Frequency is data. Tracking how often a negative emotion shows up turns a vague sense of struggle into a measurable pattern I can actually work to change.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When I want to know how often a feeling actually recurs\\"\\n  record=\\"Keep a simple tally of how often each negative emotion appears\\">\\n  How often do I feel negative emotions, and how am I tracking this?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"I can\'t manage what I haven\'t named. Cataloging the specific negative emotions I feel is the inventory step before any real strategy can exist.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When my negative feelings blur into a general \'bad\'\\"\\n  record=\\"Write the named list of negative emotions you actually experience\\">\\n  What are the negative emotions that I feel?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"A generic plan to \'feel better\' fails. Building a specific strategy for each negative emotion is what turns reactive coping into a deliberate practice that reshapes how I respond over time.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When I want a real plan, not just to white-knuckle through feelings\\"\\n  record=\\"Write a specific strategy for overcoming each negative emotion you face\\">\\n  How do I overcome each of the negative emotions I encounter? What is my strategy for overcoming each one?\\n</Question>\\n\\n### Anger\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Anger has specific triggers, and finding them is where I regain control. Distinguishing anger at a person, at a wrong, or at an annoyance points each one at a different and more useful response.\\"\\n  howOften=\\"When anger flares\\"\\n  when=\\"In the moment I feel anger rising\\"\\n  record=\\"Note who or what the anger is aimed at and what it\'s really about\\">\\n  When do I feel anger: at someone, at someone who wronged me, at someone who annoyed me?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Counting how often I get angry replaces a vague impression with a real number. The count itself often shrinks the behavior, because attention changes what it measures.\\"\\n  howOften=\\"Weekly, by keeping a simple count\\"\\n  when=\\"During any week I want a baseline on my anger\\"\\n  record=\\"Tally each instance of anger to see the true frequency\\">\\n  How often do I get angry? (Try counting it.)\\n</Question>\\n\\n### Regret\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Regret over a wrong done and regret over a path not taken call for different responses, one repair, one redirection. Separating them turns a heavy, shapeless feeling into something I can actually act on.\\"\\n  howOften=\\"When regret surfaces\\"\\n  when=\\"When I\'m weighed down by something I did or didn\'t do\\"\\n  record=\\"Name whether the regret is about a wrong or a missed alternative\\">\\n  When do I feel regret: that I did something wrong, or that I should have done something differently?\\n</Question>\\n\\n### Hopelessness\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"deep\\"\\n  why=\\"Hopelessness usually traces to either doubting an outcome or feeling blocked from it. Naming which one it is tells me whether the work is rebuilding belief or removing an obstacle.\\"\\n  howOften=\\"When hopelessness sets in\\"\\n  when=\\"When I feel like giving up on a particular hope\\"\\n  record=\\"Note whether you doubt the outcome or feel something is in the way\\">\\n  When do I feel hopeless: that something I want won\'t happen, or that something is in the way?\\n</Question>\\n\\n### Under-productivity\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The feeling of not doing enough is information about a gap between my standards and my actions. Naming where the shortfall is (work, learning, worship, focus) tells me where the feeling is actually pointing.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When I feel I\'m falling short of what I should be doing\\"\\n  record=\\"Identify which area the \'not enough\' feeling is really about\\">\\n  When do I feel like I\'m not doing enough? What feelings come from a lack of action? Not enough work, learning, or exercise? Not enough worship or focus?\\n</Question>\\n\\n### Lack of focus\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"daily\\"\\n  depth=\\"quick\\"\\n  why=\\"Counting how often I lose focus in prayer makes a slippery problem visible. The act of counting is itself a form of attention that tends to improve the very thing it measures.\\"\\n  howOften=\\"Daily, during prayer\\"\\n  when=\\"When I notice my focus drifting in prayer\\"\\n  record=\\"Tally how often you lose focus in a single prayer\\">\\n  How often do I lose focus in prayer? (Try counting it.)\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"daily\\"\\n  depth=\\"quick\\"\\n  why=\\"Losing track of where I am in prayer is a concrete, observable symptom of drift. Noticing it gives me a specific cue to gently return rather than a vague sense of distraction.\\"\\n  howOften=\\"Daily, during prayer\\"\\n  when=\\"When I lose count of my rakas\\"\\n  record=\\"Note when you lose your place, as a signal to refocus\\">\\n  Do I lose track of where I am, unsure how many rakas I\'ve prayed?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Tracking your emotions\\n\\n<SectionBanner why=\\"What gets tracked gets managed. These questions pick the few emotions most worth measuring so I don\'t try to track everything and end up tracking nothing.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Choosing which negative emotions to track focuses my limited attention on the ones that cost me most. Knowing I shouldn\'t feel them isn\'t enough; measuring them is what starts to reduce them.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When deciding what emotional data is worth collecting\\"\\n  record=\\"Pick the specific negative emotions worth tracking, and start\\">\\n  Which negative emotions should I start tracking, knowing I shouldn\'t feel them?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"core\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Ranking the top three emotions to minimize forces a real priority. I can\'t fix everything at once, so naming the most important three is what makes the effort focused and achievable.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When I need to focus my emotional work on what matters most\\"\\n  record=\\"Write the THREE feelings to minimize, ranked by importance\\">\\n  What are the THREE things I should track, ranked by importance, with regard to the negative feelings I want to minimize in my life?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Staying optimistic\\n\\n<SectionBanner why=\\"Optimism is partly a discipline of what I let into my mind and what I deliberately amplify. These questions guard the gate against negative thoughts and turn up the positive ones on purpose.\\" />\\n\\n<QuestionSection>\\n\\n### Purging negative thoughts\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"deep\\"\\n  why=\\"Negative thoughts about myself, God, love, or my abilities pollute everything downstream of them. Naming the specific pollutants is the first step to clearing the water they\'re poisoning.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When my inner monologue has turned dark\\"\\n  record=\\"List the specific negative thoughts and the area each pollutes\\">\\n  What negative thoughts are polluting your mind: about yourself, about God, about love, about success, about where you are now, about your abilities?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"deep\\"\\n  why=\\"Drawing a line against certain thoughts is an act of self-governance. Deciding in advance which ones I\'ll no longer allow in makes the refusal a standing policy instead of a moment-by-moment fight.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When I\'m ready to stop entertaining a recurring negative thought\\"\\n  record=\\"Name the thoughts you\'re banning from your mind, and hold the line\\">\\n  What negative thoughts will you no longer allow to infiltrate your mind?\\n</Question>\\n\\n### Maximizing positive emotions\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Positive emotions can be cultivated, not just waited for. Asking how I maximize them turns optimism into an active practice rather than a matter of luck.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When I want to deliberately raise my baseline mood\\"\\n  record=\\"Note what reliably amplifies your positive emotions, then do more of it\\">\\n  How do I maximize positive emotions?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The words I use, on myself and others, shape the emotions that follow. Leveraging empowering language is a simple, repeatable lever for lifting my own state and the room\'s.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When choosing how I talk to myself and others\\"\\n  record=\\"Collect the empowering words and phrases that actually shift your state\\">\\n  How do I leverage empowering words?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Further reading\\n\\n- [Affective Science on Wikipedia](https://en.wikipedia.org/wiki/Affective_science)"},{"id":"questions-for-measuring-your-progress","metadata":{"permalink":"/thoughts/questions-for-measuring-your-progress","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-measuring-your-progress.mdx","source":"@site/blog/2017-02-11-questions-for-measuring-your-progress.mdx","title":"What I Ask Myself: To Measure My Progress","description":"The questions I sit with when I want an honest read on whether I\'m winning, reaching my potential, and closing the gap to my dreams.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":11.27,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-measuring-your-progress","title":"What I Ask Myself: To Measure My Progress","kind":"question-set","sidebar_label":"My Progress","description":"The questions I sit with when I want an honest read on whether I\'m winning, reaching my potential, and closing the gap to my dreams.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: When Emotions Take Over","permalink":"/thoughts/questions-for-managing-your-emotions"},"nextItem":{"title":"What I Ask Myself: About What I\'m Learning","permalink":"/thoughts/questions-for-reflecting-on-what-youre-learning"}},"content":"Progress is easy to assume and hard to measure. It\'s worth stopping every so often to ask whether you\'re truly striving toward your potential, whether you can even tell if you\'re winning, and whether you have the will to keep going. These are the questions I sit with when I want an honest read on where I stand. Pick the ones that are uncomfortable to answer.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Potential\\n\\n<SectionBanner why=\\"Potential is the gap between who you are and who you could be. These questions check whether you\'re actually moving across that gap or just standing at its edge.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Most people never approach the edge of what they\'re capable of. Asking whether you\'ve even scratched the surface is a deliberately uncomfortable wake-up call.\\"\\n  howOften=\\"Quarterly, or whenever you suspect you\'re coasting\\"\\n  when=\\"During a longer review of where your effort is actually going\\"\\n  record=\\"Write an honest estimate of how much of your potential you\'re using\\">\\n  Have you even scratched the surface of your potential?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Striving toward your potential is a direction, not a destination. Asking whether you\'re pursuing the person you could become keeps the effort aimed at growth rather than comfort.\\"\\n  howOften=\\"Quarterly, as a check on your trajectory\\"\\n  when=\\"When reviewing whether your daily choices point toward who you want to be\\"\\n  record=\\"Note where you\'re stretching and where you\'ve settled\\">\\n  Are you striving to your potential? Are you pursuing becoming the person you can be?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Sometimes the worry that you\'re falling behind blinds you to the road you\'re already on. This question is a reminder to check whether you\'re further along than you feel.\\"\\n  howOften=\\"Quarterly, especially when discouragement creeps in\\"\\n  when=\\"When you feel stuck but haven\'t actually checked your position\\"\\n  record=\\"List the evidence that you\'re already moving in the right direction\\">\\n  Perhaps you are already on the road to your goal?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Progress is meaningless without a destination to measure it against. If you can\'t say where you\'re going, you can\'t tell whether you\'re getting closer.\\"\\n  howOften=\\"Quarterly, and any time your direction feels fuzzy\\"\\n  when=\\"When effort feels busy but aimless\\"\\n  record=\\"Write where you\'re trying to go in one or two clear sentences\\">\\n  Do you know where you are going?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Accomplishments\\n\\n<SectionBanner why=\\"What you\'ve actually done is the hard evidence of progress. These questions take stock of the ground you\'ve covered and how much remains.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"Wins fade from memory faster than setbacks. Listing what you\'ve accomplished is both a morale check and an honest measure of your output.\\"\\n  howOften=\\"Monthly, as a quick inventory of what you\'ve shipped\\"\\n  when=\\"During a monthly review or when you feel like nothing\'s moving\\"\\n  record=\\"Keep a running list of accomplishments as they happen\\">\\n  What have you accomplished?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming the distance to your dreams turns a vague aspiration into a measurable gap. You can\'t close a distance you\'ve never sized up.\\"\\n  howOften=\\"Quarterly, gauging how far you\'ve traveled\\"\\n  when=\\"When reviewing long-term goals against current reality\\"\\n  record=\\"Estimate how close you are and what\'s left between here and there\\">\\n  How close are you to fulfilling your dreams?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing the gap is one thing; knowing how to close it is another. This question pushes from diagnosis into a plan.\\"\\n  howOften=\\"Quarterly, after sizing up the distance to your goal\\"\\n  when=\\"When you\'ve named the gap and need the moves to cross it\\"\\n  record=\\"Write the specific actions that would shrink the gap\\">\\n  How do you close the gap to being successful?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Obstacles you\'ve already beaten are proof of capability you tend to forget. Counting them rebuilds the confidence to face the next one.\\"\\n  howOften=\\"Quarterly, or when a new obstacle feels insurmountable\\"\\n  when=\\"When you doubt whether you can handle what\'s in front of you\\"\\n  record=\\"List the obstacles you\'ve overcome and how you did it\\">\\n  What obstacles have you overcome?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Winning and losing\\n\\n<SectionBanner why=\\"You can\'t tell whether you\'re winning if you\'ve never defined the game or kept score. These questions force the scoreboard into view.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Wanting to win is not the same as winning, and not everyone actually wants it. This pairing checks both your position and your desire honestly.\\"\\n  howOften=\\"Monthly, taking the temperature of your effort and your want\\"\\n  when=\\"When you\'re unsure whether you\'re committed or just going through motions\\"\\n  record=\\"Write whether you\'re winning and whether you genuinely want to\\">\\n  Are you winning? Do you really want to win?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Without a scoreboard, you\'re guessing about your own progress. Keeping score is what makes winning and losing visible instead of a feeling.\\"\\n  howOften=\\"Monthly, checking whether you can even read your own results\\"\\n  when=\\"When you can\'t say with confidence whether you\'re ahead or behind\\"\\n  record=\\"Define what counts as a point and start tracking it\\">\\n  Are you keeping score? Can you tell if you are winning or losing?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"If losing costs you nothing, you won\'t fight to avoid it. Making losing painful is a way to raise your own stakes on purpose.\\"\\n  howOften=\\"Quarterly, when setting up the stakes for a goal\\"\\n  when=\\"When you keep tolerating losses because they don\'t actually hurt\\"\\n  record=\\"Write the consequence you\'ll attach to losing\\">\\n  How will you make losing painful?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"Wins you never mark don\'t register as progress. Celebrating is how you make the scoreboard motivating instead of just informative.\\"\\n  howOften=\\"Monthly, and after any meaningful win\\"\\n  when=\\"When you reach a milestone and are tempted to rush past it\\"\\n  record=\\"Decide how you\'ll mark a win before you reach it\\">\\n  How do you celebrate?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Readiness and will\\n\\n<SectionBanner why=\\"Skill gets you to the starting line, but will is what carries you through the grind. These questions test whether you have the stomach for what progress actually demands.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Anything worth doing involves failing on the way there. Being ready to pursue failure, not just tolerate it, is what separates people who try from people who wish.\\"\\n  howOften=\\"Quarterly, and before starting anything where failure is likely\\"\\n  when=\\"When you\'re about to commit to something hard enough to fail at\\"\\n  record=\\"Write whether you\'re truly ready to fail in pursuit of this\\">\\n  Are you ready to pursue failure?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The romance of winning hides the grind that produces it: the emails, the rejection, the broken promises. Facing that burden honestly is the real readiness check.\\"\\n  howOften=\\"Quarterly, and before taking on a serious pursuit\\"\\n  when=\\"When you\'re drawn to the prize but haven\'t reckoned with the cost\\"\\n  record=\\"Write the unglamorous work the goal will actually require of you\\">\\n  Are you ready to take on the emotional burden of winning? Of sending the countless emails? Of dealing with rejection and broken promises?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Will often beats raw skill over the long haul. Asking whether you\'re phenomenally willed reframes progress as a test of persistence, not just talent.\\"\\n  howOften=\\"Quarterly, when assessing what will carry you through\\"\\n  when=\\"When skill alone clearly won\'t be enough to finish\\"\\n  record=\\"Write an honest read on your will, separate from your talent\\">\\n  You may not be phenomenally skilled, but are you phenomenally willed?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Handing your state over to something you can\'t control is a quiet way to stall. Naming it is the first step to taking the wheel back.\\"\\n  howOften=\\"Monthly, scanning for where you\'ve ceded control\\"\\n  when=\\"When your progress feels hostage to something outside you\\"\\n  record=\\"Name what\'s controlling you and what reclaiming control would look like\\">\\n  Are you letting something out of your control control you?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Readiness to change\\n\\n<SectionBanner why=\\"Real change starts with deciding you\'re ready for it. These questions ask whether you\'ve actually committed to the shift or are still circling it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Knowing your why is what makes change survive the hard middle. Asking whether you\'re ready to pick it is asking whether you\'re ready to commit at all.\\"\\n  howOften=\\"Quarterly, or at the start of any real change\\"\\n  when=\\"When you\'re on the edge of a decision to change something significant\\"\\n  record=\\"Write your why, and whether you\'re ready to stand on it\\">\\n  Are you ready? Are you ready to pick your why?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Writing your story and finding yourself are acts of authorship, not waiting. This question checks whether you\'re ready to take the pen.\\"\\n  howOften=\\"Quarterly, during periods of searching or transition\\"\\n  when=\\"When you feel like life is happening to you rather than by you\\"\\n  record=\\"Note whether you\'re ready to author the next chapter on purpose\\">\\n  Are you ready to write your story? Are you ready to find yourself?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The plainest version of the readiness question is also the heaviest. Changing your life is the threshold everything else here is circling.\\"\\n  howOften=\\"Quarterly, or whenever you sense a real shift is due\\"\\n  when=\\"When you\'ve been talking about change without yet committing to it\\"\\n  record=\\"A yes or no, and what saying yes would actually require\\">\\n  Are you ready to change your life?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Waking up excited\\n\\n<SectionBanner why=\\"How you feel when you wake up is a daily readout on whether your work and your life are aligned. These questions check that signal.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Working toward something bigger than yourself is what sustains effort past the point of self-interest. This question checks whether your days point at something that large.\\"\\n  howOften=\\"Weekly, as a check on what your effort is serving\\"\\n  when=\\"During a weekly review of where your energy is going\\"\\n  record=\\"Note whether your week served a vision bigger than you, and which one\\">\\n  Do you wake up every day working towards a vision bigger than you?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Morning excitement is a fast, honest signal of alignment. Its absence over time is worth taking seriously.\\"\\n  howOften=\\"Weekly, noticing the pattern across your mornings\\"\\n  when=\\"When you notice you\'ve been waking up flat or dreading the day\\"\\n  record=\\"Track how often you wake up genuinely excited\\">\\n  Do you wake up excited every morning?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"low\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Itching to start is a rare and telling sign that you\'re on the right work. Watching for it tells you when you\'ve found something worth doing.\\"\\n  howOften=\\"Weekly, noticing whether you\'re pulled toward the work\\"\\n  when=\\"When gauging your relationship with what you\'re currently building\\"\\n  record=\\"Note the days you couldn\'t wait to start, and what you were working on\\">\\n  Do you wake up itching to work every day?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Goal achievement and tracking\\n\\n<SectionBanner why=\\"Progress you don\'t track is progress you can\'t trust. These questions build the measurement loop that turns effort into evidence.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"quick\\"\\n  why=\\"Goals are only useful if you check whether you hit them. Asking what you\'ve achieved closes the loop that goal-setting opened.\\"\\n  howOften=\\"Quarterly, reconciling goals against actual results\\"\\n  when=\\"At the end of a quarter or goal period\\"\\n  record=\\"Mark each goal as hit, missed, or in progress\\">\\n  Have you achieved any of your goals?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Task counts are a crude but real signal of throughput. Tracking them weekly keeps your sense of momentum tied to something countable.\\"\\n  howOften=\\"Weekly, as a simple throughput check\\"\\n  when=\\"At the end of each week\\"\\n  record=\\"Count completed tasks and watch the trend week over week\\">\\n  How many tasks did you complete this week?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The right report makes progress legible at a glance. Designing what to track is what turns scattered effort into a dashboard you can read.\\"\\n  howOften=\\"Monthly, or when your current view of progress feels murky\\"\\n  when=\\"When you can\'t quickly see whether you\'re moving\\"\\n  record=\\"Define the few reports or metrics that would show your progress clearly\\">\\n  What reports will help you track your progress?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Failing your way to success reframes setbacks as data points on the path, not detours off it. Asking whether you\'ve begun is asking whether you\'re in the game.\\"\\n  howOften=\\"Monthly, checking your relationship with failure\\"\\n  when=\\"When fear of failing is keeping you from starting\\"\\n  record=\\"Note the failures you\'ve already turned into forward steps\\">\\n  Have you begun failing your way to success?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-reflecting-on-what-youre-learning","metadata":{"permalink":"/thoughts/questions-for-reflecting-on-what-youre-learning","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-reflecting-on-what-youre-learning.mdx","source":"@site/blog/2017-02-11-questions-for-reflecting-on-what-youre-learning.mdx","title":"What I Ask Myself: About What I\'m Learning","description":"The questions I return to when I want to check that my learning is pointed at who I want to become and notice the gaps I keep avoiding.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":6.98,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-reflecting-on-what-youre-learning","title":"What I Ask Myself: About What I\'m Learning","kind":"question-set","sidebar_label":"My Learning","description":"The questions I return to when I want to check that my learning is pointed at who I want to become and notice the gaps I keep avoiding.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: To Measure My Progress","permalink":"/thoughts/questions-for-measuring-your-progress"},"nextItem":{"title":"What I Ask Myself: About My Priorities","permalink":"/thoughts/questions-for-reflecting-on-your-priorities"}},"content":"It\'s easy to keep learning and never stop to ask whether you\'re learning the right things. Most of us absorb whatever lands in front of us instead of choosing what to study on purpose. These are the questions I return to when I want to step back, check that my learning is pointed at who I want to become, and notice the gaps I keep avoiding. Pick the ones that make you pause.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Core learning questions\\n\\n<SectionBanner why=\\"It\'s easy to keep learning and never ask whether you\'re learning the right things. These questions point your studying at who you actually want to become.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Learning without reflection is just consumption. Pausing to name what you\'ve taken in is what turns information into understanding.\\"\\n  howOften=\\"Weekly, while what you\'ve learned is still fresh\\"\\n  when=\\"At the end of a week of study, reading, or work\\"\\n  record=\\"Write a few lines on what landed and what it changed in your thinking\\">\\n  What reflections have you had on the things you are learning?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Your past learning goals trace the shape of who you were becoming. Revisiting them shows how your interests have drifted and what you\'ve left unfinished.\\"\\n  howOften=\\"Quarterly, looking back across your learning history\\"\\n  when=\\"When reflecting on how your curiosity has shifted over time\\"\\n  record=\\"Note what you wanted to learn at each stage and whether you did\\">\\n  What did you want to learn at different points in time?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"You can spend years learning things that don\'t move you toward who you want to be. This is the question that catches misdirected effort before it costs you more time.\\"\\n  howOften=\\"Quarterly, as a directional audit of your learning\\"\\n  when=\\"When you suspect your studying has drifted from what matters\\"\\n  record=\\"Write an honest yes or no, with the evidence behind it\\">\\n  Are you learning the right things?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Learning that aligns with your purpose compounds; learning that doesn\'t just fills time. Checking the alignment keeps your effort pointed at something larger.\\"\\n  howOften=\\"Quarterly, mapping your learning against your purpose\\"\\n  when=\\"When deciding what to study next or whether to continue something\\"\\n  record=\\"Note which of your current learning threads actually serve your purpose\\">\\n  Do the things you are learning align to your purpose?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Becoming who you want to be requires learning chosen on purpose, not by accident. This question asks you to build the filter that keeps your learning aimed.\\"\\n  howOften=\\"Quarterly, or when designing your learning plan\\"\\n  when=\\"When you\'re deciding how to direct your study rather than letting it drift\\"\\n  record=\\"Write the test you\'ll use to choose what\'s worth learning\\">\\n  How do you ensure you are learning things that fulfill what you want to become?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Education focus\\n\\n<SectionBanner why=\\"Attention is finite, so what you choose to study is itself a decision worth making well. These questions help you aim your education instead of scattering it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"A scattered education produces shallow range. Naming a focus is what lets your learning go deep enough to matter.\\"\\n  howOften=\\"Quarterly, when setting your learning direction\\"\\n  when=\\"When your studying feels spread too thin to stick\\"\\n  record=\\"Write the one or two areas worth concentrating your education on\\">\\n  What should you focus your education on?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"Your curiosity is a signal worth capturing before it fades. Keeping a list of topics you want to explore turns passing interest into a plan.\\"\\n  howOften=\\"Monthly, as new curiosities surface\\"\\n  when=\\"When a topic keeps catching your attention\\"\\n  record=\\"Keep a running list of topics you want to learn more about\\">\\n  What topics do you want to learn more about? What do you want to learn about?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"quick\\"\\n  why=\\"What you enjoy learning is often where you\'ll go furthest. Noticing it helps you lean into your natural energy instead of grinding against it.\\"\\n  howOften=\\"Quarterly, noticing where your learning feels effortless\\"\\n  when=\\"When choosing between subjects to invest your time in\\"\\n  record=\\"Note the subjects that energize you rather than drain you\\">\\n  What subjects do you enjoy learning about?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Growth areas and shortcomings\\n\\n<SectionBanner why=\\"The gaps you avoid looking at are the ones that hold you back the most. These questions name what you\'d rather not, so you can actually work on it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"You can\'t improve what you won\'t name. Asking where you can grow, plainly, is what turns vague dissatisfaction into a workable list.\\"\\n  howOften=\\"Quarterly, as an honest growth audit\\"\\n  when=\\"During a review of where you want to be stronger\\"\\n  record=\\"List the areas of your life and yourself most worth improving\\">\\n  What areas in your life can you improve? What areas of yourself should you work on?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming what you\'re actively working on keeps your growth deliberate instead of drifting. It\'s the difference between improving and just hoping to.\\"\\n  howOften=\\"Monthly, tracking your current growth efforts\\"\\n  when=\\"During a monthly check on where you\'re putting growth energy\\"\\n  record=\\"Note the specific aspects you\'re currently trying to improve\\">\\n  What aspects of your life are you currently trying to improve?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing you want to grow is different from knowing how. This question pushes from intention into an actual direction for change.\\"\\n  howOften=\\"Quarterly, after naming where you want to grow\\"\\n  when=\\"When you\'ve identified a growth area but not the path through it\\"\\n  record=\\"Write the concrete way you intend to grow in each area\\">\\n  How should you grow?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Your gaps and shortcomings are uncomfortable to face but cheap to ignore at your own expense. Naming them honestly is the hardest and most useful move here.\\"\\n  howOften=\\"Quarterly, with deliberate honesty\\"\\n  when=\\"When you\'re ready to look squarely at what you\'re missing\\"\\n  record=\\"List your gaps and shortcomings plainly, without softening them\\">\\n  What are your gaps? What are your shortcomings?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Learning style\\n\\n<SectionBanner why=\\"How you learn best shapes how fast and how deeply you learn at all. Knowing your style lets you stop fighting your own wiring.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Forcing yourself to learn against your grain wastes effort. Knowing your style lets you choose methods that actually stick for you.\\"\\n  howOften=\\"When picking how to approach a new subject\\"\\n  when=\\"When deciding between reading, doing, watching, or teaching to learn something\\"\\n  record=\\"Note which learning methods consistently work best for you\\">\\n  What is your learning style?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Capturing realizations\\n\\n<SectionBanner why=\\"Insights are easy to have and easy to lose. These questions are about catching your realizations before they slip away unrecorded.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"A realization you don\'t write down rarely survives the week. Capturing them is what compounds insight over time instead of relearning it.\\"\\n  howOften=\\"Weekly, sweeping up what occurred to you\\"\\n  when=\\"At the end of a week, or right after something clicks\\"\\n  record=\\"Keep a running note of realizations as they happen\\">\\n  What realizations have you had?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Some learnings are too valuable to leave in your head. Asking what needs capturing forces you to act before the insight fades.\\"\\n  howOften=\\"Weekly, scanning for what\'s worth preserving\\"\\n  when=\\"When you\'ve learned something you don\'t want to lose\\"\\n  record=\\"Write down the learnings worth keeping in a durable place\\">\\n  What learnings need to be captured?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Experience is the richest teacher, but only if you mine it. Asking what insights have emerged turns lived events into lasting lessons.\\"\\n  howOften=\\"Weekly, reflecting on what your experiences taught you\\"\\n  when=\\"After a meaningful experience, while it\'s still vivid\\"\\n  record=\\"Write the insight each experience produced, not just what happened\\">\\n  What insights have emerged from your experiences?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-reflecting-on-your-priorities","metadata":{"permalink":"/thoughts/questions-for-reflecting-on-your-priorities","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-reflecting-on-your-priorities.mdx","source":"@site/blog/2017-02-11-questions-for-reflecting-on-your-priorities.mdx","title":"What I Ask Myself: About My Priorities","description":"The questions I sit with to check whether my time and energy are actually going to what matters most right now.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":10.64,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-reflecting-on-your-priorities","title":"What I Ask Myself: About My Priorities","kind":"question-set","sidebar_label":"My Priorities","description":"The questions I sit with to check whether my time and energy are actually going to what matters most right now.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: About What I\'m Learning","permalink":"/thoughts/questions-for-reflecting-on-what-youre-learning"},"nextItem":{"title":"What I Ask Myself: About My Worth","permalink":"/thoughts/questions-for-reflecting-on-your-worth"}},"content":"Priorities drift quietly. What mattered last month keeps occupying my calendar long after it stopped being the point. These are the questions I return to when I want to step back and check whether my time and energy are still flowing toward what actually matters. I read them slowly, and let the uncomfortable ones surface what\'s been on autopilot.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Current priorities\\n\\n<SectionBanner why=\\"Naming what matters right now is the anchor for everything else. If I can\'t say my top priorities out loud, my calendar will fill itself with whatever shouts loudest.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"If I can\'t name my current priorities clearly, I have no standard to measure my time against. This is the baseline question that the rest depend on.\\"\\n  howOften=\\"Weekly, as part of a planning ritual\\"\\n  when=\\"At the start of a week, or whenever I feel scattered\\"\\n  record=\\"Write the top three. If the list runs longer than five, it isn\'t a priority list yet.\\">\\n  What are your top priorities right now? What is currently important to you?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"Commitment is the difference between a wish and a priority. Naming what I\'ve actually committed my time to exposes the gap between what I say matters and what I\'m spending hours on.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When reviewing how the past month actually went\\"\\n  record=\\"List the goals you\'ve committed real time to this month\\">\\n  What goals are you committing yourself and your time to?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"Growth doesn\'t happen by accident. Naming the specific areas I\'ve chosen keeps me from spreading thin across too many fronts at once.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When deciding where to invest discretionary energy\\"\\n  record=\\"Pick one or two areas of growth, not ten\\">\\n  What areas of growth have you prioritized?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Time allocation\\n\\n<SectionBanner why=\\"A priority you don\'t fund with time is just a preference. This section checks whether my hours line up with what I claim matters, and forces the today-versus-eventually split.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"This is the accountability question. It compares the ideal allocation of my time against the real one, and the gap is usually uncomfortable, which is exactly why it\'s useful.\\"\\n  howOften=\\"Weekly. Check it against the calendar you actually lived\\"\\n  when=\\"At a weekly review, looking back at how the hours went\\"\\n  record=\\"Write where time should go, then where it actually went; the delta is the work\\">\\n  How should you be spending your time? Are you spending it on what matters most?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Sorting now from eventually keeps urgent-but-trivial things from crowding out important-but-quiet ones. Without the split, everything feels equally pressing.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When planning the week or triaging a task list\\"\\n  record=\\"Two columns: do immediately, do eventually\\">\\n  What should you immediately do? What do you need to do eventually?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"daily\\"\\n  depth=\\"quick\\"\\n  why=\\"Tomorrow is built by what I do today. This question forces me to connect a daily action to a future I actually want, instead of just reacting to the day.\\"\\n  howOften=\\"Daily\\"\\n  when=\\"At the start of the day, when setting the day\'s focus\\"\\n  record=\\"Name one thing today that makes tomorrow easier\\">\\n  What needs to be done today to enable tomorrow?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Priority shifts\\n\\n<SectionBanner why=\\"Priorities change, and pretending they don\'t is how stale goals keep eating my time. This section makes the changes explicit so I can act on them instead of drifting.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The \'why\' is the part that keeps a priority honest. If I can\'t explain why something is top priority right now, it probably isn\'t, or I\'ve stopped questioning it.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"During a monthly review of goals\\"\\n  record=\\"For each top goal, write the reason it earns that rank today\\">\\n  Which of your goals are top priority right now, and why?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming what dropped is as important as naming what rose. A goal that quietly fell off deserves an honest reason, otherwise I\'ll feel guilty about abandoning it without ever deciding to.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When something that used to matter has gone quiet\\"\\n  record=\\"Write what dropped and the honest reason it did\\">\\n  Which of your goals dropped in priority, and why?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The goals I\'m not tracking are the ones most likely to be neglected. This question surfaces the important things that have fallen outside any system.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"During a broader review of where my attention actually goes\\"\\n  record=\\"List anything important that lives only in your head, not in a system\\">\\n  Are there any important goals in your life that you\'re not tracking?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"Ignoring a goal is a decision, even when it\'s made by default. Naming the ignored ones lets me choose them on purpose or drop them on purpose.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When reviewing the full set of goals\\"\\n  record=\\"List the goals you\'ve been avoiding, then decide: commit or drop\\">\\n  What goals are you ignoring?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Task prioritization\\n\\n<SectionBanner why=\\"Not all tasks are equal, and the ones that pay off aren\'t always the ones I want to do. This section sorts the high-value work from the merely appealing.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Benefit and desire often point in different directions. Seeing both for the same task list tells me where I need discipline and where I can just follow my energy.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When choosing what to actually work on next\\"\\n  record=\\"Mark each task: high-benefit, want-to-do, or both\\">\\n  What tasks will benefit you the most? What tasks do you actually want to do?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Prioritization is a skill, not a feeling. Having an actual method beats sorting by whatever feels most urgent in the moment.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When the task list has grown faster than the time to do it\\"\\n  record=\\"Write down the rule you use to rank, so it\'s repeatable\\">\\n  How will you properly prioritize what you should be working on or thinking about?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"Ignored tasks accumulate quietly until they become a crisis. A regular check keeps the backlog from rotting out of sight.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"During a weekly task review\\"\\n  record=\\"Scan for stalled tasks; note which ones you\'ve been keeping up with\\">\\n  Are you ignoring any tasks? Are you keeping up with them?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Learning priorities\\n\\n<SectionBanner why=\\"Learning is a priority that\'s easy to defer because nothing breaks when I skip it. Naming what I should be learning keeps growth from being the thing that always gets cut.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"There\'s always more to learn than time to learn it. Naming what I should be learning, specifically, keeps me from drifting toward whatever\'s easiest or most entertaining.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When planning where to spend learning time\\"\\n  record=\\"List the topics that would most move your goals forward\\">\\n  What are the things you should be learning?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"monthly\\"\\n  depth=\\"quick\\"\\n  why=\\"A reading list is a learning plan in disguise. Choosing the books on purpose beats grabbing whatever happens to be in front of me.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When finishing a book and deciding what\'s next\\"\\n  record=\\"Keep a short, intentional reading queue\\">\\n  What are the books you should be reading?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Some learning is for the job; some is for the mind. Naming what expands my thinking, not just my skills, keeps me from only ever learning the immediately useful.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When my thinking feels narrow or stuck in one mode\\"\\n  record=\\"Name the learning that stretches how you think, not just what you can do\\">\\n  What do you need to learn to expand your mind?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Goals and plans\\n\\n<SectionBanner why=\\"A goal without a plan stays a hope. This section pushes each goal toward the concrete: the projects, the timing, and the reasons behind them.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Goals and plans are different things. Goals say where I\'m going; plans say how. Confusing the two is how people end up with ambitions they never act on.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"At the start of a new quarter or major chapter\\"\\n  record=\\"Write the goals, then the plan for each; keep them visibly separate\\">\\n  Have you figured out your goals? What are your plans?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Projects are where goals become work. Sorting what needs to finish soon from what I should pick up next keeps the in-progress pile from quietly growing forever.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When reviewing active and upcoming projects\\"\\n  record=\\"Two lists: finish soon, and start next\\">\\n  What projects do you need to finish soon? What projects should you work on?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The \'why\' behind a project is what keeps me going when it gets hard. Choosing the kind of project on purpose, with a reason, beats taking on whatever lands in my lap.\\"\\n  howOften=\\"Monthly\\"\\n  when=\\"When deciding whether to take on a new project\\"\\n  record=\\"For each candidate project, write the reason it\'s worth your time\\">\\n  What kind of projects should you be working on, and why?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"A goal without a reason and a date is just a label. Attaching the why and the when turns intention into something I can actually schedule.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"When committing to an action\\"\\n  record=\\"For each commitment, note the reason and the date\\">\\n  Why and when are you going to do something?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Weekly planning\\n\\n<SectionBanner why=\\"The weekly ritual is the heartbeat of staying on track. Without a repeatable rhythm, planning happens only in crisis, which is too late to matter.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"A ritual is what makes planning reliable instead of occasional. If I can\'t describe my weekly ritual, I probably don\'t have one, and the week runs me instead.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"At the same anchor point each week\\"\\n  record=\\"Write down the steps of your weekly ritual so it\'s repeatable\\">\\n  What is your weekly planning ritual?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"weekly\\"\\n  depth=\\"quick\\"\\n  why=\\"The week is the unit where intention meets reality. Naming this week\'s goals turns a vague sense of busyness into a small, checkable list.\\"\\n  howOften=\\"Weekly\\"\\n  when=\\"At the start of the week\\"\\n  record=\\"Pick a handful of goals for the week, no more\\">\\n  What are this week\'s goals?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Quests and dreams\\n\\n<SectionBanner why=\\"Beneath the weekly tasks are the bigger things I\'m actually chasing. To achieve my goals and my dreams, I set out on quests, and these questions keep those quests in view.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Framing goals as quests changes how I relate to them: a quest is something I commit to and strive for, not just a box to tick. This question keeps the bigger pursuits alive behind the daily list.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"During a longer reflection on direction\\"\\n  record=\\"Name the quests you\'re on and what each is really for\\">\\n  What quests are you on? What goals are you chasing? What will you strive to do?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Dreams stay dreams until they have a path. This question forces me to turn the thing I want most into a sequence of steps I could actually take.\\"\\n  howOften=\\"Quarterly, and whenever a dream feels stalled\\"\\n  when=\\"When a dream has lived in my head long enough to need a plan\\"\\n  record=\\"Write the dream, then the first concrete step toward realizing it\\">\\n  What do you need to do to realize your dreams? How will you realize them?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"What I want to become and master is the deepest layer of priority. It\'s the slow-moving aim that all the weekly work is supposed to serve.\\"\\n  howOften=\\"Yearly\\"\\n  when=\\"During annual reflection on identity and direction\\"\\n  record=\\"Write what you want to become and what you want to master; revisit it across years\\">\\n  What do you want to become? What do you want to master?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-reflecting-on-your-worth","metadata":{"permalink":"/thoughts/questions-for-reflecting-on-your-worth","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-reflecting-on-your-worth.mdx","source":"@site/blog/2017-02-11-questions-for-reflecting-on-your-worth.mdx","title":"What I Ask Myself: About My Worth","description":"The questions I sit with when I want an honest inventory of my value, my skills, and the way I change how people think and feel.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":10.78,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-reflecting-on-your-worth","title":"What I Ask Myself: About My Worth","kind":"question-set","sidebar_label":"My Worth","description":"The questions I sit with when I want an honest inventory of my value, my skills, and the way I change how people think and feel.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: About My Priorities","permalink":"/thoughts/questions-for-reflecting-on-your-priorities"},"nextItem":{"title":"What I Ask Myself: When I Can\'t Act","permalink":"/thoughts/questions-for-understanding-your-inaction"}},"content":"It\'s easy to confuse what I\'ve done with what I\'m worth. Worth is harder: it\'s about\\nthe value I create, the skills I actually have, and the way I change how people think\\nand feel. These are the questions I sit with when I want an honest inventory of myself\\nrather than a flattering one. I pick the ones that make me pause before I answer.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Evaluating yourself\\n\\n<SectionBanner why=\\"Before I can grow my worth, I have to be able to assess it honestly, without inflating or deflating it. These questions ask for a clear-eyed read on what actually makes me valuable.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"How I evaluate myself sets the standard I live up or down to. If I measure my worth by the wrong yardstick, I\'ll chase the wrong proof of it. This question forces me to name the yardstick out loud.\\"\\n  howOften=\\"Once a year, and any time my sense of self-worth swings hard\\"\\n  when=\\"During annual reflection, or after a success or failure that moved how I see myself\\"\\n  record=\\"Write the criteria I actually judge myself by, then ask whether those are the right ones\\">\\n  How do you evaluate yourself? What makes you valuable?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"What I think I\'m worth quietly caps what I\'ll ask for and attempt. Separating my honest self-estimate from what\'s actually valuable about me exposes where I\'m underselling myself or coasting on a flattering story.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"When I\'m about to negotiate, ask for something, or decide whether I\'m enough for a challenge\\"\\n  record=\\"Write my honest number or read, then the list of what\'s genuinely valuable; compare the two\\">\\n  What do you think you\'re worth? What is valuable about you?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming my most impressive skills isn\'t bragging; it\'s knowing my own toolkit. If I can\'t list what I\'m genuinely good at, I can\'t deploy it deliberately or build on it.\\"\\n  howOften=\\"Quarterly, as a capability check\\"\\n  when=\\"When deciding what to lead with, or what to develop further\\"\\n  record=\\"A ranked short list of my strongest skills, updated as they grow\\">\\n  What are your most impressive skills?\\n</Question>\\n\\n</QuestionSection>\\n\\n## How you add value\\n\\n<SectionBanner why=\\"Worth isn\'t a static number; it\'s something I produce by adding value to specific people and places. These questions push me from \'what am I worth\' to \'how, where, and to whom do I actually create value.\'\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"\'How do you add value\' is the active version of worth: not what I am, but what I produce for others. Adding the future tense, \'how do you plan on being valuable,\' keeps it from being a one-time accounting and makes it a direction.\\"\\n  howOften=\\"Quarterly, when I plan where to put my effort\\"\\n  when=\\"At the start of a season, or when I feel like I\'m taking more than I\'m giving\\"\\n  record=\\"Write how I add value now and the concrete plan for adding more; check the plan against my calendar\\">\\n  How do you add value? How do you plan on being valuable?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"There\'s a difference between where I could have an impact and where I choose to. The word \'choose\' is the point: my impact is finite, so deciding where to aim it is itself a statement of values.\\"\\n  howOften=\\"Quarterly, when allocating my limited attention\\"\\n  when=\\"When I\'m spread across too many places to matter in any of them\\"\\n  record=\\"List where I genuinely affect things, then pick the few places I\'m choosing to focus\\">\\n  Where can you have an impact? Where do you choose to affect?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Being valuable to myself and being valuable to society are different accounts, and both matter. Checking them together keeps me from neglecting one for the other, since a worth that serves no one and a service that empties me are both incomplete.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"When I notice I\'m pouring into others and running dry, or hoarding value and helping no one\\"\\n  record=\\"Write my value to myself and to society side by side; look for the imbalance\\">\\n  How are you valuable to yourself? To society?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Your impact on others\\n\\n<SectionBanner why=\\"A real measure of my worth is the change I leave in other people\'s heads and hearts. These questions ask me to be deliberate about the thoughts and feelings I want to invoke, instead of leaving my effect on people to chance.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"The thoughts I stir in others outlast almost anything else I do. If I\'m not clear on what I want them to think, I\'m producing influence with no aim. Naming the thoughts gives my work a target.\\"\\n  howOften=\\"Annually, and before sharing work that will reach people\\"\\n  when=\\"When preparing to publish, speak, or lead in any visible way\\"\\n  record=\\"Write the thoughts I want someone to leave with, then ask whether my current work produces them\\">\\n  What thoughts do you want to invoke from others? How do you want them to structure their thoughts?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Feelings are the part of my impact that people remember longest, often after they\'ve forgotten the details. Deciding what emotion I want to invoke turns my effect on people into something I shape rather than something that just happens.\\"\\n  howOften=\\"Annually, alongside the thoughts question\\"\\n  when=\\"When I want to be intentional about the emotional mark I leave\\"\\n  record=\\"Name the feeling I want to create; gather feedback on the feeling I actually leave\\">\\n  What emotions do you want to invoke?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"How I want to be seen and how I can actually shape that are linked. Asking both keeps the aspiration honest, because wanting to be seen a certain way means nothing unless I\'m doing the things that earn it.\\"\\n  howOften=\\"Annually\\"\\n  when=\\"When there\'s a gap between how I\'m perceived and how I want to be\\"\\n  record=\\"Write the perception I want, then the concrete behaviors that would actually create it\\">\\n  How do you want others to see you? How can you affect how others think, feel, and perceive you?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Skills and talents\\n\\n<SectionBanner why=\\"My skills are the raw material of my worth, but only if I know them honestly and develop the right ones. These questions take a real inventory of what I can do and decide where to deepen it.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing my fast ball, the one thing I do better than anything else, tells me what to lead with and lean on. Most people scatter their effort; naming the single best skill lets me build around a real strength.\\"\\n  howOften=\\"Quarterly, as I sharpen my edge\\"\\n  when=\\"When deciding what to specialize in or what to put forward\\"\\n  record=\\"Name the one signature skill plainly; if I can\'t, that\'s a sign to develop one\\">\\n  What is your fast ball, the one thing you do better than anything else?\\n</Question>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The gap between the skills I have and the balance I want is a development map. Naming both, and the why behind which to focus on, turns vague self-improvement into a deliberate plan.\\"\\n  howOften=\\"Quarterly\\"\\n  when=\\"When planning what to learn or invest in next\\"\\n  record=\\"Two columns, current balance and desired balance; write the why next to each focus choice\\">\\n  What talents and abilities do you currently have? Which do you want to focus on, and why? What balance of skills do you have versus the balance you want?\\n</Question>\\n\\n<Question\\n  power=\\"anvil\\"\\n  priority=\\"high\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"A gift left undeveloped is worth withheld from the world and from me. Asking which gift deserves developing, and committing to fully use my talents, is how raw ability turns into actual value instead of unrealized potential.\\"\\n  howOften=\\"Annually, as a stewardship check\\"\\n  when=\\"When I notice a strength I keep neglecting, or feel underused\\"\\n  record=\\"Name the gift worth developing and one concrete way I\'ll fully use it this year\\">\\n  What gift of yours is worth developing? What deserves developing? How will you fully utilize your talents?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"medium\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Asking what qualifies me to teach what I know is a tough honesty check on my real competence. If I can\'t answer it, I may know less than I think; if I can, teaching is one of the highest-value ways to use that knowledge.\\"\\n  howOften=\\"Annually, or before I set out to teach or mentor\\"\\n  when=\\"When I\'m tempted to teach something, or doubting whether I\'ve earned the right to\\"\\n  record=\\"Write the honest qualification: the experience and depth that back up what I\'d teach\\">\\n  What qualifies you to teach what you know?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Your contribution\\n\\n<SectionBanner why=\\"Worth measured at different scales looks different: what I give myself, my family, society, and the planet. These questions widen the lens so my contribution isn\'t only counted in one narrow place.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'anvil\', \'fire\']}\\n  priority=\\"core\\"\\n  cron=\\"yearly\\"\\n  depth=\\"deep\\"\\n  why=\\"Measuring my contribution across widening circles, self, family, society, planet, keeps my worth from collapsing into one easy scale. The widest circles are the ones I\'m most tempted to ignore, which is exactly why the question matters.\\"\\n  howOften=\\"Once a year, as a contribution audit\\"\\n  when=\\"During year-end reflection, when taking stock of what my life is actually producing\\"\\n  record=\\"Write the contribution at each level; the empty levels are where the next work lives\\">\\n  What is your contribution to yourself? To your family? To society? To the planet?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Pairing \'how\' with \'to whom\' keeps my plan to be valuable concrete instead of abstract. Value always has a recipient, and naming them stops me from a vague intention to help that never lands anywhere specific.\\"\\n  howOften=\\"Quarterly, when planning where to direct my value\\"\\n  when=\\"When my intention to contribute is real but unfocused\\"\\n  record=\\"Write the specific people or groups I\'ll be valuable to, and how, for each\\">\\n  How do you plan on being valuable, and to whom?\\n</Question>\\n\\n<Question\\n  priority=\\"low\\"\\n  cron=\\"yearly\\"\\n  depth=\\"moderate\\"\\n  why=\\"The resources of the world I draw on, time, attention, materials, opportunity, come with a quiet responsibility. Asking what I\'m using reframes my worth as stewardship: am I returning at least as much as I consume?\\"\\n  howOften=\\"Annually, as a stewardship reflection\\"\\n  when=\\"When taking stock of what I consume versus what I give back\\"\\n  record=\\"List the world\'s resources I rely on, then what I return in exchange\\">\\n  What resources of the world are you utilizing?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Taking inventory\\n\\n<SectionBanner why=\\"Most of my self-assessment is either too flattering or too harsh. These questions ask for a plain, honest inventory: what I actually do well, what I actually know, and what genuinely deserves more of my attention.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"An honest inventory of my skills is the antidote to both impostor feelings and inflated self-belief. Asking whether the inventory is truly honest, not flattering, is what makes it useful rather than comforting.\\"\\n  howOften=\\"Quarterly, as a deliberate honesty check\\"\\n  when=\\"When I suspect I\'m either underrating or overrating what I can actually do\\"\\n  record=\\"Write the skill list, then stress-test each entry against real evidence I\'ve done it\\">\\n  Do you have an honest inventory of the skills you have?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"quick\\"\\n  why=\\"Splitting \'what do you do well\' from \'what do you know\' separates skill from knowledge, which I tend to blur. Seeing them apart shows whether I\'m strong on doing, on knowing, or lopsided toward one.\\"\\n  howOften=\\"Quarterly, as a quick inventory\\"\\n  when=\\"When I want a fast read on my abilities versus my knowledge\\"\\n  record=\\"Two short lists, do-well and know; note where one badly outweighs the other\\">\\n  What do you do well? What do you know?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Knowing what deserves more attention to develop turns a static inventory into a growth plan. The word \'deserves\' makes me prioritize: not everything I could develop is worth the investment, so this picks the few that are.\\"\\n  howOften=\\"Quarterly, when choosing what to grow next\\"\\n  when=\\"When deciding where to put my limited development energy\\"\\n  record=\\"Pick the one or two areas that most deserve deeper investment, and why\\">\\n  What deserves more of your attention to develop further?\\n</Question>\\n\\n</QuestionSection>"},{"id":"questions-for-understanding-your-inaction","metadata":{"permalink":"/thoughts/questions-for-understanding-your-inaction","editUrl":"https://github.com/omars-lab/omars-lab.github.io/edit/master/bytesofpurpose-blog/blog/blog/2017-02-11-questions-for-understanding-your-inaction.mdx","source":"@site/blog/2017-02-11-questions-for-understanding-your-inaction.mdx","title":"What I Ask Myself: When I Can\'t Act","description":"The questions I sit with when I want to understand why I haven\'t started, what\'s holding me back, and how to break the loop.","date":"2017-02-11T00:00:00.000Z","tags":[{"inline":true,"label":"self-reflection","permalink":"/thoughts/tags/self-reflection"},{"inline":true,"label":"question-set","permalink":"/thoughts/tags/question-set"}],"readingTime":8.01,"hasTruncateMarker":true,"authors":[{"name":"Omar Eid","title":"Principal AI Architect & Entrepreneur","url":"https://github.com/omars-lab","imageURL":"/img/headshot.png","key":"oeid","page":null}],"frontMatter":{"slug":"questions-for-understanding-your-inaction","title":"What I Ask Myself: When I Can\'t Act","kind":"question-set","sidebar_label":"My Inaction","description":"The questions I sit with when I want to understand why I haven\'t started, what\'s holding me back, and how to break the loop.","authors":["oeid"],"tags":["self-reflection","question-set"],"date":"2017-02-11T00:00:00.000Z","draft":false},"unlisted":false,"prevItem":{"title":"What I Ask Myself: About My Worth","permalink":"/thoughts/questions-for-reflecting-on-your-worth"}},"content":"Knowing what I want is easy. Knowing why I still haven\'t done it is the harder, more\\nuseful work. These are the questions I return to when I\'m stuck in a loop, when I keep\\nchoosing the logical thing over the meaningful one, or when something I clearly want\\njust isn\'t getting done. I read them slowly and answer the ones that make me flinch.\\n\\n\x3c!-- truncate --\x3e\\n\\n## Naming the inaction\\n\\n<SectionBanner why=\\"I can\'t fix a problem I haven\'t named. Before any of the why or how, I have to admit plainly what I\'m not doing and stop letting it stay vague enough to ignore.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming the specific thing I\'m not doing, but should be, drags it out of the fog where it\'s easy to avoid. The two angles, what I want to do and what I should be doing, catch both the longing and the obligation I\'m dodging.\\"\\n  howOften=\\"Monthly, and any time I feel a low hum of avoidance\\"\\n  when=\\"When I sense I\'m dodging something but haven\'t made myself say what\\"\\n  record=\\"Write the specific undone thing in plain words; vagueness is how it survives\\">\\n  What haven\'t you done that you want to do? What are you not doing that you should be doing?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"core\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"The repeated \'why\' is the point: the first answer is usually an excuse, and the truth sits a few layers down. Asking it from several angles wears down the surface story until the real reason shows.\\"\\n  howOften=\\"Monthly, whenever I notice the same thing staying undone\\"\\n  when=\\"When I\'ve named the inaction and now need the honest reason for it\\"\\n  record=\\"Write the first answer, then keep asking \'and why that\' until I hit something I can\'t dodge\\">\\n  Why have you not done it yet? Why are you not doing it? Why don\'t you do it?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"\'When will you start\' converts reflection into a commitment with a date. Without a when, understanding my inaction just becomes a more sophisticated way of continuing it.\\"\\n  howOften=\\"Whenever I\'ve understood the why and am tempted to stop there\\"\\n  when=\\"The moment I catch myself analyzing instead of starting\\"\\n  record=\\"Write an actual date or trigger; \'someday\' doesn\'t count\\">\\n  When will you start?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Barriers preventing action\\n\\n<SectionBanner why=\\"Some of what stops me is real and removable; some of it is imaginary. These questions sort the genuine barriers from the excuses and ask what would actually have to change for me to move.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Naming the barriers turns a vague stuckness into a list of specific obstacles, and a list can be worked through one item at a time. What feels like an immovable wall is usually a few separate, smaller things.\\"\\n  howOften=\\"Monthly, when something stays blocked\\"\\n  when=\\"When I feel generally stuck and need to break the block into parts\\"\\n  record=\\"List each barrier separately; a single \'I can\'t\' usually hides three or four real ones\\">\\n  What barriers are preventing action?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"Asking what support or resources I\'d need shifts me from \'I can\'t\' to \'here\'s what would make it possible.\' It reframes the obstacle as a gap to fill rather than a verdict on whether I can act.\\"\\n  howOften=\\"When I\'ve named a barrier and want a path around it\\"\\n  when=\\"When I\'m blocked by a lack of something rather than a lack of will\\"\\n  record=\\"List the specific support or resources needed, and who or what could provide each\\">\\n  What support or resources would you need to move forward?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"\'What would need to change\' makes my conditions for action explicit, and often reveals that I\'m waiting on something I could change myself. The conditions I\'m waiting on are usually fewer and more in my control than they feel.\\"\\n  howOften=\\"When I catch myself waiting for conditions to be right\\"\\n  when=\\"When I keep saying \'once X happens, then I\'ll act\'\\"\\n  record=\\"Write the changes I\'m waiting on, then mark which I could actually trigger myself\\">\\n  What would need to change for you to take action?\\n</Question>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"moderate\\"\\n  why=\\"This is the question that turns a list of barriers into progress, because not every barrier is real or removable, but some are. Finding the one I can actually clear today is how the loop finally breaks.\\"\\n  howOften=\\"Right after listing my barriers\\"\\n  when=\\"When I have a barrier list and need to find the lever that actually moves\\"\\n  record=\\"Circle the removable barriers; pick the one I can clear first and start there\\">\\n  Which of these barriers can actually be removed?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Patterns that keep you stuck\\n\\n<SectionBanner why=\\"My inaction usually isn\'t a one-off; it\'s a pattern I repeat. These questions look for the loop itself, including the trap of choosing the safe, logical thing over the meaningful one, and the comfort I\'ve found in staying stuck.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power={[\'fire\', \'anvil\']}\\n  priority=\\"core\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"A single instance of inaction is a moment; a pattern is a character trait in the making. Finding the recurring shape of how I get stuck is worth far more than solving any one stuck thing, because the pattern will produce the next one.\\"\\n  howOften=\\"Quarterly, looking back across several stuck moments\\"\\n  when=\\"When I notice I\'ve been stuck the same way more than once\\"\\n  record=\\"Write the common thread across my stuck moments; the repeated element is the real target\\">\\n  What patterns keep you from taking action?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"monthly\\"\\n  depth=\\"deep\\"\\n  why=\\"Being stuck in a loop and being \'too logical\' are linked: the logical choice is often the safe one that quietly avoids the meaningful, riskier thing. This question names the trap of reasoning my way out of every leap worth taking.\\"\\n  howOften=\\"Monthly, when I notice repetitive safe choices\\"\\n  when=\\"When I keep picking the sensible option over the one that actually matters to me\\"\\n  record=\\"Note where I chose logical-and-safe over meaningful-and-risky; ask what the logic was protecting me from\\">\\n  Are you stuck in a loop? Are you doing things that are too logical?\\n</Question>\\n\\n<Question\\n  power={[\'fire\', \'chisel\']}\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Comfort in the darkness is the most dangerous kind of stuckness, because it stops feeling like a problem. This asks why I\'ve made peace with a place I shouldn\'t stay, which is usually the first honest step out of it.\\"\\n  howOften=\\"Quarterly, and whenever a bad situation has started to feel normal\\"\\n  when=\\"When something painful has quietly become my comfort zone\\"\\n  record=\\"Write what the darkness gives me that I\'m afraid to lose; that\'s the hook keeping me there\\">\\n  Why have you gotten comfortable in the darkness?\\n</Question>\\n\\n<Question\\n  power=\\"spark\\"\\n  priority=\\"medium\\"\\n  cron=\\"adhoc\\"\\n  depth=\\"quick\\"\\n  why=\\"Flipping the question to \'why NOT do things\' attacks the inertia from the other side. Often there\'s no good reason not to act, and forcing myself to defend the inaction exposes how thin its justification really is.\\"\\n  howOften=\\"Whenever I\'m defaulting to not acting\\"\\n  when=\\"When my reason for not acting is really just inertia in disguise\\"\\n  record=\\"Try to make the honest case for not doing it; if I can\'t, that\'s my answer\\">\\n  Why NOT do things?\\n</Question>\\n\\n</QuestionSection>\\n\\n## Constraints, self-imposed and external\\n\\n<SectionBanner why=\\"Some of my limits I built myself and some came from others, and they call for different responses. These questions separate the two and surface the needs and emotions quietly running the whole pattern of inaction.\\" />\\n\\n<QuestionSection>\\n\\n<Question\\n  power=\\"chisel\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"The constraints I imposed on myself are the ones I can lift the moment I see them clearly. They\'re often invisible precisely because they\'re mine, so naming them is most of the work of removing them.\\"\\n  howOften=\\"Quarterly, when I feel hemmed in\\"\\n  when=\\"When I catch myself treating a self-made rule as if it were a law of nature\\"\\n  record=\\"List my self-imposed constraints; for each, ask whether I\'d keep it if I were choosing fresh today\\">\\n  What constraints have you imposed on yourself?\\n</Question>\\n\\n<Question\\n  priority=\\"medium\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"moderate\\"\\n  why=\\"Constraints others put on me are real, but I often grant them more power than they actually hold. Separating these from my self-imposed ones tells me which limits to negotiate and which to simply stop obeying.\\"\\n  howOften=\\"Quarterly, alongside the self-imposed check\\"\\n  when=\\"When I\'m not sure whether a limit is truly external or one I\'ve adopted\\"\\n  record=\\"List the external constraints, then mark which are genuinely binding and which I\'ve just accepted\\">\\n  What constraints have others imposed on you?\\n</Question>\\n\\n<Question\\n  power=\\"fire\\"\\n  priority=\\"high\\"\\n  cron=\\"quarterly\\"\\n  depth=\\"deep\\"\\n  why=\\"Underneath most of my inaction is a need, belief, or emotion quietly steering me, often a fear I haven\'t named. Surfacing what\'s really controlling me is how I stop being run by it and start acting on purpose.\\"\\n  howOften=\\"Quarterly, and any time my inaction defies my own logic\\"\\n  when=\\"When I want something, know how to get it, and still don\'t move\\"\\n  record=\\"Write the honest needs, beliefs, and emotions driving the stall, including the ones I\'d rather not admit\\">\\n  What are the needs, beliefs, and emotions that are controlling you?\\n</Question>\\n\\n</QuestionSection>"}]}}')}}]);